const UI_SCROLL_SESSION_STORAGE_KEY = 'noteflow_ui_scroll_state_v1';

// Public-beta default: a focused, student-first navigation. Core academic views
// are on; broader optional modules (College planning, Life, Business, Course Hub)
// are off by default and can be enabled from Settings → Feature tabs (Labs).
// Existing users keep their saved selections — normalizeEnabledViews only
// overrides keys actually present in stored preferences. Review/Cram Hub stay
// "enabled" so their consolidated Testing Hub redirects work even though they
// render no standalone tab.
const STUDENT_DEFAULT_ENABLED_VIEWS = new Set(['today', 'timeline', 'notes', 'homework', 'apstudy', 'review', 'cramhub']);
function getDefaultEnabledViews() {
    return OPTIONAL_FEATURE_VIEWS.reduce((acc, view) => {
        acc[view] = STUDENT_DEFAULT_ENABLED_VIEWS.has(view);
        return acc;
    }, {});
}

function normalizeEnabledViews(raw) {
    const normalized = getDefaultEnabledViews();
    if (!raw || typeof raw !== 'object') return normalized;
    OPTIONAL_FEATURE_VIEWS.forEach(view => {
        if (Object.prototype.hasOwnProperty.call(raw, view)) {
            normalized[view] = raw[view] !== false;
        }
    });
    return normalized;
}

const SHORTCUT_PLACEMENTS = new Set(['tabs', 'sidebar']);
const SHORTCUT_TARGET_TYPES = new Set(['url', 'page']);
const MAX_CUSTOM_SHORTCUTS = 30;

function normalizeShortcutPlacement(value) {
    const normalized = String(value || '').trim().toLowerCase();
    return SHORTCUT_PLACEMENTS.has(normalized) ? normalized : 'tabs';
}

function normalizeShortcutTargetType(value, raw = {}) {
    const normalized = String(value || '').trim().toLowerCase();
    if (SHORTCUT_TARGET_TYPES.has(normalized)) return normalized;
    if (raw && (raw.pageId || raw.page_id || raw.targetPageId || raw.noteId || raw.page)) return 'page';
    return 'url';
}

function normalizeShortcutPageId(value) {
    return String(value || '').trim();
}

function sanitizeShortcutIcon(rawIcon) {
    const value = String(rawIcon || '').trim();
    if (!value) return '\u{1F517}';
    const compact = Array.from(value).slice(0, 2).join('');
    return compact || '\u{1F517}';
}

function normalizeShortcutName(rawName, fallback = 'Shortcut') {
    const cleaned = String(rawName || '').replace(/\s+/g, ' ').trim();
    return cleaned ? cleaned.slice(0, 40) : fallback;
}

function normalizeCustomShortcutEntry(raw, fallbackName = 'Shortcut') {
    if (!raw || typeof raw !== 'object') return null;
    const kind = normalizeShortcutTargetType(raw.kind || raw.type || raw.targetType, raw);
    const pageId = normalizeShortcutPageId(raw.pageId || raw.page_id || raw.targetPageId || raw.noteId || raw.page);
    const url = normalizeExternalUrl(raw.url || raw.href || '');
    if (kind === 'page') {
        if (!pageId) return null;
    } else if (!url) {
        return null;
    }
    // Migrate the legacy seeded default shortcut label from the pre-rebrand
    // app. Only rename when the label exactly matches the known legacy value
    // AND the URL points to the project GitHub repo — never touch user labels.
    let rawName = raw.name;
    if (
        typeof rawName === 'string' &&
        rawName.trim() === 'NoteFlowAtelier GitHub repo' &&
        typeof url === 'string' &&
        /github\.com/i.test(url)
    ) {
        rawName = 'Sutra GitHub repo';
    }
    return {
        id: String(raw.id || generateId()).trim() || generateId(),
        name: normalizeShortcutName(rawName, fallbackName),
        kind,
        url: kind === 'url' ? url : '',
        pageId: kind === 'page' ? pageId : '',
        icon: sanitizeShortcutIcon(raw.icon),
        placement: normalizeShortcutPlacement(raw.placement || raw.location || raw.target)
    };
}

function normalizeCustomShortcuts(rawList) {
    if (!Array.isArray(rawList)) return [];
    const seen = new Set();
    const next = [];
    rawList.forEach((item, index) => {
        if (next.length >= MAX_CUSTOM_SHORTCUTS) return;
        const normalized = normalizeCustomShortcutEntry(item, `Shortcut ${index + 1}`);
        if (!normalized) return;
        if (seen.has(normalized.id)) normalized.id = generateId();
        seen.add(normalized.id);
        next.push(normalized);
    });
    return next;
}

