const FA_STYLE_CLASSES = new Set([
    'fa',
    'fas',
    'far',
    'fab',
    'fa-solid',
    'fa-regular',
    'fa-brands',
    'fa-fw',
    'fa-lg',
    'fa-sm',
    'fa-xs',
    'fa-2x',
    'fa-3x',
    'fa-4x',
    'fa-5x'
]);

let iconFallbackObserver = null;

function hasFontAwesomePseudoContent() {
    if (typeof document === 'undefined' || !document.body) return true;
    const probe = document.createElement('i');
    probe.className = 'fas fa-play';
    probe.style.position = 'absolute';
    probe.style.visibility = 'hidden';
    probe.style.pointerEvents = 'none';
    document.body.appendChild(probe);
    const pseudoContent = window.getComputedStyle(probe, '::before').content;
    probe.remove();
    const normalized = String(pseudoContent || '').replace(/["']/g, '').trim();
    return Boolean(normalized && normalized !== 'none' && normalized !== 'normal');
}

function getPrimaryIconClass(iconEl) {
    if (!iconEl || !iconEl.classList) return '';
    const classes = Array.from(iconEl.classList);
    return classes.find(className => className.startsWith('fa-') && !FA_STYLE_CLASSES.has(className)) || '';
}

function applyFallbackToIcon(iconEl) {
    if (!iconEl || !iconEl.classList) return;
    const iconClass = getPrimaryIconClass(iconEl);
    const fallbackGlyph = ICON_FALLBACK_MAP[iconClass] || '*';
    if (!String(iconEl.textContent || '').trim()) {
        iconEl.textContent = fallbackGlyph;
    }
    iconEl.setAttribute('aria-hidden', 'true');
}

function patchMissingIcons(root = document) {
    if (!root || typeof root.querySelectorAll !== 'function') return;
    root.querySelectorAll('i[class*="fa-"]').forEach(applyFallbackToIcon);
}

function applyIconFallbackIfNeeded() {
    if (typeof document === 'undefined' || !document.body) return;

    // Atelier ships a local SVG icon system (src/components/icons). When it
    // loads it hydrates every <i class="fa-..."> element on its own, so this
    // legacy character-glyph fallback only runs in the unlikely case those
    // scripts fail to load.
    if (typeof window !== 'undefined' && window.AtelierIcons) {
        try { window.AtelierIcons.hydrate(document); } catch (e) {}
        return;
    }

    if (hasFontAwesomePseudoContent()) return;

    document.body.classList.add('icon-fallback-active');
    patchMissingIcons(document);

    if (!iconFallbackObserver && typeof MutationObserver !== 'undefined') {
        iconFallbackObserver = new MutationObserver((mutations) => {
            mutations.forEach((mutation) => {
                mutation.addedNodes.forEach((node) => {
                    if (!node || node.nodeType !== 1) return;
                    if (node.matches && node.matches('i[class*="fa-"]')) {
                        applyFallbackToIcon(node);
                    }
                    patchMissingIcons(node);
                });
            });
        });
        iconFallbackObserver.observe(document.body, { childList: true, subtree: true });
    }
}
function normalizePageIcon(icon) {
    if (typeof icon !== 'string') return '';
    const raw = String(icon).trim();
    if (!raw) return '';
    if (PAGE_ICON_MOJIBAKE_MAP[raw]) return PAGE_ICON_MOJIBAKE_MAP[raw];
    if (SEEDED_ICON_MOJIBAKE_REPAIR[raw]) return SEEDED_ICON_MOJIBAKE_REPAIR[raw];
    if (/[<>]/.test(raw)) return PAGE_ICONS.DOC;
    return raw;
}

function normalizePageTitle(rawTitle) {
    const parts = String(rawTitle || '')
        .split('::')
        .map(part => part.trim())
        .filter(Boolean);
    return parts.length ? parts.join('::') : 'Untitled';
}

function normalizeOptionalIsoTimestamp(value) {
    if (!value) return null;
    const parsed = new Date(value);
    if (Number.isNaN(parsed.getTime())) return null;
    return parsed.toISOString();
}

const NOTE_BLOCK_TYPES = Object.freeze({
    HTML_EMBED: 'htmlEmbed',
    // Handwriting / drawing block. Stores structured vector strokes (the source
    // of truth) — never a raster snapshot — so drawings scale with note width and
    // round-trip cleanly through save / .atelier export / import. See
    // src/features/handwriting.js for the engine and normalizeDrawingBlock below.
    DRAWING: 'drawing'
});

// Sizing limits for handwriting blocks (height only; width is always 100% so a
// drawing never causes horizontal page overflow on narrow viewports).
const DRAWING_BLOCK_SIZE_LIMITS = Object.freeze({
    minHeightPx: 160,
    maxHeightPx: 1200,
    defaultHeightPx: 360
});

function normalizeDrawingHeightPx(value, fallback = DRAWING_BLOCK_SIZE_LIMITS.defaultHeightPx) {
    const numeric = Number(value);
    if (!Number.isFinite(numeric)) return fallback;
    return Math.max(DRAWING_BLOCK_SIZE_LIMITS.minHeightPx, Math.min(DRAWING_BLOCK_SIZE_LIMITS.maxHeightPx, Math.round(numeric)));
}

// DOM-free, defensive normalizer for a persisted drawing block. Mirrors the
// HTML_EMBED handling in normalizePageBlocks so malformed imported data can never
// break note rendering. Strokes are validated by the handwriting engine when it
// is present, with a conservative inline fallback for headless/early contexts.
function normalizeDrawingStrokeList(rawStrokes) {
    if (typeof window !== 'undefined' && window.AtelierHandwriting && typeof window.AtelierHandwriting.normalizeStrokes === 'function') {
        return window.AtelierHandwriting.normalizeStrokes(rawStrokes);
    }
    const source = Array.isArray(rawStrokes) ? rawStrokes : [];
    return source.reduce((acc, raw) => {
        if (!raw || typeof raw !== 'object' || !Array.isArray(raw.points) || !raw.points.length) return acc;
        const points = raw.points
            .filter(p => p && typeof p === 'object' && Number.isFinite(Number(p.x)) && Number.isFinite(Number(p.y)))
            .map(p => {
                const pt = { x: Math.max(0, Math.min(1, Number(p.x))), y: Math.max(0, Math.min(1, Number(p.y))) };
                if (Number.isFinite(Number(p.p))) pt.p = Math.max(0, Math.min(1, Number(p.p)));
                return pt;
            });
        if (!points.length) return acc;
        acc.push({
            id: typeof raw.id === 'string' && raw.id ? raw.id : generateId(),
            tool: raw.tool === 'highlighter' ? 'highlighter' : 'pen',
            color: typeof raw.color === 'string' && raw.color ? raw.color : 'ink',
            width: Number.isFinite(Number(raw.width)) && Number(raw.width) > 0 ? Number(raw.width) : 0.009,
            opacity: Number.isFinite(Number(raw.opacity)) ? Math.max(0.05, Math.min(1, Number(raw.opacity))) : 1,
            points,
            createdAt: typeof raw.createdAt === 'string' ? raw.createdAt : new Date().toISOString()
        });
        return acc;
    }, []);
}

function normalizeDrawingBackground(value) {
    return ['blank', 'lined', 'grid', 'dotted'].includes(value) ? value : 'blank';
}

const HTML_EMBED_SIZE_LIMITS = Object.freeze({
    minWidthPct: 42,
    maxWidthPct: 100,
    defaultWidthPct: 100,
    minHeightPx: 180,
    maxHeightPx: 960,
    defaultHeightPx: 360
});

function normalizeHtmlEmbedWidthPct(value, fallback = HTML_EMBED_SIZE_LIMITS.defaultWidthPct) {
    const numeric = Number(value);
    if (!Number.isFinite(numeric)) return fallback;
    return Math.max(HTML_EMBED_SIZE_LIMITS.minWidthPct, Math.min(HTML_EMBED_SIZE_LIMITS.maxWidthPct, Math.round(numeric)));
}

function normalizeHtmlEmbedHeightPx(value, fallback = HTML_EMBED_SIZE_LIMITS.defaultHeightPx) {
    const numeric = Number(value);
    if (!Number.isFinite(numeric)) return fallback;
    return Math.max(HTML_EMBED_SIZE_LIMITS.minHeightPx, Math.min(HTML_EMBED_SIZE_LIMITS.maxHeightPx, Math.round(numeric)));
}

function normalizeBlockIdentifier(rawId, seenIds = null) {
    let id = String(rawId || '').trim();
    if (!id || (seenIds && seenIds.has(id))) {
        id = generateId();
    }
    if (seenIds) seenIds.add(id);
    return id;
}

function normalizePageBlocks(rawBlocks) {
    const source = Array.isArray(rawBlocks) ? rawBlocks : [];
    const seenIds = new Set();
    const now = new Date().toISOString();

    return source.reduce((acc, rawBlock) => {
        if (!rawBlock || typeof rawBlock !== 'object') return acc;
        const type = String(rawBlock.type || '').trim();
        if (!type) return acc;

        const id = normalizeBlockIdentifier(rawBlock.id, seenIds);
        const createdAt = typeof rawBlock.createdAt === 'string' ? rawBlock.createdAt : now;
        const updatedAt = typeof rawBlock.updatedAt === 'string' ? rawBlock.updatedAt : createdAt;

        if (type === NOTE_BLOCK_TYPES.HTML_EMBED) {
            const sanitizedHtml = sanitizeHtmlEmbedContent(rawBlock.html ?? rawBlock.content ?? '', { allowEmpty: true });
            acc.push({
                ...rawBlock,
                id,
                type,
                html: sanitizedHtml,
                widthPct: normalizeHtmlEmbedWidthPct(rawBlock.widthPct),
                heightPx: normalizeHtmlEmbedHeightPx(rawBlock.heightPx),
                version: 1,
                createdAt,
                updatedAt
            });
            return acc;
        }

        if (type === NOTE_BLOCK_TYPES.DRAWING) {
            // Strip any cached raster preview from prior versions — strokes are
            // authoritative and a raster snapshot must never bloat the payload.
            const { strokes, background, heightPx, preview, ...rest } = rawBlock;
            acc.push({
                ...rest,
                id,
                type,
                strokes: normalizeDrawingStrokeList(strokes),
                background: normalizeDrawingBackground(background),
                heightPx: normalizeDrawingHeightPx(heightPx),
                version: 1,
                createdAt,
                updatedAt
            });
            return acc;
        }

        acc.push({
            ...rawBlock,
            id,
            type,
            createdAt,
            updatedAt
        });
        return acc;
    }, []);
}

function clonePageBlocks(rawBlocks, options = {}) {
    const regenerateIds = options.regenerateIds === true;
    const now = new Date().toISOString();
    return normalizePageBlocks(rawBlocks).map(block => ({
        ...block,
        id: regenerateIds ? generateId() : block.id,
        createdAt: regenerateIds ? now : block.createdAt,
        updatedAt: regenerateIds ? now : block.updatedAt
    }));
}

// ===== VERSION HISTORY SNAPSHOT MODEL (Section 17) =====
// Canonical, DOM-free schema + helpers for per-page Version History snapshots.
// These live at module scope (like normalizePagesCollection) so they are pure,
// reusable across the primary and secondary editors, and verifiable headless by
// scripts/version-history-check.mjs.
//
// A snapshot has the shape:  { id, label, savedAt, state: { <captured fields> } }
//
// `state` captures ONLY user-editable, note-level authoring content that a user
// reasonably expects Version History to recover. It deliberately EXCLUDES:
//   - identity / timestamps     (id, createdAt, updatedAt)
//   - security / lock metadata  (isLocked, lockHash, lockSalt, lockedAt, lockAutoLock)
//   - lifecycle flags           (isTemporary, temporary*)
//   - workspace placement       (spaceId), sidebar UI (collapsed), per-page theme
//   - the version history array itself (versions)
// Restoring applies ONLY the fields a snapshot actually captured, so LEGACY
// snapshots (which stored just title + content) never wipe blocks/tags/etc.
const PAGE_VERSION_STATE_FIELDS = Object.freeze([
    'title', 'content', 'icon', 'tags',
    'pageMode', 'formatting', 'documentLayout',
    'comments', 'suggestions', 'footnotes', 'citations',
    'blocks'
]);

// Bounded history. Raising this is acceptable but increases per-note storage;
// snapshots store full content + blocks, so 20 balances recoverability and size.
const PAGE_VERSION_HISTORY_LIMIT = 20;

// Auto-checkpoint cadence during sustained editing (throttle window).
const VERSION_AUTOSNAPSHOT_INTERVAL_MS = 5 * 60 * 1000;

// Deep clone a snapshot value so later edits to the live page can never mutate
// stored history by reference (and vice-versa). Every captured field is plain
// JSON-serializable data (strings / arrays of plain objects).
function deepCloneVersionValue(value) {
    if (value === null || typeof value !== 'object') return value;
    try {
        return JSON.parse(JSON.stringify(value));
    } catch (err) {
        return Array.isArray(value) ? [] : {};
    }
}

// Stable, key-order-independent serialization used for de-duplication so that
// states differing only by object key order are still treated as equivalent.
function stableVersionStringify(value) {
    if (value === null || typeof value !== 'object') {
        return JSON.stringify(value === undefined ? null : value);
    }
    if (Array.isArray(value)) {
        return '[' + value.map(stableVersionStringify).join(',') + ']';
    }
    const keys = Object.keys(value).sort();
    return '{' + keys.map(k => JSON.stringify(k) + ':' + stableVersionStringify(value[k])).join(',') + '}';
}

function pageVersionStateSignature(state) {
    return stableVersionStringify(state && typeof state === 'object' ? state : {});
}

// True when two captured states are content-equivalent (suppresses no-op dupes).
function arePageVersionStatesEquivalent(a, b) {
    return pageVersionStateSignature(a) === pageVersionStateSignature(b);
}

function generateVersionSnapshotId() {
    // Prefer the app's id generator when present; fall back to a self-contained
    // id so the helper stays pure and testable without it.
    if (typeof generateId === 'function') {
        try {
            const id = generateId();
            if (id) return String(id);
        } catch (err) { /* fall through */ }
    }
    return 'ver-' + Date.now().toString(36) + '-' + Math.random().toString(36).slice(2, 8);
}

// Capture the editable state of a live page into a fresh, deep-cloned object.
function buildPageVersionStateFromPage(page) {
    const state = {};
    if (!page || typeof page !== 'object') return state;
    PAGE_VERSION_STATE_FIELDS.forEach(field => {
        const value = page[field];
        if (value === undefined || value === null) return;
        state[field] = deepCloneVersionValue(value);
    });
    // title/content are the backbone of every snapshot — guarantee string type.
    state.title = typeof page.title === 'string' ? page.title : String(page.title || '');
    state.content = typeof page.content === 'string' ? page.content : String(page.content || '');
    return state;
}

// Normalize a raw snapshot (legacy flat OR current nested) into the canonical
// shape. Legacy snapshots only carried { id, content, title, savedAt, label };
// they are lifted into `state` WITHOUT inventing empty arrays for fields they
// never captured, so a later restore won't clobber those fields.
function normalizePageVersionSnapshot(rawSnapshot) {
    if (!rawSnapshot || typeof rawSnapshot !== 'object') return null;
    const hasNestedState = rawSnapshot.state && typeof rawSnapshot.state === 'object';
    const source = hasNestedState ? rawSnapshot.state : rawSnapshot;
    const state = {};
    PAGE_VERSION_STATE_FIELDS.forEach(field => {
        const value = source[field];
        if (value === undefined || value === null) return;
        state[field] = deepCloneVersionValue(value);
    });
    if (typeof state.title !== 'string') {
        state.title = typeof rawSnapshot.title === 'string' ? rawSnapshot.title
            : (typeof source.title === 'string' ? source.title : '');
    }
    if (typeof state.content !== 'string') {
        state.content = typeof rawSnapshot.content === 'string' ? rawSnapshot.content
            : (typeof source.content === 'string' ? source.content : '');
    }
    const savedAt = (typeof rawSnapshot.savedAt === 'string' && rawSnapshot.savedAt)
        ? rawSnapshot.savedAt
        : ((typeof rawSnapshot.timestamp === 'string' && rawSnapshot.timestamp)
            ? rawSnapshot.timestamp
            : new Date().toISOString());
    return {
        id: (typeof rawSnapshot.id === 'string' && rawSnapshot.id) ? rawSnapshot.id : generateVersionSnapshotId(),
        label: (typeof rawSnapshot.label === 'string' && rawSnapshot.label) ? rawSnapshot.label : 'Snapshot',
        savedAt: savedAt,
        state: state
    };
}

// Normalize + bound an entire versions array (used on load/import). Drops
// unparseable entries instead of letting one break the whole note.
function normalizePageVersionList(rawVersions) {
    if (!Array.isArray(rawVersions)) return [];
    const normalized = [];
    rawVersions.forEach(entry => {
        const snap = normalizePageVersionSnapshot(entry);
        if (snap) normalized.push(snap);
    });
    return normalized.length > PAGE_VERSION_HISTORY_LIMIT
        ? normalized.slice(-PAGE_VERSION_HISTORY_LIMIT)
        : normalized;
}

// Build a canonical snapshot from a live page. options: { id, savedAt }.
function buildPageVersionSnapshot(page, label, options) {
    const opts = (options && typeof options === 'object') ? options : {};
    return normalizePageVersionSnapshot({
        id: opts.id,
        label: label,
        savedAt: opts.savedAt,
        state: buildPageVersionStateFromPage(page)
    });
}

// Apply a snapshot's captured state onto a live page, in place and atomically.
// Only fields the snapshot captured are touched; identity, lock/security,
// lifecycle, and the version history array are left intact. Values are
// deep-cloned so editing the restored page cannot mutate stored history.
function restorePageFromVersionSnapshot(page, rawSnapshot, options) {
    if (!page || typeof page !== 'object') return page;
    const snapshot = normalizePageVersionSnapshot(rawSnapshot);
    if (!snapshot) return page;
    const state = snapshot.state || {};
    const opts = (options && typeof options === 'object') ? options : {};
    PAGE_VERSION_STATE_FIELDS.forEach(field => {
        if (field === 'title') return; // handled below (hierarchy-aware)
        if (Object.prototype.hasOwnProperty.call(state, field)) {
            page[field] = deepCloneVersionValue(state[field]);
        }
    });
    // Title: only the leaf (the last '::'-delimited segment) is document content;
    // the parent path is tree STRUCTURE. Keep the page's CURRENT place in the
    // tree and restore just the leaf — mirroring how savePage()/loadPage() treat
    // the title field everywhere else. (A literal '::' inside a single leaf name
    // is an app-wide ambiguity in Atelier's title model, not specific to Version
    // History; we stay consistent with the rest of the app rather than diverge.)
    if (Object.prototype.hasOwnProperty.call(state, 'title')) {
        const restoredLeaf = String(state.title || '').split('::').pop();
        const currentParts = String(page.title || '').split('::');
        currentParts[currentParts.length - 1] = restoredLeaf;
        page.title = currentParts.join('::');
    }
    page.updatedAt = (typeof opts.now === 'string' && opts.now) ? opts.now : new Date().toISOString();
    return page;
}
// ===== END VERSION HISTORY SNAPSHOT MODEL =====

function normalizePagesCollection(rawPages) {
    const seenIds = new Set();
    const now = new Date().toISOString();
    return (Array.isArray(rawPages) ? rawPages : []).reduce((acc, rawPage) => {
        if (!rawPage || typeof rawPage !== 'object') return acc;
        const page = rawPage;
        let id = String(page.id || '').trim();
        if (!id || seenIds.has(id)) id = generateId();
        seenIds.add(id);
        acc.push({
            ...page,
            id,
            title: normalizePageTitle(page.title),
            content: typeof page.content === 'string' ? page.content : String(page.content || ''),
            icon: normalizePageIcon(page.icon),
            collapsed: page.collapsed === true,
            theme: normalizeStoredThemeKey(page.theme, 'default', true),
            createdAt: typeof page.createdAt === 'string' ? page.createdAt : now,
            updatedAt: typeof page.updatedAt === 'string' ? page.updatedAt : now,
            blocks: normalizePageBlocks(page.blocks),
            isTemporary: page.isTemporary === true,
            temporaryCreatedAt: normalizeOptionalIsoTimestamp(page.temporaryCreatedAt || (page.isTemporary ? page.createdAt : null)),
            temporaryExpiresAt: normalizeOptionalIsoTimestamp(page.temporaryExpiresAt || page.expiresAt),
            // Lock fields — safe defaults for workspaces that pre-date this feature
            isLocked: page.isLocked === true,
            lockHash: typeof page.lockHash === 'string' && page.lockHash ? page.lockHash : null,
            lockSalt: typeof page.lockSalt === 'string' && page.lockSalt ? page.lockSalt : null,
            lockedAt: normalizeOptionalIsoTimestamp(page.lockedAt),
            lockAutoLock: ['navigation','5min','15min','60min','session'].includes(page.lockAutoLock) ? page.lockAutoLock : 'navigation',
            // Spaces (Section 6) — pages without spaceId default to 'default' space
            spaceId: typeof page.spaceId === 'string' && page.spaceId ? page.spaceId : 'default',
            // Page mode (Section 7) — per-page page mode metadata
            pageMode: normalizePageModeMeta(page.pageMode),
            // Document background (Sutra) — per-page background image + blur + dim.
            // Stored as a data URL (like inline images) so it rides persistence,
            // .sutra inline-asset extraction, and JSON export/import automatically.
            documentBackground: normalizeDocumentBackground(page.documentBackground),
            // Formatting (Section 8) — per-page formatting metadata
            formatting: normalizePageFormatting(page.formatting),
            // Document layout (Section 9) — headers, footers, page numbers
            documentLayout: normalizeDocumentLayout(page.documentLayout),
            // Comments (Section 11) — local-only comments
            comments: Array.isArray(page.comments) ? page.comments.filter(c => c && c.id && c.text) : [],
            // Suggestions (Section 12) — suggesting mode edits
            suggestions: Array.isArray(page.suggestions) ? page.suggestions.filter(s => s && s.id) : [],
            // Footnotes/citations (Section 15)
            footnotes: Array.isArray(page.footnotes) ? page.footnotes.filter(f => f && f.id) : [],
            citations: Array.isArray(page.citations) ? page.citations.filter(c => c && c.id) : [],
            // Tags (note labels) — validate the {name,color} shape so a malformed
            // entry can't break tag rendering. Previously survived only via spread.
            tags: Array.isArray(page.tags) ? page.tags.filter(tag => tag && typeof tag === 'object' && tag.name) : [],
            // Version history (Section 17) — normalized + bounded. Legacy flat
            // snapshots and malformed entries are handled safely (never deleted
            // wholesale), keeping nested history durable across save/export/import.
            versions: normalizePageVersionList(page.versions)
        });
        return acc;
    }, []);
}

function normalizePageModeMeta(raw) {
    const r = raw && typeof raw === 'object' ? raw : {};
    return {
        enabled: r.enabled === true,
        size: (r.size === 'a4') ? 'a4' : 'letter',
        margins: {
            top: Number.isFinite(Number(r.margins && r.margins.top)) ? Number(r.margins.top) : 25.4,
            bottom: Number.isFinite(Number(r.margins && r.margins.bottom)) ? Number(r.margins.bottom) : 25.4,
            left: Number.isFinite(Number(r.margins && r.margins.left)) ? Number(r.margins.left) : 25.4,
            right: Number.isFinite(Number(r.margins && r.margins.right)) ? Number(r.margins.right) : 25.4
        }
    };
}

function normalizeDocumentBackground(raw) {
    const r = raw && typeof raw === 'object' ? raw : {};
    const hasImg = typeof r.dataUrl === 'string' && /^data:image\/(png|jpe?g|webp);/i.test(r.dataUrl);
    let blur = Math.round(Number(r.blurPx));
    if (!Number.isFinite(blur)) blur = 0;
    blur = Math.max(0, Math.min(32, blur));
    let dim = Number(r.overlayOpacity);
    if (!Number.isFinite(dim)) dim = 0.25;
    dim = Math.max(0, Math.min(0.8, dim));
    return {
        enabled: hasImg && r.enabled !== false,
        dataUrl: hasImg ? r.dataUrl : null,
        blurPx: blur,
        overlayOpacity: dim,
        name: typeof r.name === 'string' ? r.name.slice(0, 200) : '',
        mimeType: typeof r.mimeType === 'string' ? r.mimeType : '',
        fit: 'cover',
        position: 'center'
    };
}

function normalizePageFormatting(raw) {
    const r = raw && typeof raw === 'object' ? raw : {};
    return {
        fontFamily: typeof r.fontFamily === 'string' ? r.fontFamily : '',
        fontSize: typeof r.fontSize === 'string' || typeof r.fontSize === 'number' ? String(r.fontSize) : '',
        lineHeight: typeof r.lineHeight === 'string' || typeof r.lineHeight === 'number' ? String(r.lineHeight) : '',
        textColor: typeof r.textColor === 'string' ? r.textColor : '',
        alignment: ['left', 'center', 'right', 'justify'].includes(r.alignment) ? r.alignment : 'left'
    };
}

function normalizeDocumentLayout(raw) {
    const r = raw && typeof raw === 'object' ? raw : {};
    return {
        header: {
            enabled: r.header && r.header.enabled === true,
            content: typeof (r.header && r.header.content) === 'string' ? r.header.content : ''
        },
        footer: {
            enabled: r.footer && r.footer.enabled === true,
            content: typeof (r.footer && r.footer.content) === 'string' ? r.footer.content : ''
        },
        pageNumbers: {
            enabled: r.pageNumbers && r.pageNumbers.enabled === true,
            position: ['top-left','top-center','top-right','bottom-left','bottom-center','bottom-right'].includes(r.pageNumbers && r.pageNumbers.position) ? r.pageNumbers.position : 'bottom-center',
            startFrom: Number.isFinite(Number(r.pageNumbers && r.pageNumbers.startFrom)) ? Number(r.pageNumbers.startFrom) : 1
        }
    };
}

