// ===========================================================================
// Valid Testing Hub internal sections — Review and Cram are now native sub-tabs.
const TESTING_HUB_SECTIONS = ['dashboard', 'exams', 'review', 'cram', 'practice', 'mistakes', 'resources'];
const TESTING_HUB_CORE_EXAMS = ['ap', 'sat', 'act', 'psat', 'mcat', 'gre', 'lsat', 'gmat', 'toefl', 'ielts', 'clep', 'ib', 'state'];
const TESTING_HUB_MAX_VISIBLE_PINS = 4;

function getDefaultTestingHub() {
    return {
        activeExam: 'ap',
        activeSection: 'dashboard', // dashboard | exams | review | cram | practice | mistakes | resources
        // User's pinned exams — shown as the compact "active exam" strip on the
        // Exams section. Max 4 visible chips; the rest live in the picker modal.
        // 'ap' is included by default because every student has at least one AP.
        pinnedExams: ['ap'],
        // Most-recently-opened exam ids (string for core, 'custom:<id>' for custom).
        recentExams: [],
        ap: getDefaultExamProfile('ap'),
        sat: getDefaultExamProfile('sat'),
        act: getDefaultExamProfile('act'),
        mcat: getDefaultExamProfile('mcat'),
        gre: getDefaultExamProfile('gre'),
        lsat: getDefaultExamProfile('lsat'),
        gmat: getDefaultExamProfile('gmat'),
        psat: getDefaultExamProfile('psat'),
        toefl: getDefaultExamProfile('toefl'),
        ielts: getDefaultExamProfile('ielts'),
        clep: getDefaultExamProfile('clep'),
        ib: getDefaultExamProfile('ib'),
        state: getDefaultExamProfile('state'),
        custom: [] // array of custom exam profiles
    };
}

function getDefaultExamProfile(type) {
    const profiles = {
        ap: { name: 'AP', desc: 'College Board Advanced Placement — opens the AP study workspace.', sections: [], scoreMax: 5 },
        sat: { name: 'SAT', desc: 'College Board Scholastic Assessment Test (400-1600)', sections: ['Reading & Writing', 'Math'], scoreMax: 1600 },
        act: { name: 'ACT', desc: 'American College Testing (1-36 composite)', sections: ['English', 'Math', 'Reading', 'Science', 'Writing (optional)'], scoreMax: 36 },
        mcat: { name: 'MCAT', desc: 'Medical College Admission Test (472-528)', sections: ['Chem/Phys', 'CARS', 'Bio/Biochem', 'Psych/Soc'], scoreMax: 528 },
        gre: { name: 'GRE', desc: 'Graduate Record Examination', sections: ['Verbal', 'Quantitative', 'Analytical Writing'], scoreMax: 340 },
        lsat: { name: 'LSAT', desc: 'Law School Admission Test (120-180)', sections: ['Logical Reasoning', 'Analytical Reasoning', 'Reading Comprehension'], scoreMax: 180 },
        gmat: { name: 'GMAT', desc: 'Graduate Management Admission Test', sections: ['Quantitative', 'Verbal', 'Integrated Reasoning', 'AWA'], scoreMax: 805 },
        psat: { name: 'PSAT/NMSQT', desc: 'Preliminary SAT / National Merit Scholarship Qualifying Test', sections: ['Reading & Writing', 'Math'], scoreMax: 1520 },
        toefl: { name: 'TOEFL', desc: 'Test of English as a Foreign Language (0-120)', sections: ['Reading', 'Listening', 'Speaking', 'Writing'], scoreMax: 120 },
        ielts: { name: 'IELTS', desc: 'International English Language Testing System (0-9)', sections: ['Listening', 'Reading', 'Writing', 'Speaking'], scoreMax: 9 },
        clep: { name: 'CLEP', desc: 'College-Level Examination Program', sections: ['Subject test'], scoreMax: 80 },
        ib: { name: 'IB', desc: 'International Baccalaureate Diploma', sections: ['Group 1: Studies in Language and Literature', 'Group 2: Language Acquisition', 'Group 3: Individuals and Societies', 'Group 4: Sciences', 'Group 5: Mathematics', 'Group 6: The Arts'], scoreMax: 45 },
        state: { name: 'State Standardized Test', desc: 'State-administered standardized assessment', sections: ['Reading', 'Math', 'Science', 'Writing'], scoreMax: null }
    };
    const p = profiles[type] || { name: type, desc: '', sections: [], scoreMax: null };
    return {
        type,
        name: p.name,
        description: p.desc,
        examDate: null,
        targetScore: null,
        currentScore: null,
        sectionScores: {},
        // Per-section target scores (parallels sectionScores). Added in the
        // calm-overview redesign; safe-defaulted by the normalizer.
        targetSectionScores: {},
        studyStatus: 'planning', // planning | studying | reviewing | ready
        notes: '',
        // Legacy free-text resources box. Preserved verbatim; the redesigned
        // Resources panel adds structured entries in resourceLinks alongside it.
        resources: '',
        // Structured, user-added resources grouped by category.
        // [{ id, category, title, url, notes }]
        resourceLinks: [],
        // Ranked weak areas. Each: { id, name, section, manualPriority,
        // confidence (1-5), pacing (bool) }. Frequency/recency/scoreImpact
        // are derived from logged mistakes + practice at render time.
        weakAreas: [],
        // Pacing / timing notes shown in the Modules panel.
        pacingNotes: '',
        practiceTests: [],
        mistakes: [],
        tasks: [],
        sections: p.sections,
        scoreMax: p.scoreMax,
        // Collapsed/expanded state of the overview's "More details" disclosure.
        moreDetailsExpanded: false
    };
}

// Normalize a single custom-exam profile so it carries the same field set as
// the calm overview expects. Idempotent; preserves any extra stored fields.
function normalizeCustomExam(raw) {
    if (!raw || typeof raw !== 'object') return null;
    const c = { ...raw };
    if (!c.id) c.id = 'cx_' + (typeof generateId === 'function' ? generateId() : Math.random().toString(36).slice(2));
    c.name = typeof c.name === 'string' ? c.name : 'Custom exam';
    c.description = typeof c.description === 'string' ? c.description : '';
    c.examDate = c.examDate || null;
    c.targetScore = c.targetScore != null ? c.targetScore : '';
    c.currentScore = c.currentScore != null ? c.currentScore : '';
    c.studyStatus = typeof c.studyStatus === 'string' ? c.studyStatus : 'planning';
    c.sections = Array.isArray(c.sections) ? c.sections : [];
    c.sectionScores = c.sectionScores && typeof c.sectionScores === 'object' ? c.sectionScores : {};
    c.targetSectionScores = c.targetSectionScores && typeof c.targetSectionScores === 'object' ? c.targetSectionScores : {};
    c.notes = typeof c.notes === 'string' ? c.notes : '';
    c.resources = typeof c.resources === 'string' ? c.resources : '';
    c.resourceLinks = Array.isArray(c.resourceLinks) ? c.resourceLinks : [];
    c.weakAreas = Array.isArray(c.weakAreas) ? c.weakAreas : [];
    c.pacingNotes = typeof c.pacingNotes === 'string' ? c.pacingNotes : '';
    c.practiceTests = Array.isArray(c.practiceTests) ? c.practiceTests : [];
    c.mistakes = Array.isArray(c.mistakes) ? c.mistakes : [];
    c.tasks = Array.isArray(c.tasks) ? c.tasks : [];
    c.moreDetailsExpanded = !!c.moreDetailsExpanded;
    return c;
}

