        function getDefaultAcademicWorkspace() {
            return {
                onboardingSeeded: false,
                filters: {
                    status: 'all',
                    className: 'all',
                    priority: 'all',
                    sortBy: 'dueDate',
                    sortDirection: 'asc'
                },
                classes: [],
                assignments: [],
                exams: [],
                notesTemplates: [],
                flashcards: [],
                extracurriculars: []
            };
        }

        function normalizeAcademicWorkspace(data) {
            const defaults = getDefaultAcademicWorkspace();
            const source = data && typeof data === 'object' ? data : {};
            const normalized = {
                ...defaults,
                ...source
            };
            normalized.filters = {
                ...defaults.filters,
                ...(source.filters && typeof source.filters === 'object' ? source.filters : {})
            };
            normalized.classes = Array.isArray(source.classes)
                ? source.classes.map(row => createAcademicClassRow(row))
                : defaults.classes;
            normalized.assignments = Array.isArray(source.assignments)
                ? source.assignments.map(row => createAcademicAssignmentRow(row))
                : defaults.assignments;
            normalized.exams = Array.isArray(source.exams)
                ? source.exams.map(row => createAcademicExamRow(row))
                : defaults.exams;
            normalized.notesTemplates = Array.isArray(source.notesTemplates)
                ? source.notesTemplates.map(row => createAcademicNotesTemplateRow(row))
                : defaults.notesTemplates;
            normalized.flashcards = Array.isArray(source.flashcards)
                ? source.flashcards.map(row => createAcademicFlashcardRow(row))
                : defaults.flashcards;
            normalized.extracurriculars = Array.isArray(source.extracurriculars)
                ? source.extracurriculars.map(row => createAcademicExtracurricularRow(row))
                : defaults.extracurriculars;
            if (source.onboardingSeeded !== false) {
                normalized.assignments = normalized.assignments.filter(row => {
                    const title = String(row.title || '').trim();
                    const className = String(row.className || '').trim();
                    const notes = String(row.notes || '').trim();
                    return !(
                        (title === 'Calc problem set 6' && className === 'AP Calculus' && notes === 'Focus on implicit differentiation.') ||
                        (title === 'History primary source notes' && className === 'US History' && notes === 'Summarize 3 main arguments.')
                    );
                });
                normalized.exams = normalized.exams.filter(row => {
                    const title = String(row.title || '').trim();
                    const className = String(row.className || '').trim();
                    const notes = String(row.notes || '').trim();
                    return !(
                        title === 'AP Calculus Quiz' &&
                        className === 'AP Calculus' &&
                        notes === 'Covers limits + derivatives.'
                    );
                });
                normalized.extracurriculars = normalized.extracurriculars.filter(row => {
                    const name = String(row.name || '').trim();
                    const role = String(row.role || '').trim();
                    const notes = String(row.notes || '').trim();
                    return !(
                        name === 'Debate Club' &&
                        role === 'Research lead' &&
                        notes === 'Prep evidence packets.'
                    );
                });
            }
            normalized.assignments = normalized.assignments.map(row => {
                const className = String(row.className || '').trim();
                if (className) return row;
                const legacyClassName = row.classId ? getAcademicClassNameFromRows(normalized.classes, row.classId) : '';
                return { ...row, className: legacyClassName || '' };
            });
            normalized.exams = normalized.exams.map(row => {
                const className = String(row.className || '').trim();
                if (className) return row;
                const legacyClassName = row.classId ? getAcademicClassNameFromRows(normalized.classes, row.classId) : '';
                return { ...row, className: legacyClassName || '' };
            });
            const legacyFilterClassId = source && source.filters && source.filters.classId ? String(source.filters.classId) : '';
            const legacyFilterClassName = legacyFilterClassId && legacyFilterClassId !== 'all'
                ? getAcademicClassNameFromRows(normalized.classes, legacyFilterClassId)
                : '';
            normalized.filters.className = String(normalized.filters.className || legacyFilterClassName || 'all');
            delete normalized.filters.classId;
            delete normalized.studyDashboard;
            return normalized;
        }

        const COLLEGE_APP_COMPLETED_STATUSES = new Set(['submitted', 'accepted', 'waitlisted', 'rejected']);

        function clampWholeNumber(value, fallback, min, max) {
            const normalized = Math.floor(normalizeFiniteNumber(value, fallback));
            return Math.max(min, Math.min(max, normalized));
        }

        function getCollegeTrackerStatusDefaultProgress(status) {
            const normalized = String(status || '').toLowerCase();
            if (normalized === 'planning') return 10;
            if (normalized === 'in_progress') return 45;
            if (COLLEGE_APP_COMPLETED_STATUSES.has(normalized)) return 100;
            return 0;
        }

        function createCollegeAppTrackerRow(seed = {}) {
            const normalizedStatus = String(seed.status || 'planning').toLowerCase();
            const hasProgress = seed.applicationProgress !== undefined && seed.applicationProgress !== null && String(seed.applicationProgress).trim() !== '';
            const defaultProgress = getCollegeTrackerStatusDefaultProgress(normalizedStatus);
            return {
                id: seed.id || generateId(),
                school: seed.school || '',
                deadline: seed.deadline || '',
                status: normalizedStatus || 'planning',
                checklist: seed.checklist || '',
                nextDate: seed.nextDate || seed.deadline || '',
                recLettersRequired: clampWholeNumber(seed.recLettersRequired, 0, 0, 10),
                recLettersRequested: clampWholeNumber(seed.recLettersRequested, 0, 0, 10),
                recLettersReceived: clampWholeNumber(seed.recLettersReceived, 0, 0, 10),
                applicationProgress: Math.max(0, Math.min(100, Math.round(normalizeFiniteNumber(
                    hasProgress ? seed.applicationProgress : defaultProgress,
                    defaultProgress
                ))))
            };
        }

