        const PINNED_PAGE_TABS = ['life', 'collegeapp'];
        const VALID_LIFE_PAGE_IDS = new Set([
            'goals', 'habits', 'sleep', 'spending', 'journal',
            'skills', 'fitness', 'calories', 'calculator', 'books',
            'wellness'
        ]);
        const VALID_COLLEGEAPP_PAGE_IDS = new Set([
            'tracker', 'essays', 'scores', 'awards',
            'scholarships', 'decision', 'majordecision', 'sheets'
        ]);

        function getValidPinnedPageIds(tab) {
            if (tab === 'life') return VALID_LIFE_PAGE_IDS;
            if (tab === 'collegeapp') return VALID_COLLEGEAPP_PAGE_IDS;
            return new Set();
        }

        function getDefaultPinnedPages() {
            return { life: [], collegeapp: [] };
        }

        function normalizePinnedPages(source) {
            const defaults = getDefaultPinnedPages();
            const data = source && typeof source === 'object' ? source : {};
            const out = {};
            PINNED_PAGE_TABS.forEach(tab => {
                const validIds = getValidPinnedPageIds(tab);
                const seen = new Set();
                const list = Array.isArray(data[tab]) ? data[tab] : defaults[tab];
                out[tab] = list
                    .map(id => String(id || '').trim())
                    .filter(id => {
                        if (!id || seen.has(id) || !validIds.has(id)) return false;
                        seen.add(id);
                        return true;
                    });
            });
            return out;
        }

        function getPinnedPagesState() {
            if (!appData) return getDefaultPinnedPages();
            if (!appData.pinnedPages || typeof appData.pinnedPages !== 'object') {
                appData.pinnedPages = getDefaultPinnedPages();
            }
            PINNED_PAGE_TABS.forEach(tab => {
                if (!Array.isArray(appData.pinnedPages[tab])) appData.pinnedPages[tab] = [];
            });
            return appData.pinnedPages;
        }

        function isPagePinned(tabName, pageId) {
            if (!PINNED_PAGE_TABS.includes(tabName)) return false;
            const list = getPinnedPagesState()[tabName];
            return Array.isArray(list) && list.includes(String(pageId));
        }

        function getPinnedPages(tabName) {
            if (!PINNED_PAGE_TABS.includes(tabName)) return [];
            return getPinnedPagesState()[tabName].slice();
        }

        function getUnpinnedPages(tabName, allPageIds) {
            const pinned = new Set(getPinnedPages(tabName));
            return (Array.isArray(allPageIds) ? allPageIds : [])
                .map(id => String(id))
                .filter(id => !pinned.has(id));
        }

        function togglePinnedPage(tabName, pageId) {
            if (!PINNED_PAGE_TABS.includes(tabName)) return false;
            const id = String(pageId || '').trim();
            const validIds = getValidPinnedPageIds(tabName);
            if (!id || !validIds.has(id)) return false;
            const list = getPinnedPagesState()[tabName];
            const idx = list.indexOf(id);
            if (idx === -1) {
                list.push(id);
            } else {
                list.splice(idx, 1);
            }
            try { persistAppData(); } catch (err) { /* non-critical */ }
            return idx === -1;
        }

