        function openAppDb() {
            return new Promise((resolve, reject) => {
                if (typeof indexedDB === 'undefined') {
                    reject(new Error('IndexedDB unavailable'));
                    return;
                }
                let request;
                try {
                    request = indexedDB.open(APP_DB_NAME, APP_SCHEMA_VERSION);
                } catch (error) {
                    reject(error);
                    return;
                }
                request.onupgradeneeded = () => {
                    const db = request.result;
                    if (!db.objectStoreNames.contains(APP_DB_STORE)) {
                        db.createObjectStore(APP_DB_STORE);
                    }
                };
                request.onsuccess = () => resolve(request.result);
                request.onerror = () => reject(request.error);
            });
        }

        async function readAppData() {
            const db = await openAppDb();
            return new Promise((resolve, reject) => {
                const tx = db.transaction(APP_DB_STORE, 'readonly');
                const store = tx.objectStore(APP_DB_STORE);
                const request = store.get(APP_DB_KEY);
                request.onsuccess = () => resolve(request.result || null);
                request.onerror = () => reject(request.error);
            });
        }

        async function writeAppData(data) {
            const db = await openAppDb();
            return new Promise((resolve, reject) => {
                const tx = db.transaction(APP_DB_STORE, 'readwrite');
                const store = tx.objectStore(APP_DB_STORE);
                const request = store.put(data, APP_DB_KEY);
                request.onerror = () => reject(request.error || tx.error || new Error('IndexedDB write request failed'));
                tx.oncomplete = () => resolve();
                tx.onerror = () => reject(tx.error || new Error('IndexedDB transaction failed'));
                tx.onabort = () => reject(tx.error || new Error('IndexedDB transaction aborted'));
            });
        }

        function commitAppDataWithHealth(reason = 'autosave', options = {}) {
            // Run every commit through a single FIFO queue so the write + readback
            // pair is never interleaved with another commit on the shared key. The
            // chain absorbs rejections (so one failure does not stall later saves)
            // while still surfacing this operation's own result/rejection to the
            // caller.
            const run = () => performCommitAppDataWithHealth(reason, options);
            const result = persistenceCommitQueue.then(run, run);
            persistenceCommitQueue = result.then(() => undefined, () => undefined);
            return result;
        }

        async function performCommitAppDataWithHealth(reason = 'autosave', options = {}) {
            if (!appData) return null;
            const opId = (persistenceCommitSeq += 1);
            const attemptAt = getIsoTimestamp();
            const previousHealth = appSettings && appSettings.dataHealth
                ? cloneSerializable(appSettings.dataHealth, {})
                : null;
            let serialized = '';
            try {
                sutraPersistenceState.lastAttemptAt = attemptAt;
                const health = ensureSutraDataHealth();
                health.lastSaveAttemptAt = attemptAt;
                health.lastSaveReason = reason;
                if (appData) appData.settings = appSettings;
                // Capture an immutable, fully detached canonical snapshot. We persist
                // THIS exact snapshot — not the live appData — so:
                //  1. the bytes written are the bytes we verify (no structured-clone
                //     vs JSON representation drift), and
                //  2. a mutation on the live appData during the async write/readback
                //     window cannot alter what was stored, which was the root cause
                //     of the spurious "readback did not match" autosave banner.
                // A genuine partial write, quota error, aborted transaction, or
                // corrupted readback still fails verification below.
                serialized = JSON.stringify(appData);
                if (!serialized) throw new Error('Workspace serialization returned an empty payload.');
                const snapshot = JSON.parse(serialized);
                const summary = buildPersistenceSummary(serialized);
                await writeAppData(snapshot);
                if (options.verifyReadback !== false) {
                    const stored = await readAppData();
                    const storedText = JSON.stringify(stored);
                    if (hashPersistenceString(storedText) !== summary.hash) {
                        const partialError = new Error('IndexedDB readback did not match the serialized workspace.');
                        partialError.name = 'PartialWriteError';
                        throw partialError;
                    }
                }
                // Only the most recent commit may clear/advance shared health state.
                // (Commits are serialized, so opId === seq normally holds; the guard
                // is defence-in-depth against any future concurrent caller.)
                if (opId === persistenceCommitSeq) {
                    recordPersistenceSuccess(summary, {
                        clearFailure: shouldClearPersistenceFailureOnSuccess(reason)
                    });
                }
                try { notifySutraDriveLocalSave(reason, summary); } catch (driveSyncError) { /* Drive sync must never block local saving. */ }
                return summary;
            } catch (error) {
                if (previousHealth && appSettings) {
                    appSettings.dataHealth = previousHealth;
                    if (appData) appData.settings = appSettings;
                }
                recordPersistenceFailure(error, { reason, phase: reason });
                throw error;
            }
        }

        function scheduleAppSave() {
            if (pendingAppSave) return;
            pendingAppSave = setTimeout(async () => {
                pendingAppSave = null;
                try {
                    await commitAppDataWithHealth('autosave', { verifyReadback: true });
                } catch (e) {
                    console.error('Failed to save workspace data', e);
                }
            }, 250);
        }

        async function flushAppSaveNow(reason = 'manual') {
            if (pendingAppSave) {
                clearTimeout(pendingAppSave);
                pendingAppSave = null;
            }
            if (!appData) return;
            await commitAppDataWithHealth(reason, { verifyReadback: true });
        }

        function flushAppSaveOnLifecycle(reason = 'lifecycle') {
            if (lifecycleSaveFlushScheduled) return;
            lifecycleSaveFlushScheduled = true;
            try {
                savePage();
            } catch (error) {
                console.warn(`Lifecycle save snapshot failed (${reason})`, error);
            }
            Promise.resolve()
                .then(() => flushAppSaveNow(reason))
                .catch((error) => {
                    console.warn(`Lifecycle save flush failed (${reason})`, error);
                })
                .finally(() => {
                    lifecycleSaveFlushScheduled = false;
                });
        }

        function mergeAppDataDefaults(stored) {
            const defaults = getDefaultAppData();
            const merged = { ...defaults, ...stored };
            const storedSettings = stored && stored.settings ? stored.settings : {};
            merged.settings = { ...defaults.settings, ...storedSettings };
            merged.settings.font = { ...defaults.settings.font, ...(stored && stored.settings && stored.settings.font ? stored.settings.font : {}) };
            delete merged.settings.drive;
            delete merged.settings.googleCalendar;
            merged.settings.temporaryPages = normalizeTemporaryPageSettings({ ...defaults.settings.temporaryPages, ...(stored && stored.settings && stored.settings.temporaryPages ? stored.settings.temporaryPages : {}) });
            merged.settings.focusTimer = { ...defaults.settings.focusTimer, ...(stored && stored.settings && stored.settings.focusTimer ? stored.settings.focusTimer : {}) };
            merged.settings.dataHealth = {
                ...defaults.settings.dataHealth,
                ...(stored && stored.settings && stored.settings.dataHealth ? stored.settings.dataHealth : {})
            };
            merged.settings.preferences = normalizeWorkspacePreferences(
                { ...defaults.settings.preferences, ...(stored && stored.settings && stored.settings.preferences ? stored.settings.preferences : {}) },
                getLegacyPreferenceSeed({ ...defaults.settings, ...storedSettings })
            );
            merged.settings.autoEventBlocksEnabled = merged.settings.autoEventBlocksEnabled !== false;
            merged.settings.notesSplitViewEnabled = merged.settings.notesSplitViewEnabled === true;
            merged.settings.notesSplitSecondaryPageId = merged.settings.notesSplitSecondaryPageId ? String(merged.settings.notesSplitSecondaryPageId) : null;
            merged.settings.timelineSource = normalizeTimelineSourceMode(merged.settings.timelineSource);
            merged.settings.timelineViewMode = deriveTimelineViewMode(merged.settings.timelineViewMode, merged.settings.timelineLayoutMode, merged.settings.timelineLegacyMode);
            merged.settings.timelineLayoutMode = normalizeTimelineLayoutMode(merged.settings.timelineLayoutMode);
            merged.settings.timelineLegacyMode = normalizeTimelineLegacyMode(merged.settings.timelineLegacyMode);
            merged.settings.taskOrderStrategy = normalizeTaskSortStrategy(
                merged.settings.preferences.tasks.sortStrategy,
                normalizeTaskSortStrategy(merged.settings.taskOrderStrategy, 'urgent_first')
            );
            merged.settings.timeFormat = merged.settings.preferences.calendar.timeFormat;
            merged.settings.showSeconds = merged.settings.preferences.calendar.showSeconds !== false;
            merged.settings.showClock = merged.settings.preferences.calendar.showClock !== false;
            merged.settings.motionEnabled = merged.settings.preferences.appearance.motionIntensity !== 'off';
            merged.settings.customShortcuts = normalizeCustomShortcuts(
                (storedSettings && (storedSettings.customShortcuts || storedSettings.shortcutLinks))
                    || merged.settings.customShortcuts
            );
            merged.settings.enabledViews = normalizeEnabledViews(storedSettings.enabledViews);
            if (stored && stored.settings && !Object.prototype.hasOwnProperty.call(stored.settings, 'featureSelectionCompleted')) {
                merged.settings.featureSelectionCompleted = true;
            }
            // Merge onboarding state with deep defaults so newly-added keys
            // appear on every reload without wiping completed users.
            {
                const onbDefaults = defaults.settings.onboarding;
                const storedOnb = storedSettings && storedSettings.onboarding && typeof storedSettings.onboarding === 'object' ? storedSettings.onboarding : null;
                merged.settings.onboarding = {
                    ...onbDefaults,
                    ...(storedOnb || {}),
                    dayDefaults: { ...onbDefaults.dayDefaults, ...((storedOnb && storedOnb.dayDefaults) || {}) },
                    aiSetup: { ...onbDefaults.aiSetup, ...((storedOnb && storedOnb.aiSetup) || {}) },
                    classes: Array.isArray(storedOnb && storedOnb.classes) ? storedOnb.classes.slice() : [],
                    apSubjects: Array.isArray(storedOnb && storedOnb.apSubjects) ? storedOnb.apSubjects.slice() : [],
                    enabledSpaces: (storedOnb && storedOnb.enabledSpaces && typeof storedOnb.enabledSpaces === 'object')
                        ? { ...storedOnb.enabledSpaces }
                        : null
                };
            }
            merged.ui = { ...defaults.ui, ...(stored && stored.ui ? stored.ui : {}) };
            merged.streaks = { ...defaults.streaks, ...(stored && stored.streaks ? stored.streaks : {}) };
            merged.streaks.dayStates = (stored && stored.streaks && stored.streaks.dayStates) || stored.dayStates || defaults.streaks.dayStates;
            merged.streaks.taskStreaks = (stored && stored.streaks && stored.streaks.taskStreaks) || stored.taskStreaks || defaults.streaks.taskStreaks;
            merged.streaks.streakState = { ...defaults.streaks.streakState, ...((stored && stored.streaks && stored.streaks.streakState) || stored.streakState || {}) };
            merged.habitTracker = { ...defaults.habitTracker, ...(stored && stored.habitTracker ? stored.habitTracker : {}) };
            merged.habitTracker.habits = Array.isArray(merged.habitTracker.habits) ? merged.habitTracker.habits : [];
            merged.habitTracker.dayStates = merged.habitTracker.dayStates || {};
            merged.collegeTracker = normalizeCollegeTracker(stored && stored.collegeTracker ? stored.collegeTracker : defaults.collegeTracker);
            merged.academicWorkspace = normalizeAcademicWorkspace(stored && stored.academicWorkspace ? stored.academicWorkspace : defaults.academicWorkspace);
            merged.collegeAppWorkspace = normalizeCollegeAppWorkspace(stored && stored.collegeAppWorkspace ? stored.collegeAppWorkspace : defaults.collegeAppWorkspace);
            merged.lifeWorkspace = normalizeLifeWorkspace(stored && stored.lifeWorkspace ? stored.lifeWorkspace : defaults.lifeWorkspace);
            merged.businessWorkspace = normalizeBusinessWorkspace(stored && stored.businessWorkspace ? stored.businessWorkspace : defaults.businessWorkspace);
            merged.apStudyWorkspace = typeof window !== 'undefined' && typeof window.normalizeApStudyWorkspace === 'function'
                ? window.normalizeApStudyWorkspace(stored && stored.apStudyWorkspace ? stored.apStudyWorkspace : defaults.apStudyWorkspace)
                : (stored && stored.apStudyWorkspace ? stored.apStudyWorkspace : defaults.apStudyWorkspace);
            merged.homeworkWorkspace = stored && stored.homeworkWorkspace && typeof stored.homeworkWorkspace === 'object'
                ? stored.homeworkWorkspace
                : null;
            merged.reviewWorkspace = normalizeReviewWorkspace(stored && stored.reviewWorkspace ? stored.reviewWorkspace : defaults.reviewWorkspace);
            merged.courseWorkspace = normalizeCourseWorkspace(stored && stored.courseWorkspace ? stored.courseWorkspace : defaults.courseWorkspace);
            merged.focusTemplates = normalizeFocusTemplates(stored && stored.focusTemplates ? stored.focusTemplates : defaults.focusTemplates);
            merged.splitPaneContexts = normalizeSplitPaneContexts(stored && stored.splitPaneContexts ? stored.splitPaneContexts : defaults.splitPaneContexts);
            merged.pinnedPages = normalizePinnedPages(stored && stored.pinnedPages ? stored.pinnedPages : defaults.pinnedPages);
            // Spaces normalization (Section 6) — ensures default space exists, all pages have spaceId
            merged.spaces = normalizeSpacesCollection(stored && stored.spaces ? stored.spaces : defaults.spaces);
            // Cram Hub sessions (Section 31) — safe default for older workspaces
            merged.cramSessions = Array.isArray(stored && stored.cramSessions) ? stored.cramSessions : [];
            // Testing Hub (Section 32) — safe default + normalization for older workspaces
            merged.testingHub = normalizeTestingHub(stored && stored.testingHub);
            // mobileTodayMode + recentSearches live inside settings; ensure
            // older workspaces don't lose them when settings is stripped.
            const mobileMode = String(merged.settings.mobileTodayMode || 'auto');
            merged.settings.mobileTodayMode = ['auto', 'on', 'off'].includes(mobileMode) ? mobileMode : 'auto';
            merged.settings.recentSearches = normalizeRecentSearches(merged.settings.recentSearches);
            merged.settings.atelierTheme = normalizeAtelierThemeName(merged.settings.atelierTheme);
            const mergedLastView = String(merged.ui.lastActiveView || '').trim();
            merged.ui.lastActiveView = (mergedLastView === 'settings' || OPTIONAL_FEATURE_VIEWS.includes(mergedLastView))
                ? mergedLastView
                : defaults.ui.lastActiveView;
            return merged;
        }

        function normalizeThemeName(name) {
            const normalized = String(name || '').trim().toLowerCase();
            if (!normalized || normalized === 'light') return 'default';
            return normalized;
        }

        function normalizeAtelierThemeName(name) {
            const normalized = String(name || '').trim().toLowerCase();
            if (normalized === 'retro') return 'retro95';
            return ['light', 'dark', 'retro95'].includes(normalized) ? normalized : 'light';
        }

        function migrateLegacyData() {
            const data = getDefaultAppData();
            try {
                const legacyKeys = [
                    'noteflow_pages',
                    'noteflow_theme_settings',
                    'noteflow_font_settings',
                    'noteflow_animations',
                    'noteflow_sidebar_collapsed',
                    'noteflow_favorite_page',
                    'noteflow_default_page',
                    'noteflow_todos',
                    'streakApp:v1',
                    'streakApp:settings',
                    'hwCourses:v2',
                    'hwTasks:v2',
                    'homeworkCourses:v1',
                    'homeworkTasks:v1'
                ];
                const hasLegacyStorage = legacyKeys.some(key => localStorage.getItem(key) !== null);
                if (hasLegacyStorage) {
                    data.settings.featureSelectionCompleted = true;
                }
            } catch (e) {
                console.warn('Unable to inspect legacy storage keys', e);
            }

            try {
                const storedPages = localStorage.getItem('noteflow_pages');
                if (storedPages) data.pages = JSON.parse(storedPages);
            } catch (e) {
                console.warn('Unable to migrate NoteFlow pages', e);
            }

            try {
                const themeSettings = JSON.parse(localStorage.getItem('noteflow_theme_settings') || '{}');
                data.settings.theme = normalizeThemeName(themeSettings.globalTheme || 'light');
            } catch (e) {
                console.warn('Unable to migrate NoteFlow theme settings', e);
            }

            try {
                const fontSettings = JSON.parse(localStorage.getItem('noteflow_font_settings') || '{}');
                data.settings.font = { ...data.settings.font, ...fontSettings };
            } catch (e) {
                console.warn('Unable to migrate NoteFlow font settings', e);
            }

            try {
                const animations = localStorage.getItem('noteflow_animations');
                if (animations !== null) data.settings.motionEnabled = animations !== 'false';
            } catch (e) {
                console.warn('Unable to migrate animation settings', e);
            }

            try {
                const collapsed = localStorage.getItem('noteflow_sidebar_collapsed');
                if (collapsed !== null) data.settings.sidebarCollapsed = collapsed === 'true';
            } catch (e) {
                console.warn('Unable to migrate sidebar state', e);
            }

            try {
                data.ui.favoritePageId = localStorage.getItem('noteflow_favorite_page');
                data.ui.defaultPageId = localStorage.getItem('noteflow_default_page');
            } catch (e) {
                console.warn('Unable to migrate page prefs', e);
            }

            try {
                const todos = JSON.parse(localStorage.getItem('noteflow_todos') || '[]');
                todos.forEach(todo => {
                    const id = `nf_${todo.id || Date.now()}`;
                    const scheduleType = todo.recurring === 'daily' ? 'daily' : todo.recurring === 'weekly' ? 'weekly' : 'once';
                    const weeklyDays = scheduleType === 'weekly'
                        ? [new Date(todo.dueDate || Date.now()).getDay()]
                        : [];
                    data.tasks.push({
                        id,
                        title: todo.text || 'Untitled task',
                        notes: '',
                        scheduleType,
                        weeklyDays,
                        category: todo.category || 'none',
                        estimate: 0,
                        createdAt: todo.createdAt || new Date().toISOString(),
                        isActive: !todo.completed,
                        noteId: null,
                        dueDate: todo.dueDate || null,
                        priority: normalizePriorityValue(todo.priority),
                        difficulty: normalizeDifficultyValue(todo.difficulty),
                        origin: 'quick'
                    });
                    data.taskOrder.push(id);
                });
            } catch (e) {
                console.warn('Unable to migrate NoteFlow todos', e);
            }

            try {
                const streakState = JSON.parse(localStorage.getItem('streakApp:v1') || 'null');
                if (streakState) {
                    const tasks = streakState.tasks || [];
                    tasks.forEach(task => {
                        data.tasks.push({
                            ...task,
                            noteId: task.noteId || null,
                            origin: task.origin || 'streak',
                            priority: normalizePriorityValue(task.priority),
                            difficulty: normalizeDifficultyValue(task.difficulty)
                        });
                    });
                    data.taskOrder = [...data.taskOrder, ...(streakState.taskOrder || tasks.map(t => t.id))];
                    data.streaks.dayStates = streakState.dayStates || {};
                    data.streaks.taskStreaks = streakState.taskStreaks || {};
                    data.streaks.streakState = { ...data.streaks.streakState, ...(streakState.streakState || {}) };
                }
            } catch (e) {
                console.warn('Unable to migrate Streaks data', e);
            }

            try {
                const streakSettings = JSON.parse(localStorage.getItem('streakApp:settings') || 'null');
                if (streakSettings) {
                    data.settings.soundEnabled = streakSettings.soundEnabled !== false;
                    data.settings.hapticEnabled = streakSettings.hapticEnabled !== false;
                }
            } catch (e) {
                console.warn('Unable to migrate Streaks settings', e);
            }

            return data;
        }

        async function initAppData() {
            restoreSutraPersistenceState();
            let stored = null;
            try {
                stored = await readAppData();
            } catch (error) {
                console.warn('Unable to read IndexedDB workspace; starting from an in-memory safety state.', error);
                recordPersistenceFailure(error, { reason: 'startup-read', phase: 'startup-read', kind: 'indexeddb' });
            }
            if (stored) {
                appData = mergeAppDataDefaults(stored);
            } else {
                appData = migrateLegacyData();
                try {
                    await commitAppDataWithHealth('initial-migration', { verifyReadback: true });
                } catch (error) {
                    console.warn('Initial workspace persistence failed; continuing in memory.', error);
                }
            }
        }

        function getDefaultStreaks() {
            return JSON.parse(JSON.stringify(getDefaultAppData().streaks));
        }

        function hydrateStateFromAppData() {
            if (!appData) appData = getDefaultAppData();
            pages = Array.isArray(appData.pages) ? appData.pages : [];
            // Spaces (Section 6)
            spaces = normalizeSpacesCollection(appData.spaces);
            pages.forEach(p => { if (!p.spaceId) p.spaceId = 'default'; });
            // Cram Hub (Section 31)
            cramSessions = Array.isArray(appData.cramSessions) ? appData.cramSessions : [];
            // Testing Hub (Section 32)
            testingHub = normalizeTestingHub(appData.testingHub);
            tasks = Array.isArray(appData.tasks)
                ? appData.tasks.map(task => {
                    // Sutra Assistant migration: earlier Flow versions (and a few
                    // other shortcut paths) created tasks missing isActive /
                    // scheduleType, so they were invisible in every Today filter
                    // even though they appeared in the All Tasks drawer. Backfill
                    // safe defaults here, on every load. Idempotent.
                    const repaired = { ...task };
                    repaired.priority = normalizePriorityValue(task.priority);
                    repaired.difficulty = normalizeDifficultyValue(task.difficulty);
                    if (typeof repaired.isActive !== 'boolean') repaired.isActive = !repaired.completed;
                    if (typeof repaired.scheduleType !== 'string' || !repaired.scheduleType) {
                        repaired.scheduleType = (Array.isArray(repaired.weeklyDays) && repaired.weeklyDays.length) ? 'weekly' : 'once';
                    }
                    if (!Array.isArray(repaired.weeklyDays)) repaired.weeklyDays = [];
                    if (typeof repaired.estimate !== 'number') repaired.estimate = 0;
                    if (typeof repaired.category !== 'string') repaired.category = 'none';
                    return repaired;
                })
                : [];
            taskOrder = Array.isArray(appData.taskOrder) ? appData.taskOrder : tasks.map(task => task.id);

            const defaultStreaks = getDefaultStreaks();
            const storedStreaks = appData.streaks || defaultStreaks;
            dayStates = storedStreaks.dayStates || {};
            taskStreaks = storedStreaks.taskStreaks || {};
            streakState = { ...defaultStreaks.streakState, ...(storedStreaks.streakState || {}) };
            const defaultHabits = getDefaultAppData().habitTracker;
            const storedHabits = appData.habitTracker || defaultHabits;
            habits = Array.isArray(storedHabits.habits) ? storedHabits.habits : [];
            habitDayStates = storedHabits.dayStates || {};
            collegeTracker = normalizeCollegeTracker(appData.collegeTracker);
            academicWorkspace = normalizeAcademicWorkspace(appData.academicWorkspace);
            collegeAppWorkspace = normalizeCollegeAppWorkspace(appData.collegeAppWorkspace);
            lifeWorkspace = normalizeLifeWorkspace(appData.lifeWorkspace);
            businessWorkspace = normalizeBusinessWorkspace(appData.businessWorkspace);
            apStudyWorkspace = typeof window !== 'undefined' && typeof window.normalizeApStudyWorkspace === 'function'
                ? window.normalizeApStudyWorkspace(appData.apStudyWorkspace)
                : (appData.apStudyWorkspace || {});
            reviewWorkspace = normalizeReviewWorkspace(appData.reviewWorkspace);
            courseWorkspace = normalizeCourseWorkspace(appData.courseWorkspace);
            focusTemplates = normalizeFocusTemplates(appData.focusTemplates);
            splitPaneContexts = normalizeSplitPaneContexts(appData.splitPaneContexts);
            appData.pinnedPages = normalizePinnedPages(appData.pinnedPages);
            if (appData.homeworkWorkspace) {
                restoreHomeworkWorkspaceFromSnapshot(appData.homeworkWorkspace, { onlyIfEmpty: true });
            }
            // Course Hub: migrate existing Homework courses into the rich course
            // workspace and keep both stores bridged. Idempotent; never wipes.
            try { migrateAndBridgeCourses({ source: 'hydrate' }); } catch (err) { console.warn('migrateAndBridgeCourses failed on hydrate', err); }
            syncHabitTrackersAcrossViews();

            const defaultSettings = getDefaultAppData().settings;
            const storedSettings = appData.settings || {};
            appSettings = { ...defaultSettings, ...storedSettings };
            appSettings.font = { ...defaultSettings.font, ...(appData.settings && appData.settings.font ? appData.settings.font : {}) };
            appSettings.dataHealth = { ...defaultSettings.dataHealth, ...(appData.settings && appData.settings.dataHealth ? appData.settings.dataHealth : {}) };
            delete appSettings.drive;
            delete appSettings.googleCalendar;
            appSettings.temporaryPages = normalizeTemporaryPageSettings({ ...defaultSettings.temporaryPages, ...(appData.settings && appData.settings.temporaryPages ? appData.settings.temporaryPages : {}) });
            appSettings.focusTimer = { ...defaultSettings.focusTimer, ...(appData.settings && appData.settings.focusTimer ? appData.settings.focusTimer : {}) };
            // Mods & Customization (Phase C) — normalize CSS snippets + plugins.
            appSettings.customization = normalizeCustomizationSettings(appSettings.customization);
            appSettings.preferences = normalizeWorkspacePreferences(
                { ...defaultSettings.preferences, ...(appData.settings && appData.settings.preferences ? appData.settings.preferences : {}) },
                getLegacyPreferenceSeed({ ...defaultSettings, ...storedSettings })
            );
            appSettings.autoEventBlocksEnabled = appSettings.autoEventBlocksEnabled !== false;
            appSettings.notesSplitViewEnabled = appSettings.notesSplitViewEnabled === true;
            appSettings.notesSplitSecondaryPageId = appSettings.notesSplitSecondaryPageId ? String(appSettings.notesSplitSecondaryPageId) : null;
            appSettings.timelineSource = normalizeTimelineSourceMode(storedSettings.timelineSource || appSettings.timelineSource);
            appSettings.timelineViewMode = deriveTimelineViewMode(storedSettings.timelineViewMode || appSettings.timelineViewMode, storedSettings.timelineLayoutMode || appSettings.timelineLayoutMode, storedSettings.timelineLegacyMode || appSettings.timelineLegacyMode);
            appSettings.timelineLayoutMode = normalizeTimelineLayoutMode(storedSettings.timelineLayoutMode || appSettings.timelineLayoutMode);
            appSettings.timelineLegacyMode = normalizeTimelineLegacyMode(storedSettings.timelineLegacyMode || appSettings.timelineLegacyMode);
            appSettings.taskOrderStrategy = normalizeTaskSortStrategy(
                appSettings.preferences.tasks.sortStrategy,
                normalizeTaskSortStrategy(appSettings.taskOrderStrategy, 'urgent_first')
            );
            appSettings.timeFormat = appSettings.preferences.calendar.timeFormat;
            appSettings.showSeconds = appSettings.preferences.calendar.showSeconds !== false;
            appSettings.showClock = appSettings.preferences.calendar.showClock !== false;
            appSettings.motionEnabled = appSettings.preferences.appearance.motionIntensity !== 'off';
            appSettings.customShortcuts = normalizeCustomShortcuts(
                (storedSettings && (storedSettings.customShortcuts || storedSettings.shortcutLinks))
                    || appSettings.customShortcuts
            );
            appSettings.atelierTheme = normalizeAtelierThemeName(appSettings.atelierTheme);
            appSettings.enabledViews = normalizeEnabledViews(storedSettings.enabledViews || appSettings.enabledViews);
            if (!Object.prototype.hasOwnProperty.call(storedSettings, 'featureSelectionCompleted')) {
                appSettings.featureSelectionCompleted = true;
            }
            appSettings.selectedPagesForTheme = appSettings.selectedPagesForTheme || [];
            const mobileTodayChoice = String(storedSettings.mobileTodayMode || appSettings.mobileTodayMode || 'auto');
            appSettings.mobileTodayMode = ['auto', 'on', 'off'].includes(mobileTodayChoice) ? mobileTodayChoice : 'auto';
            appSettings.recentSearches = normalizeRecentSearches(storedSettings.recentSearches || appSettings.recentSearches);
            if (appSettings.dataHealth && typeof appSettings.dataHealth === 'object') {
                sutraPersistenceState = normalizePersistenceState({
                    ...sutraPersistenceState,
                    lastConfirmedSaveAt: appSettings.dataHealth.lastConfirmedSaveAt || sutraPersistenceState.lastConfirmedSaveAt,
                    lastAttemptAt: appSettings.dataHealth.lastSaveAttemptAt || sutraPersistenceState.lastAttemptAt,
                    lastSerializedBytes: appSettings.dataHealth.lastSerializedBytes || sutraPersistenceState.lastSerializedBytes,
                    lastLocalStorageBytes: appSettings.dataHealth.lastLocalStorageBytes || sutraPersistenceState.lastLocalStorageBytes,
                    lastAttachmentCount: appSettings.dataHealth.lastAttachmentCount || sutraPersistenceState.lastAttachmentCount,
                    lastAttachmentBytes: appSettings.dataHealth.lastAttachmentBytes || sutraPersistenceState.lastAttachmentBytes,
                    lastAttachmentWarnings: appSettings.dataHealth.lastAttachmentWarnings || sutraPersistenceState.lastAttachmentWarnings,
                    backupState: appSettings.dataHealth.backupState || sutraPersistenceState.backupState
                });
            }

            const defaultUi = getDefaultUiState();
            appData.ui = { ...defaultUi, ...(appData.ui || {}) };
            const uiState = ensureUiState() || appData.ui;
            const lastView = String(uiState.lastActiveView || '').trim();
            const validLastView = (lastView === 'settings' || OPTIONAL_FEATURE_VIEWS.includes(lastView))
                ? lastView
                : defaultUi.lastActiveView;
            uiState.lastActiveView = validLastView;
            activeView = validLastView || defaultUi.lastActiveView;
        }

        function persistAppData() {
            if (!appData) return;
            syncHabitTrackersAcrossViews();
            // Mirror runtime theme-targeting state into appSettings before save so
            // selectedPagesForTheme and themeApplyMode survive a refresh and travel
            // through the same export/import path. Without this, mutations to these
            // arrays at lines that don't write back to appSettings (e.g. checkbox
            // toggles in the theme picker) would be lost on reload.
            if (appSettings) {
                appSettings.themeApplyMode = ['current', 'all', 'custom'].includes(themeApplyMode)
                    ? themeApplyMode
                    : 'current';
                appSettings.selectedPagesForTheme = Array.isArray(selectedPagesForTheme)
                    ? selectedPagesForTheme.slice()
                    : [];
            }
            appData.version = APP_SCHEMA_VERSION;
            appData.pages = pages;
            appData.spaces = spaces; // Section 6 — Spaces/folders persistence
            appData.cramSessions = cramSessions; // Section 31 — Cram Hub persistence
            appData.testingHub = testingHub; // Section 32 — Testing Hub persistence
            appData.tasks = tasks;
            appData.taskOrder = taskOrder;
            appData.timeBlocks = Array.isArray(timeBlocks) ? timeBlocks : [];
            appData.streaks = {
                dayStates,
                taskStreaks,
                streakState
            };
            appData.habitTracker = {
                habits,
                dayStates: habitDayStates
            };
            appData.collegeTracker = collegeTracker;
            appData.academicWorkspace = academicWorkspace;
            appData.collegeAppWorkspace = collegeAppWorkspace;
            appData.lifeWorkspace = lifeWorkspace;
            appData.businessWorkspace = businessWorkspace;
            if (typeof window !== 'undefined' && typeof window.normalizeApStudyWorkspace === 'function') {
                apStudyWorkspace = window.normalizeApStudyWorkspace(apStudyWorkspace);
            }
            appData.apStudyWorkspace = apStudyWorkspace;
            appData.homeworkWorkspace = readHomeworkWorkspaceSnapshot();
            appData.reviewWorkspace = normalizeReviewWorkspace(reviewWorkspace);
            appData.courseWorkspace = normalizeCourseWorkspace(courseWorkspace);
            appData.focusTemplates = normalizeFocusTemplates(focusTemplates);
            appData.splitPaneContexts = normalizeSplitPaneContexts(splitPaneContexts);
            appData.pinnedPages = normalizePinnedPages(appData.pinnedPages);
            appData.settings = appSettings;
            appData.globalTheme = globalTheme;
            if (!appData.ui) appData.ui = { ...getDefaultUiState() };
            appData.ui.lastActiveView = activeView;
            scheduleAppSave();
        }

        // Application State
        let pages = [];
        // Spaces (Section 6) — workspace folders
        let spaces = [];
        let activeSpaceId = 'default';
        // Cram Hub (Section 31) — focused study sessions
        let cramSessions = [];
        let activeCramSessionId = null;
        let cramBuiltInTimer = { running: false, remaining: 0, total: 0, blockId: null, sessionId: null, interval: null };
        // Testing Hub (Section 32) — standardized testing workspace
        let testingHub = getDefaultTestingHub();
        // Tracks pages unlocked during this browser session. Reset on every page reload.
        let unlockedPageIds = new Set();
        let lockTimers = new Map(); // auto-lock countdown timers, keyed by pageId
        let currentPageId = null;
        let secondaryPageId = null;
        let activeEditorPane = 'primary';
        let splitViewEnabledBeforeFocusMode = false;
        let sidebarWasOpenBeforeFocusMode = false;
        let focusModeFullscreenLinked = false;
        let splitSecondaryDebounceTimer = null;
        let primarySaveDebounceTimer = null;
        let primaryScrollPersistTimer = null;
        let settingsControlCenterBound = false;
        let activeSettingsCategory = 'appearance';
        let settingsLastAppliedAt = null;
        const settingsDraftValues = new Map();
        const splitScrollPositions = {};
        let pageToRenameId = null; // For rename functionality
        let themeApplyMode = 'current'; // 'current', 'all', 'custom'
        let selectedPagesForTheme = [];
        let globalTheme = 'default';
        let tasks = [];
        let taskOrder = [];
        let dayStates = {};
        let taskStreaks = {};
        let streakState = getDefaultStreaks().streakState;
        let habits = [];
        let habitDayStates = {};
        let collegeTracker = getDefaultCollegeTracker();
        let academicWorkspace = getDefaultAcademicWorkspace();
        let collegeAppWorkspace = getDefaultCollegeAppWorkspace();
        let lifeWorkspace = getDefaultLifeWorkspace();
        let businessWorkspace = getDefaultBusinessWorkspace();
        let apStudyWorkspace = typeof window !== 'undefined' && typeof window.getDefaultApStudyWorkspace === 'function'
            ? window.getDefaultApStudyWorkspace()
            : { subjects: [], units: [], topics: [], sessions: [], practiceLogs: [], activity: [], settings: {} };
        let reviewWorkspace = getDefaultReviewWorkspace();
        // Courses / Course Hub workspace (rich course metadata, files, links,
        // relationships, settings). Assignments themselves continue to live in
        // the Homework store (hwTasks:v2) keyed by courseId — this workspace
