        function normalizeHexColor(value, fallback) {
            const raw = String(value || '').trim();
            return /^#[0-9a-fA-F]{6}$/.test(raw) ? raw.toLowerCase() : String(fallback || '#000000').toLowerCase();
        }

        function hexToRgbTuple(hex) {
            const normalized = normalizeHexColor(hex, '#000000').slice(1);
            const parsed = parseInt(normalized, 16);
            const r = (parsed >> 16) & 255;
            const g = (parsed >> 8) & 255;
            const b = parsed & 255;
            return [r, g, b];
        }

        function hexToRgba(hex, alpha = 1) {
            const [r, g, b] = hexToRgbTuple(hex);
            const normalizedAlpha = Math.min(Math.max(Number(alpha) || 0, 0), 1);
            return `rgba(${r}, ${g}, ${b}, ${normalizedAlpha})`;
        }

        function mixHex(hexA, hexB, weight = 0.5) {
            const [r1, g1, b1] = hexToRgbTuple(hexA);
            const [r2, g2, b2] = hexToRgbTuple(hexB);
            const normalizedWeight = Math.min(Math.max(Number(weight) || 0, 0), 1);
            const mixChannel = (a, b) => Math.round((a * (1 - normalizedWeight)) + (b * normalizedWeight));
            const toHex = (value) => Math.max(0, Math.min(255, value)).toString(16).padStart(2, '0');
            return `#${toHex(mixChannel(r1, r2))}${toHex(mixChannel(g1, g2))}${toHex(mixChannel(b1, b2))}`;
        }

        function darkenHex(hex, ratio = 0.2) {
            const [r, g, b] = hexToRgbTuple(hex);
            const scale = 1 - Math.min(Math.max(Number(ratio) || 0, 0), 0.9);
            const toHex = (value) => Math.round(value).toString(16).padStart(2, '0');
            return `#${toHex(r * scale)}${toHex(g * scale)}${toHex(b * scale)}`;
        }

        function isDarkHexColor(hex) {
            const [r, g, b] = hexToRgbTuple(hex);
            const luminance = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
            return luminance < 0.5;
        }

        const customColorPickerInstances = new WeakMap();
        let activeCustomColorPicker = null;
        let customColorPickerGlobalHandlersBound = false;

        function clamp01(value) {
            return Math.min(1, Math.max(0, Number(value) || 0));
        }

        function hsvToRgb(h, s, v) {
            const hue = ((Number(h) || 0) % 360 + 360) % 360;
            const sat = clamp01(s);
            const val = clamp01(v);
            const chroma = val * sat;
            const hueSection = hue / 60;
            const x = chroma * (1 - Math.abs((hueSection % 2) - 1));
            let rPrime = 0;
            let gPrime = 0;
            let bPrime = 0;

            if (hueSection >= 0 && hueSection < 1) {
                rPrime = chroma; gPrime = x; bPrime = 0;
            } else if (hueSection >= 1 && hueSection < 2) {
                rPrime = x; gPrime = chroma; bPrime = 0;
            } else if (hueSection >= 2 && hueSection < 3) {
                rPrime = 0; gPrime = chroma; bPrime = x;
            } else if (hueSection >= 3 && hueSection < 4) {
                rPrime = 0; gPrime = x; bPrime = chroma;
            } else if (hueSection >= 4 && hueSection < 5) {
                rPrime = x; gPrime = 0; bPrime = chroma;
            } else {
                rPrime = chroma; gPrime = 0; bPrime = x;
            }

            const m = val - chroma;
            return {
                r: Math.round((rPrime + m) * 255),
                g: Math.round((gPrime + m) * 255),
                b: Math.round((bPrime + m) * 255)
            };
        }

        function rgbChannelsToHex(r, g, b) {
            const toHex = (channel) => Math.max(0, Math.min(255, Math.round(channel))).toString(16).padStart(2, '0');
            return `#${toHex(r)}${toHex(g)}${toHex(b)}`;
        }

        function hsvToHex(h, s, v) {
            const rgb = hsvToRgb(h, s, v);
            return rgbChannelsToHex(rgb.r, rgb.g, rgb.b);
        }

        function hexToHsv(hex) {
            const [rRaw, gRaw, bRaw] = hexToRgbTuple(hex);
            const r = rRaw / 255;
            const g = gRaw / 255;
            const b = bRaw / 255;
            const max = Math.max(r, g, b);
            const min = Math.min(r, g, b);
            const delta = max - min;
            let hue = 0;

            if (delta !== 0) {
                if (max === r) hue = 60 * (((g - b) / delta) % 6);
                else if (max === g) hue = 60 * (((b - r) / delta) + 2);
                else hue = 60 * (((r - g) / delta) + 4);
            }
            if (hue < 0) hue += 360;

            const sat = max === 0 ? 0 : delta / max;
            return { h: hue, s: sat, v: max };
        }

        function updateCustomColorPickerUI(instance, emitInput = false) {
            if (!instance) return;
            const hex = normalizeHexColor(hsvToHex(instance.h, instance.s, instance.v), '#000000');
            const pointerX = Math.round(clamp01(instance.s) * 100);
            const pointerY = Math.round((1 - clamp01(instance.v)) * 100);

            instance.panelEl.style.setProperty('--nf-picker-hue', String(Math.round(instance.h)));
            instance.thumbEl.style.left = `${pointerX}%`;
            instance.thumbEl.style.top = `${pointerY}%`;
            instance.hueEl.value = String(Math.round(instance.h));
            instance.swatchEl.style.background = hex;
            instance.valueEl.textContent = hex.toUpperCase();

            if (!instance.hexInputDirty) {
                instance.hexInputEl.value = hex.toUpperCase();
            }

            if (instance.inputEl.value !== hex) {
                instance.inputEl.value = hex;
                if (emitInput) {
                    instance.inputEl.dispatchEvent(new Event('input', { bubbles: true }));
                }
            } else if (emitInput) {
                instance.inputEl.dispatchEvent(new Event('input', { bubbles: true }));
            }
        }

        function syncCustomColorPickerFromInput(inputEl) {
            if (!inputEl) return;
            const instance = customColorPickerInstances.get(inputEl);
            if (!instance) return;
            const nextHex = normalizeHexColor(inputEl.value, '#000000');
            const nextHsv = hexToHsv(nextHex);
            instance.h = nextHsv.h;
            instance.s = nextHsv.s;
            instance.v = nextHsv.v;
            updateCustomColorPickerUI(instance, false);
        }

        function closeCustomColorPicker(instance, { emitChange = true, restoreFocus = false } = {}) {
            if (!instance) return;
            instance.controlEl.classList.remove('is-open');
            instance.controlEl.classList.remove('open-up');
            instance.popoverEl.hidden = true;
            instance.hexInputDirty = false;
            instance.triggerEl.setAttribute('aria-expanded', 'false');
            if (emitChange) {
                instance.inputEl.dispatchEvent(new Event('change', { bubbles: true }));
            }
            if (restoreFocus) {
                instance.triggerEl.focus({ preventScroll: true });
            }
            if (activeCustomColorPicker === instance) {
                activeCustomColorPicker = null;
            }
        }

        function positionCustomColorPopover(instance) {
            if (!instance || !instance.popoverEl || !instance.controlEl) return;
            const popoverEl = instance.popoverEl;
            const controlEl = instance.controlEl;
            controlEl.classList.remove('open-up');
            popoverEl.style.left = '';
            popoverEl.style.right = '0';

            const viewportHeight = window.innerHeight || document.documentElement.clientHeight || 0;
            const viewportWidth = window.innerWidth || document.documentElement.clientWidth || 0;
            const controlRect = controlEl.getBoundingClientRect();
            const popoverRect = popoverEl.getBoundingClientRect();
            const spaceBelow = viewportHeight - controlRect.bottom;
            const spaceAbove = controlRect.top;

            if (spaceBelow < popoverRect.height + 12 && spaceAbove > popoverRect.height + 12) {
                controlEl.classList.add('open-up');
            }

            const nextRect = popoverEl.getBoundingClientRect();
            if (nextRect.left < 8) {
                popoverEl.style.left = '0';
                popoverEl.style.right = 'auto';
            } else if (nextRect.right > viewportWidth - 8) {
                popoverEl.style.right = '0';
                popoverEl.style.left = 'auto';
            }
        }

        function openCustomColorPicker(instance) {
            if (!instance) return;
            if (activeCustomColorPicker && activeCustomColorPicker !== instance) {
                closeCustomColorPicker(activeCustomColorPicker, { emitChange: true, restoreFocus: false });
            }
            activeCustomColorPicker = instance;
            syncCustomColorPickerFromInput(instance.inputEl);
            instance.controlEl.classList.add('is-open');
            instance.popoverEl.hidden = false;
            instance.triggerEl.setAttribute('aria-expanded', 'true');
            requestAnimationFrame(() => {
                positionCustomColorPopover(instance);
                instance.hexInputEl.focus({ preventScroll: true });
                instance.hexInputEl.select();
            });
        }

        function bindCustomColorPickerGlobalHandlers() {
            if (customColorPickerGlobalHandlersBound) return;
            customColorPickerGlobalHandlersBound = true;

            document.addEventListener('pointerdown', (event) => {
                if (!activeCustomColorPicker) return;
                if (activeCustomColorPicker.controlEl.contains(event.target)) return;
                closeCustomColorPicker(activeCustomColorPicker, { emitChange: true, restoreFocus: false });
            }, true);

            document.addEventListener('keydown', (event) => {
                if (!activeCustomColorPicker) return;
                if (event.key !== 'Escape') return;
                event.preventDefault();
                event.stopPropagation();
                closeCustomColorPicker(activeCustomColorPicker, { emitChange: true, restoreFocus: true });
            }, true);

            window.addEventListener('resize', () => {
                if (!activeCustomColorPicker) return;
                positionCustomColorPopover(activeCustomColorPicker);
            });
        }

        function initCustomColorPickers(root = document) {
            if (!root || typeof root.querySelectorAll !== 'function') return;
            bindCustomColorPickerGlobalHandlers();

            root.querySelectorAll('input[type="color"]').forEach((inputEl) => {
                if (!inputEl || inputEl.dataset.nfColorPickerInit === 'true') return;
                inputEl.dataset.nfColorPickerInit = 'true';
                inputEl.classList.add('nf-color-native-input');

                const controlEl = document.createElement('div');
                controlEl.className = 'nf-color-control';

                const triggerEl = document.createElement('button');
                triggerEl.type = 'button';
                triggerEl.className = 'nf-color-trigger';
                triggerEl.setAttribute('aria-label', `Choose ${inputEl.id || 'color'}`);
                triggerEl.setAttribute('aria-expanded', 'false');

                const swatchEl = document.createElement('span');
                swatchEl.className = 'nf-color-swatch';
                const valueEl = document.createElement('span');
                valueEl.className = 'nf-color-value';
                triggerEl.appendChild(swatchEl);
                triggerEl.appendChild(valueEl);

                const popoverEl = document.createElement('div');
                popoverEl.className = 'nf-color-popover';
                popoverEl.hidden = true;

                const panelEl = document.createElement('div');
                panelEl.className = 'nf-color-panel';
                const thumbEl = document.createElement('span');
                thumbEl.className = 'nf-color-thumb';
                panelEl.appendChild(thumbEl);

                const hueWrapEl = document.createElement('div');
                hueWrapEl.className = 'nf-color-hue-wrap';
                const hueEl = document.createElement('input');
                hueEl.className = 'nf-color-hue';
                hueEl.type = 'range';
                hueEl.min = '0';
                hueEl.max = '360';
                hueEl.step = '1';
                hueWrapEl.appendChild(hueEl);

                const fieldsEl = document.createElement('div');
                fieldsEl.className = 'nf-color-fields';
                const hexLabelEl = document.createElement('label');
                hexLabelEl.className = 'nf-color-field';
                const hexNameEl = document.createElement('span');
                hexNameEl.textContent = 'HEX';
                const hexInputEl = document.createElement('input');
                hexInputEl.type = 'text';
                hexInputEl.inputMode = 'text';
                hexInputEl.maxLength = 7;
                hexInputEl.className = 'nf-color-hex';
                hexLabelEl.appendChild(hexNameEl);
                hexLabelEl.appendChild(hexInputEl);
                fieldsEl.appendChild(hexLabelEl);

                popoverEl.appendChild(panelEl);
                popoverEl.appendChild(hueWrapEl);
                popoverEl.appendChild(fieldsEl);

                controlEl.appendChild(triggerEl);
                controlEl.appendChild(popoverEl);
                inputEl.insertAdjacentElement('afterend', controlEl);

                const initialHex = normalizeHexColor(inputEl.value, '#4f46e5');
                const initialHsv = hexToHsv(initialHex);
                const instance = {
                    inputEl,
                    controlEl,
                    triggerEl,
                    popoverEl,
                    panelEl,
                    thumbEl,
                    swatchEl,
                    valueEl,
                    hueEl,
                    hexInputEl,
                    h: initialHsv.h,
                    s: initialHsv.s,
                    v: initialHsv.v,
                    hexInputDirty: false
                };
                customColorPickerInstances.set(inputEl, instance);

                const updateFromPanelPointer = (event, emitInput) => {
                    const rect = panelEl.getBoundingClientRect();
                    if (!rect.width || !rect.height) return;
                    const nextS = clamp01((event.clientX - rect.left) / rect.width);
                    const nextV = 1 - clamp01((event.clientY - rect.top) / rect.height);
                    instance.s = nextS;
                    instance.v = nextV;
                    updateCustomColorPickerUI(instance, emitInput);
                };

                let panelPointerActive = false;
                panelEl.addEventListener('pointerdown', (event) => {
                    if (event.button !== 0) return;
                    event.preventDefault();
                    panelPointerActive = true;
                    panelEl.setPointerCapture(event.pointerId);
                    updateFromPanelPointer(event, true);
                });

                panelEl.addEventListener('pointermove', (event) => {
                    if (!panelPointerActive) return;
                    updateFromPanelPointer(event, true);
                });

                panelEl.addEventListener('pointerup', (event) => {
                    if (!panelPointerActive) return;
                    panelPointerActive = false;
                    if (panelEl.hasPointerCapture(event.pointerId)) {
                        panelEl.releasePointerCapture(event.pointerId);
                    }
                    updateFromPanelPointer(event, true);
                    inputEl.dispatchEvent(new Event('change', { bubbles: true }));
                });

                panelEl.addEventListener('pointercancel', (event) => {
                    panelPointerActive = false;
                    if (panelEl.hasPointerCapture(event.pointerId)) {
                        panelEl.releasePointerCapture(event.pointerId);
                    }
                });

                triggerEl.addEventListener('click', (event) => {
                    event.preventDefault();
                    if (activeCustomColorPicker === instance && !popoverEl.hidden) {
                        closeCustomColorPicker(instance, { emitChange: true, restoreFocus: true });
                        triggerEl.setAttribute('aria-expanded', 'false');
                    } else {
                        openCustomColorPicker(instance);
                        triggerEl.setAttribute('aria-expanded', 'true');
                    }
                });

                hueEl.addEventListener('input', () => {
                    instance.h = Number(hueEl.value) || 0;
                    updateCustomColorPickerUI(instance, true);
                });

                hueEl.addEventListener('change', () => {
                    inputEl.dispatchEvent(new Event('change', { bubbles: true }));
                });

                const commitHexInput = ({ emitChange = false } = {}) => {
                    const normalized = normalizeHexColor(hexInputEl.value, inputEl.value || '#000000');
                    const nextHsv = hexToHsv(normalized);
                    instance.h = nextHsv.h;
                    instance.s = nextHsv.s;
                    instance.v = nextHsv.v;
                    instance.hexInputDirty = false;
                    updateCustomColorPickerUI(instance, true);
                    if (emitChange) {
                        inputEl.dispatchEvent(new Event('change', { bubbles: true }));
                    }
                };

                hexInputEl.addEventListener('input', () => {
                    instance.hexInputDirty = true;
                    const raw = String(hexInputEl.value || '').trim();
                    const normalizedRaw = raw.startsWith('#') ? raw : `#${raw}`;
                    if (/^#[0-9a-fA-F]{6}$/.test(normalizedRaw)) {
                        const liveHex = normalizeHexColor(normalizedRaw, inputEl.value || '#000000');
                        const nextHsv = hexToHsv(liveHex);
                        instance.h = nextHsv.h;
                        instance.s = nextHsv.s;
                        instance.v = nextHsv.v;
                        updateCustomColorPickerUI(instance, true);
                    }
                });

                hexInputEl.addEventListener('keydown', (event) => {
                    if (event.key !== 'Enter') return;
                    event.preventDefault();
                    event.stopPropagation();
                    commitHexInput({ emitChange: true });
                });

                hexInputEl.addEventListener('blur', () => {
                    commitHexInput({ emitChange: false });
                });

                popoverEl.addEventListener('keydown', (event) => {
                    if (event.key === 'Enter') {
                        event.stopPropagation();
                    } else if (event.key === 'Escape') {
                        event.preventDefault();
                        event.stopPropagation();
                        closeCustomColorPicker(instance, { emitChange: true, restoreFocus: true });
                    }
                });

                inputEl.addEventListener('input', () => {
                    syncCustomColorPickerFromInput(inputEl);
                });

                inputEl.addEventListener('change', () => {
                    syncCustomColorPickerFromInput(inputEl);
                });

                updateCustomColorPickerUI(instance, false);
            });
        }

        function isCustomThemeKey(themeName) {
            const raw = String(themeName || '').trim().toLowerCase();
            return raw.startsWith(CUSTOM_THEME_KEY_PREFIX) && raw.length > CUSTOM_THEME_KEY_PREFIX.length;
        }

        function toCustomThemeKey(themeId) {
            const normalized = String(themeId || '').trim().toLowerCase();
            return normalized ? `${CUSTOM_THEME_KEY_PREFIX}${normalized}` : '';
        }

        function getCustomThemeIdFromKey(themeName) {
            if (!isCustomThemeKey(themeName)) return '';
            return String(themeName).trim().toLowerCase().slice(CUSTOM_THEME_KEY_PREFIX.length);
        }

        function normalizeCustomThemeRecord(rawTheme, index = 0) {
            const source = rawTheme && typeof rawTheme === 'object' ? rawTheme : {};
            const fallbackName = `${DEFAULT_CUSTOM_THEME.name} ${index + 1}`;
            const idSeed = String(source.id || '').trim().toLowerCase().replace(/[^a-z0-9_-]/g, '');
            return {
                id: idSeed || `ct_${generateId().replace(/[^a-z0-9_-]/gi, '').toLowerCase()}`,
                name: String(source.name || fallbackName).trim() || fallbackName,
                bgPrimary: normalizeHexColor(source.bgPrimary, DEFAULT_CUSTOM_THEME.bgPrimary),
                bgSecondary: normalizeHexColor(source.bgSecondary, DEFAULT_CUSTOM_THEME.bgSecondary),
                textPrimary: normalizeHexColor(source.textPrimary, DEFAULT_CUSTOM_THEME.textPrimary),
                accent: normalizeHexColor(source.accent, DEFAULT_CUSTOM_THEME.accent),
                sidebar: normalizeHexColor(source.sidebar, DEFAULT_CUSTOM_THEME.sidebar),
                button: normalizeHexColor(source.button, DEFAULT_CUSTOM_THEME.button)
            };
        }

        function ensureCustomThemeSettingsState() {
            if (!appSettings) return;
            const incoming = Array.isArray(appSettings.customThemes) ? appSettings.customThemes : [];
            const seen = new Set();
            const normalizedThemes = [];
            incoming.forEach((themeEntry, index) => {
                const normalized = normalizeCustomThemeRecord(themeEntry, index);
                if (seen.has(normalized.id)) {
                    normalized.id = `ct_${generateId().replace(/[^a-z0-9_-]/gi, '').toLowerCase()}`;
                }
                seen.add(normalized.id);
                normalizedThemes.push(normalized);
            });
            appSettings.customThemes = normalizedThemes;

            const activeId = String(appSettings.activeCustomThemeId || '').trim().toLowerCase();
            const isActiveValid = normalizedThemes.some(themeEntry => themeEntry.id === activeId);
            appSettings.activeCustomThemeId = isActiveValid
                ? activeId
                : (normalizedThemes[0] ? normalizedThemes[0].id : '');
        }

        function getCustomThemes() {
            ensureCustomThemeSettingsState();
            return appSettings && Array.isArray(appSettings.customThemes) ? appSettings.customThemes : [];
        }

        function getCustomThemeById(themeId) {
            const normalizedId = String(themeId || '').trim().toLowerCase();
            if (!normalizedId) return null;
            return getCustomThemes().find(themeEntry => themeEntry.id === normalizedId) || null;
        }

        function getActiveCustomTheme() {
            if (!appSettings) return null;
            const activeId = String(appSettings.activeCustomThemeId || '').trim().toLowerCase();
            if (!activeId) return null;
            return getCustomThemeById(activeId);
        }

        function getCustomThemesPayload(data) {
            if (Array.isArray(data)) {
                return {
                    customThemes: data,
                    activeCustomThemeId: ''
                };
            }
            if (!data || typeof data !== 'object') {
                return {
                    customThemes: [],
                    activeCustomThemeId: ''
                };
            }

            if (Array.isArray(data.customThemes) || Array.isArray(data.themes)) {
                return {
                    customThemes: Array.isArray(data.customThemes) ? data.customThemes : data.themes,
                    activeCustomThemeId: String(data.activeCustomThemeId || '').trim().toLowerCase()
                };
            }

            if (data.settings && Array.isArray(data.settings.customThemes)) {
                return {
                    customThemes: data.settings.customThemes,
                    activeCustomThemeId: String(data.settings.activeCustomThemeId || '').trim().toLowerCase()
                };
            }

            if (data.workspace && data.workspace.settings && Array.isArray(data.workspace.settings.customThemes)) {
                return {
                    customThemes: data.workspace.settings.customThemes,
                    activeCustomThemeId: String(data.workspace.settings.activeCustomThemeId || '').trim().toLowerCase()
                };
            }

            return {
                customThemes: [],
                activeCustomThemeId: ''
            };
        }

        function isCustomThemesPayload(data) {
            const extracted = getCustomThemesPayload(data);
            return Array.isArray(extracted.customThemes) && extracted.customThemes.length > 0;
        }

        function buildCustomThemesExportData() {
            ensureCustomThemeSettingsState();
            const themesList = getCustomThemes().map((themeEntry, index) => normalizeCustomThemeRecord(themeEntry, index));
            return {
                schema: CUSTOM_THEME_EXPORT_SCHEMA,
                app: 'Sutra',
                version: APP_SCHEMA_VERSION,
                exportedAt: new Date().toISOString(),
                activeCustomThemeId: String(appSettings && appSettings.activeCustomThemeId ? appSettings.activeCustomThemeId : '').trim().toLowerCase(),
                customThemes: themesList
            };
        }

        function exportCustomThemesToFile() {
            if (!appSettings) return;
            ensureCustomThemeSettingsState();
            const themesList = getCustomThemes();
            if (!themesList.length) {
                showToast('No custom themes to export');
                return;
            }

            const exportData = buildCustomThemesExportData();
            const blob = new Blob([JSON.stringify(exportData, null, 2)], { type: 'application/json' });
            const datePart = new Date().toISOString().split('T')[0];
            triggerBlobDownload(blob, `noteflow_custom_themes_${datePart}.json`);
            showToast(`Exported ${themesList.length} custom theme${themesList.length === 1 ? '' : 's'}`);
        }

        function importCustomThemesPayload(data) {
            if (!appSettings) return 0;
            ensureCustomThemeSettingsState();

            const extracted = getCustomThemesPayload(data);
            const incoming = Array.isArray(extracted.customThemes) ? extracted.customThemes : [];
            if (!incoming.length) return 0;

            const themesList = getCustomThemes();
            const existingIdSet = new Set(themesList.map(themeEntry => String(themeEntry.id || '').trim().toLowerCase()).filter(Boolean));
            const existingNameSet = new Set(themesList.map(themeEntry => String(themeEntry.name || '').trim().toLowerCase()).filter(Boolean));
            let importedCount = 0;
            let latestImportedId = '';
            const importedIdMap = new Map();

            incoming.forEach((rawTheme, index) => {
                const normalized = normalizeCustomThemeRecord(rawTheme, themesList.length + index);
                const sourceId = String(normalized.id || '').trim().toLowerCase();
                while (existingIdSet.has(normalized.id)) {
                    normalized.id = `ct_${generateId().replace(/[^a-z0-9_-]/gi, '').toLowerCase()}`;
                }
                existingIdSet.add(normalized.id);
                if (sourceId) importedIdMap.set(sourceId, normalized.id);

                const baseName = String(normalized.name || '').trim() || `${DEFAULT_CUSTOM_THEME.name} ${themesList.length + importedCount + 1}`;
                let nextName = baseName;
                let suffix = 2;
                while (existingNameSet.has(nextName.toLowerCase())) {
                    nextName = `${baseName} (${suffix})`;
                    suffix += 1;
                }
                normalized.name = nextName;
                existingNameSet.add(nextName.toLowerCase());

                themesList.push(normalized);
                latestImportedId = normalized.id;
                importedCount += 1;
            });

            const incomingActiveId = String(extracted.activeCustomThemeId || '').trim().toLowerCase();
            if (incomingActiveId && importedIdMap.has(incomingActiveId)) {
                appSettings.activeCustomThemeId = importedIdMap.get(incomingActiveId);
            } else if (!String(appSettings.activeCustomThemeId || '').trim() && latestImportedId) {
                appSettings.activeCustomThemeId = latestImportedId;
            }

            persistAppData();
            return importedCount;
        }

        async function importCustomThemesFromFile() {
            const input = document.createElement('input');
            input.type = 'file';
            input.accept = '.json,application/json';

            input.addEventListener('change', async (event) => {
                const file = event.target && event.target.files ? event.target.files[0] : null;
                if (!file) return;

                try {
                    const raw = await readFileAsText(file);
                    const parsed = JSON.parse(raw);
                    if (isWorkspacePayload(parsed)) {
                        showToast('Use Workspace Import for full backups');
                        return;
                    }
                    if (!isCustomThemesPayload(parsed)) {
                        showToast('No custom themes found in that file');
                        return;
                    }
                    const importedCount = importCustomThemesPayload(parsed);
                    if (!importedCount) {
                        showToast('No custom themes were imported');
                        return;
                    }
                    refreshCustomThemeControls();
                    showToast(`Imported ${importedCount} custom theme${importedCount === 1 ? '' : 's'}`);
                } catch (error) {
                    console.error('Custom theme import failed', error);
                    showToast('Theme import failed. Use a valid JSON file.');
                }
            }, { once: true });

            input.click();
        }

        function createCustomTheme(name, colors = {}) {
            if (!appSettings) return null;
            ensureCustomThemeSettingsState();
            const nextTheme = normalizeCustomThemeRecord({
                id: `ct_${generateId().replace(/[^a-z0-9_-]/gi, '').toLowerCase()}`,
                name: name || DEFAULT_CUSTOM_THEME.name,
                ...colors
            }, getCustomThemes().length);
            appSettings.customThemes.push(nextTheme);
            appSettings.activeCustomThemeId = nextTheme.id;
            persistAppData();
            return nextTheme;
        }

        function deleteCustomThemeById(themeId) {
            if (!appSettings) return null;
            ensureCustomThemeSettingsState();
            const normalizedId = String(themeId || '').trim().toLowerCase();
            if (!normalizedId) return null;

            const themesList = getCustomThemes();
            const targetIndex = themesList.findIndex(themeEntry => themeEntry.id === normalizedId);
            if (targetIndex < 0) return null;

            const [removedTheme] = themesList.splice(targetIndex, 1);
            const removedThemeKey = toCustomThemeKey(normalizedId);
            pages.forEach((page) => {
                if (!page) return;
                const pageTheme = String(page.theme || '').trim().toLowerCase();
                if (pageTheme === removedThemeKey) {
                    page.theme = DEFAULT_THEME_KEY;
                    if (page.customTheme) delete page.customTheme;
                }
            });

            if (String(globalTheme || '').trim().toLowerCase() === removedThemeKey) {
                globalTheme = DEFAULT_THEME_KEY;
                appSettings.theme = DEFAULT_THEME_KEY;
            }

            if (String(appSettings.activeCustomThemeId || '').trim().toLowerCase() === normalizedId) {
                appSettings.activeCustomThemeId = themesList[0] ? themesList[0].id : '';
            }

            persistAppData();
            return removedTheme;
        }

        function normalizeStoredThemeKey(themeName, fallback = DEFAULT_THEME_KEY, allowCustom = false) {
            const normalized = normalizeThemeName(themeName);
            if (allowCustom && normalized === 'custom') return 'custom';
            if (allowCustom && isCustomThemeKey(normalized)) return normalized;
            if (themes[normalized]) return normalized;
            const fallbackNormalized = normalizeThemeName(fallback);
            if (allowCustom && isCustomThemeKey(fallbackNormalized)) return fallbackNormalized;
            return themes[fallbackNormalized] ? fallbackNormalized : DEFAULT_THEME_KEY;
        }

        function getThemeMode(themeName) {
            if (isCustomThemeKey(themeName)) {
                const themeEntry = getCustomThemeById(getCustomThemeIdFromKey(themeName));
                return themeEntry && isDarkHexColor(themeEntry.bgPrimary) ? 'dark' : 'light';
            }
            const normalized = normalizeStoredThemeKey(themeName, DEFAULT_THEME_KEY);
            return themes[normalized] && themes[normalized].mode === 'dark' ? 'dark' : 'light';
        }

        function getCurrentPageThemeKey() {
            const currentPage = pages.find(p => p.id === currentPageId);
            if (currentPage && currentPage.theme) {
                return normalizeStoredThemeKey(currentPage.theme, globalTheme || DEFAULT_THEME_KEY, true);
            }
            return normalizeStoredThemeKey(globalTheme, DEFAULT_THEME_KEY, true);
        }

    // No hard limit on commits per day -- allow unlimited commits
    const MAX_COMMITS_PER_DAY = Infinity;
        const FREEZES_PER_WEEK = 2;
        const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
        const CATEGORY_COLORS = {
            none: '#9c9284',
            work: '#d8c4a1',
            health: '#7aa37a',
            personal: '#c27b66',
            learning: '#7a8bb6'
        };

        // Utility function for debouncing
        function debounce(func, wait) {
            let timeout;
            return function executedFunction(...args) {
                const later = () => {
                    clearTimeout(timeout);
                    func(...args);
                };
                clearTimeout(timeout);
                timeout = setTimeout(later, wait);
            };
        }

        // -------------------- College Tracker --------------------
        function getCollegeRows(sheetKey) {
            if (!collegeTracker || typeof collegeTracker !== 'object') {
                collegeTracker = getDefaultCollegeTracker();
            }
            if (!Array.isArray(collegeTracker[sheetKey])) {
                collegeTracker[sheetKey] = [];
            }
            return collegeTracker[sheetKey];
        }

        function setCollegeSummaryValue(id, value) {
            const el = document.getElementById(id);
            if (el) el.textContent = String(value);
        }

        function parseCollegeDate(value) {
            const raw = String(value || '').trim();
            if (!raw) return null;
            const isoDate = /^\d{4}-\d{2}-\d{2}$/;
            const date = isoDate.test(raw) ? new Date(`${raw}T00:00:00`) : new Date(raw);
            if (isNaN(date)) return null;
            date.setHours(0, 0, 0, 0);
            return date;
        }

        function countUpcomingCollegeDeadlines(daysAhead = 14) {
            const rows = getCollegeRows('deadlines');
            const today = new Date();
            today.setHours(0, 0, 0, 0);
            const cutoff = new Date(today);
            cutoff.setDate(cutoff.getDate() + Math.max(0, Number(daysAhead) || 0));

            return rows.filter(row => {
                if (row && row.submitted) return false;
                const due = parseCollegeDate(row && row.applicationDeadline);
                return !!(due && due >= today && due <= cutoff);
            }).length;
        }

        function renderCollegeSummary() {
            const researchRows = getCollegeRows('research');
            const checklistRows = getCollegeRows('checklist');
            const deadlineRows = getCollegeRows('deadlines');
            const essayRows = getCollegeRows('essays');

            const schools = new Set();
            [researchRows, checklistRows, deadlineRows].forEach(rows => {
                rows.forEach(row => {
                    const name = String(row && row.college ? row.college : '').trim();
                    if (name) schools.add(name.toLowerCase());
                });
            });

            const submittedApps = checklistRows.filter(row => !!(row && row.appSubmitted)).length;
            const acceptedCount = researchRows.filter(row => {
                const decision = String(row && row.decision ? row.decision : '').toLowerCase();
                return decision === 'accepted';
            }).length;
            const totalEssays = essayRows.filter(row => String(row && row.essay ? row.essay : '').trim()).length;
            const completedEssays = essayRows.filter(row => !!(row && row.finalDraft)).length;

            setCollegeSummaryValue('collegeSummarySchools', schools.size);
            setCollegeSummaryValue('collegeSummarySubmitted', submittedApps);
            setCollegeSummaryValue('collegeSummaryUpcoming', countUpcomingCollegeDeadlines(14));
            setCollegeSummaryValue('collegeSummaryEssays', `${completedEssays}/${Math.max(totalEssays, 0)}`);
            setCollegeSummaryValue('collegeSummaryAcceptances', acceptedCount);
        }

        function renderCollegeTextInput(sheetKey, rowId, field, value, placeholder = '') {
            return `<input class="college-input" type="text" data-college-sheet="${sheetKey}" data-college-row-id="${rowId}" data-college-field="${field}" value="${escapeHtml(String(value || ''))}" placeholder="${escapeHtml(String(placeholder || ''))}" />`;
        }

        function renderCollegeDateInput(sheetKey, rowId, field, value) {
            return `<input class="college-input" type="date" data-college-sheet="${sheetKey}" data-college-row-id="${rowId}" data-college-field="${field}" value="${escapeHtml(String(value || ''))}" />`;
        }

        function renderCollegeCheckboxInput(sheetKey, rowId, field, checked) {
            return `<input class="college-checkbox-input" type="checkbox" data-college-sheet="${sheetKey}" data-college-row-id="${rowId}" data-college-field="${field}" ${checked ? 'checked' : ''} />`;
        }

        function renderCollegeTextareaInput(sheetKey, rowId, field, value, rows = 2) {
            return `<textarea class="college-textarea" rows="${rows}" data-college-sheet="${sheetKey}" data-college-row-id="${rowId}" data-college-field="${field}" placeholder="Add notes...">${escapeHtml(String(value || ''))}</textarea>`;
        }

        function renderCollegeSelectInput(sheetKey, rowId, field, value, options) {
            const optionMarkup = (Array.isArray(options) ? options : []).map(option => {
                const val = typeof option === 'string' ? option : option.value;
                const label = typeof option === 'string' ? option : option.label;
                const selected = String(value || '') === String(val) ? 'selected' : '';
                return `<option value="${escapeHtml(String(val))}" ${selected}>${escapeHtml(String(label))}</option>`;
            }).join('');
            return `<select class="college-select" data-college-sheet="${sheetKey}" data-college-row-id="${rowId}" data-college-field="${field}">${optionMarkup}</select>`;
        }

        function renderCollegeDeleteButton(sheetKey, rowId) {
            return `<button type="button" class="icon-btn college-delete-row-btn" data-college-sheet="${sheetKey}" data-college-row-id="${rowId}" title="Delete row"><i class="fas fa-trash"></i></button>`;
        }

        function renderCollegeActionButton(label, dataset, options = {}) {
            const attrs = Object.entries(dataset || {})
                .map(([key, value]) => `data-${key}="${escapeHtml(String(value == null ? '' : value))}"`)
                .join(' ');
            const className = options.className ? ` ${options.className}` : '';
            const title = options.title ? ` title="${escapeHtml(String(options.title))}"` : '';
            return `<button type="button" class="icon-btn college-action-btn${className}" ${attrs}${title}>${escapeHtml(label)}</button>`;
        }

        function getCollegeSheetScheduleItem(sheetKey, row) {
            if (!row) return null;
            if (sheetKey === 'checklist') {
                const dueDate = String(row.earlyDeadline || row.regularDeadline || row.fafsaDeadline || row.cssDeadline || '').trim();
                if (!dueDate) return null;
                const school = trimCollegeDeadlineLabel(row.college, 'College');
                return { title: `${school} application`, dueDate, category: 'college' };
            }
            if (sheetKey === 'deadlines') {
                const dueDate = String(row.submitBy || row.applicationDeadline || row.essaysDoneBy || '').trim();
                if (!dueDate) return null;
                const school = trimCollegeDeadlineLabel(row.college, 'College');
                return { title: `${school} deadline`, dueDate, category: 'college' };
            }
            if (sheetKey === 'essays') {
                const dueDate = String(row.firstDraftBy || row.reviewBy || row.revisionBy || row.finalBy || '').trim();
                if (!dueDate) return null;
                const essay = trimCollegeDeadlineLabel(row.essay, 'Essay draft');
                return { title: essay, dueDate, category: 'writing' };
            }
            return null;
        }

        function getCollegeAppScheduleItem(collection, row) {
            if (!row) return null;
            if (collection === 'collegeTracker') {
                const dueDate = String(row.deadline || row.nextDate || '').trim();
                if (!dueDate) return null;
                const school = trimCollegeDeadlineLabel(row.school, 'College app');
                return { title: `${school} application`, dueDate, category: 'college' };
            }
            if (collection === 'essayOrganizer') {
                const dueDate = String(row.dueDate || '').trim();
                if (!dueDate) return null;
                const school = trimCollegeDeadlineLabel(row.school, 'Essay');
                return { title: `${school} essay`, dueDate, category: 'writing' };
            }
            if (collection === 'scholarships') {
                const dueDate = String(row.deadline || '').trim();
                if (!dueDate) return null;
                const name = trimCollegeDeadlineLabel(row.name, 'Scholarship');
                return { title: name, dueDate, category: 'college' };
            }
            return null;
        }

        function createCollegeEssayNoteFromContext(context = {}) {
            if (!Array.isArray(pages)) return null;
            const existingId = String(context.noteId || '').trim();
            if (existingId) {
                const existingPage = pages.find(page => String(page.id) === existingId);
                if (existingPage) {
                    try { setActiveView('notes'); loadPage && loadPage(existingPage.id); } catch (err) {}
                    return existingPage;
                }
            }

            const school = trimCollegeDeadlineLabel(context.school, 'College');
            const label = trimCollegeDeadlineLabel(context.label, 'Essay draft');
            const title = `${school} :: Essay :: ${label}`;
            const prompt = String(context.prompt || '').trim();
            const content = [
                `<h2>${escapeHtml(label)}</h2>`,
                `<p><strong>School:</strong> ${escapeHtml(school)}</p>`,
                prompt ? `<p><strong>Prompt:</strong> ${escapeHtml(prompt)}</p>` : '',
                '<h3>Angle</h3><p></p>',
                '<h3>Outline</h3><ul><li></li></ul>',
                '<h3>Draft</h3><p></p>'
            ].filter(Boolean).join('');
            const nowIso = new Date().toISOString();
            const newPage = {
                id: generateId(),
                title,
                content,
                blocks: [],
                icon: (typeof PAGE_ICONS !== 'undefined' ? PAGE_ICONS.DOC : '📄'),
                spaceId: activeSpaceId || 'default',
                collapsed: false,
                createdAt: nowIso,
                updatedAt: nowIso,
                theme: (typeof globalTheme !== 'undefined' ? globalTheme : 'default')
            };
            pages.push(newPage);
            try { savePagesToLocal && savePagesToLocal(); } catch (err) {}
            try { renderPagesList && renderPagesList(); } catch (err) {}
            try { setActiveView('notes'); loadPage && loadPage(newPage.id); } catch (err) {}
            return newPage;
        }

