        // ---- Course Hub: rendering -----------------------------------------

        function cwStatCard(icon, value, label) {
            return `
                <div class="cw-stat">
                    <div class="cw-stat-icon"><i class="fas ${icon}" aria-hidden="true"></i></div>
                    <div class="cw-stat-body">
                        <div class="cw-stat-value">${cwEsc(value)}</div>
                        <div class="cw-stat-label">${cwEsc(label)}</div>
                    </div>
                </div>`;
        }

        function cwUrgencyPill(urgency) {
            const u = String(urgency || 'medium');
            const label = u.charAt(0).toUpperCase() + u.slice(1);
            return `<span class="cw-pill cw-pill-${u}"><span class="cw-pill-dot" aria-hidden="true"></span>${cwEsc(label)}</span>`;
        }

        function cwCourseChip(course) {
            if (!course) return '';
            return `<span class="cw-course-chip"><span class="cw-chip-dot" style="background:${cwEsc(getCourseColor(course))}" aria-hidden="true"></span>${cwEsc(getCourseDisplayName(course))}</span>`;
        }

        function cwCourseCardHtml(course, activeId) {
            const stats = getCourseWorkloadStats(course.id);
            const nextClass = cwComputeNextClass(course);
            const assignments = getAssignmentsForCourse(course.id).filter(a => !a.done);
            const nextDue = assignments[0];
            const days = cwMeetingDaysLabel(course);
            const isActive = String(course.id) === String(activeId);
            return `
                <button type="button" class="cw-course-card ${isActive ? 'is-selected' : ''} ${course.archived ? 'is-archived' : ''}" data-cw-course="${cwEsc(course.id)}" aria-pressed="${isActive}">
                    <span class="cw-course-accent" style="background:${cwEsc(getCourseColor(course))}" aria-hidden="true"></span>
                    <span class="cw-course-card-body">
                        <span class="cw-course-card-top">
                            <span class="cw-course-name">${cwEsc(course.name)}${course.archived ? ' <span class="cw-archived-tag">Archived</span>' : ''}</span>
                            <span class="cw-course-menu" data-cw-course-menu="${cwEsc(course.id)}" role="button" tabindex="0" aria-label="Course actions"><i class="fas fa-ellipsis-h" aria-hidden="true"></i></span>
                        </span>
                        <span class="cw-course-meta">${cwEsc(course.teacherName || '—')}${course.room ? ' · ' + cwEsc(course.room) : ''}</span>
                        <span class="cw-course-tags">
                            ${days ? `<span class="cw-course-daypill">${cwEsc(days)}</span>` : ''}
                            ${nextClass ? `<span class="cw-course-next">Next: ${cwEsc(nextClass.dayLabel)}${nextClass.timeLabel ? ' ' + cwEsc(nextClass.timeLabel) : ''}</span>` : ''}
                        </span>
                        <span class="cw-course-due">
                            ${nextDue ? `<span class="cw-course-due-label"><i class="fas fa-circle-dot" aria-hidden="true"></i> ${cwEsc(nextDue.title)}</span><span class="cw-course-due-date">${cwEsc(nextDue.due ? cwFmtDate(nextDue.due) : 'No date')}</span>` : '<span class="cw-course-due-label cw-muted">No assignments due</span>'}
                        </span>
                        <span class="cw-course-counts">
                            <span><i class="fas fa-paperclip" aria-hidden="true"></i> ${stats.files}</span>
                            <span><i class="fas fa-note-sticky" aria-hidden="true"></i> ${stats.notes}</span>
                            <span><i class="fas fa-list-check" aria-hidden="true"></i> ${stats.open}</span>
                        </span>
                    </span>
                </button>`;
        }

        function cwFileIcon(kind) {
            const map = { syllabus: 'fa-file-lines', rubric: 'fa-list-check', worksheet: 'fa-file-pen', study_guide: 'fa-book-open', lecture_notes: 'fa-file-lines', lab: 'fa-flask', slide_deck: 'fa-file-powerpoint', image: 'fa-file-image', pdf: 'fa-file-pdf', document: 'fa-file-word', spreadsheet: 'fa-file-excel', link: 'fa-link', other: 'fa-file' };
            return map[kind] || 'fa-file';
        }

        function cwFileSize(bytes) {
            const b = Number(bytes) || 0;
            if (!b) return '';
            if (b < 1024) return `${b} B`;
            if (b < 1024 * 1024) return `${(b / 1024).toFixed(0)} KB`;
            return `${(b / 1024 / 1024).toFixed(1)} MB`;
        }

        function cwFileRowHtml(f) {
            const meta = f.storageType === 'link' ? cwEsc(f.url || 'Link') : [cwFileSize(f.sizeBytes), f.missingBlob ? 'file unavailable' : ''].filter(Boolean).join(' · ');
            return `
                <div class="cw-file-row">
                    <span class="cw-file-icon"><i class="fas ${cwFileIcon(f.kind)}" aria-hidden="true"></i></span>
                    <span class="cw-file-main">
                        <span class="cw-file-name">${cwEsc(f.name)}${f.missingBlob ? ' <span class="cw-file-missing" title="File content not available on this device">⚠</span>' : ''}</span>
                        <span class="cw-file-meta">${cwEsc(meta)}</span>
                    </span>
                    <span class="cw-file-actions">
                        <button type="button" class="cw-icon-btn" title="Open" aria-label="Open file" onclick="cwOpenFile('${cwEsc(f.id)}')"><i class="fas fa-up-right-from-square" aria-hidden="true"></i></button>
                        ${f.storageType !== 'link' ? `<button type="button" class="cw-icon-btn" title="Download" aria-label="Download" onclick="cwDownloadFile('${cwEsc(f.id)}')"><i class="fas fa-download" aria-hidden="true"></i></button>` : ''}
                        <button type="button" class="cw-icon-btn" title="Rename" aria-label="Rename" onclick="cwRenameFile('${cwEsc(f.id)}')"><i class="fas fa-pen" aria-hidden="true"></i></button>
                        <button type="button" class="cw-icon-btn cw-icon-danger" title="Delete" aria-label="Delete" onclick="cwDeleteFile('${cwEsc(f.id)}')"><i class="fas fa-trash" aria-hidden="true"></i></button>
                    </span>
                </div>`;
        }

        function cwDropzoneHtml(courseId) {
            return `
                <div class="cw-dropzone" id="cwDropzone" data-cw-dropzone="${cwEsc(courseId)}" role="button" tabindex="0" aria-label="Upload files">
                    <i class="fas fa-cloud-arrow-up" aria-hidden="true"></i>
                    <div class="cw-dropzone-text">Drag &amp; drop files here, or <span class="cw-dropzone-link">click to browse</span></div>
                    <div class="cw-dropzone-sub">Supports: PDF, DOCX, PPTX, ZIP, CSV, and more</div>
                </div>
                <input type="file" id="cwFileInput" multiple style="display:none" aria-hidden="true">`;
        }

        function cwAssignmentRowHtml(a, course) {
            const meta = cwDueMeta(a.due);
            return `
                <div class="cw-assign-row ${a.done ? 'is-done' : ''}">
                    <button type="button" class="cw-check ${a.done ? 'is-checked' : ''}" aria-label="${a.done ? 'Mark not done' : 'Mark done'}" onclick="cwToggleAssignment('${cwEsc(a.id)}')">${a.done ? '<i class="fas fa-check" aria-hidden="true"></i>' : ''}</button>
                    <span class="cw-assign-main">
                        <span class="cw-assign-title">${cwEsc(a.title)}</span>
                        <span class="cw-assign-meta"><span class="cw-due cw-due-${meta.tone}">${cwEsc(meta.label)}</span><span class="cw-type-pill">${cwEsc(a.type)}</span></span>
                    </span>
                    <button type="button" class="cw-icon-btn cw-icon-danger" title="Delete" aria-label="Delete assignment" onclick="cwDeleteAssignment('${cwEsc(a.id)}')"><i class="fas fa-trash" aria-hidden="true"></i></button>
                </div>`;
        }

        function cwRenderOverview(course) {
            const assignments = getAssignmentsForCourse(course.id);
            const openAssigns = assignments.filter(a => !a.done).slice(0, 5);
            const files = getFilesForCourse(course.id);
            const notes = getLinkedNotesForCourse(course.id);
            const decks = getReviewDecksForCourse(course.id);
            const apSubjects = getApSubjectsForCourse(course.id);
            const nextClass = cwComputeNextClass(course);
            const cats = course.gradingCategories || [];
            return `
                <div class="cw-ov-grid">
                    <section class="cw-panel">
                        <div class="cw-panel-head"><h3>Upcoming Assignments</h3><button type="button" class="cw-link" onclick="cwSetCourseTab('assignments')">View all</button></div>
                        ${openAssigns.length ? openAssigns.map(a => cwAssignmentRowHtml(a, course)).join('') : '<div class="cw-empty-line">Nothing due — you\'re caught up.</div>'}
                        <button type="button" class="cw-add-inline" onclick="cwAddAssignment('${cwEsc(course.id)}')"><i class="fas fa-plus" aria-hidden="true"></i> Add assignment</button>
                    </section>
                    <section class="cw-panel">
                        <div class="cw-panel-head"><h3>Files &amp; Resources</h3><button type="button" class="cw-link" onclick="cwSetCourseTab('files')">See all</button></div>
                        ${files.length ? files.slice(0, 5).map(cwFileRowHtml).join('') : '<div class="cw-empty-line">No files yet.</div>'}
                    </section>
                    <section class="cw-panel cw-panel-span">
                        <div class="cw-panel-head"><h3>Add Files</h3></div>
                        ${cwDropzoneHtml(course.id)}
                    </section>
                    <section class="cw-panel">
                        <div class="cw-panel-head"><h3>Linked Notes</h3><button type="button" class="cw-link" onclick="cwSetCourseTab('notes')">See all</button></div>
                        ${notes.length ? notes.slice(0, 4).map(n => `<div class="cw-note-row"><span class="cw-note-title">${cwEsc(n.title || 'Untitled note')}</span><span class="cw-note-meta">${cwEsc(n.updatedAt ? cwFmtDate(new Date(n.updatedAt)) : '')}</span></div>`).join('') : '<div class="cw-empty-line">No notes linked yet.</div>'}
                        <button type="button" class="cw-add-inline" onclick="cwNewNote('${cwEsc(course.id)}')"><i class="fas fa-plus" aria-hidden="true"></i> New note</button>
                    </section>
                    <section class="cw-panel">
                        <div class="cw-panel-head"><h3>Study</h3><button type="button" class="cw-link" onclick="cwSetCourseTab('study')">Open</button></div>
                        ${decks.length ? decks.slice(0, 3).map(d => `<div class="cw-study-row"><span>${cwEsc(d.name || d.title || 'Deck')}</span><button type="button" class="cw-mini-btn" onclick="setActiveView('review')">Open deck</button></div>`).join('') : '<div class="cw-empty-line">No review decks linked.</div>'}
                        ${apSubjects.length ? `<div class="cw-topic-chips">${apSubjects.slice(0, 1).flatMap(s => (s.tags || [])).slice(0, 6).map(t => `<span class="cw-topic-chip">${cwEsc(t)}</span>`).join('') || apSubjects.map(s => `<span class="cw-topic-chip">${cwEsc(s.name)}</span>`).join('')}</div>` : ''}
                    </section>
                    <section class="cw-panel">
                        <div class="cw-panel-head"><h3>Grade Snapshot</h3><button type="button" class="cw-link" onclick="cwSetCourseTab('grades')">Edit</button></div>
                        <div class="cw-grade-row"><div><div class="cw-grade-label">Current</div><div class="cw-grade-val">${cwEsc(course.currentGrade || '—')}</div></div><div><div class="cw-grade-label">Target</div><div class="cw-grade-val">${cwEsc(course.targetGrade || '—')}</div></div></div>
                        ${cats.length ? `<div class="cw-grade-cats">${cats.map(c => `<div class="cw-grade-cat"><span class="cw-grade-cat-name">${cwEsc(c.name)}</span><span class="cw-grade-bar"><span style="width:${Math.max(0, Math.min(100, c.currentPercent == null ? 0 : c.currentPercent))}%;background:${cwEsc(c.color)}"></span></span><span class="cw-grade-cat-pct">${c.currentPercent == null ? '—' : c.currentPercent + '%'}</span></div>`).join('')}</div>` : '<div class="cw-empty-line">No grade categories yet.</div>'}
                    </section>
                    <section class="cw-panel">
                        <div class="cw-panel-head"><h3>Next Class</h3></div>
                        ${nextClass ? `<div class="cw-nextclass"><div class="cw-nextclass-time">${cwEsc(nextClass.dayLabel)}${nextClass.timeLabel ? ' · ' + cwEsc(nextClass.timeLabel) : ''}</div><div class="cw-nextclass-room">${cwEsc(nextClass.room || course.room || 'Room TBD')}</div></div>` : '<div class="cw-empty-line">No schedule set. Add meeting days in Settings.</div>'}
                    </section>
                    <section class="cw-panel">
                        <div class="cw-panel-head"><h3>Quick Resources</h3></div>
                        <div class="cw-quick-res">
                            <button type="button" class="cw-res-card" onclick="cwSetCourseTab('calendar')"><i class="fas fa-calendar" aria-hidden="true"></i> Course Calendar</button>
                            <button type="button" class="cw-res-card" onclick="cwSetCourseTab('files')"><i class="fas fa-folder-open" aria-hidden="true"></i> Class Materials</button>
                            <button type="button" class="cw-res-card" onclick="setActiveView('apstudy')"><i class="fas fa-graduation-cap" aria-hidden="true"></i> AP Resources</button>
                        </div>
                    </section>
                </div>`;
        }

        function cwRenderCourseTabContent(course, tab) {
            if (tab === 'assignments') {
                const assignments = getAssignmentsForCourse(course.id);
                return `<section class="cw-panel cw-panel-full">
                    <div class="cw-panel-head"><h3>Assignments</h3><button type="button" class="cw-btn cw-btn-primary cw-btn-sm" onclick="cwAddAssignment('${cwEsc(course.id)}')"><i class="fas fa-plus" aria-hidden="true"></i> Add</button></div>
                    ${assignments.length ? assignments.map(a => cwAssignmentRowHtml(a, course)).join('') : '<div class="cw-empty-line">No assignments yet.</div>'}
                </section>`;
            }
            if (tab === 'files') {
                const files = getFilesForCourse(course.id);
                return `<section class="cw-panel cw-panel-full">
                    <div class="cw-panel-head"><h3>Files &amp; Resources</h3><div class="cw-head-actions"><button type="button" class="cw-btn cw-btn-ghost cw-btn-sm" onclick="cwAddResourceLink('${cwEsc(course.id)}')"><i class="fas fa-link" aria-hidden="true"></i> Add link</button><button type="button" class="cw-btn cw-btn-primary cw-btn-sm" onclick="cwAddFile('${cwEsc(course.id)}')"><i class="fas fa-upload" aria-hidden="true"></i> Upload</button></div></div>
                    ${cwDropzoneHtml(course.id)}
                    <div class="cw-file-list">${files.length ? files.map(cwFileRowHtml).join('') : '<div class="cw-empty-line">No files yet.</div>'}</div>
                </section>`;
            }
            if (tab === 'notes') {
                const notes = getLinkedNotesForCourse(course.id);
                return `<section class="cw-panel cw-panel-full">
                    <div class="cw-panel-head"><h3>Linked Notes</h3><button type="button" class="cw-btn cw-btn-primary cw-btn-sm" onclick="cwNewNote('${cwEsc(course.id)}')"><i class="fas fa-plus" aria-hidden="true"></i> New note</button></div>
                    ${notes.length ? notes.map(n => `<div class="cw-note-row"><span class="cw-note-title">${cwEsc(n.title || 'Untitled note')}</span><span class="cw-note-meta">${cwEsc(n.updatedAt ? cwFmtDate(new Date(n.updatedAt)) : '')}</span><button type="button" class="cw-mini-btn" onclick="cwUnlinkNote('${cwEsc(course.id)}','${cwEsc(n.id)}')">Unlink</button></div>`).join('') : '<div class="cw-empty-line">No notes linked. Create one or link from a note\'s class context.</div>'}
                </section>`;
            }
            if (tab === 'study') {
                const decks = getReviewDecksForCourse(course.id);
                const apSubjects = getApSubjectsForCourse(course.id);
                return `<section class="cw-panel cw-panel-full">
                    <div class="cw-panel-head"><h3>Study</h3><button type="button" class="cw-btn cw-btn-ghost cw-btn-sm" onclick="setActiveView('review')">Open Review</button></div>
                    <h4 class="cw-subhead">Review decks</h4>
                    ${decks.length ? decks.map(d => `<div class="cw-study-row"><span>${cwEsc(d.name || d.title || 'Deck')}</span><button type="button" class="cw-mini-btn" onclick="setActiveView('review')">Open</button></div>`).join('') : '<div class="cw-empty-line">No linked decks. Name a deck after this course to auto-link.</div>'}
                    <h4 class="cw-subhead">AP study</h4>
                    ${apSubjects.length ? apSubjects.map(s => `<div class="cw-study-row"><span>${cwEsc(s.name)}</span><button type="button" class="cw-mini-btn" onclick="setActiveView('apstudy')">Open</button></div>`).join('') : '<div class="cw-empty-line">No linked AP subject.</div>'}
                </section>`;
            }
            if (tab === 'calendar') {
                const events = getCalendarEventsForCourse(course.id);
                const sched = course.schedule || [];
                return `<section class="cw-panel cw-panel-full">
                    <div class="cw-panel-head"><h3>Schedule &amp; Events</h3><button type="button" class="cw-btn cw-btn-ghost cw-btn-sm" onclick="setActiveView('timeline')">Open Calendar</button></div>
                    <h4 class="cw-subhead">Weekly meetings</h4>
                    ${sched.length ? sched.map(s => `<div class="cw-study-row"><span>${cwEsc(s.day)}${s.startTime ? ' · ' + cwEsc(cwFormatTime12(s.startTime)) : ''}${s.location ? ' · ' + cwEsc(s.location) : ''}</span></div>`).join('') : '<div class="cw-empty-line">No meeting days set (add them in Settings).</div>'}
                    <h4 class="cw-subhead">Related events</h4>
                    ${events.length ? events.slice(0, 10).map(b => `<div class="cw-study-row"><span>${cwEsc(b.name || b.title || 'Event')}${b.date ? ' · ' + cwEsc(b.date) : ''}</span></div>`).join('') : '<div class="cw-empty-line">No related calendar events.</div>'}
                </section>`;
            }
            if (tab === 'grades') {
                const cats = course.gradingCategories || [];
                return `<section class="cw-panel cw-panel-full">
                    <div class="cw-panel-head"><h3>Grade Planning</h3><button type="button" class="cw-btn cw-btn-primary cw-btn-sm" onclick="cwSaveCourseGrades('${cwEsc(course.id)}')">Save</button></div>
                    <div class="cw-form-grid">
                        <label class="cw-field"><span class="cw-field-label">Current grade</span><input data-cg="currentGrade" type="text" value="${cwEsc(course.currentGrade)}" placeholder="e.g. A- 90.4%"></label>
                        <label class="cw-field"><span class="cw-field-label">Target grade</span><input data-cg="targetGrade" type="text" value="${cwEsc(course.targetGrade)}" placeholder="e.g. A 93%"></label>
                    </div>
                    <h4 class="cw-subhead">Weighted categories</h4>
                    <div class="cw-gc-list">
                        ${cats.map(c => `<div class="cw-gc-row" data-gc-row><input data-gc="name" type="text" value="${cwEsc(c.name)}" placeholder="Category"><input data-gc="weight" type="number" min="0" max="100" value="${c.weight}" placeholder="Weight %"><input data-gc="currentPercent" type="number" min="0" max="100" value="${c.currentPercent == null ? '' : c.currentPercent}" placeholder="Current %"></div>`).join('')}
                    </div>
                    <button type="button" class="cw-add-inline" onclick="cwAddGradeCategory('${cwEsc(course.id)}')"><i class="fas fa-plus" aria-hidden="true"></i> Add category</button>
                </section>`;
            }
            if (tab === 'settings') {
                const days = cwMeetingDaysLabel(course);
                const firstSched = (course.schedule || [])[0] || {};
                const typeOpts = [['class', 'Class'], ['ap', 'AP'], ['activity', 'Activity'], ['self_study', 'Self study'], ['other', 'Other']];
                return `<section class="cw-panel cw-panel-full">
                    <div class="cw-panel-head"><h3>Course Settings</h3><button type="button" class="cw-btn cw-btn-primary cw-btn-sm" onclick="cwSaveCourseSettings('${cwEsc(course.id)}')">Save changes</button></div>
                    <div class="cw-form-grid">
                        <label class="cw-field"><span class="cw-field-label">Name</span><input data-cs="name" type="text" value="${cwEsc(course.name)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Short name</span><input data-cs="shortName" type="text" value="${cwEsc(course.shortName)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Type</span><select data-cs="type">${typeOpts.map(o => `<option value="${o[0]}" ${o[0] === course.type ? 'selected' : ''}>${o[1]}</option>`).join('')}</select></label>
                        <label class="cw-field"><span class="cw-field-label">Subject area</span><input data-cs="subjectArea" type="text" value="${cwEsc(course.subjectArea)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Teacher</span><input data-cs="teacherName" type="text" value="${cwEsc(course.teacherName)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Teacher email</span><input data-cs="teacherEmail" type="email" value="${cwEsc(course.teacherEmail)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Room</span><input data-cs="room" type="text" value="${cwEsc(course.room)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Office hours</span><input data-cs="officeHours" type="text" value="${cwEsc(course.officeHours)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Term</span><input data-cs="termName" type="text" value="${cwEsc(course.termName)}"></label>
                        <label class="cw-field"><span class="cw-field-label">Color</span><input data-cs="color" type="text" value="${cwEsc(course.color)}" placeholder="#7c9cf2"></label>
                        <label class="cw-field"><span class="cw-field-label">Meeting days</span><input data-cs="meetingDays" type="text" value="${cwEsc(days)}" placeholder="Mon/Wed/Fri"></label>
                        <label class="cw-field"><span class="cw-field-label">Start time</span><input data-cs="startTime" type="time" value="${cwEsc(firstSched.startTime || '')}"></label>
                        <label class="cw-field"><span class="cw-field-label">End time</span><input data-cs="endTime" type="time" value="${cwEsc(firstSched.endTime || '')}"></label>
                    </div>
                    <label class="cw-field"><span class="cw-field-label">Description</span><textarea data-cs="description">${cwEsc(course.description)}</textarea></label>
                    <label class="cw-field"><span class="cw-field-label">Syllabus summary</span><textarea data-cs="syllabusSummary">${cwEsc(course.syllabusSummary)}</textarea></label>
                    <div class="cw-danger-row">
                        <button type="button" class="cw-btn cw-btn-ghost" onclick="cwArchiveCourse('${cwEsc(course.id)}')">${course.archived ? 'Unarchive' : 'Archive'} course</button>
                        <button type="button" class="cw-btn cw-btn-danger" onclick="cwDeleteCourse('${cwEsc(course.id)}')">Delete course</button>
                    </div>
                </section>`;
            }
            return cwRenderOverview(course);
        }

        function cwRenderCourseDetail(course) {
            const tabs = [['overview', 'Overview'], ['assignments', 'Assignments'], ['files', 'Files'], ['notes', 'Notes'], ['study', 'Study'], ['calendar', 'Calendar'], ['grades', 'Grades'], ['settings', 'Settings']];
            const tab = tabs.some(t => t[0] === cwActiveCourseTab) ? cwActiveCourseTab : 'overview';
            const meta = [course.teacherName, course.room, cwMeetingDaysLabel(course)].filter(Boolean).join(' · ');
            const tagsHtml = (course.tags || []).map(t => `<span class="cw-tag">${cwEsc(t)}</span>`).join('') + `<button type="button" class="cw-tag cw-tag-add" onclick="cwAddTag('${cwEsc(course.id)}')">+ Add tag</button>`;
            return `
                <div class="cw-detail-header">
                    <div class="cw-detail-avatar" style="background:${cwEsc(getCourseColor(course))}">${cwEsc((course.shortName || course.name || '?').slice(0, 2).toUpperCase())}</div>
                    <div class="cw-detail-headmain">
                        <h2 class="cw-detail-title">${cwEsc(course.name)}</h2>
                        <div class="cw-detail-meta">${cwEsc(meta || 'Add teacher, room & schedule in Settings')}</div>
                        <div class="cw-detail-tags">${tagsHtml}</div>
                    </div>
                    <div class="cw-detail-actions">
                        <button type="button" class="cw-btn cw-btn-primary" onclick="cwAddAssignment('${cwEsc(course.id)}')"><i class="fas fa-plus" aria-hidden="true"></i> Add Assignment</button>
                        <button type="button" class="cw-btn cw-btn-ghost" onclick="cwAddFile('${cwEsc(course.id)}')"><i class="fas fa-upload" aria-hidden="true"></i> Add File</button>
                        <button type="button" class="cw-btn cw-btn-ghost" onclick="cwNewNote('${cwEsc(course.id)}')"><i class="fas fa-note-sticky" aria-hidden="true"></i> New Note</button>
                        <button type="button" class="cw-icon-btn" aria-label="Course actions" onclick="cwSetCourseTab('settings')"><i class="fas fa-ellipsis-h" aria-hidden="true"></i></button>
                    </div>
                </div>
                <div class="cw-tabs" role="tablist">
                    ${tabs.map(t => `<button type="button" class="cw-tab ${t[0] === tab ? 'is-active' : ''}" role="tab" aria-selected="${t[0] === tab}" onclick="cwSetCourseTab('${t[0]}')">${cwEsc(t[1])}</button>`).join('')}
                </div>
                <div class="cw-tab-content">${cwRenderCourseTabContent(course, tab)}</div>`;
        }

        function renderCourseHubView(opts = {}) {
            const mount = document.getElementById('courseHubMount');
            if (!mount) return;
            const stats = calculateCourseStats();
            const filter = courseWorkspace.settings.courseFilter || 'all';
            const allCourses = getCourses({ filter: 'all' });
            const list = getCourses({ filter, search: cwCourseSearchQuery });
            let activeId = courseWorkspace.settings.activeCourseId;
            if (!getCourseById(activeId)) {
                const fallback = list[0] || allCourses.find(c => !c.archived) || allCourses[0];
                activeId = fallback ? fallback.id : null;
                courseWorkspace.settings.activeCourseId = activeId;
            }
            const activeCourse = getCourseById(activeId);

            const header = `
                <div class="cw-header">
                    <div class="cw-header-titles"><h1 class="cw-h1">Courses</h1><p class="cw-sub">Your class cockpit — everything connected to each course in one place.</p></div>
                    <div class="cw-header-controls">
                        <div class="cw-search"><i class="fas fa-search" aria-hidden="true"></i><input id="cwCourseSearch" type="search" placeholder="Search courses, files, notes..." value="${cwEsc(cwCourseSearchQuery)}" aria-label="Search courses"></div>
                        <select class="cw-filter" id="cwCourseFilter" aria-label="Filter courses" onchange="cwSetCourseFilter(this.value)">
                            <option value="all" ${filter === 'all' ? 'selected' : ''}>All Courses</option>
                            <option value="active" ${filter === 'active' ? 'selected' : ''}>Active</option>
                            <option value="archived" ${filter === 'archived' ? 'selected' : ''}>Archived</option>
                        </select>
                        <button type="button" class="cw-btn cw-btn-primary" onclick="cwNewCourse()"><i class="fas fa-plus" aria-hidden="true"></i> New Course</button>
                    </div>
                </div>`;

            const statRow = `
                <div class="cw-stat-row">
                    ${cwStatCard('fa-book', stats.activeCourses, 'Active Courses')}
                    ${cwStatCard('fa-list-check', stats.openAssignments, 'Open Assignments')}
                    ${cwStatCard('fa-paperclip', stats.files, 'Files')}
                    ${cwStatCard('fa-note-sticky', stats.linkedNotes, 'Linked Notes')}
                </div>`;

            if (!allCourses.length) {
                mount.innerHTML = `${header}${statRow}
                    <div class="cw-empty-state">
                        <div class="cw-empty-icon"><i class="fas fa-graduation-cap" aria-hidden="true"></i></div>
                        <h2>No courses yet</h2>
                        <p>Create your first course to start tracking assignments, files, notes, study decks, and grades — all in one workspace.</p>
                        <div class="cw-empty-actions">
                            <button type="button" class="cw-btn cw-btn-primary" onclick="cwNewCourse()"><i class="fas fa-plus" aria-hidden="true"></i> Create Course</button>
                            <button type="button" class="cw-btn cw-btn-ghost" onclick="cwSeedExamples()">Load example courses</button>
                        </div>
                    </div>`;
                return;
            }

            const listHtml = list.length
                ? list.map(c => cwCourseCardHtml(c, activeId)).join('')
                : '<div class="cw-empty-line" style="padding:18px">No courses match your search.</div>';

            mount.innerHTML = `
                ${header}
                ${statRow}
                <div class="cw-layout">
                    <div class="cw-course-list" role="list">${listHtml}</div>
                    <div class="cw-detail">${activeCourse ? cwRenderCourseDetail(activeCourse) : '<div class="cw-empty-line" style="padding:24px">Select a course.</div>'}</div>
                </div>`;

            cwAfterCourseRender(opts);
        }

        function cwAfterCourseRender(opts) {
            const mount = document.getElementById('courseHubMount');
            if (!mount) return;
            // Course card selection.
            mount.querySelectorAll('[data-cw-course]').forEach(card => {
                card.addEventListener('click', (e) => {
                    if (e.target.closest('[data-cw-course-menu]')) return;
                    cwSelectCourse(card.dataset.cwCourse);
                });
            });
            // Three-dot course menu -> jump to settings tab for that course.
            mount.querySelectorAll('[data-cw-course-menu]').forEach(menu => {
                const open = (e) => { e.stopPropagation(); cwSelectCourse(menu.dataset.cwCourseMenu); cwSetCourseTab('settings'); };
                menu.addEventListener('click', open);
                menu.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); open(e); } });
            });
            // Search input behavior.
            const search = document.getElementById('cwCourseSearch');
            if (search) {
                search.addEventListener('input', (e) => cwCourseSearch(e.target.value));
                if (opts && opts.keepSearchFocus) {
                    search.focus();
                    const v = search.value; search.value = ''; search.value = v;
                }
            }
            // File input + dropzone.
            const fileInput = document.getElementById('cwFileInput');
            const dropzone = document.getElementById('cwDropzone');
            const activeId = courseWorkspace.settings.activeCourseId;
            if (fileInput) {
                fileInput.addEventListener('change', (e) => {
                    const cid = (dropzone && dropzone.dataset.cwDropzone) || activeId;
                    cwHandleFiles(e.target.files, cid);
                    e.target.value = '';
                });
            }
            if (dropzone) {
                dropzone.addEventListener('click', () => { if (fileInput) fileInput.click(); });
                dropzone.addEventListener('keydown', (e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); if (fileInput) fileInput.click(); } });
                dropzone.addEventListener('dragover', (e) => { e.preventDefault(); dropzone.classList.add('is-dragover'); });
                dropzone.addEventListener('dragleave', () => dropzone.classList.remove('is-dragover'));
                dropzone.addEventListener('drop', (e) => {
                    e.preventDefault();
                    dropzone.classList.remove('is-dragover');
                    cwHandleFiles(e.dataTransfer ? e.dataTransfer.files : null, dropzone.dataset.cwDropzone || activeId);
                });
            }
        }

        function cwUnlinkNote(courseId, noteId) {
            unlinkNoteFromCourse(courseId, noteId);
            renderCourseHubView();
        }

        // =====================================================================
        // ALL DUE — rendering + interactions
        // =====================================================================

        function cwAllDueSearch(value) {
            cwAllDueSearchQuery = String(value || '');
            renderAllDueView({ keepSearchFocus: true });
        }
        function cwSetAllDueRange(range) {
            courseWorkspace.settings.allDueFilter = COURSE_DUE_RANGES.includes(range) ? range : 'overdue';
            persistAppData();
            renderAllDueView();
        }
        function cwSetAllDueCourse(value) {
            courseWorkspace.settings.allDueCourseFilter = String(value || 'all');
            persistAppData();
            renderAllDueView();
        }
        function cwOpenDueItem(source, sourceId) {
            const s = String(source || '');
            if (s === 'homework' && sourceId) {
                if (typeof window.openHomeworkTaskModal === 'function') { try { window.openHomeworkTaskModal('v2', String(sourceId)); return; } catch (e) { /* fall through */ } }
                setActiveView('homework');
                return;
            }
            if (s === 'apStudy') { setActiveView('apstudy'); return; }
            if (s === 'timeline') { setActiveView('timeline'); return; }
            if (s === 'collegeapp' || s === 'college') { setActiveView('collegeapp'); return; }
            setActiveView('homework');
        }
        function cwQuickAction(action) {
            switch (String(action || '')) {
                case 'addAssignment': cwOpenAddAssignmentModal(''); break;
                case 'newNote':
                    if (typeof createNewPage === 'function') { try { createNewPage(); break; } catch (e) {} }
                    setActiveView('notes'); break;
                case 'studyTimer':
                    if (window.flowAtelier && typeof window.flowAtelier.startFocusSession === 'function') { try { window.flowAtelier.startFocusSession(); break; } catch (e) {} }
                    if (typeof startFocusSession === 'function') { try { startFocusSession(); break; } catch (e) {} }
                    setActiveView('today'); break;
                case 'generateQuiz': setActiveView('apstudy'); break;
                case 'uploadFile': cwTriggerFilePicker(courseWorkspace.settings.activeCourseId || ''); break;
                case 'dailyReview': setActiveView('review'); break;
                default: break;
            }
        }

        function cwAllDueRow(item) {
            const course = item.courseId ? getCourseById(item.courseId) : null;
            const meta = cwDueMeta(item.due);
            const courseColor = course ? getCourseColor(course) : 'var(--text-muted)';
            return `
                <button type="button" class="ad-row" onclick="cwOpenDueItem('${cwEsc(item.source)}','${cwEsc(item.sourceId)}')">
                    <span class="ad-row-dot ad-dot-${cwEsc(item.urgency)}" aria-hidden="true"></span>
                    <span class="ad-row-title">${cwEsc(item.title)}</span>
                    <span class="ad-row-course">${course ? `<span class="cw-chip-dot" style="background:${cwEsc(courseColor)}" aria-hidden="true"></span>` : ''}${cwEsc(item.courseName || '—')}</span>
                    <span class="ad-row-due ad-due-${meta.tone}">${cwEsc(meta.label)}</span>
                    <span class="ad-row-type"><span class="cw-type-pill">${cwEsc(item.type)}</span></span>
                    <span class="ad-row-urgency">${cwUrgencyPill(item.urgency)}</span>
                </button>`;
        }

        function cwTodayScheduleItems() {
            const out = [];
            const now = new Date();
            const todayIdx = now.getDay();
            const todayKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
            // Course meetings today.
            getCourses({ filter: 'active' }).forEach(c => {
                (c.schedule || []).forEach(s => {
                    if (cwDayIndex(s.day) === todayIdx && s.startTime) {
                        const startMin = cwTimeToMinutes(s.startTime);
                        const endMin = cwTimeToMinutes(s.endTime);
                        out.push({ min: startMin == null ? 0 : startMin, time: cwFormatTime12(s.startTime), title: c.name, subtitle: s.label || 'Class', room: s.location || c.room || '', dur: (endMin && startMin) ? `${endMin - startMin}m` : '50m', color: getCourseColor(c) });
                    }
                });
            });
            // Timeline blocks today.
            (Array.isArray(timeBlocks) ? timeBlocks : []).forEach(b => {
                if (!b || String(b.date) !== todayKey) return;
                const startMin = cwTimeToMinutes(b.start);
                const endMin = cwTimeToMinutes(b.end);
                out.push({ min: startMin == null ? 0 : startMin, time: b.start ? cwFormatTime12(b.start) : '', title: b.name || b.title || 'Block', subtitle: b.category || 'Block', room: '', dur: (endMin && startMin) ? `${endMin - startMin}m` : '', color: 'var(--accent-strong)' });
            });
            out.sort((a, b) => a.min - b.min);
            return out;
        }

        function renderAllDueView(opts = {}) {
            const mount = document.getElementById('allDueMount');
            if (!mount) return;
            const courseFilter = courseWorkspace.settings.allDueCourseFilter || 'all';
            const allItems = getAllDueItems({ courseId: courseFilter, search: cwAllDueSearchQuery });
            const groups = groupDueItemsByRange(allItems);
            const now = new Date();

            const overdueCount = groups.overdue.length;
            const overdueNeedAttn = groups.overdue.filter(i => i.urgency === 'high').length;
            const todayCount = groups.today.length;
            const weekItems = [...groups.today, ...groups.tomorrow, ...groups.thisWeek];
            const weekCount = weekItems.length;
            const examItems = weekItems.filter(i => i.type === 'Exam' || /\b(exam|test|final|midterm)\b/i.test(i.title));
            const examTomorrow = groups.tomorrow.filter(i => i.type === 'Exam' || /\b(exam|test|final)\b/i.test(i.title)).length;
            const openItems = allItems.filter(i => !i.completed);
            const courseCount = new Set(openItems.map(i => i.courseId).filter(Boolean)).size;

            // Next upcoming today.
            let nextLabel = '—';
            const upcomingToday = groups.today.filter(i => i.due && i.due > now).sort((a, b) => a.due - b.due)[0];
            if (upcomingToday) {
                const diffMin = Math.round((upcomingToday.due - now) / 60000);
                nextLabel = diffMin < 60 ? `in ${Math.max(1, diffMin)}m` : `in ${Math.round(diffMin / 60)}h`;
            }
            const weekStart = startOfDay(now);
            const weekEndD = new Date(weekStart); weekEndD.setDate(weekEndD.getDate() + 7);
            const weekRange = `${cwFmtDate(weekStart)} – ${cwFmtDate(weekEndD)}`;

            const courseOptions = getCourses({ filter: 'all' }).map(c => `<option value="${cwEsc(c.id)}" ${String(c.id) === courseFilter ? 'selected' : ''}>${cwEsc(c.name)}</option>`).join('');

            const header = `
                <div class="ad-header">
                    <div class="ad-header-titles"><h1 class="cw-h1">All Due</h1><p class="cw-sub">Everything you need to get done across all your classes.</p></div>
                    <div class="cw-header-controls">
                        <div class="cw-search"><i class="fas fa-search" aria-hidden="true"></i><input id="cwAllDueSearch" type="search" placeholder="Search assignments, notes, files..." value="${cwEsc(cwAllDueSearchQuery)}" aria-label="Search due items"></div>
                        <select class="cw-filter" aria-label="Filter by course" onchange="cwSetAllDueCourse(this.value)"><option value="all" ${courseFilter === 'all' ? 'selected' : ''}>All Courses</option>${courseOptions}</select>
                        <button type="button" class="cw-btn cw-btn-primary" onclick="cwAddAssignment('')"><i class="fas fa-plus" aria-hidden="true"></i> Add Assignment</button>
                    </div>
                </div>`;

            const statRow = `
                <div class="ad-stat-row">
                    <div class="cw-stat ad-stat ad-stat-overdue"><div class="cw-stat-icon"><i class="fas fa-triangle-exclamation" aria-hidden="true"></i></div><div class="cw-stat-body"><div class="cw-stat-value">${overdueCount}</div><div class="cw-stat-label">Overdue</div><div class="ad-stat-sub">${overdueNeedAttn} need attention</div></div></div>
                    <div class="cw-stat ad-stat"><div class="cw-stat-icon"><i class="fas fa-bolt" aria-hidden="true"></i></div><div class="cw-stat-body"><div class="cw-stat-value">${todayCount}</div><div class="cw-stat-label">Due Today</div><div class="ad-stat-sub">Next: ${cwEsc(nextLabel)}</div></div></div>
                    <div class="cw-stat ad-stat"><div class="cw-stat-icon"><i class="fas fa-calendar-week" aria-hidden="true"></i></div><div class="cw-stat-body"><div class="cw-stat-value">${weekCount}</div><div class="cw-stat-label">Due This Week</div><div class="ad-stat-sub">${cwEsc(weekRange)}</div></div></div>
                    <div class="cw-stat ad-stat"><div class="cw-stat-icon"><i class="fas fa-file-pen" aria-hidden="true"></i></div><div class="cw-stat-body"><div class="cw-stat-value">${examItems.length}</div><div class="cw-stat-label">Exams This Week</div><div class="ad-stat-sub">${examTomorrow} Tomorrow</div></div></div>
                    <div class="cw-stat ad-stat"><div class="cw-stat-icon"><i class="fas fa-list-check" aria-hidden="true"></i></div><div class="cw-stat-body"><div class="cw-stat-value">${openItems.length}</div><div class="cw-stat-label">Open Assignments</div><div class="ad-stat-sub">Across ${courseCount} course${courseCount === 1 ? '' : 's'}</div></div></div>
                </div>`;

            if (!allItems.length) {
                mount.innerHTML = `${header}${statRow}
                    <div class="cw-empty-state">
                        <div class="cw-empty-icon"><i class="fas fa-circle-check" aria-hidden="true"></i></div>
                        <h2>Nothing due right now</h2>
                        <p>You're all caught up. Add an assignment, plan a study block, or set up a course to get started.</p>
                        <div class="cw-empty-actions">
                            <button type="button" class="cw-btn cw-btn-primary" onclick="cwAddAssignment('')"><i class="fas fa-plus" aria-hidden="true"></i> Add Assignment</button>
                            <button type="button" class="cw-btn cw-btn-ghost" onclick="cwQuickAction('studyTimer')">Start Study Block</button>
                            <button type="button" class="cw-btn cw-btn-ghost" onclick="setActiveView('courses')">Manage Courses</button>
                        </div>
                    </div>`;
                cwAfterAllDueRender(opts);
                return;
            }

            const ranges = [['overdue', 'Overdue'], ['today', 'Today'], ['tomorrow', 'Tomorrow'], ['thisWeek', 'This Week'], ['nextWeek', 'Next Week'], ['later', 'Later']];
            let activeRange = courseWorkspace.settings.allDueFilter || 'overdue';
            if (!groups[activeRange] || !groups[activeRange].length) {
                const firstNonEmpty = ranges.map(r => r[0]).find(r => groups[r] && groups[r].length);
                if (firstNonEmpty) activeRange = firstNonEmpty;
            }
            const rangeTabs = ranges.map(r => `<button type="button" class="ad-range-tab ${r[0] === activeRange ? 'is-active' : ''}" onclick="cwSetAllDueRange('${r[0]}')">${cwEsc(r[1])}<span class="ad-range-count">${groups[r[0]].length}</span></button>`).join('');
            const rows = (groups[activeRange] || []);
            const tableHtml = rows.length
                ? `<div class="ad-table">
                        <div class="ad-table-head"><span>Assignment</span><span>Course</span><span>Due</span><span>Type</span><span>Urgency</span></div>
                        ${rows.map(cwAllDueRow).join('')}
                   </div>`
                : '<div class="cw-empty-line" style="padding:20px">Nothing in this range.</div>';

            const majors = getUpcomingMajorDeadlines({ courseId: courseFilter });
            const majorsHtml = majors.length
                ? majors.map(m => {
                    const course = m.courseId ? getCourseById(m.courseId) : null;
                    return `<button type="button" class="ad-exam-row" onclick="cwOpenDueItem('${cwEsc(m.source)}','${cwEsc(m.sourceId)}')">
                        <span class="ad-exam-dot" style="background:${cwEsc(course ? getCourseColor(course) : 'var(--accent-strong)')}" aria-hidden="true"></span>
                        <span class="ad-exam-main"><span class="ad-exam-title">${cwEsc(m.courseName ? m.courseName + ': ' : '')}${cwEsc(m.title)}</span><span class="ad-exam-meta">${cwEsc(cwFmtDateTime(m.due))}</span></span>
                        ${cwUrgencyPill(m.urgency)}
                    </button>`;
                }).join('')
                : '<div class="cw-empty-line">No major deadlines coming up.</div>';

            // By course workload.
            const byCourse = getCourses({ filter: 'active' }).map(c => {
                const stats = getCourseWorkloadStats(c.id);
                const pct = stats.total ? Math.round((stats.done / stats.total) * 100) : 0;
                return `<div class="ad-course-row">
                    <span class="ad-course-name"><span class="cw-chip-dot" style="background:${cwEsc(getCourseColor(c))}" aria-hidden="true"></span>${cwEsc(c.name)}</span>
                    <span class="ad-course-bar"><span style="width:${pct}%;background:${cwEsc(getCourseColor(c))}"></span></span>
                    <span class="ad-course-counts">${stats.open} due${stats.overdue ? ` · <span class="ad-overdue-mini">${stats.overdue} overdue</span>` : ''}</span>
                </div>`;
            }).join('') || '<div class="cw-empty-line">No active courses.</div>';

            // Today schedule.
            const sched = cwTodayScheduleItems();
            const schedHtml = sched.length
                ? sched.map(s => `<div class="ad-sched-row"><span class="ad-sched-time">${cwEsc(s.time)}</span><span class="ad-sched-line" style="background:${cwEsc(s.color)}" aria-hidden="true"></span><span class="ad-sched-main"><span class="ad-sched-title">${cwEsc(s.title)}</span><span class="ad-sched-sub">${cwEsc(s.subtitle)}${s.room ? ' · ' + cwEsc(s.room) : ''}</span></span>${s.dur ? `<span class="ad-sched-dur">${cwEsc(s.dur)}</span>` : ''}</div>`).join('')
                : '<div class="cw-empty-line">No classes or blocks scheduled today.</div>';

            // Recent files.
            const recentFiles = (courseWorkspace.files || []).slice().sort((a, b) => String(b.updatedAt || b.createdAt || '').localeCompare(String(a.updatedAt || a.createdAt || ''))).slice(0, 5);
            const filesHtml = recentFiles.length
                ? recentFiles.map(f => { const c = getCourseById(f.courseId); return `<button type="button" class="ad-file-row" onclick="cwOpenFile('${cwEsc(f.id)}')"><span class="cw-file-icon"><i class="fas ${cwFileIcon(f.kind)}" aria-hidden="true"></i></span><span class="cw-file-main"><span class="cw-file-name">${cwEsc(f.name)}</span><span class="cw-file-meta">${cwEsc(c ? c.name : '')}${f.updatedAt ? ' · ' + cwEsc(cwFmtDate(new Date(f.updatedAt))) : ''}</span></span></button>`; }).join('')
                : '<div class="cw-empty-line">No files yet.</div>';

            mount.innerHTML = `
                ${header}
                ${statRow}
                <div class="ad-main-grid">
                    <section class="cw-panel ad-everything">
                        <div class="cw-panel-head"><h3>Everything Due</h3></div>
                        <div class="ad-range-tabs">${rangeTabs}</div>
                        ${tableHtml}
                        <button type="button" class="ad-viewall" onclick="setActiveView('homework')">View all ${openItems.length} assignments <i class="fas fa-arrow-right" aria-hidden="true"></i></button>
                    </section>
                    <section class="cw-panel ad-exams">
                        <div class="cw-panel-head"><h3>Upcoming Exams &amp; Major Deadlines</h3></div>
                        ${majorsHtml}
                        <button type="button" class="cw-link" onclick="setActiveView('timeline')">View full calendar</button>
                    </section>
                </div>
                <div class="ad-lower-grid">
                    <section class="cw-panel"><div class="cw-panel-head"><h3>By Course</h3></div>${byCourse}</section>
                    <section class="cw-panel"><div class="cw-panel-head"><h3>Today's Schedule</h3></div>${schedHtml}</section>
                    <section class="cw-panel"><div class="cw-panel-head"><h3>Quick Actions</h3></div>
                        <div class="ad-quick-grid">
                            <button type="button" class="ad-quick" onclick="cwQuickAction('addAssignment')"><i class="fas fa-plus" aria-hidden="true"></i><span>Add Assignment</span></button>
                            <button type="button" class="ad-quick" onclick="cwQuickAction('newNote')"><i class="fas fa-note-sticky" aria-hidden="true"></i><span>New Note</span></button>
                            <button type="button" class="ad-quick" onclick="cwQuickAction('studyTimer')"><i class="fas fa-clock" aria-hidden="true"></i><span>Study Timer</span></button>
                            <button type="button" class="ad-quick" onclick="cwQuickAction('generateQuiz')"><i class="fas fa-wand-magic-sparkles" aria-hidden="true"></i><span>Generate Quiz</span></button>
                            <button type="button" class="ad-quick" onclick="cwQuickAction('uploadFile')"><i class="fas fa-upload" aria-hidden="true"></i><span>Upload File</span></button>
                            <button type="button" class="ad-quick" onclick="cwQuickAction('dailyReview')"><i class="fas fa-layer-group" aria-hidden="true"></i><span>Daily Review</span></button>
                        </div>
                    </section>
                    <section class="cw-panel"><div class="cw-panel-head"><h3>Recent Files</h3></div>${filesHtml}</section>
                </div>`;
            cwAfterAllDueRender(opts);
        }

        function cwAfterAllDueRender(opts) {
            const search = document.getElementById('cwAllDueSearch');
            if (search) {
                search.addEventListener('input', (e) => cwAllDueSearch(e.target.value));
                if (opts && opts.keepSearchFocus) {
                    search.focus();
                    const v = search.value; search.value = ''; search.value = v;
                }
            }
        }

        // ---- Window exposures for inline handlers + Flow / bridges ----------
        if (typeof window !== 'undefined') {
            window.renderCourseHubView = renderCourseHubView;
            window.renderAllDueView = renderAllDueView;
            window.cwNewCourse = cwOpenNewCourseModal;
            window.cwSeedExamples = cwSeedExampleCourses;
            window.cwSelectCourse = cwSelectCourse;
            window.cwSetCourseTab = cwSetCourseTab;
            window.cwSetCourseFilter = cwSetCourseFilter;
            window.cwCourseSearch = cwCourseSearch;
            window.cwAddAssignment = cwOpenAddAssignmentModal;
            window.cwAddFile = cwTriggerFilePicker;
            window.cwNewNote = cwNewNoteForCourse;
            window.cwAddTag = cwAddCourseTag;
            window.cwAddResourceLink = cwAddResourceLinkForCourse;
            window.cwToggleAssignment = cwToggleAssignment;
            window.cwDeleteAssignment = cwDeleteAssignment;
            window.cwOpenFile = openCourseFile;
            window.cwDownloadFile = downloadCourseFile;
            window.cwRenameFile = cwRenameFile;
            window.cwDeleteFile = cwDeleteFile;
            window.cwSetFileKind = cwSetFileKind;
            window.cwArchiveCourse = cwArchiveCourse;
            window.cwDeleteCourse = cwDeleteCourse;
            window.cwSaveCourseSettings = cwSaveCourseSettings;
            window.cwSaveCourseGrades = cwSaveCourseGrades;
            window.cwAddGradeCategory = cwAddGradeCategory;
            window.cwUnlinkNote = cwUnlinkNote;
            window.cwSetAllDueRange = cwSetAllDueRange;
            window.cwSetAllDueCourse = cwSetAllDueCourse;
            window.cwAllDueSearch = cwAllDueSearch;
            window.cwOpenDueItem = cwOpenDueItem;
            window.cwQuickAction = cwQuickAction;
            // Service surface for Sutra Assistant + external callers.
            window.courseHub = {
                getCourses, getCourseById, createCourse, updateCourse, archiveCourse, hardDeleteCourse,
                getAssignmentsForCourse, createAssignmentForCourse, getFilesForCourse, addCourseResourceLink,
                linkNoteToCourse, unlinkNoteFromCourse, getLinkedNotesForCourse, getReviewDecksForCourse,
                getCalendarEventsForCourse, getCourseWorkloadStats, calculateCourseStats,
                getAllDueItems, groupDueItemsByRange, getUpcomingMajorDeadlines, getCourseColor, getCourseDisplayName
            };
        }

        // Keep Course Hub / All Due in sync when Homework changes elsewhere.
        if (typeof window !== 'undefined' && !window.__cwHomeworkSyncBound) {
            window.__cwHomeworkSyncBound = true;
            window.addEventListener('homework:updated', () => {
                try {
                    const v = document.body && document.body.dataset ? document.body.dataset.view : '';
                    if (v === 'courses') renderCourseHubView();
                    else if (v === 'alldue') renderAllDueView();
                } catch (e) { /* non-critical */ }
            });
        }

        function setActiveView(view) {
            const requestedView = typeof view === 'string' && view ? view : 'today';

            // Backward-compat: Review and Cram Hub are no longer top-level views.
            // Redirect any caller (command palette, Today buttons, search, old
            // saved active-page state, imported workspaces) into Testing Hub's
            // matching internal section. Data and routes stay intact.
            if (requestedView === 'review' || requestedView === 'cramhub') {
                const section = requestedView === 'review' ? 'review' : 'cram';
                // Defer the section switch until after Testing Hub mounts so its
                // DOM is in the active state.
                setActiveView('apstudy');
                try {
                    if (typeof switchTestingHubSection === 'function') {
                        switchTestingHubSection(section);
                    }
                } catch (e) { console.warn('Testing Hub redirect failed', e); }
                return;
            }

            const resolvedView = isViewEnabled(requestedView)
                ? requestedView
                : getFallbackView('notes');
            if (activeView === 'notes' && resolvedView !== 'notes') {
                syncCurrentPrimaryScrollState({ persist: true });
            }
            activeView = resolvedView;
            // The AP Study / Testing Hub modal lives on document.body (position:fixed).
            // If it is left open when the user navigates elsewhere it would overlay and
            // block unrelated pages, so always dismiss it when leaving that view.
            if (resolvedView !== 'apstudy' && typeof window.closeApStudyModal === 'function') {
                try { window.closeApStudyModal(); } catch (e) { /* non-critical */ }
            }
            // The Theme Panel is a position:fixed floating overlay. If left open it
            // would hover over the destination view (notably the Settings preview
            // rail, producing the "ghost panel" overlap), so dismiss it on every
            // navigation. (Section 8 ghost-panel root cause: no view-switch cleanup.)
            try {
                const themePanelEl = document.getElementById('themePanel');
                if (themePanelEl) themePanelEl.classList.remove('active');
            } catch (e) { /* non-critical */ }
            if (appData) {
                if (!appData.ui) appData.ui = { ...getDefaultUiState() };
                appData.ui.lastActiveView = resolvedView;
                persistAppData();
            }
            document.querySelectorAll('.view').forEach(section => {
                const sectionView = section.id && section.id.startsWith('view-')
                    ? section.id.slice(5)
                    : '';
                const isActive = section.id === `view-${resolvedView}` && isViewEnabled(sectionView);
                section.classList.toggle('active', isActive);
                // Keep inline display in sync with active state.
                // Some auxiliary scripts set inline display styles, which can otherwise
                // leave the selected view hidden even when it has the active class.
                section.style.display = isActive ? '' : 'none';
            });
            document.querySelectorAll('.view-tab').forEach(tab => {
                const tabView = tab.dataset.view;
                const isActive = tabView === resolvedView && isViewEnabled(tabView);
                tab.classList.toggle('active', isActive);
            });
            syncTopNavTabOverflow();
            closeMoreViewsMenu();
            // Sutra Assistant: refresh context chip + adaptive quick actions for the new view.
            try { if (window.flowAssistant && typeof window.flowAssistant.refresh === 'function') window.flowAssistant.refresh(); } catch (e) { /* non-critical */ }
            document.body.dataset.view = resolvedView;
            document.body.classList.toggle('settings-anchored-mode', resolvedView === 'settings');
            try {
                window.dispatchEvent(new CustomEvent('noteflow:view-changed', { detail: { view: resolvedView } }));
            } catch (e) { /* non-critical */ }
            // Update mobile tab toggle label and collapse the expanded list for a cleaner UX
            try {
                const toggle = document.querySelector('.view-tabs-toggle');
                if (toggle) {
                    const active = document.querySelector('.view-tab.active:not([hidden])')
                        || document.querySelector('.view-tab:not([hidden])');
                    if (active) toggle.querySelector('.view-tabs-current').textContent = active.textContent.trim();
                }
                closeMobileViewTabsMenu();
            } catch (e) { /* non-critical */ }
            if (isCompactViewport()) {
                closeCompactSidebarDrawer();
            }
            syncResponsiveViewport(false);
            // Refresh dashboard when user opens Progress view
            if (resolvedView === 'progress') {
                try { populateProgressDashboard(); } catch (e) { console.warn('populateProgressDashboard failed on view change', e); }
            }
            // Render timeline when switching to Timeline view
            if (resolvedView === 'timeline') {
                try { renderTimeline(); applyTimeMode(); } catch (e) { console.warn('renderTimeline failed on view change', e); }
            }
            if (resolvedView === 'college') {
                try { renderCollegeTracker(); } catch (e) { console.warn('renderCollegeTracker failed on view change', e); }
            }
            if (resolvedView === 'today') {
                try { renderAcademicWorkspace(); } catch (e) { console.warn('renderAcademicWorkspace failed on Today view change', e); }
                try { renderTaskViews(); } catch (e) { console.warn('renderTaskViews failed on Today view change', e); }
            }
            if (resolvedView === 'apstudy') {
                try { if (typeof renderApBattlePlan === 'function') renderApBattlePlan(); } catch (e) { /* non-critical */ }
                try {
                    if (typeof window.renderApStudyWorkspace === 'function') window.renderApStudyWorkspace();
                } catch (e) {
                    console.warn('renderApStudyWorkspace failed on view change', e);
                }
            }
            if (resolvedView === 'collegeapp') {
                try { renderCollegeAppWorkspace(); } catch (e) { console.warn('renderCollegeAppWorkspace failed on view change', e); }
            }
            if (resolvedView === 'life') {
                try { renderLifeWorkspace(); } catch (e) { console.warn('renderLifeWorkspace failed on view change', e); }
            }
            if (resolvedView === 'business') {
                try { renderBusinessWorkspace(); } catch (e) { console.warn('renderBusinessWorkspace failed on view change', e); }
            }
            if (resolvedView === 'courses') {
                try { renderCourseHubView(); } catch (e) { console.warn('renderCourseHubView failed on view change', e); }
            }
            if (resolvedView === 'alldue') {
                try { renderAllDueView(); } catch (e) { console.warn('renderAllDueView failed on view change', e); }
            }
            if (resolvedView === 'review') {
                try {
                    if (typeof window.renderReviewWorkspace === 'function') window.renderReviewWorkspace();
                } catch (e) { console.warn('renderReviewWorkspace failed on view change', e); }
                try { setSplitViewSelection(undefined, 'review'); } catch (err) { /* non-critical */ }
            }
            if (resolvedView === 'notes') {
                try { setSplitViewSelection('notes', undefined); } catch (err) { /* non-critical */ }
            }
            if (resolvedView === 'settings') {
                try { syncSettingsControls(); } catch (e) { console.warn('syncSettingsControls failed on Settings view change', e); }
            }
            if (resolvedView === 'cramhub') {
                try { if (typeof initCramHubView === 'function') initCramHubView(); } catch (e) { console.warn('initCramHubView failed', e); }
            }
            if (resolvedView === 'apstudy') {
                try { if (typeof initTestingHubView === 'function') initTestingHubView(); } catch (e) { console.warn('initTestingHubView failed', e); }
            }
            try { renderAssistantQuickSuggestions(); } catch (e) { /* non-critical */ }

            // View switches can change nav geometry and sidebar state; resync toolbar placement after layout settles.
            const resyncToolbarLayout = () => {
                try {
                    if (typeof syncToolbarLayoutWithSidebar === 'function') syncToolbarLayoutWithSidebar();
                    if (typeof positionToolbarTimeControls === 'function') positionToolbarTimeControls();
                } catch (err) {
                    console.warn('toolbar layout resync failed on view change', err);
                }
            };
            requestAnimationFrame(resyncToolbarLayout);
            setTimeout(resyncToolbarLayout, 120);
        }

        function readPreferenceControlValue(control) {
            if (!control) return null;
            const type = String(control.type || '').toLowerCase();
            if (type === 'checkbox') return !!control.checked;
            if (type === 'number' || type === 'range') {
                const numeric = Number(control.value);
                return Number.isFinite(numeric) ? numeric : control.value;
            }
            return control.value;
        }

        function writePreferenceControlValue(control, value) {
            if (!control) return;
            const type = String(control.type || '').toLowerCase();
            if (type === 'checkbox') {
                control.checked = value === true;
                return;
            }
            control.value = value == null ? '' : String(value);
        }

        function getSettingsSectionCategoryFallback() {
            const firstSection = document.querySelector('#view-settings [data-settings-section]');
            return firstSection ? String(firstSection.getAttribute('data-settings-section') || 'appearance') : 'appearance';
        }

        function getWorkspacePreferenceFromSource(source, path, fallbackValue) {
            if (!source || typeof source !== 'object') return fallbackValue;
            const resolved = String(path || '')
                .split('.')
                .reduce((acc, key) => (acc && Object.prototype.hasOwnProperty.call(acc, key) ? acc[key] : undefined), source);
            return resolved === undefined ? fallbackValue : resolved;
        }

        function getEffectiveWorkspacePreference(path, fallbackValue) {
            if (settingsDraftValues.has(path)) return settingsDraftValues.get(path);
            return getWorkspacePreference(path, fallbackValue);
        }

        function areSettingValuesEqual(a, b) {
            if (typeof a === 'number' || typeof b === 'number') {
                return Number(a) === Number(b);
            }
            if (typeof a === 'boolean' || typeof b === 'boolean') {
                return !!a === !!b;
            }
            return String(a) === String(b);
        }

        function setDraftWorkspacePreference(path, value) {
            const current = getWorkspacePreference(path, null);
            if (areSettingValuesEqual(value, current)) {
                settingsDraftValues.delete(path);
            } else {
                settingsDraftValues.set(path, value);
            }
        }

        function getCurrentSettingsCategoryLabel() {
            const activeBtn = document.querySelector('#view-settings [data-settings-nav].active');
            if (!activeBtn) return 'Section';
            const title = activeBtn.querySelector('.atelier-settings-nav-btn-title');
            return String(title ? title.textContent : activeBtn.textContent || 'Section').trim();
        }

        function updateSettingsLastAppliedLabel() {
            const label = document.getElementById('settingsLastAppliedLabel');
            if (!label) return;
            if (!settingsLastAppliedAt) {
                label.textContent = 'in this session';
                return;
            }
            label.textContent = new Date(settingsLastAppliedAt).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
        }

        function updateSettingsDraftUi() {
            const settingsRoot = document.getElementById('view-settings');
            const hasUnsaved = settingsDraftValues.size > 0;
            if (settingsRoot) settingsRoot.classList.toggle('has-unsaved-settings', hasUnsaved);

            // The redesigned page wraps everything in `.cc-page` and toggles
            // a `data-pending` attribute used to show/hide the sticky action bar.
            const ccPage = settingsRoot ? settingsRoot.querySelector('.cc-page') : null;
            if (ccPage) ccPage.dataset.pending = hasUnsaved ? 'true' : 'false';

            const statusPill = document.getElementById('settingsStatusPill');
            if (statusPill) {
                // The pill is now a structured element with .cc-status-text inside.
                // Update the text node if present, otherwise fall back to textContent
                // for backwards compat with older markup.
                const statusText = statusPill.querySelector('.cc-status-text');
                const message = hasUnsaved
                    ? `${settingsDraftValues.size} unsaved ${settingsDraftValues.size === 1 ? 'change' : 'changes'}`
                    : 'Saved';
                if (statusText) statusText.textContent = message;
                else statusPill.textContent = message;
                statusPill.dataset.state = hasUnsaved ? 'dirty' : 'saved';
            }

            const unsavedText = document.getElementById('settingsUnsavedText');
            if (unsavedText) {
                unsavedText.textContent = hasUnsaved
                    ? `${settingsDraftValues.size} staged ${settingsDraftValues.size === 1 ? 'change' : 'changes'} ready to apply`
                    : 'No pending changes';
            }

            const actionBar = document.getElementById('settingsActionBar');
            if (actionBar) actionBar.dataset.pending = hasUnsaved ? 'true' : 'false';

            const applyBtn = document.getElementById('settingsApplyBtn');
            if (applyBtn) applyBtn.disabled = !hasUnsaved;
            const revertBtn = document.getElementById('settingsRevertBtn');
            if (revertBtn) revertBtn.disabled = !hasUnsaved;
            const applyBtnTop = document.getElementById('settingsApplyBtnTop');
            if (applyBtnTop) applyBtnTop.disabled = !hasUnsaved;
            const revertBtnTop = document.getElementById('settingsRevertBtnTop');
            if (revertBtnTop) revertBtnTop.disabled = !hasUnsaved;

            const resetSectionBtn = document.getElementById('settingsResetSectionBtn');
            if (resetSectionBtn) {
                resetSectionBtn.textContent = `Reset ${getCurrentSettingsCategoryLabel()}`;
            }
        }

        function updateSettingsPreviewCard() {
            const previewSurface = document.getElementById('settingsPreviewSurface');
            if (!previewSurface) return;

            const density = String(getEffectiveWorkspacePreference('appearance.density', 'comfortable') || 'comfortable');
            const contrast = String(getEffectiveWorkspacePreference('appearance.contrast', 'standard') || 'standard');
            const cardStyle = String(getEffectiveWorkspacePreference('appearance.cardStyle', 'glass') || 'glass');
            const cornerStyle = String(getEffectiveWorkspacePreference('appearance.cornerStyle', 'rounded') || 'rounded');
            const shadow = String(getEffectiveWorkspacePreference('appearance.shadowIntensity', 'medium') || 'medium');
            const blur = String(getEffectiveWorkspacePreference('appearance.blurIntensity', 'medium') || 'medium');
            const sidebarStyle = String(getEffectiveWorkspacePreference('appearance.sidebarStyle', 'glass') || 'glass');
            const iconSize = String(getEffectiveWorkspacePreference('appearance.iconSize', 'medium') || 'medium');
            const motion = String(getEffectiveWorkspacePreference('appearance.motionIntensity', 'full') || 'full');
            const defaultView = String(getEffectiveWorkspacePreference('layout.defaultStartView', 'today') || 'today');
            const timelineDensity = String(getEffectiveWorkspacePreference('calendar.timelineDensity', 'comfortable') || 'comfortable');
            const sortStrategy = String(getEffectiveWorkspacePreference('tasks.sortStrategy', 'urgent_first') || 'urgent_first');

            previewSurface.dataset.density = density;
            previewSurface.dataset.contrast = contrast;
            previewSurface.dataset.cardStyle = cardStyle;
            previewSurface.dataset.cornerStyle = cornerStyle;
            previewSurface.dataset.shadow = shadow;
            previewSurface.dataset.blur = blur;
            previewSurface.dataset.sidebarStyle = sidebarStyle;
            previewSurface.dataset.iconSize = iconSize;

            const categoryLabel = document.getElementById('settingsPreviewCategory');
            if (categoryLabel) categoryLabel.textContent = getCurrentSettingsCategoryLabel();

            const motionLabel = document.getElementById('settingsPreviewMotion');
            if (motionLabel) motionLabel.textContent = `Motion ${motion}`;

            const densityLabel = document.getElementById('settingsPreviewDensity');
            if (densityLabel) densityLabel.textContent = `${density.charAt(0).toUpperCase()}${density.slice(1)} density`;

            const contrastLabel = document.getElementById('settingsPreviewContrast');
            if (contrastLabel) contrastLabel.textContent = `${contrast.charAt(0).toUpperCase()}${contrast.slice(1)} contrast`;

            const cardLabel = document.getElementById('settingsPreviewCardStyle');
            if (cardLabel) cardLabel.textContent = `${cardStyle.charAt(0).toUpperCase()}${cardStyle.slice(1)} cards`;

            const cornerLabel = document.getElementById('settingsPreviewCorner');
            if (cornerLabel) cornerLabel.textContent = `${cornerStyle.charAt(0).toUpperCase()}${cornerStyle.slice(1)} corners`;

            const viewLabel = document.getElementById('settingsPreviewView');
            if (viewLabel) viewLabel.textContent = defaultView.replace('apstudy', 'AP Study').replace('collegeapp', 'College');

            const timelineLabel = document.getElementById('settingsPreviewTimeline');
            if (timelineLabel) timelineLabel.textContent = timelineDensity.charAt(0).toUpperCase() + timelineDensity.slice(1);

            const sortLabel = document.getElementById('settingsPreviewTaskSort');
            if (sortLabel) sortLabel.textContent = sortStrategy.replaceAll('_', ' ');
        }

        function syncAssistantChatMemorySettingsUi() {
            const mode = String(getEffectiveWorkspacePreference('assistant.chatMemoryMode', 'stateless') || 'stateless').trim().toLowerCase();
            const depthRow = document.getElementById('assistantChatMemoryDepthRow');
            const depthControl = document.querySelector('#view-settings [data-pref-path="assistant.chatMemoryDepth"]');
            if (depthRow) depthRow.hidden = mode !== 'stateful';
            if (depthControl) depthControl.disabled = mode !== 'stateful';
            try {
                if (window.flowAssistant && typeof window.flowAssistant.updateContextChip === 'function') {
                    window.flowAssistant.updateContextChip();
                }
            } catch (error) { /* non-critical */ }
        }

        function setActiveSettingsCategory(category, options = {}) {
            const requested = String(category || '').trim().toLowerCase();
            const sections = Array.from(document.querySelectorAll('#view-settings [data-settings-section]'));
            const available = new Set(sections.map(section => String(section.getAttribute('data-settings-section') || '').toLowerCase()).filter(Boolean));
            const fallback = getSettingsSectionCategoryFallback();
            const resolved = available.has(requested) ? requested : fallback;
            activeSettingsCategory = resolved;

            document.querySelectorAll('#view-settings [data-settings-nav]').forEach(button => {
                const buttonCategory = String(button.getAttribute('data-settings-nav') || '').toLowerCase();
                button.classList.toggle('active', buttonCategory === resolved);
            });
            sections.forEach(section => {
                const sectionCategory = String(section.getAttribute('data-settings-section') || '').toLowerCase();
                const isActive = sectionCategory === resolved;
                section.classList.toggle('active', isActive);
                section.style.display = isActive ? '' : 'none';
            });

            const mobileSelect = document.getElementById('settingsCategorySelect');
            if (mobileSelect && mobileSelect.value !== resolved) {
                mobileSelect.value = resolved;
            }

            if (options.skipSearch !== true) {
                filterSettingsControlsBySearch();
            }
            updateSettingsDraftUi();
            updateSettingsPreviewCard();
            // Lazily render the Mods & Customization panels when that category opens.
            if (resolved === 'mods' && typeof renderModsSettings === 'function') {
                try { renderModsSettings(); } catch (e) { /* non-critical */ }
            }
        }

        function filterSettingsControlsBySearch() {
            const searchInput = document.getElementById('settingsSearchInput');
            const query = String(searchInput && searchInput.value || '').trim().toLowerCase();
            const section = document.querySelector(`#view-settings [data-settings-section="${activeSettingsCategory}"]`);
            if (!section) return;
            const candidates = section.querySelectorAll('[data-setting-item], .atelier-setting-row, .settings-row, .settings-card');
            let visibleCount = 0;
            candidates.forEach(item => {
                const text = String(item.textContent || '').toLowerCase();
                const show = !query || text.includes(query);
                item.style.display = show ? '' : 'none';
                if (show) visibleCount += 1;
            });
            const searchHint = document.getElementById('settingsSearchHint');
            if (searchHint) {
                searchHint.textContent = query
                    ? `${visibleCount} match${visibleCount === 1 ? '' : 'es'} in ${getCurrentSettingsCategoryLabel()}.`
                    : 'Search filters only the active category.';
            }
        }

        function syncWorkspacePreferenceControls() {
            document.querySelectorAll('#view-settings [data-pref-path]').forEach(control => {
                const path = String(control.getAttribute('data-pref-path') || '').trim();
                if (!path) return;
                const effectiveValue = getEffectiveWorkspacePreference(path, null);
                writePreferenceControlValue(control, effectiveValue);
                const isDirty = settingsDraftValues.has(path);
                control.classList.toggle('is-dirty', isDirty);
                const settingItem = control.closest('[data-setting-item], .atelier-setting-row');
                if (settingItem) settingItem.classList.toggle('is-dirty', isDirty);
            });
            const settingsRoot = document.getElementById('view-settings');
            if (settingsRoot && typeof window.refreshCustomSelects === 'function') {
                window.refreshCustomSelects(settingsRoot);
            }
            syncAssistantChatMemorySettingsUi();
            updateSettingsDraftUi();
            updateSettingsPreviewCard();
        }

        function stageSettingsSectionReset(sectionName) {
            const target = String(sectionName || '').trim().toLowerCase();
            const defaults = getDefaultWorkspacePreferences();
            const scope = target === 'all'
                ? document.querySelectorAll('#view-settings [data-pref-path]')
                : document.querySelectorAll(`#view-settings [data-settings-section="${target}"] [data-pref-path]`);
            scope.forEach(control => {
                const path = String(control.getAttribute('data-pref-path') || '').trim();
                if (!path) return;
                const defaultValue = getWorkspacePreferenceFromSource(defaults, path, null);
                if (defaultValue !== null && defaultValue !== undefined) {
                    setDraftWorkspacePreference(path, defaultValue);
                }
            });
            syncWorkspacePreferenceControls();
            filterSettingsControlsBySearch();
        }

        function revertSettingsDraftChanges() {
            if (!settingsDraftValues.size) return;
            settingsDraftValues.clear();
            syncWorkspacePreferenceControls();
            filterSettingsControlsBySearch();
            showToast('Pending changes reverted');
        }

        function applySettingsDraftChanges() {
            if (!settingsDraftValues.size) return;
            const entries = Array.from(settingsDraftValues.entries());
            let applySidebarDefault = false;
            let applyAssistantPanelDefault = false;

            entries.forEach(([path, value]) => {
                const shouldApplySidebarDefault = path === 'layout.sidebarDefault';
                const shouldApplyAssistantPanelDefault = path === 'assistant.panelDefault';
                if (shouldApplySidebarDefault) applySidebarDefault = true;
                if (shouldApplyAssistantPanelDefault) applyAssistantPanelDefault = true;
                setWorkspacePreference(path, value, {
                    refresh: false,
                    persist: false,
                    applySidebarDefault: shouldApplySidebarDefault,
                    applyAssistantPanelDefault: shouldApplyAssistantPanelDefault
                });
            });

            applyWorkspacePreferences({
                refresh: true,
                applySidebarDefault,
                applyAssistantPanelDefault
            });

            settingsDraftValues.clear();
            settingsLastAppliedAt = Date.now();
            updateSettingsLastAppliedLabel();
            persistAppData();
            syncWorkspacePreferenceControls();
            filterSettingsControlsBySearch();
            showToast(`Applied ${entries.length} ${entries.length === 1 ? 'change' : 'changes'}`);

            // Brief visual confirmation on the redesigned status pill.
            try {
                const ccPage = document.querySelector('#view-settings .cc-page');
                if (ccPage && !ccPage.classList.contains('is-saved-flash')) {
                    ccPage.classList.add('is-saved-flash');
                    setTimeout(() => ccPage.classList.remove('is-saved-flash'), 1400);
                }
            } catch (e) { /* non-critical */ }
        }

        function bindWorkspacePreferenceControls() {
            if (settingsControlCenterBound) return;
            settingsControlCenterBound = true;

            document.querySelectorAll('#view-settings [data-pref-path]').forEach(control => {
                const path = String(control.getAttribute('data-pref-path') || '').trim();
                if (!path || control.dataset.bound === 'true') return;
                control.dataset.bound = 'true';
                const listener = () => {
                    setDraftWorkspacePreference(path, readPreferenceControlValue(control));
                    syncWorkspacePreferenceControls();
                    filterSettingsControlsBySearch();
                };
                const type = String(control.type || '').toLowerCase();
                control.addEventListener(type === 'range' ? 'input' : 'change', listener);
                if (type === 'range') {
                    control.addEventListener('change', listener);
                }
            });

            document.querySelectorAll('#view-settings [data-settings-nav]').forEach(button => {
                if (button.dataset.bound === 'true') return;
                button.dataset.bound = 'true';
                button.addEventListener('click', () => {
                    setActiveSettingsCategory(button.getAttribute('data-settings-nav') || 'appearance');
                });
            });

            const mobileSelect = document.getElementById('settingsCategorySelect');
            if (mobileSelect && mobileSelect.dataset.bound !== 'true') {
                mobileSelect.dataset.bound = 'true';
                mobileSelect.addEventListener('change', () => {
                    setActiveSettingsCategory(mobileSelect.value || 'appearance');
                });
            }

            const searchInput = document.getElementById('settingsSearchInput');
            if (searchInput && searchInput.dataset.bound !== 'true') {
                searchInput.dataset.bound = 'true';
                searchInput.addEventListener('input', filterSettingsControlsBySearch);
            }

            document.querySelectorAll('#view-settings [data-settings-reset-section]').forEach(button => {
                if (button.dataset.bound === 'true') return;
                button.dataset.bound = 'true';
                button.addEventListener('click', () => {
                    const section = String(button.getAttribute('data-settings-reset-section') || '').trim().toLowerCase();
                    if (!section) return;
                    stageSettingsSectionReset(section);
                    if (section !== 'all') {
                        setActiveSettingsCategory(section, { skipSearch: false });
                    }
                    showToast(section === 'all' ? 'Reset all categories (staged)' : `Reset ${section} settings (staged)`);
                });
            });

            const resetAllBtn = document.getElementById('settingsResetAllBtn');
            if (resetAllBtn && resetAllBtn.dataset.bound !== 'true') {
                resetAllBtn.dataset.bound = 'true';
                resetAllBtn.addEventListener('click', () => {
                    stageSettingsSectionReset('all');
                    showToast('Reset all categories (staged)');
                });
            }

            const resetSectionBtn = document.getElementById('settingsResetSectionBtn');
            if (resetSectionBtn && resetSectionBtn.dataset.bound !== 'true') {
                resetSectionBtn.dataset.bound = 'true';
                resetSectionBtn.addEventListener('click', () => {
                    stageSettingsSectionReset(activeSettingsCategory || 'appearance');
                    showToast(`Reset ${getCurrentSettingsCategoryLabel()} settings (staged)`);
                });
            }

            const applyBtn = document.getElementById('settingsApplyBtn');
            if (applyBtn && applyBtn.dataset.bound !== 'true') {
                applyBtn.dataset.bound = 'true';
                applyBtn.addEventListener('click', applySettingsDraftChanges);
            }

            const revertBtn = document.getElementById('settingsRevertBtn');
            if (revertBtn && revertBtn.dataset.bound !== 'true') {
                revertBtn.dataset.bound = 'true';
                revertBtn.addEventListener('click', revertSettingsDraftChanges);
            }

            const applyBtnTop = document.getElementById('settingsApplyBtnTop');
            if (applyBtnTop && applyBtnTop.dataset.bound !== 'true') {
                applyBtnTop.dataset.bound = 'true';
                applyBtnTop.addEventListener('click', applySettingsDraftChanges);
            }

            const revertBtnTop = document.getElementById('settingsRevertBtnTop');
            if (revertBtnTop && revertBtnTop.dataset.bound !== 'true') {
                revertBtnTop.dataset.bound = 'true';
                revertBtnTop.addEventListener('click', revertSettingsDraftChanges);
            }

            const atelierDataHealthExportBtn = document.getElementById('atelierDataHealthExportBtn');
            if (atelierDataHealthExportBtn && atelierDataHealthExportBtn.dataset.bound !== 'true') {
                atelierDataHealthExportBtn.dataset.bound = 'true';
                atelierDataHealthExportBtn.addEventListener('click', () => { exportWorkspaceAsAtelierPackage(); });
            }

            const atelierDataHealthSnapshotBtn = document.getElementById('atelierDataHealthSnapshotBtn');
            if (atelierDataHealthSnapshotBtn && atelierDataHealthSnapshotBtn.dataset.bound !== 'true') {
                atelierDataHealthSnapshotBtn.dataset.bound = 'true';
                atelierDataHealthSnapshotBtn.addEventListener('click', async () => {
                    const ok = await createPreImportSafetySnapshot();
                    showToast(ok ? 'Local safety snapshot downloaded.' : 'Could not create safety snapshot.');
                });
            }

            syncWorkspacePreferenceControls();
            updateSettingsLastAppliedLabel();
            bindSutraPersistenceHealthUi();
            try { bindSutraBackupFolderUi(); updateSutraFolderUi(); } catch (e) { /* non-critical */ }
            try { bindSutraDriveSyncUi(); updateSutraDriveSyncUi(); } catch (e) { /* non-critical */ }
            updateAtelierDataHealthUi();
            setActiveSettingsCategory(activeSettingsCategory, { skipSearch: false });
        }

        function syncSettingsControls() {
            const themeButtons = document.querySelectorAll('#view-settings .cc-segment[data-theme]');
            const currentTheme = getCurrentPageThemeKey();
            const currentAtelierTheme = normalizeAtelierThemeName(appSettings && appSettings.atelierTheme);
            themeButtons.forEach(btn => {
                const active = String(btn.dataset.theme || '').trim().toLowerCase() === currentAtelierTheme;
                btn.classList.toggle('active', active);
            });
            syncPresetCardsWithTheme(currentTheme);

            const motionToggle = document.getElementById('motionToggle');
            if (motionToggle) {
                motionToggle.checked = appSettings ? appSettings.motionEnabled === false : false;
            }
            const quickAppsToggle = document.getElementById('quickAppsToggle');
            if (quickAppsToggle) {
                quickAppsToggle.checked = !!(appSettings && appSettings.quickAppLaunchersEnabled);
            }
            const focusModeToggle = document.getElementById('focusModeToggle');
            if (focusModeToggle) {
                focusModeToggle.checked = !!(appSettings && appSettings.focusModeEnabled);
            }
            applyQuickAppLaunchersVisibility();
            renderShortcutLaunchers();
            applyFocusModeState();
            applySplitViewState();
            renderShortcutSettingsList();
            const taskOrderStrategySelect = document.getElementById('taskOrderStrategySelect');
            if (taskOrderStrategySelect) {
                taskOrderStrategySelect.value = getTaskOrderStrategy();
            }
            const autoEventBlocksToggle = document.getElementById('autoEventBlocksToggle');
            if (autoEventBlocksToggle) {
                autoEventBlocksToggle.checked = !(appSettings && appSettings.autoEventBlocksEnabled === false);
            }
            syncFeatureSelectionControls();
            updateTemporaryPageSettingsUi();
            syncTutorialSettingsControls();
            bindWorkspacePreferenceControls();
            syncWorkspacePreferenceControls();
            loadFontSettingsIntoSettings();
            updateSettingsLastAppliedLabel();
            setActiveSettingsCategory(activeSettingsCategory, { skipSearch: false });
        }

        function getTemporaryPageSettings() {
            if (!appSettings) appSettings = getDefaultAppData().settings;
            appSettings.temporaryPages = normalizeTemporaryPageSettings(appSettings.temporaryPages);
            return appSettings.temporaryPages;
        }

        function getTemporaryPageDurationMs(settings = getTemporaryPageSettings()) {
            const safeSettings = normalizeTemporaryPageSettings(settings);
            const multiplier = safeSettings.durationUnit === 'days'
                ? 24 * 60 * 60 * 1000
                : safeSettings.durationUnit === 'minutes'
                    ? 60 * 1000
                    : 60 * 60 * 1000;
            return safeSettings.durationValue * multiplier;
        }

        function formatTemporaryPageLifetime(settings = getTemporaryPageSettings()) {
            const safeSettings = normalizeTemporaryPageSettings(settings);
            const label = safeSettings.durationUnit.slice(0, -1);
            return `${safeSettings.durationValue} ${label}${safeSettings.durationValue === 1 ? '' : 's'}`;
        }

        function formatTemporaryPageExpiry(isoValue) {
            const parsed = normalizeOptionalIsoTimestamp(isoValue);
            if (!parsed) return 'soon';
            return new Date(parsed).toLocaleString([], {
                month: 'short',
                day: 'numeric',
                hour: 'numeric',
                minute: '2-digit'
            });
        }

        function applyTemporaryLifetimeToPage(page, baseIso = new Date().toISOString()) {
            if (!page) return page;
            const startedAt = normalizeOptionalIsoTimestamp(baseIso) || new Date().toISOString();
            const expiresAt = new Date(new Date(startedAt).getTime() + getTemporaryPageDurationMs()).toISOString();
            page.isTemporary = true;
            page.temporaryCreatedAt = startedAt;
            page.temporaryExpiresAt = expiresAt;
            return page;
        }

        function clearTemporaryLifetimeFromPage(page) {
            if (!page) return page;
            page.isTemporary = false;
            page.temporaryCreatedAt = null;
            page.temporaryExpiresAt = null;
            return page;
        }

        function updateNewPageTemporaryPreview() {
            const toggle = document.getElementById('newPageTemporaryToggle');
            const warning = document.getElementById('newPageTemporaryWarning');
            const preview = document.getElementById('newPageTemporaryDurationPreview');
            const durationLabel = formatTemporaryPageLifetime();
            if (preview) preview.textContent = durationLabel;
            if (warning) warning.hidden = !(toggle && toggle.checked);
        }

        function updateTemporaryPageSettingsUi() {
            const settings = getTemporaryPageSettings();
            const valueInput = document.getElementById('temporaryPageDurationValue');
            const unitSelect = document.getElementById('temporaryPageDurationUnit');
            const helpText = document.getElementById('temporaryPageDurationHelp');
            if (valueInput) valueInput.value = String(settings.durationValue);
            if (unitSelect) unitSelect.value = settings.durationUnit;
            if (helpText) helpText.textContent = `New temporary pages currently expire after ${formatTemporaryPageLifetime(settings)}.`;
            updateNewPageTemporaryPreview();
        }

        function updatePageTemporaryMeta(page) {
            const metaEl = document.getElementById('pageTemporaryMeta');
            if (!metaEl) return;
            if (!page || page.isTemporary !== true || !page.temporaryExpiresAt) {
                metaEl.hidden = true;
                metaEl.innerHTML = '';
                return;
            }
            metaEl.hidden = false;
            metaEl.innerHTML = `<strong>Temporary page.</strong> This note permanently deletes itself at ${escapeHtml(formatTemporaryPageExpiry(page.temporaryExpiresAt))}. No recovery is available after expiration.`;
        }

        function isTemporaryPageExpired(page, nowMs = Date.now()) {
            if (!page || page.isTemporary !== true) return false;
            const expiresAt = normalizeOptionalIsoTimestamp(page.temporaryExpiresAt);
            if (!expiresAt) return false;
            return new Date(expiresAt).getTime() <= nowMs;
        }

        function purgeExpiredTemporaryPages(options = {}) {
            const silent = options.silent === true;
            const nowMs = Date.now();
            const expiredPages = (Array.isArray(pages) ? pages : []).filter(page => isTemporaryPageExpired(page, nowMs) && page.id !== 'help_page');
            if (!expiredPages.length) return 0;

            const expiredIds = new Set(expiredPages.map(page => String(page.id || '')));
            const currentWasRemoved = currentPageId && expiredIds.has(String(currentPageId));
            const secondaryWasRemoved = secondaryPageId && expiredIds.has(String(secondaryPageId));

            pages = (Array.isArray(pages) ? pages : []).filter(page => !expiredIds.has(String(page && page.id || '')));
            tasks = (Array.isArray(tasks) ? tasks : []).map(task => {
                if (!task || !expiredIds.has(String(task.noteId || ''))) return task;
                return { ...task, noteId: null };
            });

            if (appSettings) {
                if (expiredIds.has(String(appSettings.notesSplitSecondaryPageId || ''))) {
                    appSettings.notesSplitSecondaryPageId = null;
                }
                if (Array.isArray(appSettings.selectedPagesForTheme)) {
                    appSettings.selectedPagesForTheme = appSettings.selectedPagesForTheme.filter(id => !expiredIds.has(String(id || '')));
                }
            }
            if (appData && appData.ui) {
                if (expiredIds.has(String(appData.ui.defaultPageId || ''))) appData.ui.defaultPageId = null;
            }
            clearStoredPageUiState(Array.from(expiredIds));

            if (currentWasRemoved) currentPageId = null;
            if (secondaryWasRemoved) secondaryPageId = null;

            savePagesToLocal();

            if (pages.length === 0) {
                createDefaultPage();
            }

            renderPagesList();
            renderSidebarTags();
            renderTaskViews();

            const fallbackPage = pages.find(page => page.id !== 'help_page') || pages[0] || null;
            if (!currentPageId || !pages.find(page => page.id === currentPageId)) {
                if (fallbackPage) {
                    loadPage(fallbackPage.id);
                } else {
                    updatePageTemporaryMeta(null);
                }
            } else {
                updatePageTemporaryMeta(pages.find(page => page.id === currentPageId) || null);
            }

            if (!silent) {
                const count = expiredPages.length;
                showToast(`Removed ${count} expired temporary page${count === 1 ? '' : 's'}`);
            }
            return expiredPages.length;
        }

        async function togglePageTemporaryMode(pageId) {
            const page = pages.find(item => item && item.id === pageId);
            if (!page || page.id === 'help_page') return;

            if (page.isTemporary) {
                const shouldKeep = await showCustomConfirmDialog({
                    title: 'Keep This Page Permanently?',
                    message: `Convert "${page.title}" into a regular page and stop auto-deletion?`,
                    confirmText: 'Keep Page',
                    cancelText: 'Cancel',
                    confirmVariant: 'danger'
                });
                if (!shouldKeep) return;
                clearTemporaryLifetimeFromPage(page);
                page.updatedAt = new Date().toISOString();
                savePagesToLocal();
                renderPagesList();
                if (currentPageId === pageId) updatePageTemporaryMeta(page);
                showToast('Temporary mode removed');
                return;
            }

            const lifetime = formatTemporaryPageLifetime();
            const shouldEnable = await showCustomConfirmDialog({
                title: 'Make Page Temporary',
                message: `"${page.title}" will be permanently deleted after ${lifetime}. This action cannot be reversed after it expires.`,
                confirmText: 'Make Temporary',
                cancelText: 'Cancel',
                confirmVariant: 'danger'
            });
            if (!shouldEnable) return;

            applyTemporaryLifetimeToPage(page);
            page.updatedAt = new Date().toISOString();
            savePagesToLocal();
            renderPagesList();
            if (currentPageId === pageId) updatePageTemporaryMeta(page);
            showToast(`Temporary page enabled for ${lifetime}`);
        }

        function applyQuickAppLaunchersVisibility() {
            const launchers = document.getElementById('quickAppLaunchers');
            const integrationsDock = document.getElementById('integrationsDock');
            const addShortcutBtn = document.getElementById('addShortcutFromTabsBtn');
            if (!launchers) return;
            const enabled = !!(appSettings && appSettings.quickAppLaunchersEnabled);
            const spotifyEnabled = getWorkspacePreference('integrations.spotifyEnabled', true) !== false;
            const chatgptEnabled = getWorkspacePreference('integrations.chatgptEnabled', true) !== false;
            const spotifyBtn = launchers.querySelector('.quick-app-btn.spotify');
            const chatgptBtn = launchers.querySelector('.quick-app-btn.chatgpt');
            if (spotifyBtn) spotifyBtn.style.display = spotifyEnabled ? '' : 'none';
            if (chatgptBtn) chatgptBtn.style.display = chatgptEnabled ? '' : 'none';
            const hasVisibleQuickApp = !!(
                (spotifyBtn && spotifyBtn.style.display !== 'none')
                || (chatgptBtn && chatgptBtn.style.display !== 'none')
            );
            const tabShortcutCount = getCustomShortcuts().filter(item => normalizeShortcutPlacement(item.placement) === 'tabs').length;
            launchers.style.display = enabled && hasVisibleQuickApp ? 'inline-flex' : 'none';
            if (addShortcutBtn) {
                addShortcutBtn.style.display = 'inline-flex';
            }
            if (integrationsDock) {
                const showDock = hasVisibleQuickApp || tabShortcutCount > 0;
                integrationsDock.style.display = showDock ? 'inline-flex' : 'none';
            }
            syncTopNavTabOverflow();
        }

        function isDocumentInFullscreen() {
            return !!(
                document.fullscreenElement
                || document.webkitFullscreenElement
                || document.msFullscreenElement
            );
        }

        function requestAppFullscreen() {
            try {
                if (isDocumentInFullscreen()) return;
                const root = document.documentElement;
                if (!root) return;
                const requestFn = root.requestFullscreen || root.webkitRequestFullscreen || root.msRequestFullscreen;
                if (typeof requestFn === 'function') {
                    const promise = requestFn.call(root);
                    if (promise && typeof promise.catch === 'function') {
                        promise.catch(() => {
                            // Fullscreen can be blocked; focus mode still applies.
                        });
                    }
                }
            } catch (e) {
                // Ignore fullscreen errors.
            }
        }

        function exitAppFullscreen() {
            try {
                if (!isDocumentInFullscreen()) return;
                const exitFn = document.exitFullscreen || document.webkitExitFullscreen || document.msExitFullscreen;
                if (typeof exitFn === 'function') {
                    const promise = exitFn.call(document);
                    if (promise && typeof promise.then === 'function') {
                        // After the browser has actually shrunk the viewport back from
                        // fullscreen size, re-sync the toolbar layout. Without this, the
                        // earlier rAF/timeout-based syncs measure top-nav while still in
                        // the screen-sized fullscreen viewport, leaving the toolbar at
                        // top: 12 (focus position) when the viewport returns to normal.
                        promise.then(() => {
                            try {
                                if (typeof window !== 'undefined' && typeof window.__updateTopNavHeight === 'function') {
                                    window.__updateTopNavHeight();
                                }
                                const tw = document.querySelector('.toolbar-wrapper');
                                if (tw && !document.body.classList.contains('focus-mode')) {
                                    // Only clear `top`; sync below will reset horizontal layout.
                                    tw.style.removeProperty('top');
                                }
                                if (typeof syncToolbarLayoutWithSidebar === 'function') {
                                    syncToolbarLayoutWithSidebar();
                                }
                            } catch (_) {}
                        }).catch(() => {
                            // Ignore fullscreen exit failures.
                        });
                    }
                }
            } catch (e) {
                // Ignore fullscreen errors.
            }
        }

        function applyFocusModeState() {
            const enabled = !!(appSettings && appSettings.focusModeEnabled);
            const wasFocusModeActive = document.body.classList.contains('focus-mode');
            document.body.classList.toggle('focus-mode', enabled);
            // When focus mode is being disabled, syncToolbarLayoutWithSidebar may have left
            // inline `top: 12px` (focus position) on the toolbar with !important. Exiting
            // fullscreen is async and the deferred rAF that re-syncs the layout can race.
            // Clear the inline overrides immediately so the CSS default
            // (top: calc(var(--top-nav-height) + 20px)) takes over and the toolbar lands
            // below the now-visible top nav, even before the rAF fires.
            if (!enabled && wasFocusModeActive) {
                const toolbarWrapper = document.querySelector('.toolbar-wrapper');
                if (toolbarWrapper) {
                    // Only clear vertical position; the upcoming syncToolbarLayoutWithSidebar
                    // call will reset left/right based on the current sidebar state. Clearing
                    // horizontal styles here can leave the toolbar extended at full width
                    // for a frame, which the user notices as a "extends when it should be
                    // contracted" flash.
                    toolbarWrapper.style.removeProperty('top');
                }
            }
            // Also re-measure --top-nav-height: the .top-nav transitions display:none -> visible
            // and ResizeObserver doesn't always refire on that transition.
            if (!enabled && typeof window !== 'undefined' && typeof window.__updateTopNavHeight === 'function') {
                window.requestAnimationFrame(() => {
                    try { window.__updateTopNavHeight(); } catch (_) {}
                });
            }
            syncFullscreenClockPlacement();
            const quickToggle = document.getElementById('focusModeQuickToggle');
            if (quickToggle) {
                quickToggle.classList.toggle('is-active', enabled);
                quickToggle.setAttribute('aria-pressed', enabled ? 'true' : 'false');
                quickToggle.title = enabled ? 'Exit focus mode (fullscreen)' : 'Enter focus mode (fullscreen)';
                quickToggle.setAttribute('aria-label', enabled ? 'Exit focus mode and fullscreen' : 'Enter focus mode and fullscreen');
            }
            const icon = quickToggle ? quickToggle.querySelector('i') : null;
            if (icon) {
                icon.classList.remove('fa-expand', 'fa-compress');
                icon.classList.add(enabled ? 'fa-compress' : 'fa-expand');
            }
            if (enabled) closeMoreViewsMenu();
            if (enabled && activeView !== 'notes') {
                setActiveView(getFallbackView('notes'));
            }

            const splitToggleBtn = document.getElementById('splitNotesToggleBtn');
            if (splitToggleBtn) splitToggleBtn.style.display = enabled ? 'none' : '';
            const secondaryPane = document.getElementById('notesSecondaryPane');
            if (secondaryPane) secondaryPane.style.display = enabled ? 'none' : '';
            const mainContent = document.querySelector('.main-content');
            if (mainContent) {
                mainContent.style.removeProperty('margin-left');
                mainContent.style.removeProperty('width');
            }
            updateToolbarFocusTimerCountdown();
            if (typeof syncSidebarVisibilityState === 'function') {
                syncSidebarVisibilityState();
            }
        }

        function setFocusModeEnabled(enabled, shouldPersist = true, options = {}) {
            if (!appSettings) return;
            const nextEnabled = !!enabled;
            const includeFullscreen = options && options.includeFullscreen === true;
            if (nextEnabled) {
                splitViewEnabledBeforeFocusMode = !!appSettings.notesSplitViewEnabled;
                if (splitViewEnabledBeforeFocusMode) {
                    setSplitViewEnabled(false, { persist: false });
                }
                const sidebar = document.getElementById('sidebar');
                const sidebarOpen = !!(sidebar && !sidebar.classList.contains('collapsed'));
                sidebarWasOpenBeforeFocusMode = sidebarOpen;
                if (sidebarOpen) {
                    toggleSidebar();
                }
            } else if (splitViewEnabledBeforeFocusMode) {
                setSplitViewEnabled(true, { persist: false });
                splitViewEnabledBeforeFocusMode = false;
            }

            if (!nextEnabled) {
                focusModeFullscreenLinked = false;
                const sidebar = document.getElementById('sidebar');
                const sidebarCollapsed = !!(sidebar && sidebar.classList.contains('collapsed'));
                if (sidebarWasOpenBeforeFocusMode && sidebarCollapsed) {
                    toggleSidebar();
                }
                sidebarWasOpenBeforeFocusMode = false;
            }
            appSettings.focusModeEnabled = nextEnabled;
            applyFocusModeState();
            if (includeFullscreen) {
                if (nextEnabled) {
                    focusModeFullscreenLinked = true;
                    requestAppFullscreen();
                } else {
                    exitAppFullscreen();
                }
            }
            if (typeof syncResponsiveViewport === 'function') {
                syncResponsiveViewport(false);
            }
            if (typeof syncToolbarLayoutWithSidebar === 'function') {
                window.requestAnimationFrame(() => {
                    syncToolbarLayoutWithSidebar();
                });
                // Real fullscreen exit is async — exitFullscreen() returns a Promise that
                // resolves only after the viewport has actually shrunk back. The rAF above
                // can fire while the document is still in fullscreen, leaving the toolbar
                // measured against the wrong viewport. Re-sync at delays that cover the
                // exit window so the final layout is correct.
                if (!nextEnabled && includeFullscreen) {
                    setTimeout(() => { try { syncToolbarLayoutWithSidebar(); } catch (_) {} }, 50);
                    setTimeout(() => { try { syncToolbarLayoutWithSidebar(); } catch (_) {} }, 200);
                    setTimeout(() => { try { syncToolbarLayoutWithSidebar(); } catch (_) {} }, 500);
                }
                // Watchdog: after focus mode exits, if the toolbar still ends up at
                // viewport top (< 40 px from top, the focus-mode position is 12 px) even
                // though focus mode is off and the top-nav is visible, the inline styles
                // are stale from a race. Wipe them so CSS takes over, then re-sync.
                if (!nextEnabled) {
                    const watchdog = (delay) => setTimeout(() => {
                        try {
                            if (document.body.classList.contains('focus-mode')) return;
                            const tw = document.querySelector('.toolbar-wrapper');
                            const tn = document.querySelector('.top-nav');
                            if (!tw || !tn) return;
                            const twRect = tw.getBoundingClientRect();
                            const tnRect = tn.getBoundingClientRect();
                            const topNavVisible = tnRect.height > 0 && tnRect.bottom > 0;
                            const toolbarTooHigh = twRect.top < 40;
                            // Bad state: top-nav is visible but toolbar is overlapping above it.
                            if (topNavVisible && toolbarTooHigh && twRect.top < tnRect.bottom) {
                                // Bug confirmed: toolbar is overlapping top-nav at the very
                                // top of the viewport. Wipe ALL the inline focus-mode
                                // layout (which is what's stuck) and let the next sync
                                // recompute against the now-stable sidebar/top-nav state.
                                tw.style.removeProperty('top');
                                tw.style.removeProperty('left');
                                tw.style.removeProperty('right');
                                tw.style.removeProperty('max-width');
                                tw.style.removeProperty('width');
                                if (typeof window !== 'undefined' && typeof window.__updateTopNavHeight === 'function') {
                                    window.__updateTopNavHeight();
                                }
                                if (typeof syncToolbarLayoutWithSidebar === 'function') {
                                    syncToolbarLayoutWithSidebar();
                                }
                            }
                        } catch (_) {}
                    }, delay);
                    watchdog(750);
                    watchdog(1500);
                }
            }
            const focusModeToggle = document.getElementById('focusModeToggle');
            if (focusModeToggle) focusModeToggle.checked = nextEnabled;
            if (shouldPersist) persistAppData();
        }

        function toggleFocusMode() {
            setFocusModeEnabled(!(appSettings && appSettings.focusModeEnabled), true, { includeFullscreen: true });
        }

        function syncTutorialSettingsControls() {
            const statusEl = document.getElementById('tutorialStatusText');
            const buttonEl = document.getElementById('startTutorialBtn');
            if (!statusEl || !buttonEl || !appSettings) return;

            if (appSettings.tutorialCompleted) {
                const completedAt = appSettings.tutorialCompletedAt
                    ? new Date(appSettings.tutorialCompletedAt).toLocaleDateString()
                    : null;
                statusEl.textContent = completedAt
                    ? `Tutorial completed on ${completedAt}.`
                    : 'Tutorial completed.';
                buttonEl.textContent = 'Redo Tutorial';
            } else if (appSettings.tutorialSeen) {
                statusEl.textContent = 'Tutorial skipped — you can resume it any time.';
                buttonEl.textContent = 'Resume Tutorial';
            } else {
                statusEl.textContent = 'A guided First 10 Minutes In Sutra walkthrough: Daily Thread And Deadline Radar, Sutra Modes, Notes, Tasks, Calendar, Testing Hub, College / Life / Business, themes, and .sutra Backup And Restore.';
                buttonEl.textContent = 'Start Interactive Tutorial';
            }
        }

        function ensureSidebarExpandedForTutorial() {
            const sidebar = document.getElementById('sidebar');
            if (sidebar && sidebar.classList.contains('collapsed')) {
                toggleSidebar();
            }
        }

        function getTutorialPrimaryPage() {
            return pages.find(page => page.id !== 'help_page') || pages[0] || null;
        }

        function ensureTutorialPageLoaded() {
            const page = getTutorialPrimaryPage();
            if (!page) return null;
            if (currentPageId !== page.id) loadPage(page.id);
            return page;
        }

        function ensureTutorialNestedPageLoaded() {
            const nested = pages.find(page => page.title.includes('::'));
            if (nested) {
                if (currentPageId !== nested.id) loadPage(nested.id);
                return nested;
            }
            return ensureTutorialPageLoaded();
        }

        function setTutorialFieldValue(id, value, eventType = 'input') {
            const field = document.getElementById(id);
            if (!field) return;
            field.value = value;
            field.dispatchEvent(new Event(eventType, { bubbles: true }));
        }

        function focusEditorForTutorial() {
            const editor = document.getElementById('editor');
            if (!editor) return;
            editor.focus();
            const range = document.createRange();
            range.selectNodeContents(editor);
            range.collapse(false);
            const selection = window.getSelection();
            if (selection) {
                selection.removeAllRanges();
                selection.addRange(range);
            }
        }

        function openSlashMenuForTutorial(filterText = '') {
            focusEditorForTutorial();
            showSlashMenu();
            if (!filterText) return;
            slashFilterText = String(filterText).toLowerCase();
            slashMenuSelectedIndex = 0;
            renderSlashMenuItems(getFilteredCommands());
        }

        function closeModalIfOpen(modalId) {
            const modal = document.getElementById(modalId);
            if (modal && modal.classList.contains('active')) closeModal(modalId);
        }

        function resetTutorialTransientUi() {
            closeModalIfOpen('newPageModal');
            closeModalIfOpen('renamePageModal');

            if (typeof closeTaskModal === 'function') closeTaskModal();
            if (typeof closeBlockModal === 'function') closeBlockModal();

            const drawer = document.getElementById('allTasksDrawer');
            if (drawer) drawer.setAttribute('aria-hidden', 'true');

            const themePanel = document.getElementById('themePanel');
            if (themePanel && themePanel.classList.contains('active')) {
                themePanel.classList.remove('active');
            }
            tutorialState.openedThemePanel = false;

            const fontPanel = document.getElementById('fontSettingsPanel');
            if (fontPanel) fontPanel.style.display = 'none';

            const timerContainer = document.getElementById('focusTimer');
            if (timerContainer) timerContainer.classList.remove('expanded');

            const chatbotPanel = document.getElementById('chatbotPanel');
            if (chatbotPanel) {
                chatbotPanel.classList.remove('fullscreen');
                chatbotPanel.style.display = 'none';
                chatbotPanel.setAttribute('aria-hidden', 'true');
            }

            const chatbotInfo = document.getElementById('chatbotInfo');
            if (chatbotInfo) chatbotInfo.style.display = 'none';

            if (typeof hideToolbarTimeControls === 'function') hideToolbarTimeControls();
            if (typeof hideSlashMenu === 'function') hideSlashMenu();
            if (typeof hideEmojiPicker === 'function') hideEmojiPicker();
        }

        function closeTutorialThemePanelIfNeeded() {
            const panel = document.getElementById('themePanel');
            if (tutorialState.openedThemePanel && panel && panel.classList.contains('active')) {
                panel.classList.remove('active');
            }
            tutorialState.openedThemePanel = false;
        }

        function openThemePanelForTutorial() {
            const panel = document.getElementById('themePanel');
            if (panel && !panel.classList.contains('active')) {
                toggleThemePanel();
                tutorialState.openedThemePanel = true;
            }
        }

        function safeRunTutorial(fn) {
            if (typeof fn !== 'function') return;
            try { fn(); } catch (err) { /* swallow — never let one step break the tour */ }
        }

        function tutorialTargetExists(selectorInput) {
            if (!selectorInput) return true;
            const list = Array.isArray(selectorInput)
                ? selectorInput
                : String(selectorInput).split(',').map(s => s.trim()).filter(Boolean);
            return list.some(sel => {
                try { return !!document.querySelector(sel); }
                catch (e) { return false; }
            });
        }

        function gotoTutorialSettingsSection(section) {
            safeRunTutorial(() => setActiveView('settings'));
            if (typeof setActiveSettingsCategory === 'function') {
                safeRunTutorial(() => setActiveSettingsCategory(section));
            }
        }

        function gotoTutorialTestingHub(section) {
            safeRunTutorial(() => setActiveView('apstudy'));
            if (section && typeof switchTestingHubSection === 'function') {
                safeRunTutorial(() => switchTestingHubSection(section));
            }
        }

