        function renderIntegrationRegistry() {
            const host = document.getElementById('integrationRegistryHost');
            if (!host) return;
            const registry = getSutraIntegrationRegistry();
            host.innerHTML = registry.map(item => `
                <article class="integration-card" data-integration-id="${escapeHtml(item.id)}">
                    <div class="integration-card-head">
                        <div>
                            <div class="integration-card-title">${escapeHtml(item.name)}</div>
                            <div class="integration-card-meta">${escapeHtml(item.category)} · ${escapeHtml(item.permissions)}</div>
                        </div>
                        <span class="integration-card-status">${escapeHtml(item.status)}</span>
                    </div>
                    <div class="integration-card-copy">${escapeHtml(item.description)}</div>
                    <div class="integration-card-meta">${escapeHtml(item.privacy)}</div>
                    <div class="integration-card-actions">
                        ${item.action ? `<button type="button" class="cc-btn cc-btn-ghost cc-btn-small" data-integration-action="${escapeHtml(item.action)}">Open</button>` : '<button type="button" class="cc-btn cc-btn-ghost cc-btn-small" disabled>Unavailable</button>'}
                    </div>
                </article>`).join('');
            host.querySelectorAll('[data-integration-action]').forEach(btn => {
                btn.addEventListener('click', () => {
                    const action = btn.getAttribute('data-integration-action');
                    if (action === 'smart-import') openSmartImportWizard();
                    else if (action === 'file-import') importFromFile();
                    else if (action === 'ics') {
                        try { triggerCalendarIcsImport(); } catch (_) {}
                    } else if (action === 'drive') {
                        try { setActiveSettingsCategory('data'); document.getElementById('sutraDriveConnectBtn')?.focus(); } catch (_) {}
                    } else {
                        showToast('This integration is gated in this deployment.');
                    }
                });
            });
            try { window.SutraIntegrations = { registry: getSutraIntegrationRegistry, render: renderIntegrationRegistry }; } catch (_) {}
        }

        function normalizeSmartImportDate(raw) {
            const value = String(raw || '').trim();
            if (!value) return '';
            const iso = value.match(/\b(20\d{2})-(\d{2})-(\d{2})\b/);
            if (iso) return `${iso[1]}-${iso[2]}-${iso[3]}`;
            const slash = value.match(/\b(\d{1,2})\/(\d{1,2})\/(20\d{2})\b/);
            if (slash) return `${slash[3]}-${String(slash[1]).padStart(2, '0')}-${String(slash[2]).padStart(2, '0')}`;
            return '';
        }

        function getSmartImportDuplicateWarning(title) {
            const needle = String(title || '').trim().toLowerCase();
            if (!needle) return '';
            try {
                if ((Array.isArray(tasks) ? tasks : []).some(task => String(task.title || '').trim().toLowerCase() === needle)) return 'Possible duplicate task';
                const hwTasks = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]');
                if ((Array.isArray(hwTasks) ? hwTasks : []).some(task => String(task.title || task.text || '').trim().toLowerCase() === needle)) return 'Possible duplicate homework';
                if ((Array.isArray(timeBlocks) ? timeBlocks : []).some(block => String(block.title || block.name || '').trim().toLowerCase() === needle)) return 'Possible duplicate timeline item';
            } catch (_) {}
            return '';
        }

        function parseSmartImportText(text, sourceTitle = 'Pasted text') {
            const raw = String(text || '').slice(0, 80000);
            if (/(?:__proto__|constructor\s*:|prototype\s*:|<script|javascript:|onerror\s*=|onclick\s*=)/i.test(raw)) {
                return { proposals: [], rejected: [{ reason: 'Unsafe executable or prototype-pollution-shaped content was rejected.' }] };
            }
            const lines = raw.split(/\r?\n/).map(line => line.trim()).filter(Boolean).slice(0, 80);
            const proposals = [];
            lines.forEach((line, index) => {
                const lower = line.toLowerCase();
                const dueDate = normalizeSmartImportDate(line);
                let type = 'task';
                if (/\b(homework|assignment|problem set|worksheet|reading|lab)\b/.test(lower)) type = 'homework';
                else if (/\b(test|quiz|exam)\b/.test(lower)) type = lower.includes('quiz') ? 'quiz' : (lower.includes('test') ? 'test' : 'exam');
                else if (/\b(event|meeting|practice|appointment|deadline)\b/.test(lower) && dueDate) type = 'calendar event';
                else if (/^(class|course)\s*[:|-]/i.test(line)) type = 'class';
                else if (line.length > 160) type = 'note';
                const parts = line.split(/\s*\|\s*|\s+-\s+|\t/).filter(Boolean);
                const className = parts.length >= 3 ? parts[0].slice(0, 80) : '';
                const structuredDate = parts.map(normalizeSmartImportDate).find(Boolean);
                const dateValue = dueDate || structuredDate || '';
                const priorityValue = parts.find(part => /\b(high|urgent|medium|low)\b/i.test(part));
                const titleRaw = parts.length >= 3 ? parts[1] : (parts.length === 2 && normalizeSmartImportDate(parts[1]) ? parts[0] : line);
                const title = titleRaw
                    .replace(/\b(20\d{2}-\d{2}-\d{2}|\d{1,2}\/\d{1,2}\/20\d{2})\b/g, '')
                    .replace(/\b(high|urgent|medium|low)\b/gi, '')
                    .replace(/\s+/g, ' ')
                    .trim()
                    .slice(0, 160);
                if (!title) return;
                const warning = getSmartImportDuplicateWarning(title);
                proposals.push({
                    id: `smart_${index}_${atelierHash(line)}`,
                    type,
                    title,
                    confidence: dateValue || type === 'class' ? 'High confidence' : 'Needs review',
                    sourceSnippet: line.slice(0, 260),
                    sourceDocument: sourceTitle,
                    sourceLocation: `line ${index + 1}`,
                    proposedFields: { dueDate: dateValue, className, priority: /\b(urgent|high|important)\b/i.test(priorityValue || line) ? 'high' : 'medium' },
                    warnings: warning ? [warning] : []
                });
            });
            return { proposals, rejected: [] };
        }

        function applySmartImportProposal(proposal) {
            const type = String(proposal.type || '').toLowerCase();
            const title = String(proposal.title || '').trim().slice(0, 160);
            if (!title) throw new Error('Proposal title is required.');
            if (/(?:__proto__|constructor|prototype|<script|javascript:)/i.test(title)) throw new Error('Unsafe proposal rejected.');
            const now = new Date().toISOString();
            const fields = proposal.proposedFields || {};
            const applied = { type, id: '', title };
            if (['homework', 'test', 'quiz', 'exam'].includes(type)) {
                const courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]');
                const tasksList = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]');
                let course = (Array.isArray(courses) ? courses : []).find(c => String(c.name || '').toLowerCase() === String(fields.className || '').toLowerCase());
                if (!course) {
                    course = { id: `course_${generateId()}`, name: String(fields.className || 'Imported').slice(0, 80), color: '#5078f2', createdAt: now };
                    courses.push(course);
                }
                const item = {
                    id: `hw_${generateId()}`,
                    courseId: course.id,
                    title,
                    dueDate: normalizeSmartImportDate(fields.dueDate),
                    dueTime: fields.dueTime || '',
                    priority: fields.priority === 'high' ? 'high' : 'medium',
                    difficulty: 'medium',
                    notes: `Smart Import from ${proposal.sourceDocument || 'source'} (${proposal.sourceLocation || 'reviewed'}).`,
                    done: false,
                    createdAt: now
                };
                tasksList.push(item);
                localStorage.setItem('hwCourses:v2', JSON.stringify(courses));
                localStorage.setItem('hwTasks:v2', JSON.stringify(tasksList));
                try { window.dispatchEvent(new CustomEvent('homework:updated')); } catch (_) {}
                applied.id = item.id;
                return applied;
            }
            if (type === 'calendar event') {
                const block = {
                    id: `smart_block_${generateId()}`,
                    title,
                    name: title,
                    date: normalizeSmartImportDate(fields.dueDate) || dateKey(new Date()),
                    start: fields.start || '09:00',
                    end: fields.end || '10:00',
                    source: 'smart_import',
                    notes: proposal.sourceSnippet || ''
                };
                timeBlocks.push(block);
                if (typeof saveTimeBlocks === 'function') saveTimeBlocks();
                if (typeof renderTimeline === 'function') renderTimeline();
                applied.id = block.id;
                return applied;
            }
            if (type === 'class') {
                const courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]');
                const course = { id: `course_${generateId()}`, name: title.replace(/^class\s*[:|-]\s*/i, '').slice(0, 80), color: '#5078f2', createdAt: now };
                courses.push(course);
                localStorage.setItem('hwCourses:v2', JSON.stringify(courses));
                applied.id = course.id;
                return applied;
            }
            if (type === 'note') {
                const page = { id: generateId(), title: title.slice(0, 80), content: normalizeTextToHtml(proposal.sourceSnippet || title), blocks: [], icon: PAGE_ICONS.IMPORT, createdAt: now, updatedAt: now, theme: globalTheme };
                pages.push(page);
                savePagesToLocal();
                renderPagesList();
                applied.id = page.id;
                return applied;
            }
            const task = { id: generateId(), title, notes: `Smart Import from ${proposal.sourceDocument || 'source'} (${proposal.sourceLocation || 'reviewed'}).`, dueDate: normalizeSmartImportDate(fields.dueDate), priority: fields.priority === 'high' ? 'high' : 'medium', difficulty: 'medium', completed: false, isActive: true, scheduleType: 'once', createdAt: now };
            tasks.push(task);
            taskOrder.push(task.id);
            persistAppData();
            if (typeof renderTaskViews === 'function') renderTaskViews();
            applied.id = task.id;
            return applied;
        }

        let smartImportLastApplied = [];
        function undoSmartImportLastApplied() {
            if (!smartImportLastApplied.length) return;
            const ids = new Set(smartImportLastApplied.map(item => item.id));
            tasks = tasks.filter(task => !ids.has(task.id));
            taskOrder = taskOrder.filter(id => !ids.has(id));
            timeBlocks = timeBlocks.filter(block => !ids.has(block.id));
            pages = pages.filter(page => !ids.has(page.id));
            try {
                const hwTasks = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]').filter(item => !ids.has(item.id));
                const hwCourses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]').filter(item => !ids.has(item.id));
                localStorage.setItem('hwTasks:v2', JSON.stringify(hwTasks));
                localStorage.setItem('hwCourses:v2', JSON.stringify(hwCourses));
            } catch (_) {}
            smartImportLastApplied = [];
            persistAppData();
            savePagesToLocal();
            if (typeof saveTimeBlocks === 'function') saveTimeBlocks();
            if (typeof renderTaskViews === 'function') renderTaskViews();
            if (typeof renderTimeline === 'function') renderTimeline();
            renderPagesList();
            try { window.dispatchEvent(new CustomEvent('homework:updated')); } catch (_) {}
            showToast('Smart Import changes undone.');
        }

        function openSmartImportWizard(seedText = '') {
            const body = document.createElement('div');
            body.className = 'smart-import-layout';
            const provider = getCurrentChatProvider();
            const model = getActiveModelForProvider(provider) || getSelectedModelForProvider(provider) || 'not selected';
            body.innerHTML = `
                <p class="cc-foot-help">Choose a source, preview extracted text, review suggestions, then apply approved items only. Current mode: local rule parser; no outbound AI request is made.</p>
                <div class="smart-import-toolbar">
                    <input class="modal-input" id="smartImportFileInput" type="file" accept=".txt,.md,.markdown,.ics,text/plain,text/markdown,text/calendar">
                    <button type="button" class="cc-btn cc-btn-ghost cc-btn-small" id="smartImportAnalyzeBtn">Analyze</button>
                    <button type="button" class="cc-btn cc-btn-ghost cc-btn-small" id="smartImportDeselectBtn">Deselect all</button>
                    <button type="button" class="cc-btn cc-btn-primary cc-btn-small" id="smartImportApplyBtn">Apply approved</button>
                    <button type="button" class="cc-btn cc-btn-ghost cc-btn-small" id="smartImportUndoBtn">Undo last import</button>
                </div>
                <textarea class="modal-input smart-import-source" id="smartImportText" placeholder="Paste homework, syllabus, planning, or calendar text here.">${escapeHtml(seedText)}</textarea>
                <p class="cc-foot-help" id="smartImportDisclosure">Provider: ${escapeHtml(CHAT_PROVIDER_CONFIG[provider]?.label || provider)} · Model: ${escapeHtml(model)} · Remote status: local parser/no outbound request · Response quality depends on the provider and model you select if you opt into remote AI later.</p>
                <div id="smartImportStatus" class="cc-foot-help">No suggestions yet.</div>
                <div id="smartImportProposalList" class="smart-import-proposal-list"></div>`;
            openSutraModal({
                titleText: 'Smart Import',
                bodyNode: body,
                buttons: [{ label: 'Close', value: true }]
            });
            let proposals = [];
            const render = () => {
                const host = body.querySelector('#smartImportProposalList');
                const status = body.querySelector('#smartImportStatus');
                status.textContent = proposals.length ? `${proposals.length} suggestion${proposals.length === 1 ? '' : 's'} ready for review.` : 'No suggestions yet.';
                host.innerHTML = proposals.map((p, idx) => `
                    <div class="smart-import-proposal" data-smart-import-index="${idx}">
                        <input type="checkbox" checked aria-label="Approve suggestion">
                        <div>
                            <div class="smart-import-proposal-fields">
                                <label>Type<select class="modal-input" data-field="type">
                                    ${['homework','task','test','quiz','exam','calendar event','class','note'].map(t => `<option value="${t}" ${p.type === t ? 'selected' : ''}>${t}</option>`).join('')}
                                </select></label>
                                <label>Title<input class="modal-input" data-field="title" value="${escapeHtml(p.title)}"></label>
                                <label>Date<input class="modal-input" data-field="dueDate" type="date" value="${escapeHtml(p.proposedFields.dueDate || '')}"></label>
                                <label>Class<input class="modal-input" data-field="className" value="${escapeHtml(p.proposedFields.className || '')}"></label>
                                <label>Priority<select class="modal-input" data-field="priority"><option value="medium" ${p.proposedFields.priority !== 'high' ? 'selected' : ''}>medium</option><option value="high" ${p.proposedFields.priority === 'high' ? 'selected' : ''}>high</option></select></label>
                            </div>
                            <div class="cc-foot-help">${escapeHtml(p.confidence)} · ${escapeHtml(p.sourceLocation)} · ${escapeHtml(p.sourceSnippet)}</div>
                            ${p.warnings && p.warnings.length ? `<div class="smart-import-warning">${p.warnings.map(escapeHtml).join(' · ')}</div>` : ''}
                        </div>
                    </div>`).join('');
            };
            body.querySelector('#smartImportFileInput')?.addEventListener('change', async event => {
                const file = event.target.files && event.target.files[0];
                if (!file) return;
                const text = await file.text();
                body.querySelector('#smartImportText').value = text.slice(0, 80000);
                body.querySelector('#smartImportStatus').textContent = `Loaded ${file.name} (${Math.round(file.size / 1024)} KB).`;
            });
            body.querySelector('#smartImportAnalyzeBtn')?.addEventListener('click', () => {
                const text = body.querySelector('#smartImportText')?.value || '';
                const parsed = parseSmartImportText(text, 'Smart Import source');
                proposals = parsed.proposals;
                if (parsed.rejected.length) body.querySelector('#smartImportStatus').textContent = parsed.rejected.map(r => r.reason).join(' ');
                render();
            });
            body.querySelector('#smartImportDeselectBtn')?.addEventListener('click', () => {
                body.querySelectorAll('.smart-import-proposal input[type="checkbox"]').forEach(input => { input.checked = false; });
            });
            body.querySelector('#smartImportUndoBtn')?.addEventListener('click', undoSmartImportLastApplied);
            body.querySelector('#smartImportApplyBtn')?.addEventListener('click', () => {
                const rows = Array.from(body.querySelectorAll('.smart-import-proposal'));
                const applied = [];
                rows.forEach(row => {
                    const idx = Number(row.getAttribute('data-smart-import-index'));
                    if (!row.querySelector('input[type="checkbox"]')?.checked) return;
                    const original = proposals[idx];
                    if (!original) return;
                    const next = cloneSerializable(original, {});
                    row.querySelectorAll('[data-field]').forEach(input => {
                        const field = input.getAttribute('data-field');
                        if (field === 'type') next.type = input.value;
                        else if (field === 'title') next.title = input.value;
                        else next.proposedFields[field] = input.value;
                    });
                    if (next.confidence !== 'High confidence' && !confirm(`Apply "${next.title}" marked ${next.confidence}?`)) return;
                    applied.push(applySmartImportProposal(next));
                });
                smartImportLastApplied = applied;
                body.querySelector('#smartImportStatus').textContent = `Applied ${applied.length} approved item${applied.length === 1 ? '' : 's'}.`;
                showToast(`Smart Import applied ${applied.length} item${applied.length === 1 ? '' : 's'}.`);
            });
            setTimeout(() => body.querySelector('#smartImportText')?.focus(), 30);
        }

        function bindPublicBetaSurfaces() {
            document.getElementById('whatsNewBtn')?.addEventListener('click', openWhatsNewPanel);
            document.getElementById('whatsNewOverflowBtn')?.addEventListener('click', openWhatsNewPanel);
            document.getElementById('openSmartImportBtn')?.addEventListener('click', () => openSmartImportWizard());
            document.getElementById('openAssistantHistorySettingsBtn')?.addEventListener('click', openAssistantHistoryPanel);
            document.getElementById('exportSelectedAssistantChatBtn')?.addEventListener('click', () => exportAssistantConversation(currentChatId));
            document.getElementById('clearAssistantChatsBtn')?.addEventListener('click', clearAllAssistantChats);
            document.getElementById('reopenAiDisclosureBtn')?.addEventListener('click', openAssistantDisclosureInfo);
            document.getElementById('openAssistantGuideBtn')?.addEventListener('click', openAssistantGuide);
            renderIntegrationRegistry();
            updateWhatsNewUnreadState();
            try {
                window.SutraSmartImport = { parse: parseSmartImportText, open: openSmartImportWizard, undoLast: undoSmartImportLastApplied };
                window.SutraReleaseNotes = { open: openWhatsNewPanel, notes: SUTRA_RELEASE_NOTES };
                window.SutraAssistantChats = {
                    open: openAssistantHistoryPanel,
                    newChat: startNewAssistantChat,
                    exportSelected: () => exportAssistantConversation(currentChatId),
                    clearAll: clearAllAssistantChats,
                    getStore: () => readAssistantChatStoreFromStorage()
                };
            } catch (_) {}
        }

        async function sendChat() {
            if (!chatInput || !messagesEl) return;
            const text = chatInput.value.trim();
            if (!text) return;
            clearChatNotices();
            appendMessage('user', text);
            chatInput.value = '';

            // Sutra Assistant command layer: if the text is a recognized natural-
            // language command (open note, run deadline radar, start focus, etc.)
            // execute it locally and skip the model call entirely.
            try {
                if (window.flowAssistant && typeof window.flowAssistant.handleOutgoing === 'function') {
                    const cmd = window.flowAssistant.handleOutgoing(text);
                    if (cmd && cmd.handled) {
                        const reply = cmd.message || 'Done.';
                        appendMessage('assistant', reply);
                        convo.push({ role: 'user', content: text });
                        convo.push({ role: 'assistant', content: reply });
                        saveConvo();
                        return;
                    }
                }
            } catch (e) { /* fall through to model */ }

            // Snapshot of history BEFORE this turn (used for request enrichment). The
            // current user turn is NOT persisted yet — it is only saved once all gates
            // pass (Section 11: failed/cancelled sends must not leave orphaned history).
            const conversationSnapshot = Array.isArray(convo) ? convo.slice() : [];
            const provider = getCurrentChatProvider();
            const providerConfig = CHAT_PROVIDER_CONFIG[provider];
            const isLocalProvider = provider === 'local';
            // Local/offline endpoint config (Ollama, LM Studio, llama.cpp, etc.).
            const localEndpointCfg = isLocalProvider ? getWorkspacePreference('assistant.localEndpoint', {}) : null;
            const apiKey = getProviderApiKey(provider);
            let selectedModel = getActiveModelForProvider(provider);
            if (isLocalProvider && !selectedModel && localEndpointCfg && localEndpointCfg.model) {
                selectedModel = String(localEndpointCfg.model).trim();
            }
            if (!apiKey && !isLocalProvider) {
                appendChatNotice(`No ${providerConfig.label} API key on file. Add one in Settings ▸ Integrations, then try again.`);
                updateChatKeyBanner();
                openProviderKeySettings();
                return;
            }
            if (isLocalProvider && (!localEndpointCfg || !String(localEndpointCfg.baseUrl || '').trim())) {
                appendChatNotice('No local endpoint configured. Set a base URL in Settings ▸ Assistant ▸ Local AI endpoint (e.g. http://localhost:11434/v1).');
                return;
            }
            if (!selectedModel) {
                appendChatNotice(isLocalProvider ? 'Set a local model id in Settings ▸ Assistant, or type one in the model field.' : 'Please choose a model first.');
                return;
            }
            if (remapModelValueIfApiKey(provider, selectedModel)) {
                appendChatNotice(`The model field looked like an API key. Add the ${providerConfig.label} key in Settings, then enter the exact model ID here.`);
                openProviderKeySettings();
                return;
            }

            // Phase 2D — first remote request privacy disclosure. Nothing leaves
            // the device for a remote provider until the user has acknowledged
            // exactly what will be sent. Local on-device endpoints are configured
            // separately and skip this gate.
            if (!isLocalProvider) {
                const acknowledged = await ensureAiSendDisclosure({
                    providerLabel: providerConfig.label,
                    model: selectedModel
                });
                if (!acknowledged) {
                    appendChatNotice('Cancelled — nothing was sent to the AI provider.');
                    return;
                }
            }

            // All gates passed and (for remote providers) the send was acknowledged —
            // only now persist the user turn into history, then show the thinking state.
            convo.push({ role: 'user', content: text });
            saveConvo();
            showThinkingIndicator();
            // Call Groq REST endpoint (non-streaming simple call)
            try {
                setModelForProvider(provider, selectedModel);

                // Sutra Assistant: add app-aware system prompt + context. Falls back gracefully
                // if the module isn't loaded.
                const flowEnrichment = (typeof window !== 'undefined' && window.flowAssistant && typeof window.flowAssistant.buildRequestEnrichment === 'function')
                    ? window.flowAssistant.buildRequestEnrichment(text, providerConfig.type, { conversation: conversationSnapshot })
                    : null;
                const systemPromptText = flowEnrichment ? flowEnrichment.systemPrompt : null;
                const requestMessages = flowEnrichment && Array.isArray(flowEnrichment.requestMessages) && flowEnrichment.requestMessages.length
                    ? flowEnrichment.requestMessages
                    : [{ role: 'user', content: text }];

                // Sutra Assistant image attachments (vision). Only sent when the
                // selected provider/model is detected as vision-capable; otherwise
                // we degrade to text-only and tell the user.
                const flowAttachments = flowEnrichment && Array.isArray(flowEnrichment.attachments) ? flowEnrichment.attachments : [];
                const visionSupported = !!(flowEnrichment && flowEnrichment.visionCapability && flowEnrichment.visionCapability.supported);
                const useImages = flowAttachments.length > 0 && visionSupported;
                if (flowAttachments.length > 0 && !visionSupported) {
                    const reason = (flowEnrichment && flowEnrichment.visionCapability && flowEnrichment.visionCapability.reason) || 'The selected model is text-only.';
                    appendMessage('assistant', `(Image not sent — ${reason} I'll answer from your text.)`);
                }
                // Attachments are one-shot: clear them after this send regardless.
                try { if (window.flowAssistant && typeof window.flowAssistant.consumeAttachments === 'function') window.flowAssistant.consumeAttachments(); } catch (e) { /* ignore */ }

                const lastUserIdx = (() => { for (let k = requestMessages.length - 1; k >= 0; k -= 1) { if (requestMessages[k].role === 'user') return k; } return -1; })();

                let endpoint = providerConfig.chatEndpoint;
                let headers = { 'Content-Type': 'application/json' };
                let body = {};

                if (providerConfig.type === 'openai_compatible') {
                    if (apiKey) headers.Authorization = `Bearer ${apiKey}`;
                    if (provider === 'openrouter') {
                        headers['HTTP-Referer'] = window.location.origin || 'http://localhost';
                        headers['X-Title'] = 'Sutra';
                    }
                    if (isLocalProvider) {
                        // Build an OpenAI-compatible endpoint from the base URL.
                        let base = String((localEndpointCfg && localEndpointCfg.baseUrl) || '').trim().replace(/\/+$/, '');
                        endpoint = /\/chat\/completions$/.test(base) ? base : `${base}/chat/completions`;
                    }
                    const msgs = (systemPromptText
                        ? [{ role: 'system', content: systemPromptText }, ...requestMessages]
                        : requestMessages.slice()).map(m => ({ role: m.role, content: m.content }));
                    if (useImages) {
                        const targetIdx = systemPromptText ? lastUserIdx + 1 : lastUserIdx;
                        if (targetIdx >= 0 && msgs[targetIdx]) {
                            msgs[targetIdx] = {
                                role: 'user',
                                content: [{ type: 'text', text: String(msgs[targetIdx].content || text) }]
                                    .concat(flowAttachments.map(a => ({ type: 'image_url', image_url: { url: a.dataUrl } })))
                            };
                        }
                    }
                    body = { model: selectedModel, messages: msgs, temperature: 1 };
                } else if (providerConfig.type === 'anthropic') {
                    headers['x-api-key'] = apiKey;
                    headers['anthropic-version'] = '2023-06-01';
                    headers['anthropic-dangerous-direct-browser-access'] = 'true';
                    const msgs = requestMessages.map(m => ({ role: m.role, content: m.content }));
                    if (useImages && lastUserIdx >= 0 && msgs[lastUserIdx]) {
                        msgs[lastUserIdx] = {
                            role: 'user',
                            content: [{ type: 'text', text: String(msgs[lastUserIdx].content || text) }]
                                .concat(flowAttachments.map(a => ({
                                    type: 'image',
                                    source: { type: 'base64', media_type: a.mediaType || 'image/png', data: String(a.dataUrl || '').replace(/^data:[^,]+,/, '') }
                                })))
                        };
                    }
                    body = { model: selectedModel, max_tokens: 1024, messages: msgs };
                    if (systemPromptText) body.system = systemPromptText;
                } else if (providerConfig.type === 'gemini') {
                    endpoint = providerConfig.chatEndpoint.replace('{model}', encodeURIComponent(selectedModel));
                    endpoint += `?key=${encodeURIComponent(apiKey)}`;
                    body = {
                        contents: requestMessages.map((message, idx) => {
                            const parts = [{ text: String(message.content || '') }];
                            if (useImages && idx === lastUserIdx) {
                                flowAttachments.forEach(a => parts.push({ inline_data: { mime_type: a.mediaType || 'image/png', data: String(a.dataUrl || '').replace(/^data:[^,]+,/, '') } }));
                            }
                            return { role: message.role === 'assistant' ? 'model' : 'user', parts };
                        }),
                        generationConfig: {
                            temperature: 1,
                            maxOutputTokens: 1024
                        }
                    };
                    if (systemPromptText) {
                        body.systemInstruction = { role: 'system', parts: [{ text: systemPromptText }] };
                    }
                }

                const resp = await fetch(endpoint, { method: 'POST', headers, body: JSON.stringify(body) });

                // Try to parse JSON, but gracefully handle non-JSON responses
                let data;
                try {
                    data = await resp.json();
                } catch (e) {
                    const raw = await resp.text();
                    data = { __raw_text: raw, __parseError: true };
                }

                hideThinkingIndicator();
                let extracted = null;
                if (providerConfig.type === 'openai_compatible') extracted = extractOpenAiCompatibleMessage(data);
                else if (providerConfig.type === 'anthropic') extracted = extractAnthropicMessage(data);
                else if (providerConfig.type === 'gemini') extracted = extractGeminiMessage(data);
                if (!extracted && data && data.__raw_text) extracted = data.__raw_text;
                if (!extracted && data && data.error && data.error.message) extracted = data.error.message;
                if (!extracted && data) {
                    try { extracted = JSON.stringify(data); } catch (e) { extracted = String(data); }
                }
                if (!resp.ok) {
                    // HTTP errors are transient notices (clearable on next send), not
                    // persisted history.
                    appendChatNotice(`HTTP ${resp.status} - ${extracted || '(no details)'}`);
                } else {
                    const assistantText = extracted || '(no response)';
                    appendMessage('assistant', assistantText);
                    // Persist ONLY the user-facing final answer — never raw reasoning /
                    // chain-of-thought (any inline <think> block is stripped first).
                    const persistClean = splitThinkBlocks(assistantText).clean || assistantText;
                    convo.push({ role: 'assistant', content: persistClean });
                    saveConvo();
                }
            } catch (err) {
                hideThinkingIndicator();
                // Friendly guidance for common CORS/network failure
                let msg = 'Request failed: ' + err.message;
                if (err && err.message && err.message.toLowerCase().includes('failed to fetch')) {
                    msg += ' -- this usually means a network issue, blocked API key, or provider CORS policy from browser context.';
                }
                appendChatNotice(msg);
            }
        }

        // fullscreen toggle
        function toggleFullscreen() {
            const isFull = chatbotPanel.classList.toggle('fullscreen');
            if (isFull) {
                chatFullBtn.textContent = 'Exit';
            } else {
                chatFullBtn.textContent = 'Full';
            }
            // ensure messages area scrolls to bottom
            messagesEl.scrollTop = messagesEl.scrollHeight;
        }

        // Sutra Assistant bridge: gives src/features/flow-assistant.js live access to
        // closure-scoped state and helper functions. Defined here because tasks,
        // timeBlocks, pages, etc. are `let` bindings inside this closure and are
        // reassigned in places — getter properties keep the bridge in sync.
        //
        // IMPORTANT: the chat code lives at script-top-level, so `function toggleChat()`
        // etc. become global bindings attached to window. Capturing the originals into
        // local consts here lets the bridge call the real implementations without the
        // window aliases turning into self-referential infinite loops once we reassign
        // the global names.
        try {
            const flowSafe = (fn) => (typeof fn === 'function');
            const _origToggleChat = toggleChat;
            const _origSendChat = sendChat;
            const _origInsertIntoEditor = insertIntoEditor;
            const _origSetActiveView = setActiveView;
            const _origPersistAppData = persistAppData;
            const _origSaveTimeBlocks = (typeof saveTimeBlocks === 'function') ? saveTimeBlocks : null;
            const _origRenderTimeline = (typeof renderTimeline === 'function') ? renderTimeline : null;
            const _origRenderTaskViews = (typeof renderTaskViews === 'function') ? renderTaskViews : null;
            const _origRenderPagesList = (typeof renderPagesList === 'function') ? renderPagesList : null;
            const _origRenderMarkdown = (typeof renderMarkdown === 'function') ? renderMarkdown : null;
            const _origGenerateId = (typeof generateId === 'function') ? generateId : null;
            const _origCollectDeadlines = (typeof collectWorkspaceDeadlines === 'function') ? collectWorkspaceDeadlines : null;
            const _origLoadPage = (typeof loadPage === 'function') ? loadPage : null;
            const _origShowToast = (typeof showToast === 'function') ? showToast : null;
            // Canonical helpers Flow reuses instead of re-implementing app behavior.
            const _origQuickCapture = (typeof openQuickCaptureModal === 'function') ? openQuickCaptureModal : null;
            const _origScheduleGeneric = (typeof scheduleGenericItemAsBlock === 'function') ? scheduleGenericItemAsBlock : null;
            const _origOpenDeadlineRadar = (typeof openDeadlineRadar === 'function') ? openDeadlineRadar : null;
            const _origOpenClassDashboard = (typeof openClassDashboardDrawer === 'function') ? openClassDashboardDrawer : null;
            const _origWeeklyReview = (typeof createWeeklyReviewNote === 'function') ? createWeeklyReviewNote : null;
            const _origStartFocus = (typeof startFocusSession === 'function') ? startFocusSession : null;
            const _origGlobalSearch = (typeof openGlobalSearchPanel === 'function') ? openGlobalSearchPanel : null;
            const _origOpenTaskModal = (typeof openTaskModal === 'function') ? openTaskModal : null;
            const _origExportAtelier = (typeof exportWorkspaceAsAtelier === 'function') ? exportWorkspaceAsAtelier
                : ((typeof exportWorkspaceAsAtelierPackage === 'function') ? exportWorkspaceAsAtelierPackage : null);

            window.flowAtelier = {
                get tasks() { return tasks; },
                get pages() { return pages; },
                get timeBlocks() { return timeBlocks; },
                get cramSessions() { return cramSessions; },
                get currentPageId() { return currentPageId; },
                get activeView() { return activeView; },
                get unlockedPageIds() { return unlockedPageIds; },
                get collegeAppWorkspace() { return collegeAppWorkspace; },
                get apStudyWorkspace() { return apStudyWorkspace; },
                get reviewWorkspace() { return reviewWorkspace; },
                insertIntoEditor: (text) => _origInsertIntoEditor(text),
                persistAppData: () => { if (_origPersistAppData) _origPersistAppData(); },
                saveTimeBlocks: () => { if (_origSaveTimeBlocks) _origSaveTimeBlocks(); },
                renderTimeline: () => { if (_origRenderTimeline) _origRenderTimeline(); },
                renderTaskViews: () => { if (_origRenderTaskViews) _origRenderTaskViews(); },
                renderPagesList: () => { if (_origRenderPagesList) _origRenderPagesList(); },
                renderReviewWorkspace: () => { if (typeof window.renderReviewWorkspace === 'function') window.renderReviewWorkspace(); },
                setActiveView: (view) => { if (_origSetActiveView) _origSetActiveView(view); },
                generateId: () => (_origGenerateId ? _origGenerateId() : `id_${Date.now().toString(36)}`),
                toggleChat: () => { if (_origToggleChat) _origToggleChat(); },
                sendChat: () => { if (_origSendChat) _origSendChat(); },
                collectWorkspaceDeadlines: () => (_origCollectDeadlines ? _origCollectDeadlines() : []),
                renderMarkdown: (t) => (_origRenderMarkdown ? _origRenderMarkdown(t) : String(t || '')),
                showToast: (m) => { if (_origShowToast) _origShowToast(m); },
                loadPage: (id) => { if (_origLoadPage) _origLoadPage(id); },
                getActiveEditor: () => (typeof editorEl !== 'undefined' ? editorEl : document.getElementById('editor')),
                // Reused canonical workflows (undefined return = unavailable).
                openQuickCaptureModal: (text) => (_origQuickCapture ? (_origQuickCapture(text), true) : undefined),
                scheduleGenericItemAsBlock: (item) => (_origScheduleGeneric ? (_origScheduleGeneric(item), true) : undefined),
                openDeadlineRadar: () => (_origOpenDeadlineRadar ? (_origOpenDeadlineRadar(), true) : undefined),
                openClassDashboardDrawer: (id) => (_origOpenClassDashboard ? (_origOpenClassDashboard(id), true) : undefined),
                createWeeklyReviewNote: () => (_origWeeklyReview ? (_origWeeklyReview(), true) : undefined),
                startFocusSession: (taskId, opts) => (_origStartFocus ? (_origStartFocus(taskId, opts), true) : undefined),
                openGlobalSearchPanel: (q) => (_origGlobalSearch ? (_origGlobalSearch(q), true) : undefined),
                openTaskModal: (taskId, preset) => (_origOpenTaskModal ? (_origOpenTaskModal(taskId, preset), true) : undefined),
                exportWorkspaceAsAtelier: () => (_origExportAtelier ? (_origExportAtelier(), true) : undefined)
            };
            // Convenience aliases on window so flow-assistant can call direct refs.
            // We assign captured originals (NOT recursive arrows), so the chat code's
            // own `addEventListener('click', toggleChat)` still gets the real function
            // when it runs immediately after this block.
            if (!window.insertIntoEditor) window.insertIntoEditor = _origInsertIntoEditor;
            if (!window.toggleChat) window.toggleChat = _origToggleChat;
            if (!window.sendChat) window.sendChat = _origSendChat;
            if (!window.setActiveView) window.setActiveView = _origSetActiveView;
            if (!window.persistAppData) window.persistAppData = _origPersistAppData;
            if (_origSaveTimeBlocks && !window.saveTimeBlocks) window.saveTimeBlocks = _origSaveTimeBlocks;
            if (_origRenderTimeline && !window.renderTimeline) window.renderTimeline = _origRenderTimeline;
            if (_origRenderTaskViews && !window.renderTaskViews) window.renderTaskViews = _origRenderTaskViews;
            if (_origRenderPagesList && !window.renderPagesList) window.renderPagesList = _origRenderPagesList;
            if (_origRenderMarkdown && !window.renderMarkdown) window.renderMarkdown = _origRenderMarkdown;
            if (_origGenerateId && !window.generateId) window.generateId = _origGenerateId;
            if (_origCollectDeadlines && !window.collectWorkspaceDeadlines) window.collectWorkspaceDeadlines = _origCollectDeadlines;
        } catch (err) {
            console.warn('Sutra Assistant bridge install failed:', err);
        }

        if (chatbotBtn) chatbotBtn.addEventListener('click', toggleChat);
        if (chatSendBtn) chatSendBtn.addEventListener('click', sendChat);
        if (chatNewBtn) chatNewBtn.addEventListener('click', startNewAssistantChat);
        if (chatHistoryBtn) chatHistoryBtn.addEventListener('click', openAssistantHistoryPanel);
        if (chatGuideBtn) chatGuideBtn.addEventListener('click', openAssistantGuide);
        if (saveChatKeysBtn) saveChatKeysBtn.addEventListener('click', saveAllApiKeys);
        if (chatInfoBtn) chatInfoBtn.addEventListener('click', openChatInfo);
        if (chatKeyBannerBtn) chatKeyBannerBtn.addEventListener('click', openProviderKeySettings);
        if (chatCloseBtn) chatCloseBtn.addEventListener('click', () => { if (chatbotPanel.classList.contains('fullscreen')) chatbotPanel.classList.remove('fullscreen'); toggleChat(); });
        if (chatFullBtn) chatFullBtn.addEventListener('click', toggleFullscreen);
        if (chatInput) chatInput.addEventListener('keypress', (e)=>{ if(e.key==='Enter' && !e.shiftKey){ e.preventDefault(); sendChat(); } });
        if (chatProviderSelect) {
            chatProviderSelect.addEventListener('change', () => {
                const provider = getCurrentChatProvider();
                syncProviderUi(provider);
            });
        }
        if (chatModelSelect) {
            chatModelSelect.addEventListener('change', () => {
                const provider = getCurrentChatProvider();
                const model = String(chatModelSelect.value || '').trim();
                if (model) setModelForProvider(provider, model);
            });
        }
        if (chatCustomModelInput) {
            chatCustomModelInput.addEventListener('change', () => {
                const provider = getCurrentChatProvider();
                const value = chatCustomModelInput.value || '';
                if (!remapModelValueIfApiKey(provider, value)) setCustomModelForProvider(provider, value);
            });
            chatCustomModelInput.addEventListener('keypress', (e) => {
                if (e.key !== 'Enter') return;
                e.preventDefault();
                const provider = getCurrentChatProvider();
                const value = chatCustomModelInput.value || '';
                if (!remapModelValueIfApiKey(provider, value)) {
                    setCustomModelForProvider(provider, value);
                    showToast('Custom model saved');
                }
            });
        }
        if (refreshChatModelsBtn) {
            refreshChatModelsBtn.addEventListener('click', refreshModelsForCurrentProvider);
        }
        [groqApiKeyInput, openaiApiKeyInput, anthropicApiKeyInput, geminiApiKeyInput, openrouterApiKeyInput]
            .filter(Boolean)
            .forEach(input => {
                input.addEventListener('keypress', (e) => {
                    if (e.key !== 'Enter') return;
                    e.preventDefault();
                    saveAllApiKeys();
                });
            });

        // Sutra Assistant redesigned panel: the provider chip in the header
        // (#chatSettingsCurrent) acts as a settings toggle, and the popover
        // has its own close button (#chatSettingsCloseBtn). The previous
        // <details> auto-toggle is gone; we wire explicit click handlers
        // and outside-click dismissal.
        function flowToggleSettingsPopover(force) {
            const popover = document.getElementById('chatSettingsShell');
            if (!popover) return;
            const willShow = (typeof force === 'boolean') ? force : popover.hasAttribute('hidden');
            if (willShow) popover.removeAttribute('hidden');
            else popover.setAttribute('hidden', '');
        }
        if (chatSettingsCurrent) {
            chatSettingsCurrent.addEventListener('click', (e) => {
                e.stopPropagation();
                flowToggleSettingsPopover();
            });
        }
        const chatSettingsCloseBtn = document.getElementById('chatSettingsCloseBtn');
        if (chatSettingsCloseBtn) {
            chatSettingsCloseBtn.addEventListener('click', () => flowToggleSettingsPopover(false));
        }
        // Outside click closes the popover (but not when clicking inside it).
        document.addEventListener('click', (e) => {
            const popover = document.getElementById('chatSettingsShell');
            if (!popover || popover.hasAttribute('hidden')) return;
            if (popover.contains(e.target)) return;
            if (e.target === chatSettingsCurrent) return;
            flowToggleSettingsPopover(false);
        });

        // Auto-grow the input textarea up to its CSS max-height.
        if (chatInput) {
            const autosize = () => {
                chatInput.style.height = 'auto';
                chatInput.style.height = Math.min(chatInput.scrollHeight, 140) + 'px';
            };
            chatInput.addEventListener('input', autosize);
            chatInput.addEventListener('focus', autosize);
        }

        // Initialize
        populateKeyInputsFromStorage();
        syncProviderUi(getCurrentChatProvider());
        // load and render conversation history
        loadConvo();
        renderCurrentChatMessages();
        bindPublicBetaSurfaces();

// ===============================================================================
// TIMELINE / TIME-BLOCKING (TimeTile integration)
// ===============================================================================

let timeBlocks = [];
let editingBlockId = null;
let timeMode = null; // null = auto
let timelineViewDateKey = null;
let timelineSourceMode = 'atelier';
let timelineViewMode = 'week';
let timelineLayoutMode = 'legacy';
let timelineLegacyMode = 'week';
let timelineLastKnownTodayKey = dateKey(new Date());

function getTimelineViewDate() {
    const key = timelineViewDateKey || dateKey(new Date());
    return parseDate(key);
}

function addDays(dateObj, days) {
    const d = new Date(dateObj.getTime());
    d.setDate(d.getDate() + Number(days || 0));
    return d;
}

function getBlocksForDate(dateObj) {
    return (Array.isArray(timeBlocks) ? timeBlocks : [])
        .filter(block => doesTimeBlockOccurOnDate(block, dateObj))
        .map(block => {
            const startMins = parseTimeToMinutes(block.start);
            const endMins = parseTimeToMinutes(block.end);
            if (!Number.isFinite(startMins) || !Number.isFinite(endMins)) return null;
            return { block, startMins, endMins };
        })
        .filter(Boolean)
        .sort((a, b) => a.startMins - b.startMins)
        .map(item => item.block);
}

function normalizeBlockDate(value) {
    if (!value) return null;
    if (/^\d{4}-\d{2}-\d{2}$/.test(String(value))) return String(value);
    const d = new Date(value);
    if (isNaN(d)) return null;
    return dateKey(d);
}

function syncTimelineDateToCurrentDay(force = false) {
    const todayKey = dateKey(new Date());
    if (todayKey === timelineLastKnownTodayKey && !force) return false;
    const shouldFollowToday = force || !timelineViewDateKey || timelineViewDateKey === timelineLastKnownTodayKey;
    timelineLastKnownTodayKey = todayKey;
    if (!shouldFollowToday || timelineViewDateKey === todayKey) return false;
    timelineViewDateKey = todayKey;
    if (appSettings) {
        appSettings.timelineViewDate = timelineViewDateKey;
        persistAppData();
    }
    return true;
}

function doesTimeBlockOccurOnDate(block, targetDate) {
    if (!block || !targetDate) return false;
    const recurrence = String(block.recurrence || 'none').toLowerCase();
    const targetKey = dateKey(targetDate);
    let explicitDate = normalizeBlockDate(block.date);
    if (!explicitDate && block.source === 'calendar_ics') {
        // Backward compatibility for old imports that missed "date".
        explicitDate = normalizeBlockDate(block.createdAt) || normalizeBlockDate(block.updatedAt);
    }
    const recurrenceUntil = normalizeBlockDate(block.recurrenceUntil);

    if (explicitDate && targetKey < explicitDate) return false;
    if (recurrenceUntil && targetKey > recurrenceUntil) return false;

    // Calendar imports default to fixed-date events.
    // Recurrence is honored only when preserveRecurrence is explicitly enabled.
    if (block.source === 'calendar_ics' && block.preserveRecurrence !== true) {
        return explicitDate ? explicitDate === targetKey : false;
    }

    if (recurrence === 'daily') return true;
    if (recurrence === 'weekdays') return targetDate.getDay() >= 1 && targetDate.getDay() <= 5;
    if (recurrence === 'weekly') {
        if (Array.isArray(block.weeklyDays) && block.weeklyDays.length > 0) {
            return block.weeklyDays.includes(targetDate.getDay());
        }
        if (explicitDate) return parseDate(explicitDate).getDay() === targetDate.getDay();
        const created = block.createdAt ? new Date(block.createdAt) : null;
        const anchorDay = created && !isNaN(created) ? created.getDay() : targetDate.getDay();
        return targetDate.getDay() === anchorDay;
    }

    // one-time / none
    if (explicitDate) return explicitDate === targetKey;
    if (block.source === 'calendar_ics') return false;
    return true; // legacy manual blocks without date continue to show
}

// Time mode detection
function detectTimeMode() {
    const hour = new Date().getHours();
    if (hour >= 5 && hour < 12) return 'morning';
    if (hour >= 12 && hour < 17) return 'afternoon';
    if (hour >= 17 && hour < 21) return 'evening';
    return 'night';
}

function getCurrentTimeMode() {
    return timeMode || detectTimeMode();
}

function applyTimeMode() {
    const mode = getCurrentTimeMode();
    document.body.setAttribute('data-time-mode', mode);
    const badge = document.getElementById('timeModeBadge');
    if (badge) badge.textContent = mode.charAt(0).toUpperCase() + mode.slice(1);
}

function initTimeModeSelector() {
    const select = document.getElementById('timeModeSelect');
    if (!select) return;
    select.value = timeMode || '';
    select.addEventListener('change', (e) => {
        timeMode = e.target.value || null;
        applyTimeMode();
        // Save preference
        if (appSettings) {
            appSettings.timeMode = timeMode;
            persistAppData();
        }
    });
}

// Time blocks data persistence
function loadTimeBlocks() {
    if (appData && appData.timeBlocks) {
        timeBlocks = appData.timeBlocks;
    } else {
        timeBlocks = [];
    }
}

function saveTimeBlocks() {
    if (appData) {
        appData.timeBlocks = timeBlocks;
        persistAppData();
    }
}

function generateBlockId() {
    return 'block_' + Date.now() + '_' + Math.random().toString(36).substr(2,9);
}

function getStartOfWeek(dateObj) {
    const d = new Date(dateObj.getFullYear(), dateObj.getMonth(), dateObj.getDate());
    d.setDate(d.getDate() - d.getDay());
    d.setHours(0, 0, 0, 0);
    return d;
}

function getLegacyTimelineHeading(mode, viewDate) {
    if (mode === 'week') {
        const start = getStartOfWeek(viewDate);
        const end = addDays(start, 6);
        return `Week: ${start.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - ${end.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;
    }
    if (mode === 'month') {
        return `Month: ${viewDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}`;
    }
    if (mode === 'year') {
        return `Year: ${viewDate.toLocaleDateString('en-US', { year: 'numeric' })}`;
    }
    return `Day: ${viewDate.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}`;
}

function getLegacyTimelineVisibleDates(mode, viewDate) {
    if (mode === 'day') return [viewDate];
    if (mode === 'week') {
        const start = getStartOfWeek(viewDate);
        return Array.from({ length: 7 }, (_, index) => addDays(start, index));
    }
    if (mode === 'month') {
        const year = viewDate.getFullYear();
        const month = viewDate.getMonth();
        const dayCount = new Date(year, month + 1, 0).getDate();
        return Array.from({ length: dayCount }, (_, index) => new Date(year, month, index + 1));
    }
    return [viewDate];
}

function buildLegacyTimelineDayCell(dateObj, blocks, options = {}) {
    const inCurrentPeriod = options.inCurrentPeriod !== false;
    const count = blocks.length;
    const dayNum = dateObj.getDate();
    const weekday = dateObj.toLocaleDateString('en-US', { weekday: 'short' });
    const key = dateKey(dateObj);
    const todayKey = dateKey(new Date());
    const eventPreview = blocks.slice(0, 3).map(block => {
        const name = escapeHtml(String(block.name || 'Untitled'));
        return `<div class="timeline-calendar-event">${escapeHtml(block.start || '--:--')} ${name}</div>`;
    }).join('');
    const more = count > 3 ? `<div class="timeline-calendar-more">+${count - 3} more</div>` : '';
    const classes = [
        'timeline-calendar-cell',
        inCurrentPeriod ? '' : 'outside',
        key === todayKey ? 'today' : '',
        key === timelineViewDateKey ? 'selected' : ''
    ].filter(Boolean).join(' ');

    return `
        <button type="button" class="${classes}" data-date="${key}">
            <div class="timeline-calendar-dayhead">
                <span class="timeline-calendar-daynum">${dayNum}</span>
                <span class="timeline-calendar-weekday">${weekday}</span>
            </div>
            <div class="timeline-calendar-count">${count} event${count === 1 ? '' : 's'}</div>
            <div class="timeline-calendar-events">${eventPreview || '<div class="timeline-calendar-empty">No events</div>'}${more}</div>
        </button>
    `;
}

function countLegacyTimelineBlocksInMonth(year, monthIndex, sourceMode = timelineSourceMode) {
    const days = new Date(year, monthIndex + 1, 0).getDate();
    let total = 0;
    for (let d = 1; d <= days; d += 1) {
        total += getTimelineBlocksForDate(new Date(year, monthIndex, d), sourceMode).length;
    }
    return total;
}

function persistTimelineViewPreferences() {
    if (!appSettings) return;
    appSettings.timelineViewDate = timelineViewDateKey;
    appSettings.timelineSource = timelineSourceMode;
    appSettings.timelineViewMode = timelineViewMode;
    appSettings.timelineLayoutMode = timelineLayoutMode;
    appSettings.timelineLegacyMode = timelineLegacyMode;
    persistAppData();
}

function shiftLegacyTimelineAnchor(mode, direction) {
    const step = Number(direction || 0);
    if (!Number.isFinite(step) || step === 0) return;
    const next = getTimelineViewDate();
    if (mode === 'year') next.setFullYear(next.getFullYear() + step);
    else if (mode === 'month') next.setMonth(next.getMonth() + step);
    else if (mode === 'week') next.setDate(next.getDate() + (step * 7));
    else next.setDate(next.getDate() + step);
    timelineViewDateKey = dateKey(next);
    persistTimelineViewPreferences();
    renderTimeline();
}

function bindLegacyTimelineInteractions(container, mode) {
    if (!container) return;
    container.querySelectorAll('[data-nav]').forEach(btn => {
        btn.addEventListener('click', () => {
            const direction = Number(btn.getAttribute('data-nav') || '0');
            shiftLegacyTimelineAnchor(mode, direction);
        });
    });
    container.querySelectorAll('[data-date]').forEach(btn => {
        btn.addEventListener('click', () => {
            const selectedDate = normalizeBlockDate(btn.getAttribute('data-date'));
            if (!selectedDate) return;
            timelineViewDateKey = selectedDate;
            timelineLegacyMode = mode === 'year' ? 'month' : 'day';
            timelineViewMode = normalizeTimelineLegacyMode(timelineLegacyMode);
            persistTimelineViewPreferences();
            renderTimeline();
        });
    });
}

function renderLegacyTimelineOverview(mode, viewDate, container, sourceMode = timelineSourceMode) {
    if (!container) return;
    const weekdayLabels = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
    if (mode === 'week') {
        const start = getStartOfWeek(viewDate);
        const days = Array.from({ length: 7 }, (_, i) => addDays(start, i));
        const rangeLabel = `${start.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} - ${addDays(start, 6).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;
        container.innerHTML = `
            <div class="timeline-calendar-toolbar">
                <div class="timeline-calendar-title">Weekly Overview: ${rangeLabel}</div>
                <div class="timeline-calendar-nav">
                    <button type="button" class="neumo-btn timeline-mini-btn" data-nav="-1">Prev Week</button>
                    <button type="button" class="neumo-btn timeline-mini-btn" data-nav="1">Next Week</button>
                </div>
            </div>
            <div class="timeline-weekday-row">${weekdayLabels.map(name => `<div>${name}</div>`).join('')}</div>
            <div class="timeline-calendar-grid week">
                ${days.map(day => buildLegacyTimelineDayCell(day, getTimelineBlocksForDate(day, sourceMode))).join('')}
            </div>
            <div class="timeline-calendar-hint">Click a day to open Day view.</div>
        `;
        bindLegacyTimelineInteractions(container, mode);
        return;
    }

    if (mode === 'month') {
        const monthStart = new Date(viewDate.getFullYear(), viewDate.getMonth(), 1);
        const monthEnd = new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 0);
        const firstGridDate = addDays(monthStart, -monthStart.getDay());
        const cells = Array.from({ length: 42 }, (_, idx) => addDays(firstGridDate, idx));
        container.innerHTML = `
            <div class="timeline-calendar-toolbar">
                <div class="timeline-calendar-title">${viewDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}</div>
                <div class="timeline-calendar-nav">
                    <button type="button" class="neumo-btn timeline-mini-btn" data-nav="-1">Prev Month</button>
                    <button type="button" class="neumo-btn timeline-mini-btn" data-nav="1">Next Month</button>
                </div>
            </div>
            <div class="timeline-weekday-row">${weekdayLabels.map(name => `<div>${name}</div>`).join('')}</div>
            <div class="timeline-calendar-grid month">
                ${cells.map(day => buildLegacyTimelineDayCell(day, getTimelineBlocksForDate(day, sourceMode), {
                    inCurrentPeriod: day >= monthStart && day <= monthEnd
                })).join('')}
            </div>
            <div class="timeline-calendar-hint">Click any date to open Day view.</div>
        `;
        bindLegacyTimelineInteractions(container, mode);
        return;
    }

    const year = viewDate.getFullYear();
    const months = Array.from({ length: 12 }, (_, m) => {
        const firstDate = new Date(year, m, 1);
        const total = countLegacyTimelineBlocksInMonth(year, m, sourceMode);
        return `
            <button type="button" class="timeline-year-card" data-date="${dateKey(firstDate)}">
                <div class="timeline-year-month">${firstDate.toLocaleDateString('en-US', { month: 'long' })}</div>
                <div class="timeline-year-count">${total} event${total === 1 ? '' : 's'}</div>
            </button>
        `;
    }).join('');
    container.innerHTML = `
        <div class="timeline-calendar-toolbar">
            <div class="timeline-calendar-title">${year} Overview</div>
            <div class="timeline-calendar-nav">
                <button type="button" class="neumo-btn timeline-mini-btn" data-nav="-1">Prev Year</button>
                <button type="button" class="neumo-btn timeline-mini-btn" data-nav="1">Next Year</button>
            </div>
        </div>
        <div class="timeline-year-grid">${months}</div>
        <div class="timeline-calendar-hint">Click a month to open Month view.</div>
    `;
    bindLegacyTimelineInteractions(container, mode);
}

function renderLegacyTimelineDay(container, viewDate, sourceMode = timelineSourceMode) {
    if (!container) return;
    container.innerHTML = `
        <div class="timeline-container">
            <div class="timeline-scale"></div>
            <div class="timeline-blocks"></div>
        </div>
    `;
    const scaleEl = container.querySelector('.timeline-scale');
    const blocksEl = container.querySelector('.timeline-blocks');
    if (!scaleEl || !blocksEl) return;

    scaleEl.innerHTML = '';
    blocksEl.innerHTML = '';

    const containerHeight = getTimelineSurfaceHeightPx();
    const pxPerHour = containerHeight / 24;
    const gridSpan = Math.max(0, Math.round(blocksEl.clientWidth || 0));
    scaleEl.style.setProperty('--timeline-grid-span', `${gridSpan}px`);
    requestAnimationFrame(() => {
        const settledWidth = Math.max(0, Math.round(blocksEl.clientWidth || 0));
        if (settledWidth !== gridSpan) scaleEl.style.setProperty('--timeline-grid-span', `${settledWidth}px`);
    });

    for (let h = 0; h < 24; h += 2) {
        const marker = document.createElement('div');
        marker.className = 'hour-marker';
        marker.style.top = `${h * pxPerHour}px`;
        marker.textContent = formatTimelineAxisLabel(h);
        scaleEl.appendChild(marker);
    }

    const now = new Date();
    const nowMins = now.getHours() * 60 + now.getMinutes();
    const isViewingToday = dateKey(viewDate) === dateKey(new Date());
    let currentBlockId = null;
    const GAP = 12;
    const blocksData = getTimelineBlocksForDate(viewDate, sourceMode).map(block => {
        const startMins = parseTimeToMinutes(block.start);
        const endMins = parseTimeToMinutes(block.end);
        if (!Number.isFinite(startMins) || !Number.isFinite(endMins)) return null;
        const duration = Math.max(30, endMins - startMins);
        return {
            block,
            startMins,
            endMins,
            top: (startMins / 60) * pxPerHour,
            height: Math.max(30, (duration / 60) * pxPerHour)
        };
    }).filter(Boolean);

    const placed = [];
    blocksData.forEach(data => {
        const { block, startMins } = data;
        if (isViewingToday && nowMins >= data.startMins && nowMins < data.endMins) currentBlockId = block.id;
        let desiredTop = data.top;
        let desiredBottom = desiredTop + data.height;
        let attempts = 0;
        while (placed.some(item => !(desiredBottom <= item.top || desiredTop >= item.bottom)) && attempts < 120) {
            desiredTop += GAP;
            desiredBottom = desiredTop + data.height;
            attempts += 1;
        }
        const sourceLabel = getTimelineBlockSourceLabel(block);
        const el = document.createElement('div');
        el.className = `timeline-block${currentBlockId === block.id ? ' current' : ''}`;
        el.style.top = `${desiredTop}px`;
        el.style.height = `${data.height}px`;
        el.style.borderLeftColor = block.color || 'var(--accent)';
        el.style.zIndex = String(Math.max(1, 240 - Math.floor(startMins / 6)));
        el.innerHTML = `
            <div class="block-name">${escapeHtml(block.name || 'Untitled')}</div>
            <div class="block-time">${escapeHtml(String(block.start || '--:--'))} -> ${escapeHtml(String(block.end || '--:--'))} | ${escapeHtml(sourceLabel)}</div>
        `;
        el.addEventListener('click', () => openBlockModal(block));
        blocksEl.appendChild(el);
        placed.push({ top: desiredTop, bottom: desiredBottom });
    });

    if (isViewingToday) {
        const nowLine = document.createElement('div');
        nowLine.className = 'now-indicator';
        nowLine.style.top = `${(nowMins / 60) * pxPerHour}px`;
        nowLine.setAttribute('data-now-label', 'NOW');
        blocksEl.appendChild(nowLine);
    }
}

function doesBlockMatchTimelineSource(block, _sourceMode) {
    const includeApStudyTasks = getWorkspacePreference('tasks.includeApStudy', true) !== false;
    const blockSource = String(block && block.source || '').toLowerCase();
    if (!includeApStudyTasks && (blockSource === 'ap_study_session' || blockSource === 'ap_study_exam')) {
        return false;
    }
    return true;
}

function getTimelineBlocksForDate(dateObj, sourceMode = timelineSourceMode) {
    return getBlocksForDate(dateObj).filter(block => doesBlockMatchTimelineSource(block, sourceMode));
}

function getTimelineBlockSourceLabel(block) {
    if (!block) return 'Sutra';
    if (block.source === 'calendar_google') return 'Imported Calendar';
    if (block.source === 'calendar_ics') return 'Imported Calendar';
    if (block.source === 'planner_auto') return 'Auto-blocked';
    if (block.source === 'planner_plan') return 'Plan';
    if (block.source === 'ap_study_session') return 'AP Study';
    if (block.source === 'ap_study_exam') return 'AP Exam';
    if (block.source === 'sat_exam') return 'SAT Exam';
    if (block.source === 'hw_due') return 'Homework Due';
    return 'Sutra';
}

function formatTimelineAxisLabel(hourValue) {
    const normalized = ((Number(hourValue) % 24) + 24) % 24;
    const prefers24 = getWorkspacePreference('calendar.timeFormat', '12') === '24';
    if (prefers24) {
        return `${String(normalized).padStart(2, '0')}:00`;
    }
    const suffix = normalized >= 12 ? 'PM' : 'AM';
    const hour = normalized % 12 || 12;
    return `${hour}${suffix}`;
}

function formatTimelineAxisLabelForMinutes(totalMinutes) {
    const minutesValue = Math.max(0, Math.min((24 * 60) - 1, Math.round(Number(totalMinutes) || 0)));
    const hour = Math.floor(minutesValue / 60);
    const minute = minutesValue % 60;
    const prefers24 = getWorkspacePreference('calendar.timeFormat', '12') === '24';
    if (prefers24) {
        return `${String(hour).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
    }
    const suffix = hour >= 12 ? 'PM' : 'AM';
    const normalizedHour = hour % 12 || 12;
    if (minute === 0) return `${normalizedHour}${suffix}`;
    return `${normalizedHour}:${String(minute).padStart(2, '0')}${suffix}`;
}

function buildTimelineLaneAssignments(blocks) {
    const prepared = (Array.isArray(blocks) ? blocks : [])
        .map(block => {
            const startMins = parseTimeToMinutes(block && block.start);
            const endMins = parseTimeToMinutes(block && block.end);
            if (!Number.isFinite(startMins) || !Number.isFinite(endMins)) return null;
            const safeEnd = endMins > startMins ? endMins : Math.min(startMins + 30, 24 * 60);
            return {
                block,
                startMins,
                endMins: safeEnd,
                durationMins: safeEnd - startMins,
                laneIndex: 0
            };
        })
        .filter(Boolean)
        .sort((a, b) => a.startMins - b.startMins || b.durationMins - a.durationMins);

    const laneEndTimes = [];
    prepared.forEach(item => {
        let laneIndex = laneEndTimes.findIndex(endMins => endMins <= item.startMins);
        if (laneIndex === -1) {
            laneIndex = laneEndTimes.length;
            laneEndTimes.push(item.endMins);
        } else {
            laneEndTimes[laneIndex] = item.endMins;
        }
        item.laneIndex = laneIndex;
    });

    return {
        items: prepared,
        laneCount: Math.max(1, laneEndTimes.length)
    };
}

function buildResolvedTimelineEntries(dateObj, sourceMode = timelineSourceMode) {
    const resolvedDateKey = dateKey(dateObj);
    return getTimelineBlocksForDate(dateObj, sourceMode).map(block => {
        const [startHour, startMinute] = String(block.start || '00:00').split(':').map(Number);
        const [endHour, endMinute] = String(block.end || '00:30').split(':').map(Number);
        const startsAt = new Date(dateObj.getFullYear(), dateObj.getMonth(), dateObj.getDate(), startHour || 0, startMinute || 0, 0, 0);
        const endsAt = new Date(dateObj.getFullYear(), dateObj.getMonth(), dateObj.getDate(), endHour || 0, endMinute || 0, 0, 0);
        return {
            block,
            dateKey: resolvedDateKey,
            startsAt,
            endsAt
        };
    });
}

function syncTimelineLegacySettingsFromViewMode(nextViewMode) {
    const normalized = normalizeTimelineViewMode(nextViewMode);
    timelineViewMode = normalized;
    if (['day', 'week', 'month', 'year'].includes(normalized)) {
        timelineLayoutMode = 'legacy';
        timelineLegacyMode = normalized;
    } else {
        timelineLayoutMode = 'modern';
    }
    return normalized;
}

function formatTimelineDuration(durationMinutes) {
    const safeMinutes = Math.max(0, Math.round(Number(durationMinutes || 0) || 0));
    const hours = Math.floor(safeMinutes / 60);
    const minutes = safeMinutes % 60;
    if (hours && minutes) return `${hours}h ${minutes}m`;
    if (hours) return `${hours}h`;
    return `${minutes}m`;
}

function getTimelineHeading(viewMode, viewDate) {
    const mode = normalizeTimelineViewMode(viewMode);
    if (mode === 'planner') {
        return `Daily Planner: ${viewDate.toLocaleDateString('en-US', { weekday: 'long', month: 'short', day: 'numeric' })}`;
    }
    return getLegacyTimelineHeading(mode, viewDate);
}

function getTimelineVisibleDatesForMode(viewMode, viewDate) {
    const mode = normalizeTimelineViewMode(viewMode);
    if (mode === 'planner') return [viewDate];
    return getLegacyTimelineVisibleDates(mode, viewDate);
}

function createTimelineTaskState(task, dateKeyStr, completedSet = new Set(), committedSet = new Set()) {
    if (!task || !task.id) return null;
    return {
        task,
        completed: completedSet.has(task.id),
        committed: committedSet.has(task.id),
        priority: normalizePriorityValue(task.priority),
        difficulty: normalizeDifficultyValue(task.difficulty),
        dueDelta: getTaskDueDeltaDays(task, dateKeyStr),
        estimatedMinutes: getTaskEstimatedMinutes(task)
    };
}

function getTimelineTaskPoolForDate(dateKeyStr) {
    const dayState = getDayState(dateKeyStr);
    const completedSet = new Set((dayState && Array.isArray(dayState.completedTaskIds)) ? dayState.completedTaskIds : []);
    const committedSet = new Set((dayState && Array.isArray(dayState.committedTaskIds)) ? dayState.committedTaskIds : []);
    const seen = new Set();
    return collectPlannerCandidateTasksForDate(dateKeyStr)
        .filter(task => {
            if (!task || !task.id) return false;
            if (seen.has(task.id)) return false;
            seen.add(task.id);
            return true;
        })
        .sort(compareTasksForDisplay)
        .map(task => createTimelineTaskState(task, dateKeyStr, completedSet, committedSet))
        .filter(Boolean);
}

function getExplicitTimelineTasksForBlock(block, dateKeyStr, taskPoolMap, completedSet, committedSet) {
    if (!block) return [];
    const items = [];
    const addTask = (taskId, relation = 'linked') => {
        const normalizedTaskId = String(taskId || '');
        if (!normalizedTaskId || items.some(entry => String(entry.task && entry.task.id || '') === normalizedTaskId)) return;
        const pooled = taskPoolMap.get(normalizedTaskId);
        if (pooled) {
            items.push({ ...pooled, relation });
            return;
        }
        const fallbackTask = (Array.isArray(tasks) ? tasks : []).find(task => String(task && task.id || '') === normalizedTaskId);
        const fallbackState = createTimelineTaskState(fallbackTask, dateKeyStr, completedSet, committedSet);
        if (fallbackState) items.push({ ...fallbackState, relation });
    };

    if (block.plannerTaskId) addTask(block.plannerTaskId, 'linked');
    const autoTaskMatch = String(block.autoSourceKey || '').match(/^auto:task:([^:]+):\d{4}-\d{2}-\d{2}$/);
    if (autoTaskMatch) addTask(autoTaskMatch[1], 'linked');
    return items;
}

function buildTimelineKeywordSet(text) {
    return new Set(
        String(text || '')
            .toLowerCase()
            .split(/[^a-z0-9]+/)
            .filter(word => word.length > 2 && !['the', 'and', 'for', 'with', 'from', 'into', 'task', 'block'].includes(word))
    );
}

function canTimelineBlockCarrySuggestedTasks(block) {
    if (!block) return false;
    if (block.source === 'calendar_google' || block.source === 'calendar_ics') return false;
    if (block.plannerTaskId) return false;
    if (/^auto:task:/.test(String(block.autoSourceKey || ''))) return false;
    const category = String(block.category || 'default').toLowerCase();
    return !['break', 'personal', 'health'].includes(category);
}

function getTimelineBlockTaskCapacity(block) {
    const startMins = parseTimeToMinutes(block && block.start);
    const endMins = parseTimeToMinutes(block && block.end);
    const duration = Math.max(0, (Number.isFinite(endMins) ? endMins : 0) - (Number.isFinite(startMins) ? startMins : 0));
    if (duration < 45) return 0;
    if (duration < 75) return 1;
    if (duration < 125) return 2;
    return 3;
}

function getTimelineSuggestionScore(block, taskState, dateKeyStr) {
    if (!block || !taskState || !taskState.task) return 0;
    const blockCategory = String(block.category || 'default').toLowerCase();
    const taskCategory = String(taskState.task.category || '').toLowerCase();
    let score = 0;
    if (blockCategory && blockCategory !== 'default' && blockCategory === taskCategory) score += 6;
    if (taskState.committed) score += 3;
    if (taskState.priority === 'high') score += 2;
    else if (taskState.priority === 'medium') score += 1;
    if (Number.isFinite(taskState.dueDelta)) {
        if (taskState.dueDelta < 0) score += 4;
        else if (taskState.dueDelta === 0) score += 3;
        else if (taskState.dueDelta === 1) score += 2;
    }
    if (blockCategory === 'learning' && (taskCategory === 'learning' || taskState.task.origin === 'homework' || taskState.task.origin === 'ap_study')) score += 4;
    const blockWords = buildTimelineKeywordSet(`${block.name || ''} ${block.category || ''}`);
    const taskWords = buildTimelineKeywordSet(`${taskState.task.title || ''} ${taskState.task.notes || ''}`);
    let overlap = 0;
    blockWords.forEach(word => {
        if (taskWords.has(word)) overlap += 1;
    });
    score += Math.min(4, overlap * 2);
    if (dateKeyStr === today() && taskState.task.noteId) score += 1;
    return score;
}

function buildTimelineDayModel(dateObj, sourceMode = timelineSourceMode) {
    const dateKeyStr = dateKey(dateObj);
    const dayState = getDayState(dateKeyStr);
    const completedSet = new Set((dayState && Array.isArray(dayState.completedTaskIds)) ? dayState.completedTaskIds : []);
    const committedSet = new Set((dayState && Array.isArray(dayState.committedTaskIds)) ? dayState.committedTaskIds : []);
    const blocks = getTimelineBlocksForDate(dateObj, sourceMode);
    const taskPool = getTimelineTaskPoolForDate(dateKeyStr);
    const taskPoolMap = new Map(taskPool.map(item => [String(item.task.id), item]));
    const assignments = new Map();
    const assignedTaskIds = new Set();

    blocks.forEach(block => {
        const explicitTasks = getExplicitTimelineTasksForBlock(block, dateKeyStr, taskPoolMap, completedSet, committedSet);
        if (!explicitTasks.length) return;
        assignments.set(String(block.id || ''), explicitTasks);
        explicitTasks.forEach(item => assignedTaskIds.add(String(item.task.id)));
    });

    let suggestionPool = taskPool.filter(item => !assignedTaskIds.has(String(item.task.id)) && !item.completed);
    blocks.forEach(block => {
        const blockId = String(block && block.id || '');
        const existing = assignments.get(blockId) || [];
        const openSlots = Math.max(0, getTimelineBlockTaskCapacity(block) - existing.length);
        if (!canTimelineBlockCarrySuggestedTasks(block) || openSlots <= 0) return;
        const ranked = suggestionPool
            .map(item => ({
                item,
                score: getTimelineSuggestionScore(block, item, dateKeyStr)
            }))
            .filter(entry => entry.score > 0 || String(block.category || 'default').toLowerCase() === 'default')
            .sort((a, b) => b.score - a.score || compareTasksForDisplay(a.item.task, b.item.task))
            .slice(0, openSlots)
            .map(entry => ({ ...entry.item, relation: 'suggested' }));
        if (!ranked.length) return;
        assignments.set(blockId, existing.concat(ranked));
        ranked.forEach(item => assignedTaskIds.add(String(item.task.id)));
        suggestionPool = suggestionPool.filter(item => !assignedTaskIds.has(String(item.task.id)));
    });

    const remainingTasks = taskPool
        .filter(item => !item.completed && !assignedTaskIds.has(String(item.task.id)))
        .sort((a, b) => compareTasksForDisplay(a.task, b.task));
    const totalTaskCount = taskPool.length;
    const completedTaskCount = taskPool.filter(item => item.completed).length;
    const remainingTaskCount = taskPool.filter(item => !item.completed).length;
    const scheduledMinutes = blocks.reduce((sum, block) => {
        const start = parseTimeToMinutes(block && block.start);
        const end = parseTimeToMinutes(block && block.end);
        if (!Number.isFinite(start) || !Number.isFinite(end)) return sum;
        return sum + Math.max(0, end - start);
    }, 0);
    const focusMinutes = blocks.reduce((sum, block) => {
        const start = parseTimeToMinutes(block && block.start);
        const end = parseTimeToMinutes(block && block.end);
        if (!Number.isFinite(start) || !Number.isFinite(end)) return sum;
        return String(block.category || '').toLowerCase() === 'break' ? sum : sum + Math.max(0, end - start);
    }, 0);
    const completionPercent = totalTaskCount > 0 ? Math.round((completedTaskCount / totalTaskCount) * 100) : 0;
    const highPriorityOpen = taskPool.filter(item => !item.completed && item.priority === 'high').length;

    return {
        dateObj,
        dateKey: dateKeyStr,
        blocks,
        assignments,
        taskPool,
        remainingTasks,
        summary: {
            totalTaskCount,
            completedTaskCount,
            remainingTaskCount,
            completionPercent,
            scheduledMinutes,
            focusMinutes,
            highPriorityOpen,
            linkedTaskCount: assignedTaskIds.size
        }
    };
}

function getTimelineWindowForDates(visibleDates, sourceMode = timelineSourceMode) {
    const entries = (Array.isArray(visibleDates) ? visibleDates : [])
        .flatMap(dateObj => buildResolvedTimelineEntries(dateObj, sourceMode))
        .map(entry => ({
            startMinutes: (entry.startsAt.getHours() * 60) + entry.startsAt.getMinutes(),
            endMinutes: (entry.endsAt.getHours() * 60) + entry.endsAt.getMinutes()
        }));
    const todayKey = today();
    const includesToday = (Array.isArray(visibleDates) ? visibleDates : []).some(dateObj => dateKey(dateObj) === todayKey);
    const plannerWindow = getPlannerDayWindowFromPreferences();
    const baseStart = plannerWindow.startMinutes;
    const baseEnd = plannerWindow.endMinutes;
    let minMinutes = baseStart;
    let maxMinutes = baseEnd;

    if (entries.length) {
        minMinutes = Math.max(0, Math.min(...entries.map(entry => entry.startMinutes)) - 60);
        maxMinutes = Math.min(24 * 60, Math.max(...entries.map(entry => entry.endMinutes)) + 60);
    }
    if (includesToday) {
        const now = new Date();
        const nowMinutes = (now.getHours() * 60) + now.getMinutes();
        minMinutes = Math.min(minMinutes, Math.max(0, nowMinutes - 120));
        maxMinutes = Math.max(maxMinutes, Math.min(24 * 60, nowMinutes + 120));
    }

    minMinutes = Math.max(baseStart, Math.floor(minMinutes / 60) * 60);
    maxMinutes = Math.min(baseEnd, Math.ceil(maxMinutes / 60) * 60);
    if (maxMinutes <= minMinutes) {
        minMinutes = baseStart;
        maxMinutes = Math.max(baseStart + 60, baseEnd);
    }
    if (maxMinutes - minMinutes < 60) {
        maxMinutes = Math.min(baseEnd, minMinutes + 60);
        if (maxMinutes - minMinutes < 60) {
            minMinutes = Math.max(baseStart, maxMinutes - 60);
        }
    }

    return {
        startMinutes: minMinutes,
        endMinutes: maxMinutes,
        spanMinutes: Math.max(60, maxMinutes - minMinutes)
    };
}

function getTimelineBlockState(block, dateObj, assignedTasks = []) {
    const startMins = parseTimeToMinutes(block && block.start);
    const endMins = parseTimeToMinutes(block && block.end);
    const safeEndMins = Number.isFinite(endMins) && Number.isFinite(startMins) && endMins > startMins
        ? endMins
        : Math.min((Number(startMins) || 0) + 30, 24 * 60);
    const durationMinutes = Math.max(15, safeEndMins - (Number(startMins) || 0));
    const startLabel = String(block && block.start || '--:--');
    const endLabel = String(block && block.end || '--:--');
    const dayStart = new Date(dateObj.getFullYear(), dateObj.getMonth(), dateObj.getDate(), Math.floor((Number(startMins) || 0) / 60), (Number(startMins) || 0) % 60);
    const dayEnd = new Date(dateObj.getFullYear(), dateObj.getMonth(), dateObj.getDate(), Math.floor(safeEndMins / 60), safeEndMins % 60);
    const now = new Date();
    const dateKeyStr = dateKey(dateObj);
    const isToday = dateKeyStr === today();
    const isCurrent = isToday && now >= dayStart && now < dayEnd;
    const isPast = dateKeyStr < today() || (isToday && now >= dayEnd);
    const completedTasks = assignedTasks.filter(item => item.completed).length;
    const progressValue = assignedTasks.length
        ? Math.round((completedTasks / assignedTasks.length) * 100)
        : isCurrent
            ? Math.round(((now - dayStart) / Math.max(1, dayEnd - dayStart)) * 100)
            : isPast
                ? 100
                : 0;
    const statusLabel = assignedTasks.length
        ? `${completedTasks}/${assignedTasks.length} tasks`
        : isCurrent
            ? 'Live now'
            : isPast
                ? 'Finished'
                : 'Scheduled';
    const compact = durationMinutes < 65;
    const taskLimit = compact ? 0 : durationMinutes < 95 ? 1 : durationMinutes < 150 ? 2 : 3;

    return {
        block,
        startMins: Number(startMins) || 0,
        endMins: safeEndMins,
        durationMinutes,
        startLabel,
        endLabel,
        durationLabel: formatTimelineDuration(durationMinutes),
        assignedTasks,
        progressValue: Math.max(0, Math.min(100, progressValue)),
        statusLabel,
        isCurrent,
        isPast,
        compact,
        taskLimit
    };
}

function getTimelineTaskMetaBits(taskState) {
    const bits = [];
    if (taskState.committed) bits.push('Committed');
    if (taskState.relation === 'suggested') bits.push('Suggested');
    if (taskState.dueDelta < 0) bits.push('Overdue');
    else if (taskState.dueDelta === 0) bits.push('Due today');
    else if (taskState.dueDelta === 1) bits.push('Due tomorrow');
    else if (taskState.task && taskState.task.dueDate) bits.push(`Due ${parseDate(taskState.task.dueDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`);
    bits.push(formatTimelineDuration(taskState.estimatedMinutes));
    return bits;
}

function getTimelineBlockColors(block) {
    const safeColor = normalizeHexColor(block && block.color ? block.color : '#d8c4a1', '#d8c4a1');
    const lightBackground = !isDarkHexColor(safeColor);
    return {
        background: lightBackground ? hexToRgba(safeColor, 0.24) : hexToRgba(safeColor, 0.9),
        borderColor: lightBackground ? hexToRgba(safeColor, 0.54) : hexToRgba(safeColor, 0.92),
        textColor: lightBackground ? '#102033' : '#ffffff'
    };
}

function buildTimelinePositionStyle(item, laneCount, windowData, minimumHeightPx = 66) {
    const insetPct = 2;
    const usablePct = 96;
    const laneWidthPct = usablePct / Math.max(1, laneCount);
    const leftPct = insetPct + (item.laneIndex * laneWidthPct);
    const widthPct = Math.max(18, laneWidthPct - 1.2);
    const topPct = ((item.startMins - windowData.startMinutes) / windowData.spanMinutes) * 100;
    const heightPct = (item.durationMins / windowData.spanMinutes) * 100;
    return `top:${Math.max(0, topPct)}%;height:max(calc(${Math.max(heightPct, 1)}% - 6px), ${minimumHeightPx}px);left:${leftPct}%;width:${widthPct}%;`;
}

function bindTimelineInteractiveElements(container) {
    if (!container) return;
    container.querySelectorAll('[data-block-id]').forEach(card => {
        if (card.dataset.timelineBound === 'true') return;
        const openBlock = () => {
            const blockId = String(card.getAttribute('data-block-id') || '');
            const block = (Array.isArray(timeBlocks) ? timeBlocks : []).find(item => String(item && item.id || '') === blockId);
            if (block) openBlockModal(block);
        };
        card.dataset.timelineBound = 'true';
        card.addEventListener('click', (event) => {
            if (event.target && event.target.closest('[data-timeline-task-id]')) return;
            openBlock();
        });
        card.addEventListener('keydown', (event) => {
            if (event.key === 'Enter' || event.key === ' ') {
                event.preventDefault();
                openBlock();
            }
        });
    });
    container.querySelectorAll('[data-timeline-task-id]').forEach(button => {
        if (button.dataset.timelineTaskBound === 'true') return;
        button.dataset.timelineTaskBound = 'true';
        button.addEventListener('click', (event) => {
            event.stopPropagation();
            const taskId = String(button.getAttribute('data-timeline-task-id') || '');
            if (taskId) openTaskModal(taskId);
        });
    });
}

function renderTimelinePlannerView(viewDate, sourceMode = timelineSourceMode) {
    const dayModel = buildTimelineDayModel(viewDate, sourceMode);
    const focusState = getTimelineFocusState([viewDate], sourceMode);
    const windowData = getTimelineWindowForDates([viewDate], sourceMode);
    const laneData = buildTimelineLaneAssignments(dayModel.blocks);
    const axisLabels = [];
    const hourLines = [];
    const halfHourLines = [];

    for (let minute = windowData.startMinutes; minute <= windowData.endMinutes; minute += 60) {
        const topPct = ((minute - windowData.startMinutes) / windowData.spanMinutes) * 100;
        axisLabels.push(`<div class="timeline-vertical-axis-label" style="top:${topPct}%;">${formatTimelineAxisLabelForMinutes(minute)}</div>`);
        hourLines.push(`<div class="timeline-vertical-hour-line${minute % (3 * 60) === 0 ? ' major' : ''}" style="top:${topPct}%;"></div>`);
        if (minute < windowData.endMinutes) {
            const halfPct = (((minute + 30) - windowData.startMinutes) / windowData.spanMinutes) * 100;
            halfHourLines.push(`<div class="timeline-vertical-quarter-line" style="top:${halfPct}%;"></div>`);
        }
    }

    const blocksHtml = laneData.items.length
        ? laneData.items.map(item => {
            const blockState = getTimelineBlockState(item.block, viewDate, dayModel.assignments.get(String(item.block.id || '')) || []);
            const colors = getTimelineBlockColors(item.block);
            const visibleTasks = blockState.assignedTasks.slice(0, blockState.taskLimit);
            const extraTaskCount = Math.max(0, blockState.assignedTasks.length - visibleTasks.length);
            const taskRows = blockState.compact || !visibleTasks.length
                ? ''
                : `
                    <div class="timeline-planner-task-list">
                        ${visibleTasks.map(taskState => `
                            <button type="button" class="timeline-planner-task${taskState.completed ? ' is-complete' : ''}" data-timeline-task-id="${escapeHtml(String(taskState.task.id || ''))}">
                                <span class="timeline-task-check" aria-hidden="true"></span>
                                <span class="timeline-task-content">
                                    <span class="timeline-task-title">${escapeHtml(String(taskState.task.title || 'Untitled task'))}</span>
                                    <span class="timeline-task-meta">${getTimelineTaskMetaBits(taskState).map(bit => `<span>${escapeHtml(bit)}</span>`).join('')}</span>
                                </span>
                            </button>
                        `).join('')}
                        ${extraTaskCount > 0 ? `<div class="timeline-task-meta"><span>+${extraTaskCount} more task${extraTaskCount === 1 ? '' : 's'}</span></div>` : ''}
                    </div>
                `;
            return `
                <article
                    class="timeline-planner-block${blockState.isCurrent ? ' current' : ''}${blockState.compact ? ' compact' : ''}"
                    tabindex="0"
                    role="button"
                    data-block-id="${escapeHtml(String(item.block.id || ''))}"
                    style="${buildTimelinePositionStyle(item, laneData.laneCount, windowData, blockState.compact ? 56 : 76)}background:${colors.background};border-color:${colors.borderColor};color:${colors.textColor};"
                >
                    <div class="timeline-planner-block-top">
                        <div>
                            <div class="timeline-planner-block-time">${escapeHtml(`${blockState.startLabel} - ${blockState.endLabel}`)}</div>
                            <h3 class="timeline-planner-block-title">${escapeHtml(String(item.block.name || 'Untitled'))}</h3>
                        </div>
                        <div class="timeline-planner-block-badges">
                            <span class="timeline-block-badge">${escapeHtml(blockState.durationLabel)}</span>
                            <span class="timeline-block-badge ghost">${escapeHtml(getTimelineBlockSourceLabel(item.block))}</span>
                        </div>
                    </div>
                    <div class="timeline-planner-block-meta">
                        <span>${escapeHtml(blockState.statusLabel)}</span>
                        <span>${escapeHtml(String(item.block.category || 'default'))}</span>
                    </div>
                    <div>
                        <div class="timeline-progress-copy"><span>${escapeHtml(blockState.statusLabel)}</span><span>${blockState.progressValue}%</span></div>
                        <div class="timeline-progress-track"><div class="timeline-progress-fill" style="width:${blockState.progressValue}%;"></div></div>
                    </div>
                    ${taskRows}
                </article>
            `;
        }).join('')
        : '<div class="timeline-empty-day" style="position:absolute;inset:0;"><div class="timeline-empty-state"><strong>No blocks on the timeline</strong><span>Add an event or run Shape My Day to turn this date into a structured schedule.</span></div></div>';

    const looseTaskHtml = dayModel.remainingTasks.length
        ? dayModel.remainingTasks.slice(0, 5).map(taskState => `
            <div class="timeline-planner-queue-item">
                <strong>${escapeHtml(String(taskState.task.title || 'Untitled task'))}</strong>
                <span>${escapeHtml(getTimelineTaskMetaBits(taskState).join(' • '))}</span>
            </div>
        `).join('')
        : '<div class="timeline-planner-sidecard-note">Every active task in this planning pool is either complete or assigned to a block.</div>';

    const focusHtml = focusState && focusState.block
        ? `
            <div class="timeline-planner-queue-item">
                <strong>${escapeHtml(String(focusState.block.name || 'Untitled'))}</strong>
                <span>${escapeHtml(String(focusState.block.start || '--:--'))} - ${escapeHtml(String(focusState.block.end || '--:--'))} • ${escapeHtml(getTimelineBlockSourceLabel(focusState.block))}</span>
            </div>
            <div class="timeline-progress-track"><div class="timeline-progress-fill" style="width:${Math.max(0, Math.min(100, Number(focusState.progressValue || 0)))}%;"></div></div>
        `
        : '<div class="timeline-planner-sidecard-note">No live or upcoming block is active on this date yet.</div>';

    const nowLineHtml = dayModel.dateKey === today()
        ? (() => {
            const now = new Date();
            const minutes = (now.getHours() * 60) + now.getMinutes();
            const topPct = ((minutes - windowData.startMinutes) / windowData.spanMinutes) * 100;
            return `<div class="timeline-vertical-now" style="top:${topPct}%;" data-now-label="Now"></div>`;
        })()
        : '';

    return `
        <div class="timeline-planner-shell">
            <section class="timeline-planner-summary">
                <div class="timeline-planner-summary-top">
                    <div class="timeline-planner-date">
                        <div class="timeline-planner-kicker">${dayModel.dateKey === today() ? 'Today at Sutra' : 'Daily control panel'}</div>
                        <h3 class="timeline-planner-title">${escapeHtml(viewDate.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' }))}</h3>
                        <p class="timeline-planner-subtitle">A focused planning surface built from your existing calendar blocks, due work, homework sync, and task commitments.</p>
                    </div>
                    <div class="timeline-planner-chip-row">
                        <span class="timeline-planner-chip"><strong>${dayModel.blocks.length}</strong> blocks</span>
                        <span class="timeline-planner-chip"><strong>${dayModel.summary.linkedTaskCount}</strong> tasks mapped</span>
                        <span class="timeline-planner-chip"><strong>${formatTimelineDuration(dayModel.summary.focusMinutes)}</strong> focus time</span>
                    </div>
                </div>
                <div class="timeline-planner-metrics">
                    <div class="timeline-planner-metric"><span class="timeline-planner-metric-label">Completion</span><span class="timeline-planner-metric-value">${dayModel.summary.completionPercent}%</span><span class="timeline-planner-metric-note">${dayModel.summary.completedTaskCount}/${dayModel.summary.totalTaskCount} tasks done</span></div>
                    <div class="timeline-planner-metric"><span class="timeline-planner-metric-label">Remaining</span><span class="timeline-planner-metric-value">${dayModel.summary.remainingTaskCount}</span><span class="timeline-planner-metric-note">${dayModel.remainingTasks.length} still need a slot</span></div>
                    <div class="timeline-planner-metric"><span class="timeline-planner-metric-label">Focus Window</span><span class="timeline-planner-metric-value">${formatTimelineDuration(dayModel.summary.focusMinutes)}</span><span class="timeline-planner-metric-note">${formatTimelineDuration(dayModel.summary.scheduledMinutes)} scheduled overall</span></div>
                    <div class="timeline-planner-metric"><span class="timeline-planner-metric-label">Priority Pressure</span><span class="timeline-planner-metric-value">${dayModel.summary.highPriorityOpen}</span><span class="timeline-planner-metric-note">high-priority items still open</span></div>
                </div>
            </section>
            <div class="timeline-planner-content">
                <section class="timeline-planner-track-shell">
                    <div class="timeline-planner-track-header">
                        <div class="timeline-planner-track-title"><strong>Daily timeline</strong><span>Time-blocked execution view with nested task context inside each block.</span></div>
                        <span class="timeline-planner-track-chip">${escapeHtml(formatTimelineDuration(dayModel.summary.scheduledMinutes))} scheduled</span>
                    </div>
                    <div class="timeline-vertical-layout">
                        <div class="timeline-vertical-axis" style="--timeline-surface-height:var(--timeline-surface-height-pref,760px);">${axisLabels.join('')}</div>
                        <div class="timeline-vertical-surface" style="--timeline-surface-height:var(--timeline-surface-height-pref,760px);">${hourLines.join('')}${halfHourLines.join('')}${nowLineHtml}<div class="timeline-vertical-lanes">${blocksHtml}</div></div>
                    </div>
                </section>
                <aside class="timeline-planner-sidebar">
                    <section class="timeline-planner-sidecard">
                        <div class="timeline-planner-sidecard-header"><span class="timeline-planner-sidecard-title">${escapeHtml(focusState.heading || 'Current / Next')}</span><span class="neumo-chip">${escapeHtml(String(focusState.countdownText || (focusState.viewingToday ? 'Live now' : 'Scheduled')))}</span></div>
                        ${focusHtml}
                    </section>
                    <section class="timeline-planner-sidecard">
                        <div class="timeline-planner-sidecard-header"><span class="timeline-planner-sidecard-title">Loose tasks</span><span class="neumo-chip">${dayModel.remainingTasks.length}</span></div>
                        <div class="timeline-planner-sidecard-note">These are active items for the day that still sit outside a time block.</div>
                        <div class="timeline-planner-queue">${looseTaskHtml}</div>
                    </section>
                </aside>
            </div>
        </div>
    `;
}

function renderTimelineThreeDayView(viewDate, sourceMode = timelineSourceMode) {
    const visibleDates = [addDays(viewDate, -1), viewDate, addDays(viewDate, 1)];
    const centerKey = dateKey(viewDate);
    const todayKey = today();
    const windowData = getTimelineWindowForDates(visibleDates, sourceMode);
    const cards = visibleDates.map(dateObj => {
        const dayModel = buildTimelineDayModel(dateObj, sourceMode);
        const laneData = buildTimelineLaneAssignments(dayModel.blocks);
        const isToday = dayModel.dateKey === todayKey;
        const kicker = isToday ? 'Today' : dayModel.dateKey === centerKey ? 'Center day' : dayModel.dateKey < centerKey ? 'Lead-in' : 'Look ahead';
        const axisLabels = [];
        const lines = [];
        for (let minute = windowData.startMinutes; minute <= windowData.endMinutes; minute += 60) {
            const topPct = ((minute - windowData.startMinutes) / windowData.spanMinutes) * 100;
            axisLabels.push(`<div class="timeline-vertical-axis-label" style="top:${topPct}%;">${formatTimelineAxisLabelForMinutes(minute)}</div>`);
            lines.push(`<div class="timeline-vertical-hour-line${minute % (3 * 60) === 0 ? ' major' : ''}" style="top:${topPct}%;"></div>`);
            if (minute < windowData.endMinutes) {
                const halfPct = (((minute + 30) - windowData.startMinutes) / windowData.spanMinutes) * 100;
                lines.push(`<div class="timeline-vertical-quarter-line" style="top:${halfPct}%;"></div>`);
            }
        }
        const blockCards = laneData.items.length
            ? laneData.items.map(item => {
                const blockState = getTimelineBlockState(item.block, dateObj, dayModel.assignments.get(String(item.block.id || '')) || []);
                const colors = getTimelineBlockColors(item.block);
                return `
                    <article
                        class="timeline-three-day-block${blockState.isCurrent ? ' current' : ''}${blockState.compact ? ' compact' : ''}"
                        tabindex="0"
                        role="button"
                        data-block-id="${escapeHtml(String(item.block.id || ''))}"
                        style="${buildTimelinePositionStyle(item, laneData.laneCount, windowData, blockState.compact ? 52 : 64)}background:${colors.background};border-color:${colors.borderColor};color:${colors.textColor};"
                    >
                        <div class="timeline-three-day-block-top">
                            <div>
                                <div class="timeline-three-day-block-time">${escapeHtml(`${blockState.startLabel} - ${blockState.endLabel}`)}</div>
                                <h3 class="timeline-three-day-block-title">${escapeHtml(String(item.block.name || 'Untitled'))}</h3>
                            </div>
                            <div class="timeline-three-day-block-badges"><span class="timeline-block-badge">${escapeHtml(blockState.durationLabel)}</span></div>
                        </div>
                        <div class="timeline-three-day-block-meta">
                            <span>${escapeHtml(getTimelineBlockSourceLabel(item.block))}</span>
                            <span>${escapeHtml(blockState.statusLabel)}</span>
                            ${blockState.assignedTasks.length ? `<span>${blockState.assignedTasks.length} task${blockState.assignedTasks.length === 1 ? '' : 's'}</span>` : ''}
                        </div>
                        <div class="timeline-progress-track"><div class="timeline-progress-fill" style="width:${blockState.progressValue}%;"></div></div>
                    </article>
                `;
            }).join('')
            : '<div class="timeline-three-day-empty" style="position:absolute;inset:0;"><div class="timeline-empty-state"><strong>No blocks</strong><span>This day is open for the selected source.</span></div></div>';
        const nowLineHtml = isToday
            ? (() => {
                const now = new Date();
                const minutes = (now.getHours() * 60) + now.getMinutes();
                const topPct = ((minutes - windowData.startMinutes) / windowData.spanMinutes) * 100;
                return `<div class="timeline-vertical-now" style="top:${topPct}%;" data-now-label="Now"></div>`;
            })()
            : '';
        return `
            <section class="timeline-three-day-day${isToday ? ' today' : ''}">
                <div class="timeline-three-day-header">
                    <div class="timeline-three-day-titleblock">
                        <div class="timeline-three-day-kicker">${escapeHtml(kicker)}</div>
                        <div class="timeline-three-day-title">${escapeHtml(dateObj.toLocaleDateString('en-US', { weekday: 'long' }))}</div>
                        <div class="timeline-three-day-subtitle">${escapeHtml(dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }))}</div>
                    </div>
                    <div class="timeline-three-day-chips">
                        <span class="timeline-three-day-chip">${dayModel.blocks.length} blocks</span>
                        <span class="timeline-three-day-chip">${dayModel.summary.completionPercent}% done</span>
                        <span class="timeline-three-day-chip">${formatTimelineDuration(dayModel.summary.focusMinutes)}</span>
                    </div>
                </div>
                <div class="timeline-three-day-track">
                    <div class="timeline-vertical-axis" style="--timeline-surface-height:var(--timeline-surface-height-pref,760px);">${axisLabels.join('')}</div>
                    <div class="timeline-vertical-surface timeline-three-day-surface" style="--timeline-surface-height:var(--timeline-surface-height-pref,760px);">${lines.join('')}${nowLineHtml}<div class="timeline-vertical-lanes">${blockCards}</div></div>
                </div>
            </section>
        `;
    }).join('');

    return `<div class="timeline-three-day-grid">${cards}</div>`;
}

function renderTimelineDayRow(dateObj, sourceMode = timelineSourceMode) {
    const now = new Date();
    const todayKey = dateKey(now);
    const rowKey = dateKey(dateObj);
    const isToday = rowKey === todayKey;
    const blocks = getTimelineBlocksForDate(dateObj, sourceMode);
    const laneData = buildTimelineLaneAssignments(blocks);
    const hourMarkers = Array.from({ length: 9 }, (_, index) => index * 3);
    const hourLabelsHtml = hourMarkers.map(hourValue => `
        <div class="timeline-hour-label" style="left:${(hourValue / 24) * 100}%;">${formatTimelineAxisLabel(hourValue)}</div>
    `).join('');
    const gridLinesHtml = hourMarkers.map(hourValue => `
        <div class="timeline-grid-line ${hourValue % 6 === 0 ? 'major' : ''}" style="left:${(hourValue / 24) * 100}%;"></div>
    `).join('');

    const laneHtml = laneData.laneCount
        ? Array.from({ length: laneData.laneCount }, (_, laneIndex) => {
            const cards = laneData.items
                .filter(item => item.laneIndex === laneIndex)
                .map(item => {
                    const block = item.block;
                    const safeColor = normalizeHexColor(block.color || '#5b7cfa', '#5b7cfa');
                    const lightBackground = !isDarkHexColor(safeColor);
                    const background = lightBackground ? hexToRgba(safeColor, 0.24) : hexToRgba(safeColor, 0.9);
                    const borderColor = hexToRgba(safeColor, lightBackground ? 0.52 : 0.92);
                    const textColor = lightBackground ? '#102033' : '#ffffff';
                    const leftPct = Math.max(0, Math.min(100, (item.startMins / (24 * 60)) * 100));
                    const rawWidthPct = (item.durationMins / (24 * 60)) * 100;
                    const widthPct = Math.min(100 - leftPct, Math.max(rawWidthPct, 3.5));
                    const isCurrent = isToday && now >= buildResolvedTimelineEntries(dateObj, sourceMode).find(entry => entry.block.id === block.id)?.startsAt && now < buildResolvedTimelineEntries(dateObj, sourceMode).find(entry => entry.block.id === block.id)?.endsAt;
                    return `
                        <button
                            type="button"
                            class="timeline-event-card${isCurrent ? ' current' : ''}"
                            data-block-id="${escapeHtml(String(block.id || ''))}"
                            style="left:${leftPct}%;width:calc(${widthPct}% - 6px);background:${background};border-color:${borderColor};color:${textColor};"
                        >
                            <div class="timeline-event-time">${escapeHtml(String(block.start || '--:--'))} - ${escapeHtml(String(block.end || '--:--'))}</div>
                            <div class="timeline-event-title">${escapeHtml(String(block.name || 'Untitled'))}</div>
                            <div class="timeline-event-source">${escapeHtml(getTimelineBlockSourceLabel(block))}</div>
                        </button>
                    `;
                })
                .join('');
            return `<div class="timeline-lane">${cards}</div>`;
        }).join('')
        : '<div class="timeline-empty-day"><div class="timeline-empty-state"><strong>No events</strong><span>This day is clear for the selected source.</span></div></div>';

    const nowLineHtml = isToday
        ? `<div class="timeline-grid-now" style="left:${((now.getHours() * 60 + now.getMinutes()) / (24 * 60)) * 100}%;"></div>`
        : '';

    return `
        <article class="timeline-day-row${isToday ? ' today' : ''}" data-date="${rowKey}">
            <div class="timeline-day-header">
                <div class="timeline-day-header-top">
                    <div class="timeline-day-kicker">${isToday ? 'Today' : rowKey < todayKey ? 'Yesterday' : 'Tomorrow'}</div>
                    <div class="timeline-day-title">${dateObj.toLocaleDateString('en-US', { weekday: 'long' })}</div>
                    <div class="timeline-day-subtitle">${dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}</div>
                </div>
                <div class="timeline-day-count">${blocks.length} event${blocks.length === 1 ? '' : 's'}</div>
            </div>
            <div class="timeline-track-shell">
                <div class="timeline-track">
                    <div class="timeline-hour-labels">${hourLabelsHtml}</div>
                    <div class="timeline-track-grid">${gridLinesHtml}</div>
                    ${nowLineHtml}
                    ${laneHtml}
                </div>
            </div>
        </article>
    `;
}

function getTimelineFocusState(visibleDates, sourceMode = timelineSourceMode) {
    const now = new Date();
    const entries = visibleDates
        .flatMap(dateObj => buildResolvedTimelineEntries(dateObj, sourceMode))
        .sort((a, b) => a.startsAt - b.startsAt);

    const current = entries.find(entry => now >= entry.startsAt && now < entry.endsAt);
    if (current) {
        return {
            block: current.block,
            heading: 'Current Event',
            countdownText: null,
            progressValue: Math.min(100, Math.max(0, ((now - current.startsAt) / Math.max(1, current.endsAt - current.startsAt)) * 100)),
            viewingToday: true
        };
    }

    const upcoming = entries.find(entry => entry.startsAt > now);
    if (upcoming) {
        return {
            block: upcoming.block,
            heading: 'Next Event',
            countdownText: `Starts ${upcoming.startsAt.toLocaleString([], { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' })}`,
            progressValue: 0,
            viewingToday: false
        };
    }

    const last = entries[entries.length - 1] || null;
    if (last) {
        return {
            block: last.block,
            heading: 'Last Event in Range',
            countdownText: `${last.startsAt.toLocaleDateString([], { month: 'short', day: 'numeric' })} ${String(last.block.start || '')}`,
            progressValue: 100,
            viewingToday: false
        };
    }

    return {
        block: null,
        heading: 'Current / Next Event',
        countdownText: '--:--',
        progressValue: 0,
        viewingToday: false
    };
}

function updateTimelineSourceStatus(sourceMode, visibleDates, options = {}) {
    const statusEl = document.getElementById('timelineSourceStatus');
    if (!statusEl) return;
    const viewMode = normalizeTimelineViewMode(options.viewMode || timelineViewMode);

    if (viewMode === 'planner') {
        statusEl.textContent = 'Planner mode turns the selected day into an execution board with time blocks, task context, and completion pressure surfaced together.';
        return;
    }
    statusEl.textContent = `${viewMode.charAt(0).toUpperCase() + viewMode.slice(1)} view is active.`;
}

// Render timeline
function renderTimeline() {
    const plannerRoot = document.getElementById('timelinePlannerView');
    const legacyRoot = document.getElementById('timelineLegacyCalendar');
    const headingEl = document.getElementById('timelineHeading');
    const dateInput = document.getElementById('timelineDateInput');
    const sourceSelect = document.getElementById('timelineSourceSelect');
    const currentCard = document.getElementById('currentBlockCard');
    if (!plannerRoot && !legacyRoot) return;

    purgeExpiredTemporaryPages({ silent: true });
    syncTimelineDateToCurrentDay();
    const viewDate = getTimelineViewDate();
    const viewKey = dateKey(viewDate);
    timelineSourceMode = normalizeTimelineSourceMode(timelineSourceMode || (appSettings && appSettings.timelineSource) || 'atelier');
    timelineViewMode = deriveTimelineViewMode(
        timelineViewMode || (appSettings && appSettings.timelineViewMode),
        timelineLayoutMode || (appSettings && appSettings.timelineLayoutMode),
        timelineLegacyMode || (appSettings && appSettings.timelineLegacyMode)
    );
    syncTimelineLegacySettingsFromViewMode(timelineViewMode);

    if (dateInput) dateInput.value = viewKey;
    if (sourceSelect) sourceSelect.value = timelineSourceMode;
    document.querySelectorAll('[data-timeline-view-mode]').forEach(button => {
        const isActive = String(button.getAttribute('data-timeline-view-mode') || '') === timelineViewMode;
        button.classList.toggle('active', isActive);
        button.setAttribute('aria-selected', isActive ? 'true' : 'false');
    });

    if (timelineViewMode === 'planner') {
        if (headingEl) headingEl.textContent = getTimelineHeading('planner', viewDate);
        if (plannerRoot) {
            plannerRoot.hidden = false;
            plannerRoot.style.display = 'grid';
            plannerRoot.innerHTML = renderTimelinePlannerView(viewDate, timelineSourceMode);
            bindTimelineInteractiveElements(plannerRoot);
        }
        if (legacyRoot) {
            legacyRoot.hidden = true;
            legacyRoot.style.display = 'none';
            legacyRoot.innerHTML = '';
        }
        if (currentCard) currentCard.style.display = 'none';
        updateTimelineSourceStatus(timelineSourceMode, [viewDate], { viewMode: 'planner' });
        return;
    }

    if (plannerRoot) {
        plannerRoot.hidden = true;
        plannerRoot.style.display = 'none';
        plannerRoot.innerHTML = '';
    }

    if (timelineLayoutMode === 'legacy') {
        if (legacyRoot) {
            legacyRoot.hidden = false;
            legacyRoot.style.display = 'grid';
        }

        const mode = normalizeTimelineLegacyMode(timelineViewMode);
        if (headingEl) headingEl.textContent = getLegacyTimelineHeading(mode, viewDate);

        if (mode === 'day') {
            renderLegacyTimelineDay(legacyRoot, viewDate, timelineSourceMode);
            if (currentCard) currentCard.style.display = 'block';
            updateCurrentBlockCard({
                ...getTimelineFocusState([viewDate], timelineSourceMode),
                emptyText: 'No events are scheduled for this day.'
            });
        } else {
            renderLegacyTimelineOverview(mode, viewDate, legacyRoot, timelineSourceMode);
            if (currentCard) currentCard.style.display = 'none';
        }

        updateTimelineSourceStatus(
            timelineSourceMode,
            getLegacyTimelineVisibleDates(mode, viewDate),
            { viewMode: mode }
        );
        return;
    }
}

function updateCurrentBlockCard(blockOrState, maybeOptions = {}) {
    const infoEl = document.getElementById('currentBlockInfo');
    const progressEl = document.getElementById('blockProgressFill');
    const countdownEl = document.getElementById('blockCountdown');
    const headingEl = document.getElementById('currentBlockCardHeading');

    const state = blockOrState && typeof blockOrState === 'object' && Object.prototype.hasOwnProperty.call(blockOrState, 'block')
        ? blockOrState
        : { block: blockOrState, ...(typeof maybeOptions === 'boolean' ? { viewingToday: maybeOptions } : maybeOptions) };
    const block = state.block || null;

    if (headingEl) headingEl.textContent = state.heading || 'Current / Next Event';

    if (!block) {
        if (infoEl) infoEl.textContent = state.emptyText || 'No events are scheduled in the visible three-day range.';
        if (progressEl) progressEl.style.width = '0%';
        if (countdownEl) countdownEl.textContent = state.countdownText || '--:--';
        return;
    }

    const safeName = escapeHtml(String(block.name || 'Untitled'));
    const safeTime = `${block.start} -> ${block.end}`;
    const refUrl = normalizeExternalUrl(block.referenceUrl);
    const sourceLabel = getTimelineBlockSourceLabel(block);
    const docsLinkHtml = refUrl
        ? `<br><a href="${escapeHtml(refUrl)}" target="_blank" rel="noopener noreferrer">Open reference</a>`
        : '';
    if (infoEl) {
        infoEl.innerHTML = `<strong style="font-size:18px;">${safeName}</strong><br><span style="color:var(--text-secondary)">${escapeHtml(safeTime)} | ${escapeHtml(sourceLabel)}</span>${docsLinkHtml}`;
    }
    if (progressEl) {
        const progressValue = Number.isFinite(Number(state.progressValue)) ? Number(state.progressValue) : 0;
        progressEl.style.width = `${Math.max(0, Math.min(100, progressValue))}%`;
    }
    if (countdownEl) {
        countdownEl.textContent = state.countdownText || (state.viewingToday ? 'Live now' : 'Scheduled');
    }
}

// Block modal
function openBlockModal(block) {
    if (block && typeof window !== 'undefined' && typeof window.handleApStudyBlockOpen === 'function') {
        const handled = window.handleApStudyBlockOpen(block);
        if (handled) return;
    }
    editingBlockId = block ? block.id : null;
    const modal = document.getElementById('blockModal');
    const titleEl = document.getElementById('blockModalTitle');
    const deleteBtn = document.getElementById('deleteBlockBtn');
    const nameInput = document.getElementById('blockNameInput');
    const startInput = document.getElementById('blockStartInput');
    const endInput = document.getElementById('blockEndInput');
    const categoryInput = document.getElementById('blockCategoryInput');
    const colorInput = document.getElementById('blockColorInput');

    if (nameInput) nameInput.value = block ? block.name : '';
    if (startInput) {
        startInput.value = block ? block.start : '09:00';
        clearInlineFieldError(startInput);
    }
    if (endInput) {
        endInput.value = block ? block.end : '10:00';
        clearInlineFieldError(endInput);
    }
    if (categoryInput) categoryInput.value = block ? (block.category || 'default') : 'default';
    if (colorInput) colorInput.value = block ? (block.color || '#d8c4a1') : '#d8c4a1';
    const recurrenceValue = block
        ? ((block.source === 'calendar_ics' && block.preserveRecurrence !== true) ? 'none' : (block.recurrence || 'none'))
        : 'none';
    const recurrenceInput = document.getElementById('blockRecurrenceInput');
    if (recurrenceInput) recurrenceInput.value = recurrenceValue;
    const dateInput = document.getElementById('blockDateInput');
    if (dateInput) dateInput.value = block ? (normalizeBlockDate(block.date) || '') : dateKey(getTimelineViewDate());
    const refInput = document.getElementById('blockReferenceInput');
    if (refInput) {
        refInput.value = block ? (block.referenceUrl || '') : '';
        clearInlineFieldError(refInput);
    }

    titleEl.textContent = block ? 'Edit Time Block' : 'Add Time Block';
    deleteBtn.style.display = block ? 'inline-block' : 'none';

    modal.classList.add('active');
    modal.style.display = 'flex';
}

function closeBlockModal() {
    const modal = document.getElementById('blockModal');
    modal.classList.remove('active');
    modal.style.display = 'none';
    editingBlockId = null;
    clearInlineFieldError(document.getElementById('blockStartInput'));
    clearInlineFieldError(document.getElementById('blockEndInput'));
    clearInlineFieldError(document.getElementById('blockReferenceInput'));
}

function saveBlockFromModal() {
    const name = document.getElementById('blockNameInput').value.trim() || 'Untitled Block';
    const startInput = document.getElementById('blockStartInput');
    const endInput = document.getElementById('blockEndInput');
    let start = startInput ? startInput.value : '';
    let end = endInput ? endInput.value : '';
    const category = document.getElementById('blockCategoryInput').value;
    const color = document.getElementById('blockColorInput').value;
    const recurrence = document.getElementById('blockRecurrenceInput').value;
    const dateInput = document.getElementById('blockDateInput');
    const explicitDate = dateInput ? normalizeBlockDate(dateInput.value) : null;
    const referenceUrlInput = document.getElementById('blockReferenceInput');
    const rawReferenceUrl = referenceUrlInput ? String(referenceUrlInput.value || '').trim() : '';
    const referenceUrl = normalizeExternalUrl(rawReferenceUrl);
    clearInlineFieldError(startInput);
    clearInlineFieldError(endInput);
    clearInlineFieldError(referenceUrlInput);
    const startMins = parseTimeToMinutes(start);
    let endMins = parseTimeToMinutes(end);
    const missingStartTime = !Number.isFinite(startMins);
    const missingEndTime = !Number.isFinite(endMins);
    if (missingStartTime || missingEndTime) {
        if (missingStartTime) setInlineFieldError(startInput, 'Enter a valid start time.');
        if (missingEndTime) setInlineFieldError(endInput, 'Enter a valid end time.');
        showToast('Valid start/end times are required');
        if (missingStartTime && startInput) {
            startInput.focus();
        } else if (missingEndTime && endInput) {
            endInput.focus();
        }
        return;
    }
    if (rawReferenceUrl && !referenceUrl) {
        setInlineFieldError(referenceUrlInput, 'Enter a valid http(s) URL or leave this field empty.');
        showToast('Reference URL is invalid');
        if (referenceUrlInput) referenceUrlInput.focus();
        return;
    }
    if (endMins <= startMins) {
        endMins = Math.min(startMins + 30, 23 * 60 + 59);
        end = minutesToTimeString(endMins);
    }

    if (editingBlockId) {
        // Update existing
        const idx = timeBlocks.findIndex(b => b.id === editingBlockId);
        if (idx !== -1) {
            const existing = timeBlocks[idx] || {};
            const isCalendarImport = existing.source === 'calendar_ics';
            const preserveRecurrence = isCalendarImport ? recurrence !== 'none' : !!existing.preserveRecurrence;
            const nextRecurrence = (isCalendarImport && !preserveRecurrence) ? 'none' : recurrence;
            const baseDate = explicitDate || normalizeBlockDate(timeBlocks[idx].date) || dateKey(getTimelineViewDate());
            timeBlocks[idx] = {
                ...timeBlocks[idx],
                name,
                start,
                end,
                category,
                color,
                recurrence: nextRecurrence,
                preserveRecurrence,
                date: baseDate,
                referenceUrl,
                updatedAt: Date.now()
            };
        }
    } else {
        // Create new
        const baseDate = explicitDate || dateKey(getTimelineViewDate());
        timeBlocks.push({
            id: generateBlockId(),
            name,
            start,
            end,
            category,
            color,
            recurrence,
            date: baseDate,
            referenceUrl,
            createdAt: Date.now(),
            updatedAt: Date.now()
        });
    }

    // Sort by start time
    timeBlocks.sort((a, b) => {
        const [ah, am] = a.start.split(':').map(Number);
        const [bh, bm] = b.start.split(':').map(Number);
        return (ah * 60 + am) - (bh * 60 + bm);
    });

    saveTimeBlocks();
    closeBlockModal();
    renderTimeline();
    showToast(editingBlockId ? 'Block updated!' : 'Block created!');
}

function deleteBlock() {
    if (!editingBlockId) return;
    timeBlocks = timeBlocks.filter(b => b.id !== editingBlockId);
    saveTimeBlocks();
    closeBlockModal();
    renderTimeline();
    showToast('Block deleted');
}

// Initialize timeline
function initTimeline() {
    loadTimeBlocks();
    timelineViewDateKey = normalizeBlockDate(appSettings && appSettings.timelineViewDate) || dateKey(new Date());
    timelineSourceMode = normalizeTimelineSourceMode(
        getWorkspacePreference('calendar.defaultSource', (appSettings && appSettings.timelineSource) || 'atelier')
    );
    timelineViewMode = deriveTimelineViewMode(
        getWorkspacePreference('calendar.defaultView', (appSettings && appSettings.timelineViewMode) || 'three-day'),
        appSettings && appSettings.timelineLayoutMode,
        appSettings && appSettings.timelineLegacyMode
    );
    timelineLayoutMode = normalizeTimelineLayoutMode(appSettings && appSettings.timelineLayoutMode);
    timelineLegacyMode = normalizeTimelineLegacyMode(appSettings && appSettings.timelineLegacyMode);
    syncTimelineLegacySettingsFromViewMode(timelineViewMode);
    timelineLastKnownTodayKey = timelineViewDateKey;
    syncTimelineDateToCurrentDay(true);
    applyTimeMode();
    initTimeModeSelector();

    const dateInput = document.getElementById('timelineDateInput');
    if (dateInput) {
        dateInput.value = timelineViewDateKey;
        dateInput.addEventListener('change', (event) => {
            const nextKey = normalizeBlockDate(event.target && event.target.value);
            timelineViewDateKey = nextKey || dateKey(new Date());
            persistTimelineViewPreferences();
            renderTimeline();
        });
    }

    const sourceSelect = document.getElementById('timelineSourceSelect');
    if (sourceSelect) {
        sourceSelect.value = timelineSourceMode;
        sourceSelect.addEventListener('change', (event) => {
            timelineSourceMode = normalizeTimelineSourceMode(event.target && event.target.value);
            persistTimelineViewPreferences();
            renderTimeline();
        });
    }

    document.querySelectorAll('[data-timeline-view-mode]').forEach(button => {
        button.addEventListener('click', () => {
            const nextMode = normalizeTimelineViewMode(button.getAttribute('data-timeline-view-mode'));
            syncTimelineLegacySettingsFromViewMode(nextMode);
            persistTimelineViewPreferences();
            renderTimeline();
        });
    });

    renderTimeline();

    // Add block button
    const addBtn = document.getElementById('addBlockBtn');
    if (addBtn) {
        addBtn.addEventListener('click', () => openBlockModal(null));
    }

    // Delete button in modal
    const deleteBtn = document.getElementById('deleteBlockBtn');
    if (deleteBtn) {
        deleteBtn.addEventListener('click', deleteBlock);
    }

    ['blockStartInput', 'blockEndInput', 'blockReferenceInput'].forEach((fieldId) => {
        const field = document.getElementById(fieldId);
        if (!field || field.dataset.validationBound === 'true') return;
        field.dataset.validationBound = 'true';
        field.addEventListener('input', () => clearInlineFieldError(field));
        field.addEventListener('change', () => clearInlineFieldError(field));
    });

    // Update timeline every minute
    setInterval(() => {
        syncTimelineDateToCurrentDay();
        if (activeView === 'timeline') {
            renderTimeline();
            applyTimeMode();
        }
    }, 60000);
}

// ============================================================================
// Command Palette, Quick Capture, Global Search, Weekly Review, AP Battle Plan,
// Class Dashboard. Kept at the end of app.js so they don't disturb existing
// indentation. All functions become window globals (regular script scope).
// ============================================================================

function escapeCommandHtml(value) {
    const div = document.createElement('div');
    div.textContent = String(value == null ? '' : value);
    return div.innerHTML;
}

// ---------- Quick Capture ----------
function parseQuickCaptureText(text) {
    const raw = String(text || '').trim();
    if (!raw) return null;
    const out = { title: raw, type: 'task', dueDate: '', dueTime: '', priority: 'medium', classHint: '' };
    let working = raw;

    // Very light natural-date parse.
    const now = new Date();
    const iso = (d) => {
        const y = d.getFullYear();
        const m = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        return `${y}-${m}-${day}`;
    };
    const weekdays = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
    const weekdayRe = new RegExp(`\\b(?:on )?(${weekdays.join('|')})\\b`, 'i');
    const lower = working.toLowerCase();
    if (/\btoday\b/.test(lower)) {
        out.dueDate = iso(now);
        working = working.replace(/\btoday\b/i, '').trim();
    } else if (/\btomorrow\b/.test(lower)) {
        const t = new Date(now); t.setDate(t.getDate() + 1);
        out.dueDate = iso(t);
        working = working.replace(/\btomorrow\b/i, '').trim();
    } else {
        const wdMatch = lower.match(weekdayRe);
        if (wdMatch) {
            const target = weekdays.indexOf(wdMatch[1].toLowerCase());
            const delta = ((target - now.getDay() + 7) % 7) || 7;
            const t = new Date(now); t.setDate(t.getDate() + delta);
            out.dueDate = iso(t);
            working = working.replace(weekdayRe, '').trim();
        }
    }

    // Time parse e.g. "6pm", "18:00", "3:30pm".
    const timeMatch = working.match(/\b(\d{1,2})(?::(\d{2}))?\s*(am|pm)?\b/i);
    if (timeMatch) {
        let h = parseInt(timeMatch[1], 10);
        const min = timeMatch[2] ? parseInt(timeMatch[2], 10) : 0;
        const suffix = (timeMatch[3] || '').toLowerCase();
        if (suffix === 'pm' && h < 12) h += 12;
        if (suffix === 'am' && h === 12) h = 0;
        if (h >= 0 && h <= 23 && min >= 0 && min <= 59 && (suffix || timeMatch[0].includes(':'))) {
            out.dueTime = `${String(h).padStart(2, '0')}:${String(min).padStart(2, '0')}`;
            working = working.replace(timeMatch[0], '').trim();
        }
    }

    // Priority hints.
    if (/\bhigh\b|!!/.test(lower)) { out.priority = 'high'; working = working.replace(/\bhigh\b|!!/ig, '').trim(); }
    else if (/\blow\b/.test(lower)) { out.priority = 'low'; working = working.replace(/\blow\b/ig, '').trim(); }
    if (/\bhard\b/.test(lower)) working = working.replace(/\bhard\b/i, '').trim();

    // Type hints.
    if (/\bap\s+\w+|\bfrq\b|\bmcq\b|\bpractice test\b/i.test(working)) {
        out.type = 'apsession';
    } else if (/\bhomework\b|\bhw\b|\bassignment\b/i.test(working)) {
        out.type = 'homework';
        working = working.replace(/\bhomework\b|\bhw\b|\bassignment\b/ig, '').trim();
    } else if (/\bcollege\b|\bessay\b|\bscholarship\b/i.test(working)) {
        out.type = 'college';
    } else if (/\bnote\b|^note:/i.test(working)) {
        out.type = 'note';
        working = working.replace(/\bnote\b|^note:/ig, '').trim();
    } else if (/\bblock\b|\bcalendar\b|\bschedule\b/i.test(working)) {
        out.type = 'block';
    }

    // Class hint: "chem homework", "ap physics frq" -> first words.
    const classMatch = working.match(/^([A-Za-z][A-Za-z0-9 &.]{0,30})/);
    if (classMatch) out.classHint = classMatch[1].trim();

    out.title = working.replace(/\s+/g, ' ').trim() || raw;
    if (/\bdue\b/i.test(out.title)) out.title = out.title.replace(/\bdue\b/ig, '').replace(/\s+/g, ' ').trim();
    return out;
}

function getQuickCaptureApSubjects() {
    if (typeof apStudyWorkspace === 'undefined' || !apStudyWorkspace || !Array.isArray(apStudyWorkspace.subjects)) {
        return [];
    }
    return apStudyWorkspace.subjects.filter(subject => subject && String(subject.id || '').trim());
}

function syncQuickCaptureApSubjectField(parsed, modal) {
    const field = modal && modal.querySelector ? modal.querySelector('#quickCaptureApSubjectField') : null;
    const select = modal && modal.querySelector ? modal.querySelector('#quickCaptureApSubject') : null;
    const help = modal && modal.querySelector ? modal.querySelector('#quickCaptureApSubjectHelp') : null;
    if (!field || !select || !help) return { subjects: [], selectedSubject: null };

    const isApCapture = parsed && parsed.type === 'apsession';
    const subjects = getQuickCaptureApSubjects();
    const previousValue = String(select.value || '');
    field.hidden = !isApCapture;

    if (!isApCapture) {
        select.innerHTML = '<option value="">Choose AP subject…</option>';
        select.value = '';
        select.disabled = false;
        help.textContent = 'Choose the AP subject before saving.';
        return { subjects, selectedSubject: null };
    }

    if (subjects.length === 0) {
        select.innerHTML = '<option value="">No AP subjects yet</option>';
        select.value = '';
        select.disabled = true;
        help.textContent = 'No AP subjects found. This will fall back to a task until you add one.';
        return { subjects, selectedSubject: null };
    }

    if (subjects.length === 1) {
        const only = subjects[0];
        select.innerHTML = `<option value="${escapeHtml(String(only.id))}">${escapeHtml(String(only.name || 'AP subject'))}</option>`;
        select.value = String(only.id);
        select.disabled = true;
        help.textContent = `Only one AP subject exists, so this will save to ${only.name || 'that subject'}.`;
        return { subjects, selectedSubject: only };
    }

    select.innerHTML = [
        '<option value="">Choose AP subject…</option>',
        ...subjects.map(subject => `<option value="${escapeHtml(String(subject.id))}">${escapeHtml(String(subject.name || 'AP subject'))}</option>`)
    ].join('');
    select.disabled = false;
    select.value = subjects.some(subject => String(subject.id) === previousValue) ? previousValue : '';
    help.textContent = 'Multiple AP subjects found. Pick the correct one before saving.';
    return {
        subjects,
        selectedSubject: subjects.find(subject => String(subject.id) === String(select.value || '')) || null
    };
}

function openQuickCaptureModal(prefillText) {
    const modal = document.getElementById('quickCaptureModal');
    if (!modal) return;
    const input = modal.querySelector('#quickCaptureInput');
    const previewEl = modal.querySelector('#quickCapturePreview');
    const typeSelect = modal.querySelector('#quickCaptureType');
    const dateInput = modal.querySelector('#quickCaptureDate');
    const timeInput = modal.querySelector('#quickCaptureTime');
    const apSubjectSelect = modal.querySelector('#quickCaptureApSubject');
    if (!input || !previewEl || !typeSelect || !dateInput || !timeInput || !apSubjectSelect) return;

    input.value = String(prefillText || '');
    const updatePreview = () => {
        const parsed = parseQuickCaptureText(input.value);
        if (!parsed) {
            previewEl.textContent = 'Start typing to capture…';
            return;
        }
        typeSelect.value = parsed.type;
        dateInput.value = parsed.dueDate || '';
        timeInput.value = parsed.dueTime || '';
        const apMeta = syncQuickCaptureApSubjectField(parsed, modal);
        const bits = [];
        let destination = '';
        switch (parsed.type) {
            case 'apsession': {
                if (apMeta.subjects.length === 0) {
                    destination = 'Task (AP Study label — no subject yet)';
                } else if (apMeta.selectedSubject) {
                    destination = `AP Study session · ${apMeta.selectedSubject.name || 'Subject'}`;
                } else {
                    destination = 'AP Study session · choose subject';
                }
                break;
            }
            case 'college': {
                const isEssay = /\bessay\b|\bpersonal statement\b|\bcommon\s*app\b/i.test(parsed.title);
                destination = isEssay ? 'College essay plan' : 'Task (College label)';
                break;
            }
            case 'homework': destination = 'Homework assignment'; break;
            case 'note': destination = 'Note'; break;
            case 'block': destination = 'Timeline block'; break;
            default: destination = 'Task';
        }
        bits.push(`→ ${destination}`);
        if (parsed.dueDate) bits.push(`date: ${parsed.dueDate}`);
        if (parsed.dueTime) bits.push(`time: ${parsed.dueTime}`);
        if (parsed.priority && parsed.priority !== 'medium') bits.push(`priority: ${parsed.priority}`);
        if (parsed.classHint) bits.push(`class hint: ${parsed.classHint}`);
        previewEl.textContent = `“${parsed.title}” · ${bits.join(' · ')}`;
    };
    input.oninput = updatePreview;
    typeSelect.onchange = () => {
        syncQuickCaptureApSubjectField({ type: String(typeSelect.value || 'task') }, modal);
    };
    apSubjectSelect.onchange = updatePreview;
    updatePreview();

    modal.classList.add('active');
    modal.setAttribute('aria-hidden', 'false');
    setTimeout(() => input.focus(), 50);
}

function closeQuickCaptureModal() {
    const modal = document.getElementById('quickCaptureModal');
    if (!modal) return;
    modal.classList.remove('active');
    modal.setAttribute('aria-hidden', 'true');
}

function submitQuickCapture() {
    const modal = document.getElementById('quickCaptureModal');
    if (!modal) return;
    const input = modal.querySelector('#quickCaptureInput');
    const typeSelect = modal.querySelector('#quickCaptureType');
    const dateInput = modal.querySelector('#quickCaptureDate');
    const timeInput = modal.querySelector('#quickCaptureTime');
    const apSubjectSelect = modal.querySelector('#quickCaptureApSubject');
    if (!input || !typeSelect) return;
    const title = String(input.value || '').trim();
    if (!title) {
        if (typeof showToast === 'function') showToast('Type something to capture.');
        return;
    }
    const type = String(typeSelect.value || 'task');
    const dueDate = String((dateInput && dateInput.value) || '');
    const dueTime = String((timeInput && timeInput.value) || '');

    try {
        switch (type) {
            case 'homework': {
                if (typeof localStorage === 'undefined') break;
                const hwTasksRaw = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]');
                const uid = `${Date.now().toString(36)}${Math.random().toString(36).slice(2, 7)}`;
                hwTasksRaw.push({
                    id: uid,
                    courseId: '',
                    title,
                    text: title,
                    done: false,
                    dueDate,
                    dueTime,
                    due: dueDate,
                    priority: 'medium',
                    difficulty: 'medium',
                    notes: '',
                    createdAt: new Date().toISOString(),
                    updatedAt: new Date().toISOString()
                });
                localStorage.setItem('hwTasks:v2', JSON.stringify(hwTasksRaw));
                try { window.dispatchEvent(new CustomEvent('homework:updated')); } catch (err) {}
                if (typeof showToast === 'function') showToast('Homework captured.');
                break;
            }
            case 'note': {
                if (typeof pages !== 'undefined') {
                    const now = new Date().toISOString();
                    pages.push({
                        id: (typeof generateId === 'function' ? generateId() : `p${Date.now()}`),
                        title: title.slice(0, 120),
                        content: '',
                        blocks: [],
                        icon: (typeof PAGE_ICONS !== 'undefined' ? PAGE_ICONS.DOC : '📄'),
                        collapsed: false,
                        createdAt: now,
                        updatedAt: now,
                        theme: (typeof globalTheme !== 'undefined' ? globalTheme : 'default')
                    });
                    try { savePagesToLocal && savePagesToLocal(); } catch (err) {}
                    try { renderPagesList && renderPagesList(); } catch (err) {}
                    if (typeof showToast === 'function') showToast('Note captured.');
                }
                break;
            }
            case 'block': {
                if (typeof timeBlocks !== 'undefined' && Array.isArray(timeBlocks)) {
                    timeBlocks.push({
                        id: (typeof generateId === 'function' ? generateId() : `b${Date.now()}`),
                        date: dueDate || (new Date()).toISOString().slice(0, 10),
                        start: dueTime || '09:00',
                        end: dueTime ? (function(t){ const [h,m] = t.split(':').map(Number); const nh = (h+1)%24; return `${String(nh).padStart(2,'0')}:${String(m).padStart(2,'0')}`; })(dueTime) : '10:00',
                        name: title,
                        category: 'general'
                    });
                    try { saveTimeBlocks && saveTimeBlocks(); } catch (err) {}
                    try { if (activeView === 'timeline' && typeof renderTimeline === 'function') renderTimeline(); } catch (err) {}
                    if (typeof showToast === 'function') showToast('Block scheduled.');
                }
                break;
            }
            case 'apsession': {
                let routed = false;
                try {
                    const subjects = getQuickCaptureApSubjects();
                    if (subjects.length > 0) {
                        const nowIso = new Date().toISOString();
                        const sessionId = `apsession_${Date.now().toString(36)}_${Math.random().toString(36).slice(2,6)}`;
                        let subject = null;
                        if (subjects.length === 1) {
                            subject = subjects[0];
                        } else {
                            const selectedId = String((apSubjectSelect && apSubjectSelect.value) || '').trim();
                            subject = subjects.find(item => String(item.id) === selectedId) || null;
                            if (!subject) {
                                if (typeof showToast === 'function') showToast('Choose an AP subject before saving.');
                                return;
                            }
                        }
                        if (!Array.isArray(apStudyWorkspace.sessions)) apStudyWorkspace.sessions = [];
                        apStudyWorkspace.sessions.push({
                            id: sessionId,
                            subjectId: subject.id,
                            unitId: null,
                            topicId: null,
                            title: title.slice(0, 160),
                            date: dueDate || nowIso.slice(0, 10),
                            time: dueTime || '18:00',
                            durationMinutes: 60,
                            priority: 'medium',
                            status: 'scheduled',
                            sessionType: /\bfrq\b/i.test(title) ? 'frq' : (/\bmcq\b|\bpractice test\b/i.test(title) ? 'practice' : 'review'),
                            noteId: null,
                            notes: 'Captured via Quick Capture.',
                            completedAt: null,
                            updatedAt: nowIso,
                            createdAt: nowIso
                        });
                        if (typeof window.syncApStudySessionsIntoTaskStore === 'function') {
                            try { window.syncApStudySessionsIntoTaskStore({ persist: true }); } catch (err) {}
                        } else if (typeof persistAppData === 'function') {
                            try { persistAppData(); } catch (err) {}
                        }
                        if (typeof window.renderApStudyWorkspace === 'function') {
                            try { window.renderApStudyWorkspace(); } catch (err) {}
                        }
                        routed = true;
                        if (typeof showToast === 'function') showToast(`AP Study session created for ${subject.name || 'subject'}.`);
                    }
                } catch (err) { console.warn(err); }
                if (!routed && typeof tasks !== 'undefined' && Array.isArray(tasks)) {
                    tasks.push({
                        id: (typeof generateId === 'function' ? generateId() : `t${Date.now()}`),
                        title,
                        notes: '',
                        completed: false,
                        priority: 'medium',
                        difficulty: 'medium',
                        dueDate,
                        dueTime,
                        category: 'AP Study',
                        createdAt: new Date().toISOString()
                    });
                    try { persistAppData && persistAppData(); } catch (err) {}
                    try { renderTaskViews && renderTaskViews(); } catch (err) {}
                    if (typeof showToast === 'function') showToast('Add an AP subject to enable native AP sessions. Captured as task.');
                }
                break;
            }
            case 'college': {
                let routed = false;
                try {
                    if (/\bessay\b|\bpersonal statement\b|\bcommon\s*app\b/i.test(title) && typeof collegeTracker !== 'undefined' && collegeTracker) {
                        if (!Array.isArray(collegeTracker.essays)) collegeTracker.essays = [];
                        const id = (typeof generateId === 'function' ? generateId() : `e${Date.now()}`);
                        collegeTracker.essays.push({
                            id,
                            essay: title.slice(0, 160),
                            firstDraftBy: dueDate || '',
                            firstDraftDone: false,
                            reviewBy: '',
                            reviewSubmitted: false,
                            revisionBy: '',
                            revisionSubmitted: false,
                            finalBy: dueDate || '',
                            finalDraft: false,
                            wordLimit: '',
                            notes: 'Captured via Quick Capture.'
                        });
                        try { persistAppData && persistAppData(); } catch (err) {}
                        try { if (typeof renderCollegeApp === 'function') renderCollegeApp(); } catch (err) {}
                        routed = true;
                        if (typeof showToast === 'function') showToast('Essay added to College Plan.');
                    }
                } catch (err) { console.warn(err); }
                if (!routed && typeof tasks !== 'undefined' && Array.isArray(tasks)) {
                    tasks.push({
                        id: (typeof generateId === 'function' ? generateId() : `t${Date.now()}`),
                        title,
                        notes: '',
                        completed: false,
                        priority: 'medium',
                        difficulty: 'medium',
                        dueDate,
                        dueTime,
                        category: 'College',
                        createdAt: new Date().toISOString()
                    });
                    try { persistAppData && persistAppData(); } catch (err) {}
                    try { renderTaskViews && renderTaskViews(); } catch (err) {}
                    if (typeof showToast === 'function') showToast('College task captured. (Tip: include “essay” to route into College essays.)');
                }
                break;
            }
            case 'task':
            default: {
                if (typeof tasks !== 'undefined' && Array.isArray(tasks)) {
                    tasks.push({
                        id: (typeof generateId === 'function' ? generateId() : `t${Date.now()}`),
                        title,
                        notes: '',
                        completed: false,
                        priority: 'medium',
                        difficulty: 'medium',
                        dueDate,
                        dueTime,
                        category: 'General',
                        createdAt: new Date().toISOString()
                    });
                    try { persistAppData && persistAppData(); } catch (err) {}
                    try { renderTaskViews && renderTaskViews(); } catch (err) {}
                    if (typeof showToast === 'function') showToast('Task captured.');
                }
                break;
            }
        }
    } catch (err) {
        console.warn('Quick Capture failed', err);
        if (typeof showToast === 'function') showToast('Quick Capture failed.');
    }

    try { renderTodayDailyBrief && renderTodayDailyBrief(); } catch (err) {}
    closeQuickCaptureModal();
}

// ---------- Global Search ----------
function globalSearchAll(query) {
    const q = String(query || '').trim().toLowerCase();
    if (!q) return { notes: [], tasks: [], homework: [], apstudy: [], college: [], timeline: [], review: [], trackers: [] };
    const results = { notes: [], tasks: [], homework: [], apstudy: [], college: [], timeline: [], review: [], trackers: [] };
    const MAX = 10;

    // Notes. Locked pages (not unlocked in session) only match on title — no content snippets.
    try {
        const stripHtml = (html) => String(html || '').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ');
        const _unlocked = typeof unlockedPageIds !== 'undefined' ? unlockedPageIds : new Set();
        (Array.isArray(pages) ? pages : []).forEach(page => {
            if (results.notes.length >= MAX) return;
            const pageIsLocked = page.isLocked && page.lockHash && !_unlocked.has(page.id);
            const title = String(page.title || '').toLowerCase();
            const body = pageIsLocked ? '' : stripHtml(page.content).toLowerCase();
            if (title.includes(q) || body.includes(q)) {
                results.notes.push({
                    id: page.id,
                    title: page.title || 'Untitled',
                    context: pageIsLocked ? 'Locked page' : body.slice(0, 80),
                    action: () => { try { setActiveView('notes'); if (typeof loadPage === 'function') loadPage(page.id); } catch (err) {} }
                });
            }
        });
    } catch (err) {}

    // Tasks.
    try {
        (Array.isArray(tasks) ? tasks : []).forEach(task => {
            if (results.tasks.length >= MAX) return;
            const title = String(task.title || '').toLowerCase();
            if (title.includes(q)) {
                results.tasks.push({
                    id: task.id,
                    title: task.title || 'Untitled task',
                    context: task.dueDate || '',
                    action: () => { setActiveView('today'); }
                });
            }
        });
    } catch (err) {}

    // Homework.
    try {
        if (typeof localStorage !== 'undefined') {
            const hw = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]');
            const courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]');
            const cmap = new Map((Array.isArray(courses) ? courses : []).map(c => [String(c.id), c.name || 'Class']));
            (Array.isArray(hw) ? hw : []).forEach(h => {
                if (results.homework.length >= MAX) return;
                const title = String(h.title || h.text || '').toLowerCase();
                if (title.includes(q)) {
                    results.homework.push({
                        id: h.id,
                        title: h.title || h.text || 'Homework',
                        context: [cmap.get(String(h.courseId || '')) || '', h.dueDate || ''].filter(Boolean).join(' · '),
                        action: () => { setActiveView('homework'); }
                    });
                }
            });
        }
    } catch (err) {}

    // AP Study.
    try {
        const aps = (typeof apStudyWorkspace !== 'undefined' ? apStudyWorkspace : null) || {};
        (Array.isArray(aps.subjects) ? aps.subjects : []).forEach(s => {
            if (results.apstudy.length >= MAX) return;
            const name = String(s.name || '').toLowerCase();
            if (name.includes(q)) {
                results.apstudy.push({
                    id: s.id,
                    title: `AP: ${s.name || 'Subject'}`,
                    context: s.examDate ? `Exam ${s.examDate}` : '',
                    action: () => { setActiveView('apstudy'); }
                });
            }
        });
    } catch (err) {}

    // College checklist.
    try {
        const ct = (typeof collegeTracker !== 'undefined' ? collegeTracker : null) || {};
        (Array.isArray(ct.checklist) ? ct.checklist : []).forEach(row => {
            if (results.college.length >= MAX) return;
            const college = String(row.college || '').toLowerCase();
            if (college.includes(q)) {
                results.college.push({
                    id: row.id,
                    title: `College: ${row.college || 'School'}`,
                    context: row.applicationDeadline ? `Due ${row.applicationDeadline}` : '',
                    action: () => { setActiveView('collegeapp'); }
                });
            }
        });
    } catch (err) {}

    // Timeline.
    try {
        (Array.isArray(timeBlocks) ? timeBlocks : []).forEach(b => {
            if (results.timeline.length >= MAX) return;
            const name = String(b.name || b.title || '').toLowerCase();
            if (name.includes(q)) {
                results.timeline.push({
                    id: b.id,
                    title: b.name || b.title || 'Block',
                    context: `${b.date || ''} ${b.start || ''}`.trim(),
                    action: () => { setActiveView('timeline'); }
                });
            }
        });
    } catch (err) {}

    // Review (decks + cards). Delegated to the review module so the search
    // panel and command palette stay in sync with the Review tab itself.
    try {
        if (typeof window !== 'undefined' && typeof window.getReviewSearchResults === 'function') {
            const reviewHits = window.getReviewSearchResults(q) || [];
            reviewHits.slice(0, MAX).forEach(hit => {
                results.review.push({
                    id: hit.id,
                    title: hit.title,
                    context: hit.context || '',
                    action: hit.action || (() => { try { setActiveView('review'); } catch (err) {} })
                });
            });
        }
    } catch (err) {}

    // Trackers: habits, goals, reading list. Each item navigates to the most
    // useful destination so search doubles as cross-feature navigation.
    try {
        const habitList = Array.isArray(habits) ? habits : [];
        habitList.forEach(habit => {
            if (results.trackers.length >= MAX) return;
            if (!habit) return;
            const name = String(habit.name || '').toLowerCase();
            if (name.includes(q)) {
                results.trackers.push({
                    id: habit.id,
                    title: `Habit: ${habit.name || 'Untitled'}`,
                    context: 'Open Today to mark complete',
                    action: () => { try { setActiveView('today'); } catch (err) {} }
                });
            }
        });
    } catch (err) {}
    try {
        const lw = (typeof lifeWorkspace !== 'undefined' ? lifeWorkspace : null) || {};
        const goals = Array.isArray(lw.goals) ? lw.goals : [];
        goals.forEach(goal => {
            if (results.trackers.length >= MAX) return;
            const title = String(goal && (goal.title || goal.name) || '').toLowerCase();
            if (title.includes(q)) {
                results.trackers.push({
                    id: goal.id || `goal_${Math.random().toString(36).slice(2, 8)}`,
                    title: `Goal: ${goal.title || goal.name || 'Untitled goal'}`,
                    context: goal.targetDate || goal.deadline || '',
                    action: () => { try { setActiveView('life'); } catch (err) {} }
                });
            }
        });
        const reading = Array.isArray(lw.reading) ? lw.reading : (Array.isArray(lw.readingList) ? lw.readingList : []);
        reading.forEach(book => {
            if (results.trackers.length >= MAX) return;
            const title = String(book && (book.title || book.name) || '').toLowerCase();
            const author = String(book && book.author || '').toLowerCase();
            if (title.includes(q) || author.includes(q)) {
                results.trackers.push({
                    id: book.id || `read_${Math.random().toString(36).slice(2, 8)}`,
                    title: `Reading: ${book.title || book.name || 'Untitled'}`,
                    context: book.author || book.status || '',
                    action: () => { try { setActiveView('life'); } catch (err) {} }
                });
            }
        });
    } catch (err) {}

    return results;
}

// ---------- Command Palette ----------
function getCommandPaletteCommands() {
    const mode = (typeof getActiveWorkspaceMode === 'function') ? getActiveWorkspaceMode() : 'standard';
    const modeHides = (view) => (typeof shouldShowViewForWorkspaceMode === 'function') ? !shouldShowViewForWorkspaceMode(view) : false;

    const commands = [
        { id: 'open-today', label: 'Open Today', hint: 'Go to the Today dashboard', run: () => setActiveView('today') },
        { id: 'open-timeline', label: 'Open Timeline / Calendar', hint: 'Timeline view', hidden: modeHides('timeline'), run: () => setActiveView('timeline') },
        { id: 'open-notes', label: 'Open Notes', hint: 'Notes workspace', hidden: modeHides('notes'), run: () => setActiveView('notes') },
        { id: 'open-homework', label: 'Open Homework', hint: 'Homework organizer', hidden: modeHides('homework'), run: () => setActiveView('homework') },
        { id: 'open-apstudy', label: 'Open Testing Hub', hint: 'Dashboard, exams, review, cram', hidden: modeHides('apstudy'), run: () => setActiveView('apstudy') },
        { id: 'open-testing-dashboard', label: 'Testing Hub: Dashboard', hint: 'Next step + KPIs', hidden: modeHides('apstudy'), run: () => { try { setActiveView('apstudy'); if (typeof switchTestingHubSection === 'function') switchTestingHubSection('dashboard'); } catch (err) {} } },
        { id: 'open-testing-exams', label: 'Testing Hub: Exams', hint: 'AP, SAT, ACT, MCAT, and more', hidden: modeHides('apstudy'), run: () => { try { setActiveView('apstudy'); if (typeof switchTestingHubSection === 'function') switchTestingHubSection('exams'); } catch (err) {} } },
        { id: 'open-testing-mistakes', label: 'Testing Hub: Mistakes', hint: 'Triage unresolved mistakes across exams', hidden: modeHides('apstudy'), run: () => { try { setActiveView('apstudy'); if (typeof switchTestingHubSection === 'function') switchTestingHubSection('mistakes'); } catch (err) {} } },
        { id: 'open-testing-add-exam', label: 'Testing Hub: Add exam…', hint: 'Pin an exam or create a custom one', hidden: modeHides('apstudy'), run: () => { try { closeCommandPalette(); setActiveView('apstudy'); if (typeof window.openTestingHubExamPicker === 'function') window.openTestingHubExamPicker({ focusAdd: true }); } catch (err) {} } },
        { id: 'open-review', label: 'Open Review', hint: 'Spaced repetition & active recall (in Testing Hub)', hidden: modeHides('review'), run: () => setActiveView('review') },
        { id: 'start-review-session', label: 'Start review session', hint: 'Step through due cards', hidden: modeHides('review'), run: () => { try { closeCommandPalette(); if (typeof window !== 'undefined' && typeof window.startReviewSessionFromShortcut === 'function') window.startReviewSessionFromShortcut(); } catch (err) {} } },
        { id: 'open-cramhub', label: 'Open Cram Hub', hint: 'Cram plans, brain dump, emergency mode (in Testing Hub)', hidden: modeHides('cramhub'), run: () => setActiveView('cramhub') },
        { id: 'new-cram-plan', label: 'Generate Cram Plan…', hint: 'Plan a focused study sprint', hidden: modeHides('cramhub'), run: () => { try { closeCommandPalette(); setActiveView('cramhub'); const topic = document.getElementById('cramTopicInput'); if (topic) topic.focus(); } catch (err) {} } },
        { id: 'open-collegeapp', label: 'Open College', hint: 'College apps', hidden: modeHides('collegeapp'), run: () => setActiveView('collegeapp') },
        { id: 'open-life', label: 'Open Life', hint: 'Life workspace', hidden: modeHides('life'), run: () => setActiveView('life') },
        { id: 'open-business', label: 'Open Business', hint: 'Projects & Work', hidden: modeHides('business'), run: () => setActiveView('business') },
        { id: 'open-settings', label: 'Open Settings', hint: 'Workspace control center', run: () => setActiveView('settings') },
        { id: 'open-deadline-radar', label: 'Open Deadline Radar', hint: 'See every upcoming deadline', run: () => { closeCommandPalette(); openDeadlineRadar(); } },
        { id: 'quick-capture', label: 'Quick Capture…', hint: 'Create task/homework/note/block', run: () => { closeCommandPalette(); openQuickCaptureModal(''); } },
        { id: 'search-everywhere', label: 'Search everywhere…', hint: 'Full cross-workspace search', run: () => { closeCommandPalette(); openGlobalSearchPanel(''); } },
        { id: 'homework-paste-import', label: 'Import homework (paste)…', hint: 'Paste assignments from a portal', hidden: modeHides('homework'), run: () => { closeCommandPalette(); openHomeworkPasteImport(''); } },
        { id: 'split-presets', label: 'Split-screen workflow…', hint: 'Note + Assignment, Essay + Research, etc.', hidden: modeHides('notes'), run: () => { closeCommandPalette(); setActiveView('notes'); openNotesSplitPresetsPicker(); } },
        { id: 'create-note', label: 'Create note', hint: 'New page', run: () => { try { createNewPage && createNewPage(); } catch (err) {} } },
        { id: 'add-task', label: 'Add task', hint: 'Open task modal', run: () => { try { openTaskModal && openTaskModal(); } catch (err) {} } },
        { id: 'add-homework', label: 'Add homework (open Homework)', hint: 'Homework add flow', hidden: modeHides('homework'), run: () => setActiveView('homework') },
        { id: 'add-ap-subject', label: 'Add AP subject', hint: 'AP Study add subject', hidden: modeHides('apstudy'), run: () => { try { setActiveView('apstudy'); if (typeof window.openApStudyAddSubject === 'function') window.openApStudyAddSubject(); } catch (err) {} } },
        { id: 'start-focus', label: 'Start focus timer', hint: 'Focus timer', run: () => { try { startTimer && startTimer(); } catch (err) {} } },
        { id: 'toggle-theme-panel', label: 'Toggle theme panel', hint: 'Theme switcher', run: () => { try { toggleThemePanel && toggleThemePanel(); } catch (err) {} } },
        { id: 'export-atelier', label: 'Export encrypted .sutra backup', hint: 'Full workspace backup', run: async () => { closeCommandPalette(); try { if (exportWorkspaceAsAtelierPackage) await exportWorkspaceAsAtelierPackage(); } catch (err) {} } },
        { id: 'create-weekly-review', label: 'Create Weekly Review note', hint: 'Summarize your week', run: () => { closeCommandPalette(); createWeeklyReviewNote(); } },
        { id: 'rerun-onboarding', label: 'Restart Sutra Setup', hint: 'Re-open onboarding wizard', run: () => { closeCommandPalette(); try { markStudentOnboardingCompleted(false); showStudentOnboarding(); } catch (err) {} } },
        // Sutra Assistant commands — contextual workspace assistant. Each command
        // opens the Flow panel, primes the input with a view-aware prompt, and
        // (in most cases) auto-sends so the user gets immediate context-driven help.
        { id: 'flow-ask', label: 'Ask Sutra…', hint: 'Open the Sutra Assistant panel', run: () => { closeCommandPalette(); try { window.flowAssistant && window.flowAssistant.askFlow('', { send: false }); } catch (err) {} } },
        { id: 'flow-ask-note', label: 'Ask Sutra about current note', hint: 'Flow uses the open note as context', hidden: modeHides('notes'), run: () => { closeCommandPalette(); try { setActiveView('notes'); window.flowAssistant && window.flowAssistant.askFlow('Looking at this note, what would you suggest I do next? Be specific and reference the content.', { send: true }); } catch (err) {} } },
        { id: 'flow-plan-day', label: 'Sutra: Shape my day', hint: 'Generate a realistic plan from tasks and timeline', run: () => { closeCommandPalette(); try { setActiveView('today'); window.flowAssistant && window.flowAssistant.askFlow('Plan my day from my open tasks and timeline. Propose create_timeline_block actions for the most important items.', { send: true }); } catch (err) {} } },
        { id: 'flow-cards-from-note', label: 'Sutra: Create review cards from current note', hint: 'Build a deck of 8–15 cards', hidden: modeHides('notes'), run: () => { closeCommandPalette(); try { setActiveView('notes'); window.flowAssistant && window.flowAssistant.askFlow('Read this note and propose a create_review_deck action with 8–15 high-quality front/back cards covering the key concepts.', { send: true }); } catch (err) {} } },
        { id: 'flow-schedule-tasks', label: 'Sutra: Schedule my open tasks', hint: 'Propose timeline blocks for open tasks', hidden: modeHides('timeline'), run: () => { closeCommandPalette(); try { setActiveView('timeline'); window.flowAssistant && window.flowAssistant.askFlow('Look at my open tasks and propose create_timeline_block actions to place focus blocks for them across today and tomorrow.', { send: true }); } catch (err) {} } },
        { id: 'flow-import-assignments', label: 'Sutra: Import assignments from pasted text', hint: 'Paste a syllabus or portal text — Flow proposes homework', hidden: modeHides('homework'), run: () => { closeCommandPalette(); try { setActiveView('homework'); window.flowAssistant && window.flowAssistant.askFlow('I am going to paste assignment text from a class portal. Parse it and propose create_homework actions for each assignment you find. Wait for my paste.', { send: false }); } catch (err) {} } },
        { id: 'flow-context-depth', label: 'Sutra: Change context depth…', hint: 'Settings ▸ Assistant ▸ Context depth', run: () => { closeCommandPalette(); try { setActiveView('settings'); const navBtn = document.querySelector('[data-settings-nav="assistant"]'); if (navBtn) navBtn.click(); const target = document.getElementById('settings-flow-keys'); if (target && target.scrollIntoView) target.scrollIntoView({ behavior: 'smooth', block: 'center' }); } catch (err) {} } }
    ];

    // Dynamic: one "Open class dashboard" command per existing class.
    try {
        if (typeof localStorage !== 'undefined') {
            const courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]');
            (Array.isArray(courses) ? courses : []).slice(0, 12).forEach(course => {
                if (!course || !course.id) return;
                const type = course.type === 'misc' ? 'Misc' : 'Class';
                commands.push({
                    id: `open-class-${course.id}`,
                    label: `Open class: ${String(course.name || 'Untitled')}`,
                    hint: `${type} dashboard`,
                    hidden: modeHides('homework') && !hasWorkspaceData('homework'),
                    run: () => { closeCommandPalette(); openClassDashboardDrawer(course.id); }
                });
            });
        }
    } catch (err) { /* non-critical */ }

    // Append commands contributed by enabled local plugins (Phase C). Bridged via
    // a window global because this builder lives outside the app closure.
    try {
        if (Array.isArray(window.__atelierPluginCommands)) {
            window.__atelierPluginCommands.forEach(c => { if (c && c.label && typeof c.run === 'function') commands.push(c); });
        }
    } catch (err) { /* non-critical */ }

    return commands.filter(c => c.hidden !== true);
}

function openCommandPalette(initialQuery) {
    const modal = document.getElementById('commandPaletteModal');
    if (!modal) return;
    const input = modal.querySelector('#commandPaletteInput');
    const list = modal.querySelector('#commandPaletteList');
    if (!input || !list) return;
    input.value = String(initialQuery || '');
    renderCommandPalette(input.value);
    modal.classList.add('active');
    modal.setAttribute('aria-hidden', 'false');
    document.body.classList.add('command-palette-open');
    setTimeout(() => { try { input.focus(); input.select(); } catch (err) {} }, 20);
}

function closeCommandPalette() {
    const modal = document.getElementById('commandPaletteModal');
    if (!modal) return;
    modal.classList.remove('active');
    modal.setAttribute('aria-hidden', 'true');
    document.body.classList.remove('command-palette-open');
}

function renderCommandPalette(query) {
    const modal = document.getElementById('commandPaletteModal');
    if (!modal) return;
    const list = modal.querySelector('#commandPaletteList');
    if (!list) return;
    const q = String(query || '').trim().toLowerCase();

    // Section 1: commands.
    const commands = getCommandPaletteCommands();
    const matchedCommands = q
        ? commands.filter(c => c.label.toLowerCase().includes(q) || (c.hint && c.hint.toLowerCase().includes(q)))
        : commands;

    let html = '';
    html += '<div class="command-palette-section-label">Commands</div>';
    if (matchedCommands.length === 0) {
        html += '<div class="command-palette-empty">No matching commands.</div>';
    } else {
        html += '<ul class="command-palette-list">';
        matchedCommands.forEach((cmd, idx) => {
            html += `<li class="command-palette-item" data-cmd-id="${escapeCommandHtml(cmd.id)}" data-cmd-idx="${idx}" tabindex="0">
                <div class="command-palette-item-label">${escapeCommandHtml(cmd.label)}</div>
                ${cmd.hint ? `<div class="command-palette-item-hint">${escapeCommandHtml(cmd.hint)}</div>` : ''}
            </li>`;
        });
        html += '</ul>';
    }

    // Section 2: global search results (only when a query is typed).
    if (q) {
        const results = globalSearchAll(q);
        const renderGroup = (label, arr) => {
            if (!Array.isArray(arr) || arr.length === 0) return '';
            let inner = '';
            arr.forEach((r, idx) => {
                inner += `<li class="command-palette-item" data-search-key="${escapeCommandHtml(label)}" data-search-idx="${idx}" tabindex="0">
                    <div class="command-palette-item-label">${escapeCommandHtml(r.title)}</div>
                    ${r.context ? `<div class="command-palette-item-hint">${escapeCommandHtml(r.context)}</div>` : ''}
                </li>`;
            });
            return `<div class="command-palette-section-label">${escapeCommandHtml(label)}</div><ul class="command-palette-list">${inner}</ul>`;
        };
        html += renderGroup('Notes', results.notes);
        html += renderGroup('Tasks', results.tasks);
        html += renderGroup('Homework', results.homework);
        html += renderGroup('AP Study', results.apstudy);
        html += renderGroup('College', results.college);
        html += renderGroup('Timeline', results.timeline);

        // Attach search results for event handlers.
        modal._searchResults = results;
    } else {
        modal._searchResults = null;
    }

    list.innerHTML = html;

    // Click handlers.
    list.querySelectorAll('[data-cmd-id]').forEach(node => {
        node.addEventListener('click', () => {
            const cmdId = node.getAttribute('data-cmd-id');
            const cmd = getCommandPaletteCommands().find(c => c.id === cmdId);
            if (cmd && typeof cmd.run === 'function') {
                try { cmd.run(); } catch (err) { console.warn(err); }
            }
            // Commands that open modals call closeCommandPalette themselves; otherwise close.
            if (!cmd || !/open-deadline-radar|quick-capture|export-atelier|create-weekly-review|rerun-onboarding/.test(String(cmd.id))) {
                closeCommandPalette();
            }
        });
    });
    list.querySelectorAll('[data-search-key]').forEach(node => {
        node.addEventListener('click', () => {
            const key = node.getAttribute('data-search-key');
            const idx = Number(node.getAttribute('data-search-idx') || '0');
            const groupMap = { 'Notes': 'notes', 'Tasks': 'tasks', 'Homework': 'homework', 'AP Study': 'apstudy', 'College': 'college', 'Timeline': 'timeline' };
            const groupKey = groupMap[key];
            const r = modal._searchResults && modal._searchResults[groupKey] && modal._searchResults[groupKey][idx];
            if (r && typeof r.action === 'function') {
                try { r.action(); } catch (err) {}
            }
            closeCommandPalette();
        });
    });
}

function bindCommandPaletteInput() {
    const modal = document.getElementById('commandPaletteModal');
    if (!modal || modal.dataset.bound === 'true') return;
    modal.dataset.bound = 'true';
    const input = modal.querySelector('#commandPaletteInput');
    const list = modal.querySelector('#commandPaletteList');
    if (!input || !list) return;
    input.addEventListener('input', () => renderCommandPalette(input.value));
    input.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') { e.preventDefault(); closeCommandPalette(); return; }
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            const items = list.querySelectorAll('.command-palette-item');
            if (items[0]) items[0].focus();
        } else if (e.key === 'Enter') {
            e.preventDefault();
            const items = list.querySelectorAll('.command-palette-item');
            if (items[0]) items[0].click();
        }
    });
    list.addEventListener('keydown', (e) => {
        const items = Array.from(list.querySelectorAll('.command-palette-item'));
        const idx = items.indexOf(document.activeElement);
        if (e.key === 'ArrowDown') { e.preventDefault(); if (items[idx + 1]) items[idx + 1].focus(); }
        else if (e.key === 'ArrowUp') { e.preventDefault(); if (idx > 0) items[idx - 1].focus(); else input.focus(); }
        else if (e.key === 'Enter') { e.preventDefault(); if (document.activeElement && document.activeElement.classList.contains('command-palette-item')) document.activeElement.click(); }
        else if (e.key === 'Escape') { e.preventDefault(); closeCommandPalette(); }
    });
    const backdrop = modal.querySelector('.command-palette-backdrop');
    if (backdrop) backdrop.addEventListener('click', closeCommandPalette);
}

// Global Cmd/Ctrl+K handler — opens palette everywhere except inside editor fields
// and except on the AP Study view (which already uses Ctrl+K for add-subject).
document.addEventListener('keydown', (event) => {
    if (!(event.ctrlKey || event.metaKey) || event.altKey) return;
    const key = typeof event.key === 'string' ? event.key.toLowerCase() : '';
    // Ctrl/Cmd+K (no Shift) is the canonical Command Palette shortcut. Ctrl/Cmd+Shift+P
    // is an optional IDE-style alternate. Insert Link now lives on Ctrl/Cmd+Shift+K.
    const isPaletteKey = (key === 'k' && !event.shiftKey) || (key === 'p' && event.shiftKey);
    if (!isPaletteKey) return;
    const target = event.target;
    // Don't hijack typing in real form fields, but DO allow the note editor
    // (a contentEditable region) so the palette opens from inside note text.
    if (target && (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.tagName === 'SELECT')) return;
    const apStudyView = document.getElementById('view-apstudy');
    const apStudyActive = apStudyView && apStudyView.classList.contains('active');
    // When AP Study is active, Ctrl/Cmd+K is owned by its add-subject handler; do not double-trigger.
    if (apStudyActive && key === 'k' && typeof window.openApStudyAddSubject === 'function') return;
    event.preventDefault();
    bindCommandPaletteInput();
    openCommandPalette('');
});

// Shift+Cmd/Ctrl+F opens the standalone Global Search panel.
document.addEventListener('keydown', (event) => {
    if (!(event.ctrlKey || event.metaKey) || !event.shiftKey || event.altKey) return;
    if (typeof event.key !== 'string' || event.key.toLowerCase() !== 'f') return;
    const target = event.target;
    if (target && (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.tagName === 'SELECT' || target.isContentEditable === true)) return;
    event.preventDefault();
    try { openGlobalSearchPanel(''); } catch (err) { /* non-critical */ }
});

// ---------- Weekly Review ----------
function createWeeklyReviewNote() {
    try {
        const now = new Date();
        const start = new Date(now); start.setDate(start.getDate() - 6); start.setHours(0, 0, 0, 0);
        const startKey = start.toISOString().slice(0, 10);
        const endKey = now.toISOString().slice(0, 10);

        // Tasks this week.
        const allTasks = Array.isArray(tasks) ? tasks : [];
        const taskInRange = (t) => {
            const d = t.dueDate ? new Date(`${t.dueDate}T00:00:00`) : null;
            return d && !isNaN(d) && d >= start && d <= now;
        };
        const doneTasks = allTasks.filter(t => t.completed && taskInRange(t));
        const missedTasks = allTasks.filter(t => !t.completed && t.dueDate && new Date(`${t.dueDate}T23:59:59`) < now && new Date(`${t.dueDate}T00:00:00`) >= start);

        // Homework this week.
        const hwTasksRaw = (typeof localStorage !== 'undefined') ? (function(){ try { return JSON.parse(localStorage.getItem('hwTasks:v2') || '[]'); } catch(e){ return []; } })() : [];
        const hwInRange = (h) => {
            const d = h.dueDate ? new Date(`${h.dueDate}T00:00:00`) : null;
            return d && !isNaN(d) && d >= start && d <= now;
        };
        const doneHw = (Array.isArray(hwTasksRaw) ? hwTasksRaw : []).filter(h => h.done && hwInRange(h));
        const missedHw = (Array.isArray(hwTasksRaw) ? hwTasksRaw : []).filter(h => !h.done && h.dueDate && new Date(`${h.dueDate}T23:59:59`) < now && new Date(`${h.dueDate}T00:00:00`) >= start);

        // Upcoming deadlines next 7 days.
        let upcomingList = [];
        try {
            const allDeadlines = typeof collectWorkspaceDeadlines === 'function' ? collectWorkspaceDeadlines() : [];
            const weekEnd = new Date(now); weekEnd.setDate(weekEnd.getDate() + 7);
            upcomingList = allDeadlines.filter(d => d.due >= now && d.due <= weekEnd).slice(0, 15);
        } catch (err) {}

        const escHtml = (s) => String(s || '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
        const lines = [];
        lines.push(`<h2>Weekly Review · ${escHtml(startKey)} → ${escHtml(endKey)}</h2>`);
        lines.push(`<h3>Completed (${doneTasks.length + doneHw.length})</h3>`);
        lines.push('<ul>');
        doneTasks.forEach(t => lines.push(`<li>${escHtml(t.title || 'Task')}</li>`));
        doneHw.forEach(h => lines.push(`<li>Homework: ${escHtml(h.title || h.text || 'Assignment')}</li>`));
        if (doneTasks.length + doneHw.length === 0) lines.push('<li><em>Nothing logged as completed this week.</em></li>');
        lines.push('</ul>');
        lines.push(`<h3>Missed / Overdue (${missedTasks.length + missedHw.length})</h3>`);
        lines.push('<ul>');
        missedTasks.forEach(t => lines.push(`<li>${escHtml(t.title || 'Task')} · due ${escHtml(t.dueDate || '')}</li>`));
        missedHw.forEach(h => lines.push(`<li>Homework: ${escHtml(h.title || h.text || 'Assignment')} · due ${escHtml(h.dueDate || '')}</li>`));
        if (missedTasks.length + missedHw.length === 0) lines.push('<li><em>No missed items.</em></li>');
        lines.push('</ul>');
        lines.push(`<h3>Next week · upcoming deadlines (${upcomingList.length})</h3>`);
        lines.push('<ul>');
        upcomingList.forEach(d => lines.push(`<li>${escHtml(d.title)} · ${escHtml(d.source)} · ${escHtml(d.due.toLocaleDateString())}</li>`));
        if (upcomingList.length === 0) lines.push('<li><em>No deadlines on file.</em></li>');
        lines.push('</ul>');
        lines.push('<h3>Reflection</h3>');
        lines.push('<p>What went well this week?</p><p><br></p>');
        lines.push('<p>What slipped, and why?</p><p><br></p>');
        lines.push('<p>Top 3 priorities for next week:</p><ol><li></li><li></li><li></li></ol>');

        if (typeof pages !== 'undefined' && Array.isArray(pages)) {
            const now2 = new Date().toISOString();
            const page = {
                id: (typeof generateId === 'function' ? generateId() : `wr${Date.now()}`),
                title: `Weekly Review · ${endKey}`,
                content: lines.join('\n'),
                blocks: [],
                icon: (typeof PAGE_ICONS !== 'undefined' ? PAGE_ICONS.DOC : '📅'),
                collapsed: false,
                createdAt: now2,
                updatedAt: now2,
                theme: (typeof globalTheme !== 'undefined' ? globalTheme : 'default')
            };
            pages.push(page);
            try { savePagesToLocal && savePagesToLocal(); } catch (err) {}
            try { renderPagesList && renderPagesList(); } catch (err) {}
            try { setActiveView('notes'); loadPage && loadPage(page.id); } catch (err) {}
            if (typeof showToast === 'function') showToast('Weekly Review note created.');
        }
    } catch (err) {
        console.warn('Weekly Review failed', err);
        if (typeof showToast === 'function') showToast('Weekly Review failed.');
    }
}

// ---------- AP Exam Battle Plan ----------
function computeApBattlePlan() {
    const aps = (typeof apStudyWorkspace !== 'undefined' && apStudyWorkspace) ? apStudyWorkspace : null;
    if (!aps) return { subject: null, recommendation: 'Add an AP subject to start planning.' };
    const subjects = Array.isArray(aps.subjects) ? aps.subjects : [];
    if (subjects.length === 0) return { subject: null, recommendation: 'Add an AP subject to start planning.' };

    // Pick the subject with the soonest exam date, else the first.
    const now = new Date();
    const sorted = subjects
        .map(s => ({ s, d: s.examDate ? new Date(`${s.examDate}T${s.examTime || '23:59'}:00`) : null }))
        .filter(x => x.d && !isNaN(x.d))
        .sort((a, b) => a.d - b.d);
    const pick = (sorted[0] && sorted[0].s) || subjects[0];
    const daysLeft = sorted[0] ? Math.max(0, Math.round((sorted[0].d - now) / 86400000)) : null;

    const units = Array.isArray(aps.units) ? aps.units.filter(u => u.subjectId === pick.id) : [];
    const weakUnits = units.filter(u => u.weakFlag || (u.confidenceLevel != null && u.confidenceLevel <= 2));
    const practiceLogs = Array.isArray(aps.practiceLogs) ? aps.practiceLogs.filter(l => l.subjectId === pick.id) : [];

    let recommendation;
    let sessionType = 'review';
    let reason;

    if (!pick.examDate) {
        recommendation = `Add the exam date for ${pick.name || 'this AP subject'} to unlock the Battle Plan.`;
        reason = 'Exam date is missing.';
    } else if (practiceLogs.length === 0) {
        recommendation = `Run a diagnostic practice set for ${pick.name}.`;
        sessionType = 'practice test';
        reason = 'No practice logs yet — diagnostic practice will expose weak areas.';
    } else if (weakUnits.length > 0) {
        recommendation = `Review weak units in ${pick.name}: ${weakUnits.slice(0, 3).map(u => u.title).join(', ')}.`;
        sessionType = 'weak-area review';
        reason = `${weakUnits.length} weak unit${weakUnits.length === 1 ? '' : 's'} flagged.`;
    } else if (daysLeft !== null && daysLeft <= 14) {
        recommendation = `Run a timed FRQ + MCQ mixed set for ${pick.name}.`;
        sessionType = 'mixed session';
        reason = `Only ${daysLeft} day${daysLeft === 1 ? '' : 's'} until the exam — emphasize high-impact practice.`;
    } else if ((pick.confidenceLevel != null && pick.confidenceLevel <= 2)) {
        recommendation = `Review core concepts in ${pick.name}, then short practice.`;
        sessionType = 'review';
        reason = 'Confidence is low — rebuild foundation before ramping up.';
    } else {
        recommendation = `Next unit progress session for ${pick.name}.`;
        sessionType = 'review';
        reason = 'On track — keep steady unit progress.';
    }

    return { subject: pick, recommendation, reason, sessionType, daysLeft, weakUnits };
}

function renderApBattlePlan() {
    const host = document.getElementById('apBattlePlanCard');
    if (!host) return;
    const plan = computeApBattlePlan();
    if (!plan.subject) {
        host.innerHTML = `
            <div class="eyebrow">AP Battle Plan</div>
            <h3>No AP subjects yet</h3>
            <p>Add an AP subject to see a tailored study recommendation.</p>`;
        return;
    }
    const countdown = plan.daysLeft == null ? 'Exam date not set' : `${plan.daysLeft} day${plan.daysLeft === 1 ? '' : 's'} to exam`;
    host.innerHTML = `
        <div class="eyebrow">AP Battle Plan · ${escapeCommandHtml(plan.subject.name || 'Subject')}</div>
        <h3>${escapeCommandHtml(plan.recommendation)}</h3>
        <p class="ap-battle-reason">${escapeCommandHtml(plan.reason || '')}</p>
        <p class="ap-battle-meta">Suggested session: <strong>${escapeCommandHtml(plan.sessionType)}</strong> · ${escapeCommandHtml(countdown)}</p>
        <div class="ap-battle-actions">
            <button type="button" class="neumo-btn" id="apBattleCreateSessionBtn" title="Add this to AP Study sessions">Create AP Study session</button>
            <button type="button" class="neumo-btn" id="apBattleCreateNoteBtn" title="Create an AP unit note linked to this subject">Create AP unit note</button>
            <button type="button" class="neumo-btn" id="apBattleCreateTaskBtn">Log as task</button>
            <button type="button" class="neumo-btn" id="apBattleScheduleBtn">Schedule block</button>
            <button type="button" class="neumo-btn" id="apBattleOpenRadarBtn">Open Deadline Radar</button>
        </div>
    `;
    const sessionBtn = host.querySelector('#apBattleCreateSessionBtn');
    if (sessionBtn) sessionBtn.addEventListener('click', () => {
        const session = (typeof createApStudySessionFromBattlePlan === 'function') ? createApStudySessionFromBattlePlan(plan) : null;
        if (session) {
            if (typeof showToast === 'function') showToast('AP Study session created.');
        } else if (typeof showToast === 'function') {
            showToast('Could not create AP session — logged as task instead.');
        }
    });
    const noteBtn = host.querySelector('#apBattleCreateNoteBtn');
    if (noteBtn) noteBtn.addEventListener('click', () => {
        const p = (typeof createApUnitNoteFromBattlePlan === 'function') ? createApUnitNoteFromBattlePlan(plan) : null;
        if (p && typeof showToast === 'function') showToast('AP unit note created.');
    });
    const taskBtn = host.querySelector('#apBattleCreateTaskBtn');
    if (taskBtn) taskBtn.addEventListener('click', () => {
        try {
            tasks.push({
                id: (typeof generateId === 'function' ? generateId() : `t${Date.now()}`),
                title: plan.recommendation,
                notes: plan.reason || '',
                completed: false,
                priority: 'high',
                difficulty: 'medium',
                dueDate: '',
                dueTime: '',
                category: 'AP Study',
                createdAt: new Date().toISOString()
            });
            persistAppData && persistAppData();
            renderTaskViews && renderTaskViews();
            if (typeof showToast === 'function') showToast('AP Battle Plan logged as task.');
        } catch (err) { console.warn(err); }
    });
    const scheduleBtn = host.querySelector('#apBattleScheduleBtn');
    if (scheduleBtn) scheduleBtn.addEventListener('click', () => {
        try {
            const iso = (new Date()).toISOString().slice(0, 10);
            timeBlocks.push({
                id: (typeof generateId === 'function' ? generateId() : `b${Date.now()}`),
                date: iso,
                start: '18:00',
                end: '19:00',
                name: `${plan.subject.name || 'AP'}: ${plan.recommendation}`.slice(0, 160),
                category: 'study'
            });
            saveTimeBlocks && saveTimeBlocks();
            if (typeof showToast === 'function') showToast('Scheduled for today 6pm — edit in Timeline.');
        } catch (err) { console.warn(err); }
    });
    const radarBtn = host.querySelector('#apBattleOpenRadarBtn');
    if (radarBtn) radarBtn.addEventListener('click', () => { openDeadlineRadar(); });
}

// ---------- Class Dashboard drawer ----------
function openClassDashboardDrawer(courseId) {
    const drawer = document.getElementById('classDashboardDrawer');
    if (!drawer) return;
    const body = drawer.querySelector('.class-dashboard-body');
    if (!body) return;

    let courses = [];
    let hw = [];
    try {
        courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]');
        hw = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]');
    } catch (err) {}

    const course = (Array.isArray(courses) ? courses : []).find(c => String(c.id) === String(courseId));
    if (!course) {
        body.innerHTML = `<div class="empty-state"><div class="empty-title">Class not found</div></div>`;
        drawer.classList.add('active');
        drawer.setAttribute('aria-hidden', 'false');
        return;
    }

    const courseTasks = (Array.isArray(hw) ? hw : []).filter(t => String(t.courseId) === String(course.id));
    const pending = courseTasks.filter(t => !t.done);
    const done = courseTasks.filter(t => t.done);

    // Upcoming deadlines for this class (from shared aggregator).
    let upcoming = [];
    try {
        const all = typeof collectWorkspaceDeadlines === 'function' ? collectWorkspaceDeadlines() : [];
        upcoming = all.filter(d => d.source === 'homework' && d.subtitle === course.name).slice(0, 8);
    } catch (err) {}

    // AP subject link heuristic: match by name prefix.
    let apLink = null;
    try {
        const aps = (typeof apStudyWorkspace !== 'undefined' && apStudyWorkspace) ? apStudyWorkspace : null;
        if (aps && Array.isArray(aps.subjects)) {
            const lc = String(course.name || '').toLowerCase();
            apLink = aps.subjects.find(s => {
                const n = String(s.name || '').toLowerCase();
                return n && (n === lc || n.includes(lc) || lc.includes(n));
            }) || null;
        }
    } catch (err) {}

    const escH = escapeCommandHtml;
    const linkedNotes = (typeof getNotesLinkedToClass === 'function') ? getNotesLinkedToClass(course.id) : [];
    const unlinkedNotes = (Array.isArray(pages) ? pages : [])
        .filter(p => p && !p.classLinkId && p.id !== 'help_page' && String(p.title || '').trim())
        .slice(0, 50);

    body.innerHTML = `
        <div class="class-dash-head">
            <div class="eyebrow">Class</div>
            <h3>${escH(course.name)}</h3>
            <p class="class-dash-meta">${escH(course.type === 'misc' ? 'Misc / Extracurricular' : 'Class')} · ${pending.length} open · ${done.length} done · ${linkedNotes.length} note${linkedNotes.length === 1 ? '' : 's'}</p>
        </div>
        <div class="class-dash-section">
            <h4>Open homework (${pending.length})</h4>
            <ul class="class-dash-list">
                ${pending.slice(0, 8).map(t => `<li>${escH(t.title || t.text || 'Assignment')}${t.dueDate ? ' · due ' + escH(t.dueDate) : ''}</li>`).join('') || '<li><em>Nothing open.</em></li>'}
            </ul>
        </div>
        <div class="class-dash-section">
            <h4>Upcoming deadlines</h4>
            <ul class="class-dash-list">
                ${upcoming.map(d => `<li>${escH(d.title)} · ${escH(d.due.toLocaleDateString())}</li>`).join('') || '<li><em>No upcoming deadlines.</em></li>'}
            </ul>
        </div>
        <div class="class-dash-section">
            <h4>Linked notes (${linkedNotes.length})</h4>
            <ul class="class-dash-list" id="classDashLinkedNotes">
                ${linkedNotes.length === 0 ? '<li><em>No notes linked yet.</em></li>' : linkedNotes.slice(0, 8).map(n => `<li><button type="button" class="class-dash-note-open" data-note-id="${escH(n.id)}">${escH(n.title || 'Untitled')}</button> <button type="button" class="class-dash-note-unlink" data-unlink-id="${escH(n.id)}" title="Unlink from this class">unlink</button></li>`).join('')}
            </ul>
            <div class="class-dash-link-row">
                <select id="classDashLinkNoteSelect" class="modal-input" aria-label="Link existing note to this class">
                    <option value="">Link existing note…</option>
                    ${unlinkedNotes.map(n => `<option value="${escH(n.id)}">${escH((n.title || 'Untitled').slice(0, 80))}</option>`).join('')}
                </select>
                <button type="button" class="neumo-btn" id="classDashLinkNoteBtn">Link</button>
                <button type="button" class="neumo-btn" id="classDashNewNoteBtn">+ New class note</button>
            </div>
        </div>
        <div class="class-dash-section">
            <h4>AP subject link</h4>
            <p>${apLink ? `<strong>${escH(apLink.name)}</strong> — <button type="button" class="neumo-btn class-dash-ap-open">Open AP Study</button>` : 'No AP Study subject matched by name. You can still link manually later.'}</p>
        </div>
        <div class="class-dash-actions">
            <button type="button" class="neumo-btn" id="classDashOpenHwBtn">Open Homework</button>
            <button type="button" class="neumo-btn" id="classDashFocusBtn">Start focus timer</button>
            <button type="button" class="neumo-btn" id="classDashCloseBtn">Close</button>
        </div>
    `;
    const openHw = body.querySelector('#classDashOpenHwBtn');
    if (openHw) openHw.addEventListener('click', () => { closeClassDashboardDrawer(); setActiveView('homework'); });
    const focusBtn = body.querySelector('#classDashFocusBtn');
    if (focusBtn) focusBtn.addEventListener('click', () => { try { startTimer && startTimer(); } catch (err) {} });
    const closeBtn = body.querySelector('#classDashCloseBtn');
    if (closeBtn) closeBtn.addEventListener('click', closeClassDashboardDrawer);
    const apOpen = body.querySelector('.class-dash-ap-open');
    if (apOpen) apOpen.addEventListener('click', () => { closeClassDashboardDrawer(); setActiveView('apstudy'); });

    body.querySelectorAll('.class-dash-note-open').forEach(btn => btn.addEventListener('click', () => {
        const id = btn.getAttribute('data-note-id');
        closeClassDashboardDrawer();
        try { setActiveView('notes'); loadPage && loadPage(id); } catch (err) {}
    }));
    body.querySelectorAll('.class-dash-note-unlink').forEach(btn => btn.addEventListener('click', () => {
        const id = btn.getAttribute('data-unlink-id');
        if (typeof linkCurrentNoteToClass === 'function') linkCurrentNoteToClass(id, '');
        openClassDashboardDrawer(courseId);
    }));
    const linkBtn = body.querySelector('#classDashLinkNoteBtn');
    const linkSel = body.querySelector('#classDashLinkNoteSelect');
    if (linkBtn && linkSel) {
        linkBtn.addEventListener('click', () => {
            const pid = linkSel.value;
            if (!pid) { if (typeof showToast === 'function') showToast('Pick a note to link.'); return; }
            if (typeof linkCurrentNoteToClass === 'function') {
                linkCurrentNoteToClass(pid, course.id);
                if (typeof showToast === 'function') showToast('Note linked to class.');
                openClassDashboardDrawer(courseId);
            }
        });
    }
    const newNoteBtn = body.querySelector('#classDashNewNoteBtn');
    if (newNoteBtn) newNoteBtn.addEventListener('click', () => {
        if (typeof createNoteLinkedToClass === 'function') {
            createNoteLinkedToClass(course.id, `${course.name} — notes`);
            closeClassDashboardDrawer();
        }
    });

    drawer.classList.add('active');
    drawer.setAttribute('aria-hidden', 'false');
}

function closeClassDashboardDrawer() {
    const drawer = document.getElementById('classDashboardDrawer');
    if (!drawer) return;
    drawer.classList.remove('active');
    drawer.setAttribute('aria-hidden', 'true');
}

// ---------- "Schedule this" for Deadline Radar items ----------
function scheduleDeadlineItemAsBlock(item) {
    if (!item || typeof timeBlocks === 'undefined') return;
    try {
        const d = item.due instanceof Date ? item.due : new Date(item.due);
        if (isNaN(d)) return;
        const iso = d.toISOString().slice(0, 10);
        const defaultStart = (item.source === 'apexam') ? '09:00' : '18:00';
        timeBlocks.push({
            id: (typeof generateId === 'function' ? generateId() : `b${Date.now()}`),
            date: iso,
            start: defaultStart,
            end: (function(){ const [h,m] = defaultStart.split(':').map(Number); const nh=(h+1)%24; return `${String(nh).padStart(2,'0')}:${String(m).padStart(2,'0')}`; })(),
            name: `Prep: ${item.title || ''}`.slice(0, 120),
            category: item.source === 'apexam' ? 'study' : 'general'
        });
        saveTimeBlocks && saveTimeBlocks();
        if (typeof showToast === 'function') showToast('Prep block scheduled.');
    } catch (err) { console.warn(err); }
}

// ---------- Generic "Schedule this" for any item w/ due date + title ----------
function scheduleGenericItemAsBlock(item) {
    if (!item || typeof timeBlocks === 'undefined') return false;
    try {
        const raw = item.dueDate || item.due || item.date || '';
        const d = raw ? new Date(`${String(raw).slice(0,10)}T00:00:00`) : new Date();
        if (isNaN(d)) return false;
        const iso = d.toISOString().slice(0, 10);
        const start = item.dueTime || '18:00';
        const end = (function(t){ const [h,m] = String(t).split(':').map(Number); const nh=(Number(h||0)+1)%24; return `${String(nh).padStart(2,'0')}:${String(Number(m||0)).padStart(2,'0')}`; })(start);
        timeBlocks.push({
            id: (typeof generateId === 'function' ? generateId() : `b${Date.now()}`),
            date: iso,
            start,
            end,
            name: `Prep: ${String(item.title || item.name || 'Work').slice(0, 120)}`,
            category: item.category || 'general'
        });
        saveTimeBlocks && saveTimeBlocks();
        if (activeView === 'timeline' && typeof renderTimeline === 'function') { try { renderTimeline(); } catch (err) {} }
        if (typeof showToast === 'function') showToast('Prep block scheduled.');
        return true;
    } catch (err) { console.warn(err); return false; }
}

// ================================================================
// Homework paste import
// ================================================================
function parseHomeworkPasteText(text) {
    const raw = String(text || '').trim();
    if (!raw) return [];
    const lines = raw.split(/\r?\n/).map(l => l.replace(/\t/g, ' | ').trim()).filter(Boolean);
    const out = [];
    const now = new Date();
    const classKeywords = ['math','algebra','geometry','trig','calc','calculus','stats','statistics','english','lang','lit','history','apush','us history','world history','euro','biology','bio','chem','chemistry','physics','science','spanish','french','german','latin','chinese','japanese','art','music','pe','health','econ','economics','gov','government','psychology','psych','sociology','cs','computer science','programming','compsci'];

    const parseDateAnywhere = (str) => {
        const s = String(str || '');
        const m1 = s.match(/\b(\d{4})-(\d{2})-(\d{2})\b/);
        if (m1) return `${m1[1]}-${m1[2]}-${m1[3]}`;
        const m2 = s.match(/\b(\d{1,2})[\/-](\d{1,2})(?:[\/-](\d{2,4}))?\b/);
        if (m2) {
            const mm = String(Math.max(1, Math.min(12, Number(m2[1])))).padStart(2, '0');
            const dd = String(Math.max(1, Math.min(31, Number(m2[2])))).padStart(2, '0');
            let yy = m2[3] ? Number(m2[3]) : now.getFullYear();
            if (yy < 100) yy += 2000;
            return `${yy}-${mm}-${dd}`;
        }
        const months = ['jan','feb','mar','apr','may','jun','jul','aug','sep','oct','nov','dec'];
        const m3 = s.toLowerCase().match(/\b(jan|feb|mar|apr|may|jun|jul|aug|sep|oct|nov|dec)[a-z]*\.?\s+(\d{1,2})(?:,\s*(\d{4}))?/);
        if (m3) {
            const mm = String(months.indexOf(m3[1]) + 1).padStart(2, '0');
            const dd = String(Math.max(1, Math.min(31, Number(m3[2])))).padStart(2, '0');
            const yy = m3[3] ? Number(m3[3]) : now.getFullYear();
            return `${yy}-${mm}-${dd}`;
        }
        if (/\btomorrow\b/i.test(s)) { const t = new Date(now); t.setDate(t.getDate()+1); return t.toISOString().slice(0,10); }
        if (/\btoday\b/i.test(s)) { return now.toISOString().slice(0,10); }
        const weekdays = ['sunday','monday','tuesday','wednesday','thursday','friday','saturday'];
        const m4 = s.toLowerCase().match(/\b(sunday|monday|tuesday|wednesday|thursday|friday|saturday)\b/);
        if (m4) {
            const target = weekdays.indexOf(m4[1]);
            const delta = ((target - now.getDay() + 7) % 7) || 7;
            const t = new Date(now); t.setDate(t.getDate()+delta);
            return t.toISOString().slice(0,10);
        }
        return '';
    };

    const parseTimeAnywhere = (str) => {
        const s = String(str || '');
        const m = s.match(/\b(\d{1,2})(?::(\d{2}))?\s*(am|pm)\b/i);
        if (m) {
            let h = Number(m[1]);
            const mm = m[2] ? Number(m[2]) : 0;
            if ((m[3] || '').toLowerCase() === 'pm' && h < 12) h += 12;
            if ((m[3] || '').toLowerCase() === 'am' && h === 12) h = 0;
            if (h >= 0 && h <= 23 && mm >= 0 && mm <= 59) {
                return `${String(h).padStart(2,'0')}:${String(mm).padStart(2,'0')}`;
            }
        }
        const m2 = s.match(/\b(\d{2}):(\d{2})\b/);
        if (m2) return `${m2[1]}:${m2[2]}`;
        return '';
    };

    const detectDifficulty = (s) => {
        const l = String(s).toLowerCase();
        if (/\b(hard|difficult|challenging|tough)\b/.test(l)) return 'hard';
        if (/\b(easy|simple|quick)\b/.test(l)) return 'easy';
        return 'medium';
    };
    const detectPriority = (s) => {
        const l = String(s).toLowerCase();
        if (/\b(urgent|asap|high priority|!!|important)\b/.test(l)) return 'high';
        if (/\b(low priority|whenever|someday)\b/.test(l)) return 'low';
        return 'medium';
    };
    const detectClass = (s) => {
        const l = String(s).toLowerCase();
        // Try "AP <Subject>" first.
        const ap = l.match(/\bap\s+([a-z][a-z0-9 &]{1,30})/);
        if (ap) return `AP ${ap[1].trim().replace(/\s+/g,' ').split(' ').map(w => w.charAt(0).toUpperCase()+w.slice(1)).join(' ')}`;
        for (const kw of classKeywords) {
            if (l.includes(kw)) {
                return kw.split(' ').map(w => w.charAt(0).toUpperCase()+w.slice(1)).join(' ');
            }
        }
        return '';
    };

    lines.forEach(rawLine => {
        if (!rawLine) return;
        // Skip obvious header-ish lines.
        if (/^(class|subject|assignment|title|due|date|priority|difficulty)\s*[:|]/i.test(rawLine) && !/\d/.test(rawLine)) return;

        // Accept pipe-/tab-/dash-separated or free-form formats.
        let parts = rawLine.split(/\s*\|\s*|\s{2,}|\t/).map(p => p.trim()).filter(Boolean);
        if (parts.length < 2) {
            const dashParts = rawLine.split(/\s+[-–—]\s+/).map(p => p.trim()).filter(Boolean);
            if (dashParts.length >= 2) parts = dashParts;
        }

        let klass = '';
        let title = '';
        let dueDate = '';
        let dueTime = '';

        if (parts.length >= 2) {
            klass = parts[0];
            title = parts[1];
            const rest = parts.slice(2).join(' ');
            dueDate = parseDateAnywhere(`${parts[2] || ''} ${rest}`);
            dueTime = parseTimeAnywhere(`${parts[2] || ''} ${rest}`);
        } else {
            // Single free-form line — detect due substring.
            const m = rawLine.match(/\b(due[:\s]+)(.+)$/i);
            if (m) {
                const before = rawLine.slice(0, m.index).trim();
                const after = m[2].trim();
                dueDate = parseDateAnywhere(after);
                dueTime = parseTimeAnywhere(after);
                klass = detectClass(before);
                title = before.replace(new RegExp(`^${klass}`, 'i'), '').replace(/^[:\-–—\s]+/, '').trim() || before;
            } else {
                klass = detectClass(rawLine);
                title = rawLine.replace(new RegExp(`^${klass}`, 'i'), '').trim();
                dueDate = parseDateAnywhere(rawLine);
                dueTime = parseTimeAnywhere(rawLine);
            }
        }

        if (!klass) klass = detectClass(title) || '';
        title = String(title || '').replace(/\s+/g, ' ').trim();
        klass = String(klass || '').replace(/\s+/g, ' ').trim();
        if (!title) return;

        out.push({
            className: klass,
            title,
            dueDate: dueDate || '',
            dueTime: dueTime || '',
            difficulty: detectDifficulty(rawLine),
            priority: detectPriority(rawLine),
            raw: rawLine
        });
    });

    return out;
}

function openHomeworkPasteImport(prefillText) {
    const modal = document.getElementById('homeworkPasteImportModal');
    if (!modal) return;
    const textarea = modal.querySelector('#homeworkPasteInput');
    const previewHost = modal.querySelector('#homeworkPastePreview');
    const statusEl = modal.querySelector('#homeworkPasteStatus');
    if (!textarea || !previewHost) return;
    textarea.value = String(prefillText || '');

    // Courses map.
    let courses = [];
    try { courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]') || []; } catch (err) { courses = []; }
    const classOptions = courses
        .filter(c => c && c.id)
        .map(c => ({ id: c.id, name: c.name || 'Class', type: c.type === 'misc' ? 'misc' : 'class' }));

    modal._parsed = [];

    const renderPreview = () => {
        const parsed = parseHomeworkPasteText(textarea.value);
        modal._parsed = parsed;
        if (!parsed.length) {
            previewHost.innerHTML = '<p class="hw-paste-empty">Paste assignments above. One per line works best. Example: <em>AP Chem | Lab writeup | 2026-04-28 | hard</em>.</p>';
            if (statusEl) statusEl.textContent = '';
            return;
        }
        const classOptionHtml = (selected) => {
            const newOpt = '<option value="__new__">+ Create new class</option>';
            const existing = classOptions.map(o => `<option value="${escapeCommandHtml(o.id)}"${selected === o.id ? ' selected' : ''}>${escapeCommandHtml(o.name)}${o.type === 'misc' ? ' (misc)' : ''}</option>`).join('');
            return `<option value="">— Unassigned —</option>${existing}${newOpt}`;
        };
        const rows = parsed.map((row, idx) => {
            const match = classOptions.find(o => String(o.name).toLowerCase() === String(row.className || '').toLowerCase());
            return `<tr data-hw-paste-row="${idx}">
                <td><input data-field="title" class="modal-input hw-paste-input" type="text" value="${escapeCommandHtml(row.title || '')}" aria-label="Assignment title" /></td>
                <td>
                    <select data-field="courseId" class="modal-input hw-paste-input" aria-label="Class">${classOptionHtml(match ? match.id : '')}</select>
                    <input data-field="newClassName" class="modal-input hw-paste-input hw-paste-new-class" type="text" value="${escapeCommandHtml(row.className || '')}" aria-label="New class name" placeholder="New class name" style="${match ? 'display:none;' : ''}" />
                </td>
                <td><input data-field="dueDate" class="modal-input hw-paste-input" type="date" value="${escapeCommandHtml(row.dueDate || '')}" aria-label="Due date" /></td>
                <td><input data-field="dueTime" class="modal-input hw-paste-input" type="time" value="${escapeCommandHtml(row.dueTime || '')}" aria-label="Due time" /></td>
                <td>
                    <select data-field="difficulty" class="modal-input hw-paste-input" aria-label="Difficulty">
                        <option value="easy"${row.difficulty==='easy'?' selected':''}>Easy</option>
                        <option value="medium"${row.difficulty==='medium'?' selected':''}>Medium</option>
                        <option value="hard"${row.difficulty==='hard'?' selected':''}>Hard</option>
                    </select>
                </td>
                <td>
                    <select data-field="priority" class="modal-input hw-paste-input" aria-label="Priority">
                        <option value="low"${row.priority==='low'?' selected':''}>Low</option>
                        <option value="medium"${row.priority==='medium'?' selected':''}>Medium</option>
                        <option value="high"${row.priority==='high'?' selected':''}>High</option>
                    </select>
                </td>
                <td><label class="hw-paste-skip"><input type="checkbox" data-field="skip" />Skip</label></td>
            </tr>`;
        }).join('');
        previewHost.innerHTML = `
            <div class="hw-paste-table-wrap">
                <table class="hw-paste-table" role="grid">
                    <thead><tr><th>Title</th><th>Class</th><th>Date</th><th>Time</th><th>Difficulty</th><th>Priority</th><th></th></tr></thead>
                    <tbody>${rows}</tbody>
                </table>
            </div>
        `;
        if (statusEl) statusEl.textContent = `${parsed.length} row${parsed.length === 1 ? '' : 's'} parsed · review and import.`;

        // Toggle new-class name visibility when "__new__" is picked.
        previewHost.querySelectorAll('select[data-field="courseId"]').forEach(sel => {
            sel.addEventListener('change', () => {
                const row = sel.closest('tr');
                const newInput = row && row.querySelector('input[data-field="newClassName"]');
                if (newInput) newInput.style.display = sel.value === '__new__' ? '' : 'none';
            });
        });
    };

    textarea.oninput = renderPreview;
    renderPreview();

    modal.classList.add('active');
    modal.setAttribute('aria-hidden', 'false');
    setTimeout(() => { try { textarea.focus(); } catch (err) {} }, 40);
}

function closeHomeworkPasteImport() {
    const modal = document.getElementById('homeworkPasteImportModal');
    if (!modal) return;
    modal.classList.remove('active');
    modal.setAttribute('aria-hidden', 'true');
}

function submitHomeworkPasteImport() {
    const modal = document.getElementById('homeworkPasteImportModal');
    if (!modal) return;
    const previewHost = modal.querySelector('#homeworkPastePreview');
    const statusEl = modal.querySelector('#homeworkPasteStatus');
    if (!previewHost) return;
    const parsed = Array.isArray(modal._parsed) ? modal._parsed : [];
    const rowEls = Array.from(previewHost.querySelectorAll('[data-hw-paste-row]'));
    if (!rowEls.length) {
        if (typeof showToast === 'function') showToast('Nothing to import. Paste assignments first.');
        return;
    }

    let courses = [];
    let tasks = [];
    try { courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]') || []; } catch (err) { courses = []; }
    try { tasks = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]') || []; } catch (err) { tasks = []; }

    const makeId = () => `${Date.now().toString(36)}${Math.random().toString(36).slice(2, 7)}`;
    const ensureCourseId = (courseId, newName) => {
        if (courseId && courseId !== '__new__') return courseId;
        const name = String(newName || '').trim();
        if (!name) return '';
        const existing = courses.find(c => String(c.name || '').toLowerCase() === name.toLowerCase());
        if (existing) return existing.id;
        const fresh = { id: makeId(), name, type: 'class' };
        courses.push(fresh);
        return fresh.id;
    };

    let imported = 0;
    let skipped = 0;
    let invalid = 0;

    rowEls.forEach((row, idx) => {
        const base = parsed[idx] || {};
        const skipEl = row.querySelector('input[data-field="skip"]');
        if (skipEl && skipEl.checked) { skipped++; return; }
        const title = String((row.querySelector('input[data-field="title"]') || {}).value || base.title || '').trim();
        if (!title) { invalid++; return; }
        const courseSelect = row.querySelector('select[data-field="courseId"]');
        const newClassInput = row.querySelector('input[data-field="newClassName"]');
        const courseId = ensureCourseId(courseSelect ? courseSelect.value : '', newClassInput ? newClassInput.value : '');
        const dueDate = String((row.querySelector('input[data-field="dueDate"]') || {}).value || '');
        const dueTime = String((row.querySelector('input[data-field="dueTime"]') || {}).value || '');
        const difficulty = String((row.querySelector('select[data-field="difficulty"]') || {}).value || base.difficulty || 'medium');
        const priority = String((row.querySelector('select[data-field="priority"]') || {}).value || base.priority || 'medium');
        const nowIso = new Date().toISOString();
        tasks.push({
            id: makeId(),
            courseId,
            title,
            text: title,
            done: false,
            dueDate,
            dueTime,
            due: dueDate,
            priority,
            difficulty,
            notes: base.raw && base.raw !== title ? `Imported: ${String(base.raw).slice(0, 220)}` : '',
            createdAt: nowIso,
            updatedAt: nowIso
        });
        imported++;
    });

    try { localStorage.setItem('hwCourses:v2', JSON.stringify(courses)); } catch (err) {}
    try { localStorage.setItem('hwTasks:v2', JSON.stringify(tasks)); } catch (err) {}
    try { window.dispatchEvent(new CustomEvent('homework:updated')); } catch (err) {}
    try { renderTodayDailyBrief && renderTodayDailyBrief(); } catch (err) {}

    const summary = `Imported ${imported}${skipped ? ` · skipped ${skipped}` : ''}${invalid ? ` · ${invalid} invalid` : ''}.`;
    if (statusEl) statusEl.textContent = summary;
    if (typeof showToast === 'function') showToast(summary);
    if (imported > 0) closeHomeworkPasteImport();
}

// ================================================================
// Class Dashboard: note linking + creation
// ================================================================
function getNotesLinkedToClass(courseId) {
    if (!courseId || typeof pages === 'undefined') return [];
    return (Array.isArray(pages) ? pages : []).filter(p => p && String(p.classLinkId || '') === String(courseId));
}

function linkCurrentNoteToClass(pageId, courseId) {
    if (typeof pages === 'undefined') return false;
    const page = (Array.isArray(pages) ? pages : []).find(p => p && String(p.id) === String(pageId));
    if (!page) return false;
    page.classLinkId = courseId ? String(courseId) : '';
    page.updatedAt = new Date().toISOString();
    try { savePagesToLocal && savePagesToLocal(); } catch (err) {}
    try { renderPagesList && renderPagesList(); } catch (err) {}
    return true;
}

function createNoteLinkedToClass(courseId, titleSeed) {
    if (typeof pages === 'undefined') return null;
    let courseName = '';
    try {
        const courses = JSON.parse(localStorage.getItem('hwCourses:v2') || '[]');
        const c = (Array.isArray(courses) ? courses : []).find(c => String(c.id) === String(courseId));
        if (c) courseName = c.name || '';
    } catch (err) {}
    const nowIso = new Date().toISOString();
    const title = String(titleSeed || (courseName ? `${courseName} — notes` : 'Class notes')).slice(0, 120);
    const newPage = {
        id: (typeof generateId === 'function' ? generateId() : `p${Date.now()}`),
        title,
        content: '',
        blocks: [],
        icon: (typeof PAGE_ICONS !== 'undefined' ? PAGE_ICONS.DOC : '📄'),
        collapsed: false,
        createdAt: nowIso,
        updatedAt: nowIso,
        theme: (typeof globalTheme !== 'undefined' ? globalTheme : 'default'),
        classLinkId: String(courseId || '')
    };
    pages.push(newPage);
    try { savePagesToLocal && savePagesToLocal(); } catch (err) {}
    try { renderPagesList && renderPagesList(); } catch (err) {}
    try { setActiveView('notes'); loadPage && loadPage(newPage.id); } catch (err) {}
    return newPage;
}

// ================================================================
// AP Battle Plan: native-ish AP Study session + note helpers
// ================================================================
function createApStudySessionFromBattlePlan(plan) {
    if (!plan || !plan.subject) return null;
    if (typeof apStudyWorkspace === 'undefined' || !apStudyWorkspace) return null;
    try {
        const id = `apsession_${Date.now().toString(36)}_${Math.random().toString(36).slice(2,6)}`;
        const nowIso = new Date().toISOString();
        const today = nowIso.slice(0, 10);
        const session = {
            id,
            subjectId: plan.subject.id,
            unitId: (plan.weakUnits && plan.weakUnits[0]) ? plan.weakUnits[0].id : null,
            topicId: null,
            title: String(plan.recommendation || 'AP study session').slice(0, 160),
            date: today,
            time: '18:00',
            durationMinutes: 60,
            priority: (plan.daysLeft != null && plan.daysLeft <= 14) ? 'high' : 'medium',
            status: 'scheduled',
            sessionType: plan.sessionType === 'practice test' ? 'practice' : (plan.sessionType === 'mixed session' ? 'mixed' : 'review'),
            noteId: null,
            notes: String(plan.reason || ''),
            completedAt: null,
            updatedAt: nowIso,
            createdAt: nowIso
        };
        if (!Array.isArray(apStudyWorkspace.sessions)) apStudyWorkspace.sessions = [];
        apStudyWorkspace.sessions.push(session);
        if (typeof window.syncApStudySessionsIntoTaskStore === 'function') {
            try { window.syncApStudySessionsIntoTaskStore({ persist: true }); } catch (err) {}
        } else if (typeof persistAppData === 'function') {
            try { persistAppData(); } catch (err) {}
        }
        if (typeof window.renderApStudyWorkspace === 'function') {
            try { window.renderApStudyWorkspace(); } catch (err) {}
        }
        return session;
    } catch (err) { console.warn(err); return null; }
}

function createApUnitNoteFromBattlePlan(plan) {
    if (!plan || !plan.subject || typeof pages === 'undefined') return null;
    const nowIso = new Date().toISOString();
    const subjectName = plan.subject.name || 'AP Subject';
    const weak = (plan.weakUnits && plan.weakUnits[0]) ? plan.weakUnits[0].title : '';
    const title = weak ? `${subjectName} — ${weak}` : `${subjectName} — study notes`;
    const content = `<h2>${title.replace(/</g,'&lt;')}</h2><p><em>${String(plan.reason || '').replace(/</g,'&lt;')}</em></p><p>${String(plan.recommendation || '').replace(/</g,'&lt;')}</p>`;
    const page = {
        id: (typeof generateId === 'function' ? generateId() : `p${Date.now()}`),
        title: title.slice(0, 120),
        content,
        blocks: [],
        icon: (typeof PAGE_ICONS !== 'undefined' ? PAGE_ICONS.DOC : '📄'),
        collapsed: false,
        createdAt: nowIso,
        updatedAt: nowIso,
        theme: (typeof globalTheme !== 'undefined' ? globalTheme : 'default'),
        apSubjectId: plan.subject.id || '',
        apUnitId: (plan.weakUnits && plan.weakUnits[0] && plan.weakUnits[0].id) || ''
    };
    pages.push(page);
    try { savePagesToLocal && savePagesToLocal(); } catch (err) {}
    try { renderPagesList && renderPagesList(); } catch (err) {}
    try { setActiveView('notes'); loadPage && loadPage(page.id); } catch (err) {}
    return page;
}

// ================================================================
// Split-Screen Workflow Presets
// ================================================================
const NOTES_SPLIT_PRESETS = [
    { id: 'note-assignment', label: 'Note + Assignment', description: 'Write notes alongside an open homework assignment.' },
    { id: 'note-ap-unit', label: 'Note + AP Unit', description: 'Draft study notes beside AP unit context.' },
    { id: 'essay-research', label: 'Essay + Research', description: 'Edit an essay while a research note stays open.' },
    { id: 'today-note', label: 'Today Plan + Notes', description: 'Quick daily-plan notes next to your current page.' },
    { id: 'calendar-note', label: 'Calendar + Note', description: 'A loose schedule sketch alongside your current note.' }
];

function getNotesSplitPresets() { return NOTES_SPLIT_PRESETS.slice(); }

function applyNotesSplitPreset(presetId) {
    if (typeof pages === 'undefined') return false;
    const preset = NOTES_SPLIT_PRESETS.find(p => p.id === presetId);
    if (!preset) return false;
    try {
        // Ensure split is enabled.
        if (typeof setSplitViewEnabled === 'function' && appSettings && !appSettings.notesSplitViewEnabled) {
            setSplitViewEnabled(true);
        }
    } catch (err) {}

    const nowIso = new Date().toISOString();
    const mkPage = (seedTitle, seedContent, extra = {}) => {
        const page = Object.assign({
            id: (typeof generateId === 'function' ? generateId() : `p${Date.now()}${Math.floor(Math.random()*1e4)}`),
            title: String(seedTitle || 'New note').slice(0, 120),
            content: String(seedContent || ''),
            blocks: [],
            icon: (typeof PAGE_ICONS !== 'undefined' ? PAGE_ICONS.DOC : '📄'),
            collapsed: false,
            createdAt: nowIso,
            updatedAt: nowIso,
            theme: (typeof globalTheme !== 'undefined' ? globalTheme : 'default')
        }, extra);
        pages.push(page);
        return page;
    };

    let secondary = null;
    switch (preset.id) {
        case 'note-assignment': {
            let hwList = [];
            try { hwList = JSON.parse(localStorage.getItem('hwTasks:v2') || '[]'); } catch (err) {}
            const open = (Array.isArray(hwList) ? hwList : []).filter(t => !t.done).sort((a,b) => String(a.dueDate||'').localeCompare(String(b.dueDate||'')));
            const first = open[0];
            const title = first ? `Working on: ${first.title || first.text || 'Assignment'}` : 'Assignment notes';
            const body = first ? `<p><strong>Due:</strong> ${first.dueDate || 'TBD'}</p><p><em>Paste or type assignment details, then draft your work here.</em></p>` : '<p><em>Create or open an assignment in Homework to pair it here.</em></p>';
            secondary = mkPage(title, body, { splitPresetId: preset.id });
            break;
        }
        case 'note-ap-unit': {
            const aps = (typeof apStudyWorkspace !== 'undefined' && apStudyWorkspace) ? apStudyWorkspace : null;
            const subject = aps && Array.isArray(aps.subjects) ? aps.subjects[0] : null;
            const title = subject ? `${subject.name} — unit notes` : 'AP unit notes';
            const body = subject ? `<p><em>Subject:</em> ${String(subject.name || '').replace(/</g,'&lt;')}</p><p>Draft unit summaries, confusion points, and practice targets.</p>` : '<p><em>Add an AP subject to auto-pair context.</em></p>';
            secondary = mkPage(title, body, { splitPresetId: preset.id, apSubjectId: subject ? subject.id : '' });
            break;
        }
        case 'essay-research': {
            secondary = mkPage('Research — sources & quotes', '<h3>Research</h3><ul><li>Source 1 — </li><li>Source 2 — </li></ul><p><em>Paste excerpts here while you draft the essay.</em></p>', { splitPresetId: preset.id });
            break;
        }
        case 'today-note': {
            const today = new Date();
            const stamp = today.toISOString().slice(0,10);
            secondary = mkPage(`Today plan · ${stamp}`, '<h3>Today</h3><ul><li>☐ </li><li>☐ </li><li>☐ </li></ul><p><em>Rough daily plan. Convert to tasks via Quick Capture if needed.</em></p>', { splitPresetId: preset.id });
            break;
        }
        case 'calendar-note': {
            secondary = mkPage('Calendar sketch', '<p><em>Blocks for today</em></p><ul><li>Morning — </li><li>Afternoon — </li><li>Evening — </li></ul>', { splitPresetId: preset.id });
            break;
        }
        default:
            return false;
    }

    try { savePagesToLocal && savePagesToLocal(); } catch (err) {}
    try { renderPagesList && renderPagesList(); } catch (err) {}

    try {
        if (typeof secondaryPageId !== 'undefined' && secondary) {
            // loadSecondaryPage is defined inside a closure, so rely on setSplitViewEnabled's applySplitViewState() path.
            if (appSettings) appSettings.notesSplitSecondaryPageId = secondary.id;
            if (typeof setSplitViewEnabled === 'function') setSplitViewEnabled(true);
            if (typeof loadSecondaryPage === 'function') loadSecondaryPage(secondary.id);
        }
    } catch (err) { /* non-critical */ }

    if (typeof showToast === 'function') showToast(`Split preset: ${preset.label}`);
    return true;
}

function openNotesSplitPresetsPicker() {
    const existing = document.getElementById('notesSplitPresetsPopover');
    if (existing) { existing.parentNode.removeChild(existing); return; }
    const host = document.getElementById('splitNotesToggleBtn');
    const popover = document.createElement('div');
    popover.id = 'notesSplitPresetsPopover';
    popover.className = 'notes-split-presets-popover';
    popover.setAttribute('role', 'menu');
    popover.innerHTML = `
        <div class="notes-split-presets-head">Split workflow presets</div>
        <ul class="notes-split-presets-list">
            ${NOTES_SPLIT_PRESETS.map(p => `
                <li><button type="button" class="neumo-btn notes-split-preset-btn" data-preset-id="${p.id}">
                    <span class="preset-label">${p.label}</span>
                    <span class="preset-desc">${p.description}</span>
                </button></li>
            `).join('')}
        </ul>
    `;
    document.body.appendChild(popover);
    if (host && host.getBoundingClientRect) {
        const r = host.getBoundingClientRect();
        popover.style.position = 'fixed';
        popover.style.top = `${Math.round(r.bottom + 8)}px`;
        popover.style.left = `${Math.round(Math.max(12, r.left - 120))}px`;
        popover.style.zIndex = 1500;
    }
    popover.querySelectorAll('[data-preset-id]').forEach(btn => {
        btn.addEventListener('click', () => {
            try { applyNotesSplitPreset(btn.getAttribute('data-preset-id')); } catch (err) { console.warn(err); }
            if (popover.parentNode) popover.parentNode.removeChild(popover);
        });
    });
    const close = (ev) => {
        if (!popover.contains(ev.target)) {
            if (popover.parentNode) popover.parentNode.removeChild(popover);
            document.removeEventListener('mousedown', close, true);
        }
    };
    setTimeout(() => document.addEventListener('mousedown', close, true), 20);
}

// ================================================================
// Global Search standalone panel
// ================================================================
function openGlobalSearchPanel(initialQuery) {
    const modal = document.getElementById('globalSearchPanel');
    if (!modal) return;
    const input = modal.querySelector('#globalSearchInput');
    const results = modal.querySelector('#globalSearchResults');
    if (!input || !results) return;
    input.value = String(initialQuery || '');

    const render = () => {
        const q = String(input.value || '').trim();
        if (!q) {
            const recent = (typeof appSettings === 'object' && appSettings && Array.isArray(appSettings.recentSearches))
                ? appSettings.recentSearches.slice(0, 6)
                : [];
            const recentHtml = recent.length
                ? `<section class="global-search-group"><h4>Recent</h4><ul>${recent.map((entry, idx) => `<li class="global-search-item" data-gs-recent="${idx}" tabindex="0"><div class="global-search-item-title">${escapeCommandHtml(entry.query)}</div></li>`).join('')}</ul></section>`
                : '';
            results.innerHTML = `<div class="global-search-empty">Type to search notes, tasks, homework, AP, Review, trackers, College, Timeline…</div>${recentHtml}`;
            results.querySelectorAll('[data-gs-recent]').forEach(node => {
                node.addEventListener('click', () => {
                    const idx = Number(node.getAttribute('data-gs-recent'));
                    const entry = recent[idx];
                    if (!entry) return;
                    input.value = entry.query;
                    render();
                });
            });
            return;
        }
        const data = globalSearchAll(q);
        const mode = (typeof getActiveWorkspaceMode === 'function') ? getActiveWorkspaceMode() : 'standard';
        const modeAllows = (view) => (typeof shouldShowViewForWorkspaceMode === 'function') ? shouldShowViewForWorkspaceMode(view) : true;

        const groups = [];
        if (modeAllows('notes')) groups.push(['Notes', data.notes]);
        groups.push(['Tasks', data.tasks]);
        if (modeAllows('homework')) groups.push(['Homework', data.homework]);
        if (modeAllows('apstudy')) groups.push(['AP Study', data.apstudy]);
        if (modeAllows('review')) groups.push(['Review', data.review]);
        groups.push(['Trackers', data.trackers]);
        if (modeAllows('collegeapp')) groups.push(['College', data.college]);
        if (modeAllows('timeline')) groups.push(['Timeline', data.timeline]);
        // Persist a compact recent-search trail so command-palette/global-search
        // can show recent queries when the input is empty.
        try {
            if (typeof appSettings === 'object' && appSettings) {
                const list = Array.isArray(appSettings.recentSearches) ? appSettings.recentSearches : [];
                const filtered = list.filter(entry => entry && entry.query && entry.query.toLowerCase() !== q);
                filtered.unshift({ query: q, at: new Date().toISOString() });
                appSettings.recentSearches = filtered.slice(0, 25);
                if (typeof persistAppData === 'function') persistAppData();
            }
        } catch (err) { /* non-critical */ }

        const hasAny = groups.some(([, arr]) => Array.isArray(arr) && arr.length);
        if (!hasAny) {
            results.innerHTML = '<div class="global-search-empty">No matches in this workspace.</div>';
            modal._searchResults = null;
            return;
        }
        const html = groups.map(([label, arr]) => {
            if (!Array.isArray(arr) || !arr.length) return '';
            const items = arr.map((r, i) => `
                <li class="global-search-item" data-gs-group="${escapeCommandHtml(label)}" data-gs-idx="${i}" tabindex="0">
                    <div class="global-search-item-title">${escapeCommandHtml(r.title || '')}</div>
                    ${r.context ? `<div class="global-search-item-meta">${escapeCommandHtml(r.context)}</div>` : ''}
                </li>`).join('');
            return `<section class="global-search-group"><h4>${escapeCommandHtml(label)}</h4><ul>${items}</ul></section>`;
        }).join('');
        results.innerHTML = html;
        modal._searchResults = data;

        results.querySelectorAll('.global-search-item').forEach(node => {
            node.addEventListener('click', () => {
                const group = node.getAttribute('data-gs-group');
                const idx = Number(node.getAttribute('data-gs-idx'));
                const current = modal._searchResults || {};
                const map = { 'Notes': 'notes', 'Tasks': 'tasks', 'Homework': 'homework', 'AP Study': 'apstudy', 'Review': 'review', 'Trackers': 'trackers', 'College': 'college', 'Timeline': 'timeline' };
                const arr = current[map[group] || ''] || [];
                const hit = arr[idx];
                if (hit && typeof hit.action === 'function') {
                    closeGlobalSearchPanel();
                    try { hit.action(); } catch (err) { console.warn(err); }
                }
            });
        });
    };
    input.oninput = render;
    render();

    modal.classList.add('active');
    modal.setAttribute('aria-hidden', 'false');
    setTimeout(() => { try { input.focus(); input.select(); } catch (err) {} }, 30);
}

function closeGlobalSearchPanel() {
    const modal = document.getElementById('globalSearchPanel');
    if (!modal) return;
    modal.classList.remove('active');
    modal.setAttribute('aria-hidden', 'true');
}

// =============================================================================
// FOCUS SESSION MODULE
// Cinematic full-screen focus mode for active tasks.
// State lives in appSettings.activeFocusSession (travels through all
// persist / export / import paths automatically via appSettings).
// =============================================================================

const FS_AMBIENT_PRESETS = ['gradient', 'fireplace', 'nightsky', 'rain', 'library'];
const FS_DEFAULT_AMBIENT = 'gradient';
const FS_DEFAULT_DURATION_SECONDS = 25 * 60;

// Runtime state — mirrors appSettings.activeFocusSession during a session.
let _fsSession = null;
let _fsIntervalId = null;
let _fsKeyboardBound = false;

function _fsGenerateId() {
    return 'fs_' + Math.random().toString(36).substr(2, 9) + '_' + Date.now().toString(36);
}

function _fsNormalizeSession(raw) {
    if (!raw || typeof raw !== 'object') return null;
    const plannedRaw = Number(raw.plannedDurationSeconds);
    const elapsedRaw = Number(raw.elapsedSeconds);
    return {
        id:                     raw.id ? String(raw.id) : _fsGenerateId(),
        taskId:                 raw.taskId ? String(raw.taskId) : null,
        taskTitle:              String(raw.taskTitle || 'Focus Session'),
        taskNote:               String(raw.taskNote || ''),
        plannedDurationSeconds: Number.isFinite(plannedRaw) && plannedRaw >= 0 ? Math.floor(plannedRaw) : FS_DEFAULT_DURATION_SECONDS,
        elapsedSeconds:         Number.isFinite(elapsedRaw) && elapsedRaw >= 0 ? Math.floor(elapsedRaw) : 0,
        running:                false,  // never restore as actively running — safety
        sessionNotes:           String(raw.sessionNotes || ''),
        ambient:                FS_AMBIENT_PRESETS.includes(raw.ambient) ? raw.ambient : FS_DEFAULT_AMBIENT,
        startedAt:              raw.startedAt ? String(raw.startedAt) : new Date().toISOString(),
        lastTickAt:             raw.lastTickAt ? String(raw.lastTickAt) : null
    };
}

// ---------- Overlay open / close ----------

function _fsOpenOverlay() {
    const overlay = document.getElementById('focusSessionOverlay');
    if (!overlay) return;

    _fsPopulateUI();

    overlay.removeAttribute('hidden');
    overlay.setAttribute('aria-hidden', 'false');
    document.body.classList.add('fs-active');

    // Trigger CSS transition on next frame
    requestAnimationFrame(function() {
        requestAnimationFrame(function() {
            overlay.classList.add('fs-visible');
        });
    });

    // Focus the play button for keyboard users
    var playBtn = document.getElementById('fsPlayBtn');
    if (playBtn) setTimeout(function() { try { playBtn.focus(); } catch (e) {} }, 120);
}

function _fsCloseOverlay(reason) {
    _fsPauseTimer();

    // Flush notes before closing
    var notesArea = document.getElementById('fsNotesTextarea');
    if (notesArea && _fsSession) _fsSession.sessionNotes = notesArea.value || '';

    if (reason !== 'abandon') {
        _fsPersistSession();
    }

    var overlay = document.getElementById('focusSessionOverlay');
    if (overlay) {
        overlay.classList.remove('fs-visible');
        setTimeout(function() {
            overlay.setAttribute('hidden', '');
            overlay.setAttribute('aria-hidden', 'true');
        }, 450);
    }
    document.body.classList.remove('fs-active');

    // Close notes panel if open
    var notesPanel = document.getElementById('fsNotesPanel');
    if (notesPanel && !notesPanel.hasAttribute('hidden')) {
        notesPanel.setAttribute('hidden', '');
    }

    if (reason === 'abandon') {
        _fsSession = null;
        _fsPersistSession();
    }
}

// ---------- UI population ----------

function _fsPopulateUI() {
    if (!_fsSession) return;
    var s = _fsSession;

    var titleEl  = document.getElementById('fsTaskTitle');
    var noteEl   = document.getElementById('fsTaskNote');
    var notesArea= document.getElementById('fsNotesTextarea');

    if (titleEl) titleEl.textContent = s.taskTitle;
    if (noteEl) {
        noteEl.textContent  = s.taskNote;
        noteEl.style.display = s.taskNote ? '' : 'none';
    }
    if (notesArea) notesArea.value = s.sessionNotes || '';

    fsSetAmbient(s.ambient, false);
    _fsUpdateUI();
}

function _fsUpdateUI() {
    if (!_fsSession) return;
    var s        = _fsSession;
    var planned  = s.plannedDurationSeconds;
    var elapsed  = s.elapsedSeconds;
    var remaining= planned > 0 ? Math.max(0, planned - elapsed) : elapsed;

    // Main timer — shows remaining when planned > 0, otherwise elapsed
    var timerEl = document.getElementById('fsTimerDisplay');
    if (timerEl) {
        var display = planned > 0 ? remaining : elapsed;
        timerEl.textContent = _fsFormatTime(display);
        timerEl.classList.toggle('is-done', planned > 0 && remaining === 0);
    }

    // Elapsed / planned labels
    var elapsedEl = document.getElementById('fsElapsed');
    var plannedEl = document.getElementById('fsPlanned');
    if (elapsedEl) elapsedEl.textContent = _fsFormatTime(elapsed, true);
    if (plannedEl) plannedEl.textContent = planned > 0 ? _fsFormatTime(planned, true) : '∞';

    // Progress bar
    var fillEl = document.getElementById('fsProgressFill');
    if (fillEl) {
        var pct = planned > 0 ? Math.min(100, (elapsed / planned) * 100) : 0;
        fillEl.style.width = pct + '%';
        var track = fillEl.closest('[role="progressbar"]') || fillEl.parentElement;
        if (track) track.setAttribute('aria-valuenow', Math.round(pct));
    }

    // Status pill
    var pillEl = document.getElementById('fsStatusPill');
    if (pillEl) {
        if (planned > 0 && elapsed >= planned) {
            pillEl.textContent  = "Time's up!";
            pillEl.className    = 'fs-status-pill is-done';
        } else if (s.running) {
            pillEl.textContent  = 'Focusing';
            pillEl.className    = 'fs-status-pill is-focusing';
        } else if (elapsed === 0) {
            pillEl.textContent  = 'Ready';
            pillEl.className    = 'fs-status-pill';
        } else {
            pillEl.textContent  = 'Paused';
            pillEl.className    = 'fs-status-pill';
        }
    }

    // Play button icon + state
    var playBtn  = document.getElementById('fsPlayBtn');
    var playIcon = document.getElementById('fsPlayIcon');
    if (playBtn && playIcon) {
        var isPlaying = s.running;
        playBtn.classList.toggle('is-playing', isPlaying);
        playBtn.setAttribute('aria-label', isPlaying ? 'Pause timer' : 'Start timer');
        playBtn.title = isPlaying ? 'Pause (Space)' : 'Play (Space)';
        playIcon.className = isPlaying ? 'fas fa-pause' : 'fas fa-play';
        playIcon.setAttribute('aria-hidden', 'true');
    }

    // Complete button: only show when a task is linked
    var completeBtn = document.getElementById('fsCompleteBtn');
    if (completeBtn) completeBtn.style.display = s.taskId ? '' : 'none';
}

// ---------- Timer tick ----------

function _fsStartTimer() {
    if (!_fsSession || _fsSession.running) return;
    _fsSession.running   = true;
    _fsSession.lastTickAt = new Date().toISOString();
    if (_fsIntervalId) clearInterval(_fsIntervalId);
    _fsIntervalId = setInterval(_fsTick, 1000);
    _fsUpdateUI();
}

function _fsPauseTimer() {
    if (!_fsSession || !_fsSession.running) return;
    _fsSession.running = false;
    if (_fsIntervalId) { clearInterval(_fsIntervalId); _fsIntervalId = null; }
    _fsUpdateUI();
}

function _fsTick() {
    if (!_fsSession) return;
    _fsSession.elapsedSeconds += 1;
    _fsSession.lastTickAt = new Date().toISOString();

    var planned = _fsSession.plannedDurationSeconds;
    if (planned > 0 && _fsSession.elapsedSeconds >= planned) {
        _fsSession.elapsedSeconds = planned;
        _fsPauseTimer();
        _fsUpdateUI();
        _fsPersistSession();
        try { if (typeof playTimerDoneChime === 'function') playTimerDoneChime(); } catch (e) {}
        try { if (typeof showToast === 'function') showToast('Focus session complete! Great work.', { durationMs: 4000 }); } catch (e) {}
        return;
    }

    _fsUpdateUI();
    // Autosave every 30 s to guard against accidental closure
    if (_fsSession.elapsedSeconds % 30 === 0) _fsPersistSession();
}

// ---------- Public controls (called from onclick) ----------

function fsTogglePlay() {
    if (!_fsSession) return;
    _fsSession.running ? _fsPauseTimer() : _fsStartTimer();
    _fsPersistSession();
}

function fsReset() {
    if (!_fsSession) return;
    _fsPauseTimer();
    _fsSession.elapsedSeconds = 0;
    _fsSession.lastTickAt     = null;
    _fsUpdateUI();
    _fsPersistSession();
}

function fsRestart() {
    fsReset();
    _fsStartTimer();
}

function fsMinimize() {
    // Save state and close visually; session keeps running in background (paused)
    _fsPauseTimer();
    _fsCloseOverlay('minimize');
    try { if (typeof showToast === 'function') showToast('Session saved — tap "Launch Focus Mode" to return.', { durationMs: 3500 }); } catch (e) {}
}

async function fsClose() {
    if (_fsSession && _fsSession.elapsedSeconds > 5) {
        const message = 'Close this focus session? Your current progress will be cleared.';
        let ok;
        if (typeof atelierConfirm === 'function') {
            ok = await atelierConfirm(message, { title: 'Close focus session', confirmText: 'Close session', cancelText: 'Keep going', destructive: true });
        } else {
            ok = confirm(message);
        }
        if (!ok) return;
    }
    _fsCloseOverlay('abandon');
}

function fsSaveAndContinue() {
    if (!_fsSession) { _fsCloseOverlay('save'); return; }
    var notesArea = document.getElementById('fsNotesTextarea');
    if (notesArea) _fsSession.sessionNotes = notesArea.value || '';
    _fsPauseTimer();
    _fsCloseOverlay('save');
    try { if (typeof showToast === 'function') showToast('Focus session saved.'); } catch (e) {}
}

function fsCompleteTask() {
    if (!_fsSession) return;
    var notesArea = document.getElementById('fsNotesTextarea');
    if (notesArea) _fsSession.sessionNotes = notesArea.value || '';

    var taskId = _fsSession.taskId;
    if (taskId) {
        var linkedTask = (typeof tasks !== 'undefined' && Array.isArray(tasks) ? tasks : []).find(function(t) { return t && t.id === taskId; });
        if (linkedTask) {
            try {
                // Check if not already completed today before toggling
                var todayKey = typeof today === 'function' ? today() : '';
                var ds = todayKey && typeof getDayState === 'function' ? getDayState(todayKey) : null;
                var alreadyDone = ds && Array.isArray(ds.completedTaskIds) && ds.completedTaskIds.includes(taskId);
                if (!alreadyDone && typeof toggleComplete === 'function') {
                    toggleComplete(taskId);
                } else if (alreadyDone) {
                    try { if (typeof showToast === 'function') showToast('"' + linkedTask.title + '" was already marked complete.'); } catch (e) {}
                }
            } catch (e) { /* non-critical */ }
        }
    }

    _fsSession = null;
    _fsPersistSession();
    _fsCloseOverlay('complete');
}

function fsSetAmbient(preset, save) {
    if (!FS_AMBIENT_PRESETS.includes(preset)) return;

    var bgEl = document.getElementById('fsAmbientBg');
    if (bgEl) bgEl.setAttribute('data-ambient', preset);

    document.querySelectorAll('.fs-ambient-chip').forEach(function(chip) {
        chip.classList.toggle('active', chip.getAttribute('data-ambient') === preset);
    });

    if (_fsSession && save !== false) {
        _fsSession.ambient = preset;
        _fsPersistSession();
    }
}

function fsToggleNotes() {
    var panel = document.getElementById('fsNotesPanel');
    if (!panel) return;
    var isOpen = !panel.hasAttribute('hidden');
    if (isOpen) {
        var notesArea = document.getElementById('fsNotesTextarea');
        if (notesArea && _fsSession) _fsSession.sessionNotes = notesArea.value || '';
        panel.setAttribute('hidden', '');
    } else {
        panel.removeAttribute('hidden');
        setTimeout(function() {
            var notesArea = document.getElementById('fsNotesTextarea');
            if (notesArea) try { notesArea.focus(); } catch (e) {}
        }, 50);
    }
}

// ---------- Persistence ----------

function _fsPersistSession() {
    if (typeof appSettings === 'undefined' || !appSettings) return;
    appSettings.activeFocusSession = _fsSession ? Object.assign({}, _fsSession) : null;
    try { if (typeof persistAppData === 'function') persistAppData(); } catch (e) { /* non-critical */ }
}

function restoreFocusSessionIfActive() {
    if (typeof appSettings === 'undefined' || !appSettings) return;
    var raw = appSettings.activeFocusSession;
    if (!raw || typeof raw !== 'object' || !raw.id) return;

    var restored = _fsNormalizeSession(raw);
    if (!restored) return;

    // If the session was running when last saved, calculate catch-up time
    // (treat as paused — don't auto-resume after a reload)
    if (raw.running && raw.lastTickAt) {
        try {
            var lastTick = new Date(raw.lastTickAt);
            var now = new Date();
            var passedSecs = Math.floor((now - lastTick) / 1000);
            if (passedSecs > 0 && passedSecs < 7200) {
                var maxElapsed = restored.plannedDurationSeconds > 0 ? restored.plannedDurationSeconds : passedSecs + restored.elapsedSeconds;
                restored.elapsedSeconds = Math.min(restored.elapsedSeconds + passedSecs, maxElapsed);
            }
        } catch (e) { /* non-critical */ }
    }

    _fsSession = restored;

    // Update the sidebar launch button label to signal an active session
    _fsUpdateLaunchBtnLabel();
}

function _fsUpdateLaunchBtnLabel() {
    var btn = document.getElementById('fsLaunchBtn');
    if (!btn) return;
    if (_fsSession && _fsSession.id) {
        btn.innerHTML = '<i class="fas fa-expand-alt" aria-hidden="true"></i> Resume Focus Session';
    } else {
        btn.innerHTML = '<i class="fas fa-expand-alt" aria-hidden="true"></i> Launch Focus Mode';
    }
}

// Called from the sidebar button — opens existing session or starts a blank one
function startFocusSession(taskId, opts) {
    opts = opts || {};

    // If there's already an active session and no new taskId, reopen it
    if (_fsSession && _fsSession.id && !taskId) {
        _fsOpenOverlay();
        return;
    }

    // If there's a session tied to the same task, reopen that
    if (_fsSession && _fsSession.id && taskId && _fsSession.taskId === taskId) {
        _fsOpenOverlay();
        return;
    }

    // New session
    var task = taskId ? ((typeof tasks !== 'undefined' && Array.isArray(tasks) ? tasks : []).find(function(t) { return t && t.id === taskId; }) || null) : null;

    var plannedDuration = FS_DEFAULT_DURATION_SECONDS;
    if (opts.plannedDurationSeconds !== undefined) {
        var p = Math.floor(Number(opts.plannedDurationSeconds) || 0);
        if (p >= 0) plannedDuration = p;
    } else if (task) {
        try {
            var mins = typeof getTaskEstimatedMinutes === 'function' ? getTaskEstimatedMinutes(task) : 0;
            if (mins > 0) plannedDuration = mins * 60;
        } catch (e) { /* non-critical */ }
    }

    _fsSession = {
        id:                     _fsGenerateId(),
        taskId:                 task ? task.id : null,
        taskTitle:              task ? (task.title || 'Focus Session') : (opts.title || 'Focus Session'),
        taskNote:               task ? (task.notes || '') : (opts.note || ''),
        plannedDurationSeconds: plannedDuration,
        elapsedSeconds:         0,
        running:                false,
        sessionNotes:           '',
        ambient:                opts.ambient || FS_DEFAULT_AMBIENT,
        startedAt:              new Date().toISOString(),
        lastTickAt:             null
    };

    _fsOpenOverlay();
    _fsPersistSession();
    _fsUpdateLaunchBtnLabel();
}

// ---------- Keyboard ----------

function initFocusSessionKeyboard() {
    if (_fsKeyboardBound) return;
    _fsKeyboardBound = true;

    document.addEventListener('keydown', function(e) {
        var overlay = document.getElementById('focusSessionOverlay');
        if (!overlay || overlay.hasAttribute('hidden') || !_fsSession) return;

        // Don't intercept typing in text fields
        var tag = e.target && e.target.tagName;
        if (tag === 'TEXTAREA' || tag === 'INPUT' || tag === 'SELECT') return;
        if (e.target && (e.target.isContentEditable)) return;

        if (e.code === 'Space' || e.key === ' ') {
            e.preventDefault();
            fsTogglePlay();
        } else if (e.key === 'Escape') {
            e.preventDefault();
            fsMinimize();
        } else if (e.key === 'Enter') {
            e.preventDefault();
            if (_fsSession && _fsSession.taskId) fsCompleteTask();
        }
    }, true);
}

// ---------- Time formatting ----------

function _fsFormatTime(totalSeconds, compact) {
    var s   = Math.max(0, Math.floor(Number(totalSeconds) || 0));
    var h   = Math.floor(s / 3600);
    var m   = Math.floor((s % 3600) / 60);
    var sec = s % 60;
    var pad = function(n) { return String(n).padStart(2, '0'); };
    if (h > 0) return h + ':' + pad(m) + ':' + pad(sec);
    if (compact) return m + ':' + pad(sec);
    return pad(m) + ':' + pad(sec);
}























